INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('e6d84b7080fed5ac', '78a43a7ac135d5d7', '6ec34f64d8ae235b', 'Services', 'services', 'src/app/components/sections/StrategicServicesSection.tsx', '@/app/components/sections', 1, 'StrategicServicesSection', '{"confidence":0.9,"parseStatus":"parsed","displayOrder":1}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('ed65386a6d2ee357', '6214c13d4994a673', 'a5036340ba4de876', 'FAQ Content', 'faq-content', 'src/app/pages/faq.tsx', 'src/app/pages/faq.tsx', 1, 'FAQContentSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8\">\n          <Accordion type=\"single\" collapsible className=\"space-y-4\">\n            {faqs.map((faq, index) => (\n              <AccordionItem \n                key={index} \n                value={`item-${index}`}\n                className=\"bg-white border border-border rounded px-6\"\n              >\n                <AccordionTrigger className=\"text-left hover:no-underline py-6\">\n                  <span className=\"pr-4\">{faq.question}</span>\n                </AccordionTrigger>\n                <AccordionContent className=\"text-muted-foreground leading-relaxed pb-6\">\n                  {faq.answer}\n                </AccordionContent>\n              </AccordionItem>\n            ))}\n          </Accordion>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('0a9f7c5f8595ea33', '6214c13d4994a673', '928cbe9e54d8c24f', 'Attorney Profiles', 'attorney-profiles', 'src/app/pages/about.tsx', 'src/app/pages/about.tsx', 2, 'AttorneyProfilesSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-12 text-foreground text-center\">\n            Our Attorneys\n          </h2>\n          \n          {/* Rebecca Windsor */}\n          <div className=\"mb-20\">\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={markPhoto}\n                    alt=\"Portrait of Mark Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Mark Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  mark@windsorlaw.us<br />\n                  (626) 792-6700\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had &quot;fought like tigers&quot; for his client in an alien smuggling trial.\n                  </p>\n                  <p>\n                    Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\n                  </p>\n                  <p>\n                    Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\n                  </p>\n                  <p>\n                    Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\n                  </p>\n                  \n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Bar Admissions</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>State Bar of California</li>\n                      <li>California State Courts</li>\n                      <li>U.S. District Court, Northern District of California</li>\n                      <li>U.S. District Court, Central District of California</li>\n                      <li>U.S. District Court, Southern District of California</li>\n                      <li>U.S. Court of Appeals, Ninth Circuit</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A. in History, Brown University</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Michael Kimball */}\n          <div>\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={katyPhoto}\n                    alt=\"Portrait of Katy Kimball Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Katy Kimball Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  katy@windsorlaw.us<br />\n                  (213) 663-9219\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\n                  </p>\n                  <p>\n                    She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\n                  </p>\n                  <p>\n                    Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\n                  </p>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A., Vassar College</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Experience</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)</li>\n                      <li>Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)</li>\n                      <li>Private practice focused on federal criminal defense and appeals</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('69c138aef5a67859', '6214c13d4994a673', '5aafb0c755ce76ec', 'Practice Areas Overview', 'practice-areas-overview', 'src/app/pages/home.tsx', 'src/app/pages/home.tsx', 2, 'PracticeAreasOverviewSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Areas of Practice\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              We handle a wide range of federal criminal matters with precision and dedication.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n            {practiceAreas.map((area) => (\n              <div key={area.title} className=\"border border-border p-6 rounded hover:border-primary/30 transition-colors\">\n                <h3 className=\"text-lg mb-3\">{area.title}</h3>\n                <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                  {area.description}\n                </p>\n              </div>\n            ))}\n          </div>\n          <div className=\"text-center mt-12\">\n            <Link \n              to=\"/practice-areas\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              View All Practice Areas\n            </Link>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('730d24f9268f2be7', '78a43a7ac135d5d7', '6ec34f64d8ae235b', 'Solutions', 'solutions', 'src/app/components/sections/SolutionsSection.tsx', '@/app/components/sections', 2, 'SolutionsSection', '{"confidence":0.9,"parseStatus":"parsed","displayOrder":2}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('9465cabf3163ae40', '6214c13d4994a673', '3aa7c9b56e48fbe3', 'Section 3', 'section-3', 'src/app/pages/successes.tsx', 'src/app/pages/successes.tsx', 2, 'Section3Section', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-16\">\n        <div className=\"mx-auto max-w-4xl px-6 lg:px-8\">\n          <div className=\"border-l-4 border-primary/30 pl-6\">\n            <p className=\"text-sm italic leading-relaxed text-muted-foreground\">\n              The results described above were achieved in specific cases and do\n              not guarantee or predict a similar result in any future case.\n              Every case is unique and must be evaluated on its own facts and\n              circumstances. Client results depend on a variety of factors\n              including the facts of the case, applicable law, venue, and the\n              skill and preparation of all parties involved.\n            </p>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('94a9092ff104c344', '6214c13d4994a673', 'a5036340ba4de876', 'CTA', 'cta', 'src/app/pages/faq.tsx', 'src/app/pages/faq.tsx', 2, 'CTASection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Have More Questions?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Every case is unique. Contact us for a confidential consultation to discuss your specific situation.\n          </p>\n          <a \n            href=\"/contact\" \n            className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n          >\n            Contact Us Today\n          </a>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('e6af3e9046fa03b1', '6214c13d4994a673', '9e4a7e6abffd2938', 'Jurisdictions', 'jurisdictions', 'src/app/pages/contact.tsx', 'src/app/pages/contact.tsx', 2, 'JurisdictionsSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Areas We Serve\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto leading-relaxed\">\n              We represent clients throughout Southern California and the Ninth Circuit. Our practice includes the following federal courts:\n            </p>\n          </div>\n\n          <div className=\"grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto\">\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Central District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Central District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• Los Angeles County</li>\n                <li>• Orange County</li>\n                <li>• Riverside County</li>\n                <li>• San Bernardino County</li>\n                <li>• San Luis Obispo County</li>\n                <li>• Santa Barbara County</li>\n                <li>• Ventura County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Southern District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Southern District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• San Diego County</li>\n                <li>• Imperial County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded md:col-span-2\">\n              <h3 className=\"mb-4 text-lg\">U.S. Court of Appeals, Ninth Circuit</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We handle appeals throughout the Ninth Circuit Court of Appeals, which covers federal appeals from California, Oregon, Washington, Arizona, Nevada, Idaho, Montana, Alaska, and Hawaii.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('f0418e8f5f6488f1', '6214c13d4994a673', '159beb30efd4673f', 'Federal Court Info', 'federal-court-info', 'src/app/pages/practice-areas.tsx', 'src/app/pages/practice-areas.tsx', 2, 'FederalCourtInfoSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto\">\n            <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n              Understanding Federal Criminal Defense\n            </h2>\n            <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n              <p>\n                Federal criminal cases are fundamentally different from state prosecutions. They are typically more complex, involve more sophisticated investigation techniques, and carry harsher penalties. The federal criminal justice system has its own set of rules, procedures, and sentencing guidelines.\n              </p>\n              <p>\n                Federal prosecutors are well-resourced and highly skilled. By the time charges are filed, the government has often been investigating for months or years. This is why having experienced federal defense counsel is critical—not just after charges are filed, but ideally during the investigation phase when strategic intervention can sometimes prevent charges altogether.\n              </p>\n              <p>\n                We practice primarily in the U.S. District Courts for the Central District of California (which includes Los Angeles, Orange County, Riverside, San Bernardino, San Luis Obispo, Santa Barbara, and Ventura Counties) and the Southern District of California (which includes San Diego and Imperial Counties). We also handle appeals in the Ninth Circuit Court of Appeals.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('41a0628f635681d8', '6214c13d4994a673', '5aafb0c755ce76ec', 'Notable Results', 'notable-results', 'src/app/pages/home.tsx', 'src/app/pages/home.tsx', 3, 'NotableResultsSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":3,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Representative Results\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              Our track record speaks to our commitment to zealous advocacy and client service.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-2 gap-8\">\n            {featuredResults.map((result) => (\n              <div key={result.title} className=\"bg-white p-8 rounded\">\n                <div className=\"mb-4\">\n                  <span className=\"inline-block rounded bg-primary/10 px-3 py-1 text-xs uppercase tracking-wider text-primary\">\n                    {result.charge}\n                  </span>\n                </div>\n                <h3 className=\"text-lg mb-4 text-primary\">{result.title}</h3>\n                <div className=\"text-sm text-muted-foreground leading-relaxed\">\n                  {result.summary}\n                </div>\n              </div>\n            ))}\n          </div>\n          <div className=\"text-center mt-12\">\n            <Link \n              to=\"/successes\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              View More Results\n            </Link>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('5c0f83636ab8632f', '6214c13d4994a673', '928cbe9e54d8c24f', 'Jurisdictions', 'jurisdictions', 'src/app/pages/about.tsx', 'src/app/pages/about.tsx', 3, 'JurisdictionsSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":3,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n            Jurisdictions Served\n          </h2>\n          <div className=\"max-w-3xl mx-auto\">\n            <p className=\"text-center text-muted-foreground leading-relaxed mb-8\">\n              We are admitted to practice and regularly appear in the following courts:\n            </p>\n            <div className=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Trial Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. District Court, Central District of California</li>\n                  <li>• U.S. District Court, Southern District of California</li>\n                  <li>• Northern District of California</li>\n                  <li>• Superior Court of California</li>\n                </ul>\n              </div>\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Appellate Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. Court of Appeals, Ninth Circuit</li>\n                </ul>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('e81e788cd1e2e8af', '6214c13d4994a673', '159beb30efd4673f', 'Pre Indictment', 'pre-indictment', 'src/app/pages/practice-areas.tsx', 'src/app/pages/practice-areas.tsx', 3, 'PreIndictmentSection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":3,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto text-center\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Pre-Indictment Representation\n            </h2>\n            <p className=\"text-muted-foreground leading-relaxed mb-8\">\n              If you are under federal investigation but have not yet been charged, early legal intervention is crucial. We can work with prosecutors and agents during the investigation phase, potentially avoiding charges or significantly reducing their severity.\n            </p>\n            <p className=\"text-muted-foreground leading-relaxed\">\n              Common signs you may be under federal investigation include contact from federal agents, subpoenas for documents or testimony, or notification that you are a \"target\" or \"subject\" of an investigation.\n            </p>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
INSERT OR REPLACE INTO repo_sections (id, repo_id, page_id, name, section_key, source_file, import_path, sort_order, component_name, metadata_json) VALUES ('a69a5c74d74b04bb', '6214c13d4994a673', '5aafb0c755ce76ec', 'CTA', 'cta', 'src/app/pages/home.tsx', 'src/app/pages/home.tsx', 4, 'CTASection', '{"confidence":0.88,"parseStatus":"parsed","displayOrder":4,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Facing Criminal Charges?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Time is critical in federal or California state criminal matters. We keep our caseload selective, evaluate cases creatively, and work flexibly with a client''s budget so they can receive strong representation.\n          </p>\n          <div className=\"flex flex-col sm:flex-row gap-4 justify-center\">\n            <Link \n              to=\"/contact\" \n              className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n            >\n              Contact Us Today\n            </Link>\n            <Link \n              to=\"/faq\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              Frequently Asked Questions\n            </Link>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true}');
