e:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:bg-input/30 aspect-square size-4 shrink-0 rounded-full border shadow-xs transition-[color,box-shadow] outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50\",\n        className,\n      )}\n      {...props}\n    >\n      <RadioGroupPrimitive.Indicator\n        data-slot=\"radio-group-indicator\"\n        className=\"relative flex items-center justify-center\"\n      >\n        <CircleIcon className=\"fill-primary absolute top-1/2 left-1/2 size-2 -translate-x-1/2 -translate-y-1/2\" />\n      </RadioGroupPrimitive.Indicator>\n    </RadioGroupPrimitive.Item>\n  );\n}\n\nexport { RadioGroup, RadioGroupItem };\n"},{"path":"src/app/components/ui/resizable.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport { GripVerticalIcon } from \"lucide-react\";\nimport * as ResizablePrimitive from \"react-resizable-panels\";\n\nimport { cn } from \"./utils\";\n\nfunction ResizablePanelGroup({\n  className,\n  ...props\n}: React.ComponentProps<typeof ResizablePrimitive.PanelGroup>) {\n  return (\n    <ResizablePrimitive.PanelGroup\n      data-slot=\"resizable-panel-group\"\n      className={cn(\n        \"flex h-full w-full data-[panel-group-direction=vertical]:flex-col\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction ResizablePanel({\n  ...props\n}: React.ComponentProps<typeof ResizablePrimitive.Panel>) {\n  return <ResizablePrimitive.Panel data-slot=\"resizable-panel\" {...props} />;\n}\n\nfunction ResizableHandle({\n  withHandle,\n  className,\n  ...props\n}: React.ComponentProps<typeof ResizablePrimitive.PanelResizeHandle> & {\n  withHandle?: boolean;\n}) {\n  return (\n    <ResizablePrimitive.PanelResizeHandle\n      data-slot=\"resizable-handle\"\n      className={cn(\n        \"bg-border focus-visible:ring-ring relative flex w-px items-center justify-center after:absolute after:inset-y-0 after:left-1/2 after:w-1 after:-translate-x-1/2 focus-visible:ring-1 focus-visible:ring-offset-1 focus-visible:outline-hidden data-[panel-group-direction=vertical]:h-px data-[panel-group-direction=vertical]:w-full data-[panel-group-direction=vertical]:after:left-0 data-[panel-group-direction=vertical]:after:h-1 data-[panel-group-direction=vertical]:after:w-full data-[panel-group-direction=vertical]:after:-translate-y-1/2 data-[panel-group-direction=vertical]:after:translate-x-0 [&[data-panel-group-direction=vertical]>div]:rotate-90\",\n        className,\n      )}\n      {...props}\n    >\n      {withHandle && (\n        <div className=\"bg-border z-10 flex h-4 w-3 items-center justify-center rounded-xs border\">\n          <GripVerticalIcon className=\"size-2.5\" />\n        </div>\n      )}\n    </ResizablePrimitive.PanelResizeHandle>\n  );\n}\n\nexport { ResizablePanelGroup, ResizablePanel, ResizableHandle };\n"},{"path":"src/app/components/ui/scroll-area.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as ScrollAreaPrimitive from \"@radix-ui/react-scroll-area\";\n\nimport { cn } from \"./utils\";\n\nfunction ScrollArea({\n  className,\n  children,\n  ...props\n}: React.ComponentProps<typeof ScrollAreaPrimitive.Root>) {\n  return (\n    <ScrollAreaPrimitive.Root\n      data-slot=\"scroll-area\"\n      className={cn(\"relative\", className)}\n      {...props}\n    >\n      <ScrollAreaPrimitive.Viewport\n        data-slot=\"scroll-area-viewport\"\n        className=\"focus-visible:ring-ring/50 size-full rounded-[inherit] transition-[color,box-shadow] outline-none focus-visible:ring-[3px] focus-visible:outline-1\"\n      >\n        {children}\n      </ScrollAreaPrimitive.Viewport>\n      <ScrollBar />\n      <ScrollAreaPrimitive.Corner />\n    </ScrollAreaPrimitive.Root>\n  );\n}\n\nfunction ScrollBar({\n  className,\n  orientation = \"vertical\",\n  ...props\n}: React.ComponentProps<typeof ScrollAreaPrimitive.ScrollAreaScrollbar>) {\n  return (\n    <ScrollAreaPrimitive.ScrollAreaScrollbar\n      data-slot=\"scroll-area-scrollbar\"\n      orientation={orientation}\n      className={cn(\n        \"flex touch-none p-px transition-colors select-none\",\n        orientation === \"vertical\" &&\n          \"h-full w-2.5 border-l border-l-transparent\",\n        orientation === \"horizontal\" &&\n          \"h-2.5 flex-col border-t border-t-transparent\",\n        className,\n      )}\n      {...props}\n    >\n      <ScrollAreaPrimitive.ScrollAreaThumb\n        data-slot=\"scroll-area-thumb\"\n        className=\"bg-border relative flex-1 rounded-full\"\n      />\n    </ScrollAreaPrimitive.ScrollAreaScrollbar>\n  );\n}\n\nexport { ScrollArea, ScrollBar };\n"},{"path":"src/app/components/ui/select.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as SelectPrimitive from \"@radix-ui/react-select\";\nimport {\n  CheckIcon,\n  ChevronDownIcon,\n  ChevronUpIcon,\n} from \"lucide-react\";\n\nimport { cn } from \"./utils\";\n\nfunction Select({\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Root>) {\n  return <SelectPrimitive.Root data-slot=\"select\" {...props} />;\n}\n\nfunction SelectGroup({\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Group>) {\n  return <SelectPrimitive.Group data-slot=\"select-group\" {...props} />;\n}\n\nfunction SelectValue({\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Value>) {\n  return <SelectPrimitive.Value data-slot=\"select-value\" {...props} />;\n}\n\nfunction SelectTrigger({\n  className,\n  size = \"default\",\n  children,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Trigger> & {\n  size?: \"sm\" | \"default\";\n}) {\n  return (\n    <SelectPrimitive.Trigger\n      data-slot=\"select-trigger\"\n      data-size={size}\n      className={cn(\n        \"border-input data-[placeholder]:text-muted-foreground [&_svg:not([class*=''text-''])]:text-muted-foreground focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:bg-input/30 dark:hover:bg-input/50 flex w-full items-center justify-between gap-2 rounded-md border bg-input-background px-3 py-2 text-sm whitespace-nowrap transition-[color,box-shadow] outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50 data-[size=default]:h-9 data-[size=sm]:h-8 *:data-[slot=select-value]:line-clamp-1 *:data-[slot=select-value]:flex *:data-[slot=select-value]:items-center *:data-[slot=select-value]:gap-2 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*=''size-''])]:size-4\",\n        className,\n      )}\n      {...props}\n    >\n      {children}\n      <SelectPrimitive.Icon asChild>\n        <ChevronDownIcon className=\"size-4 opacity-50\" />\n      </SelectPrimitive.Icon>\n    </SelectPrimitive.Trigger>\n  );\n}\n\nfunction SelectContent({\n  className,\n  children,\n  position = \"popper\",\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Content>) {\n  return (\n    <SelectPrimitive.Portal>\n      <SelectPrimitive.Content\n        data-slot=\"select-content\"\n        className={cn(\n          \"bg-popover text-popover-foreground data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 relative z-50 max-h-(--radix-select-content-available-height) min-w-[8rem] origin-(--radix-select-content-transform-origin) overflow-x-hidden overflow-y-auto rounded-md border shadow-md\",\n          position === \"popper\" &&\n            \"data-[side=bottom]:translate-y-1 data-[side=left]:-translate-x-1 data-[side=right]:translate-x-1 data-[side=top]:-translate-y-1\",\n          className,\n        )}\n        position={position}\n        {...props}\n      >\n        <SelectScrollUpButton />\n        <SelectPrimitive.Viewport\n          className={cn(\n            \"p-1\",\n            position === \"popper\" &&\n              \"h-[var(--radix-select-trigger-height)] w-full min-w-[var(--radix-select-trigger-width)] scroll-my-1\",\n          )}\n        >\n          {children}\n        </SelectPrimitive.Viewport>\n        <SelectScrollDownButton />\n      </SelectPrimitive.Content>\n    </SelectPrimitive.Portal>\n  );\n}\n\nfunction SelectLabel({\n  className,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Label>) {\n  return (\n    <SelectPrimitive.Label\n      data-slot=\"select-label\"\n      className={cn(\"text-muted-foreground px-2 py-1.5 text-xs\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SelectItem({\n  className,\n  children,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Item>) {\n  return (\n    <SelectPrimitive.Item\n      data-slot=\"select-item\"\n      className={cn(\n        \"focus:bg-accent focus:text-accent-foreground [&_svg:not([class*=''text-''])]:text-muted-foreground relative flex w-full cursor-default items-center gap-2 rounded-sm py-1.5 pr-8 pl-2 text-sm outline-hidden select-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*=''size-''])]:size-4 *:[span]:last:flex *:[span]:last:items-center *:[span]:last:gap-2\",\n        className,\n      )}\n      {...props}\n    >\n      <span className=\"absolute right-2 flex size-3.5 items-center justify-center\">\n        <SelectPrimitive.ItemIndicator>\n          <CheckIcon className=\"size-4\" />\n        </SelectPrimitive.ItemIndicator>\n      </span>\n      <SelectPrimitive.ItemText>{children}</SelectPrimitive.ItemText>\n    </SelectPrimitive.Item>\n  );\n}\n\nfunction SelectSeparator({\n  className,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.Separator>) {\n  return (\n    <SelectPrimitive.Separator\n      data-slot=\"select-separator\"\n      className={cn(\"bg-border pointer-events-none -mx-1 my-1 h-px\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SelectScrollUpButton({\n  className,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.ScrollUpButton>) {\n  return (\n    <SelectPrimitive.ScrollUpButton\n      data-slot=\"select-scroll-up-button\"\n      className={cn(\n        \"flex cursor-default items-center justify-center py-1\",\n        className,\n      )}\n      {...props}\n    >\n      <ChevronUpIcon className=\"size-4\" />\n    </SelectPrimitive.ScrollUpButton>\n  );\n}\n\nfunction SelectScrollDownButton({\n  className,\n  ...props\n}: React.ComponentProps<typeof SelectPrimitive.ScrollDownButton>) {\n  return (\n    <SelectPrimitive.ScrollDownButton\n      data-slot=\"select-scroll-down-button\"\n      className={cn(\n        \"flex cursor-default items-center justify-center py-1\",\n        className,\n      )}\n      {...props}\n    >\n      <ChevronDownIcon className=\"size-4\" />\n    </SelectPrimitive.ScrollDownButton>\n  );\n}\n\nexport {\n  Select,\n  SelectContent,\n  SelectGroup,\n  SelectItem,\n  SelectLabel,\n  SelectScrollDownButton,\n  SelectScrollUpButton,\n  SelectSeparator,\n  SelectTrigger,\n  SelectValue,\n};\n"},{"path":"src/app/components/ui/separator.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as SeparatorPrimitive from \"@radix-ui/react-separator\";\n\nimport { cn } from \"./utils\";\n\nfunction Separator({\n  className,\n  orientation = \"horizontal\",\n  decorative = true,\n  ...props\n}: React.ComponentProps<typeof SeparatorPrimitive.Root>) {\n  return (\n    <SeparatorPrimitive.Root\n      data-slot=\"separator-root\"\n      decorative={decorative}\n      orientation={orientation}\n      className={cn(\n        \"bg-border shrink-0 data-[orientation=horizontal]:h-px data-[orientation=horizontal]:w-full data-[orientation=vertical]:h-full data-[orientation=vertical]:w-px\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nexport { Separator };\n"},{"path":"src/app/components/ui/sheet.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as SheetPrimitive from \"@radix-ui/react-dialog\";\nimport { XIcon } from \"lucide-react\";\n\nimport { cn } from \"./utils\";\n\nfunction Sheet({ ...props }: React.ComponentProps<typeof SheetPrimitive.Root>) {\n  return <SheetPrimitive.Root data-slot=\"sheet\" {...props} />;\n}\n\nfunction SheetTrigger({\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Trigger>) {\n  return <SheetPrimitive.Trigger data-slot=\"sheet-trigger\" {...props} />;\n}\n\nfunction SheetClose({\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Close>) {\n  return <SheetPrimitive.Close data-slot=\"sheet-close\" {...props} />;\n}\n\nfunction SheetPortal({\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Portal>) {\n  return <SheetPrimitive.Portal data-slot=\"sheet-portal\" {...props} />;\n}\n\nfunction SheetOverlay({\n  className,\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Overlay>) {\n  return (\n    <SheetPrimitive.Overlay\n      data-slot=\"sheet-overlay\"\n      className={cn(\n        \"data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 fixed inset-0 z-50 bg-black/50\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SheetContent({\n  className,\n  children,\n  side = \"right\",\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Content> & {\n  side?: \"top\" | \"right\" | \"bottom\" | \"left\";\n}) {\n  return (\n    <SheetPortal>\n      <SheetOverlay />\n      <SheetPrimitive.Content\n        data-slot=\"sheet-content\"\n        className={cn(\n          \"bg-background data-[state=open]:animate-in data-[state=closed]:animate-out fixed z-50 flex flex-col gap-4 shadow-lg transition ease-in-out data-[state=closed]:duration-300 data-[state=open]:duration-500\",\n          side === \"right\" &&\n            \"data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right inset-y-0 right-0 h-full w-3/4 border-l sm:max-w-sm\",\n          side === \"left\" &&\n            \"data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left inset-y-0 left-0 h-full w-3/4 border-r sm:max-w-sm\",\n          side === \"top\" &&\n            \"data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top inset-x-0 top-0 h-auto border-b\",\n          side === \"bottom\" &&\n            \"data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom inset-x-0 bottom-0 h-auto border-t\",\n          className,\n        )}\n        {...props}\n      >\n        {children}\n        <SheetPrimitive.Close className=\"ring-offset-background focus:ring-ring data-[state=open]:bg-secondary absolute top-4 right-4 rounded-xs opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-hidden disabled:pointer-events-none\">\n          <XIcon className=\"size-4\" />\n          <span className=\"sr-only\">Close</span>\n        </SheetPrimitive.Close>\n      </SheetPrimitive.Content>\n    </SheetPortal>\n  );\n}\n\nfunction SheetHeader({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sheet-header\"\n      className={cn(\"flex flex-col gap-1.5 p-4\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SheetFooter({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sheet-footer\"\n      className={cn(\"mt-auto flex flex-col gap-2 p-4\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SheetTitle({\n  className,\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Title>) {\n  return (\n    <SheetPrimitive.Title\n      data-slot=\"sheet-title\"\n      className={cn(\"text-foreground font-semibold\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SheetDescription({\n  className,\n  ...props\n}: React.ComponentProps<typeof SheetPrimitive.Description>) {\n  return (\n    <SheetPrimitive.Description\n      data-slot=\"sheet-description\"\n      className={cn(\"text-muted-foreground text-sm\", className)}\n      {...props}\n    />\n  );\n}\n\nexport {\n  Sheet,\n  SheetTrigger,\n  SheetClose,\n  SheetContent,\n  SheetHeader,\n  SheetFooter,\n  SheetTitle,\n  SheetDescription,\n};\n"},{"path":"src/app/components/ui/sidebar.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport { Slot } from \"@radix-ui/react-slot\";\nimport { VariantProps, cva } from \"class-variance-authority\";\nimport { PanelLeftIcon } from \"lucide-react\";\n\nimport { useIsMobile } from \"./use-mobile\";\nimport { cn } from \"./utils\";\nimport { Button } from \"./button\";\nimport { Input } from \"./input\";\nimport { Separator } from \"./separator\";\nimport {\n  Sheet,\n  SheetContent,\n  SheetDescription,\n  SheetHeader,\n  SheetTitle,\n} from \"./sheet\";\nimport { Skeleton } from \"./skeleton\";\nimport {\n  Tooltip,\n  TooltipContent,\n  TooltipProvider,\n  TooltipTrigger,\n} from \"./tooltip\";\n\nconst SIDEBAR_COOKIE_NAME = \"sidebar_state\";\nconst SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7;\nconst SIDEBAR_WIDTH = \"16rem\";\nconst SIDEBAR_WIDTH_MOBILE = \"18rem\";\nconst SIDEBAR_WIDTH_ICON = \"3rem\";\nconst SIDEBAR_KEYBOARD_SHORTCUT = \"b\";\n\ntype SidebarContextProps = {\n  state: \"expanded\" | \"collapsed\";\n  open: boolean;\n  setOpen: (open: boolean) => void;\n  openMobile: boolean;\n  setOpenMobile: (open: boolean) => void;\n  isMobile: boolean;\n  toggleSidebar: () => void;\n};\n\nconst SidebarContext = React.createContext<SidebarContextProps | null>(null);\n\nfunction useSidebar() {\n  const context = React.useContext(SidebarContext);\n  if (!context) {\n    throw new Error(\"useSidebar must be used within a SidebarProvider.\");\n  }\n\n  return context;\n}\n\nfunction SidebarProvider({\n  defaultOpen = true,\n  open: openProp,\n  onOpenChange: setOpenProp,\n  className,\n  style,\n  children,\n  ...props\n}: React.ComponentProps<\"div\"> & {\n  defaultOpen?: boolean;\n  open?: boolean;\n  onOpenChange?: (open: boolean) => void;\n}) {\n  const isMobile = useIsMobile();\n  const [openMobile, setOpenMobile] = React.useState(false);\n\n  // This is the internal state of the sidebar.\n  // We use openProp and setOpenProp for control from outside the component.\n  const [_open, _setOpen] = React.useState(defaultOpen);\n  const open = openProp ?? _open;\n  const setOpen = React.useCallback(\n    (value: boolean | ((value: boolean) => boolean)) => {\n      const openState = typeof value === \"function\" ? value(open) : value;\n      if (setOpenProp) {\n        setOpenProp(openState);\n      } else {\n        _setOpen(openState);\n      }\n\n      // This sets the cookie to keep the sidebar state.\n      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`;\n    },\n    [setOpenProp, open],\n  );\n\n  // Helper to toggle the sidebar.\n  const toggleSidebar = React.useCallback(() => {\n    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open);\n  }, [isMobile, setOpen, setOpenMobile]);\n\n  // Adds a keyboard shortcut to toggle the sidebar.\n  React.useEffect(() => {\n    const handleKeyDown = (event: KeyboardEvent) => {\n      if (\n        event.key === SIDEBAR_KEYBOARD_SHORTCUT &&\n        (event.metaKey || event.ctrlKey)\n      ) {\n        event.preventDefault();\n        toggleSidebar();\n      }\n    };\n\n    window.addEventListener(\"keydown\", handleKeyDown);\n    return () => window.removeEventListener(\"keydown\", handleKeyDown);\n  }, [toggleSidebar]);\n\n  // We add a state so that we can do data-state=\"expanded\" or \"collapsed\".\n  // This makes it easier to style the sidebar with Tailwind classes.\n  const state = open ? \"expanded\" : \"collapsed\";\n\n  const contextValue = React.useMemo<SidebarContextProps>(\n    () => ({\n      state,\n      open,\n      setOpen,\n      isMobile,\n      openMobile,\n      setOpenMobile,\n      toggleSidebar,\n    }),\n    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar],\n  );\n\n  return (\n    <SidebarContext.Provider value={contextValue}>\n      <TooltipProvider delayDuration={0}>\n        <div\n          data-slot=\"sidebar-wrapper\"\n          style={\n            {\n              \"--sidebar-width\": SIDEBAR_WIDTH,\n              \"--sidebar-width-icon\": SIDEBAR_WIDTH_ICON,\n              ...style,\n            } as React.CSSProperties\n          }\n          className={cn(\n            \"group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full\",\n            className,\n          )}\n          {...props}\n        >\n          {children}\n        </div>\n      </TooltipProvider>\n    </SidebarContext.Provider>\n  );\n}\n\nfunction Sidebar({\n  side = \"left\",\n  variant = \"sidebar\",\n  collapsible = \"offcanvas\",\n  className,\n  children,\n  ...props\n}: React.ComponentProps<\"div\"> & {\n  side?: \"left\" | \"right\";\n  variant?: \"sidebar\" | \"floating\" | \"inset\";\n  collapsible?: \"offcanvas\" | \"icon\" | \"none\";\n}) {\n  const { isMobile, state, openMobile, setOpenMobile } = useSidebar();\n\n  if (collapsible === \"none\") {\n    return (\n      <div\n        data-slot=\"sidebar\"\n        className={cn(\n          \"bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col\",\n          className,\n        )}\n        {...props}\n      >\n        {children}\n      </div>\n    );\n  }\n\n  if (isMobile) {\n    return (\n      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>\n        <SheetContent\n          data-sidebar=\"sidebar\"\n          data-slot=\"sidebar\"\n          data-mobile=\"true\"\n          className=\"bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 [&>button]:hidden\"\n          style={\n            {\n              \"--sidebar-width\": SIDEBAR_WIDTH_MOBILE,\n            } as React.CSSProperties\n          }\n          side={side}\n        >\n          <SheetHeader className=\"sr-only\">\n            <SheetTitle>Sidebar</SheetTitle>\n            <SheetDescription>Displays the mobile sidebar.</SheetDescription>\n          </SheetHeader>\n          <div className=\"flex h-full w-full flex-col\">{children}</div>\n        </SheetContent>\n      </Sheet>\n    );\n  }\n\n  return (\n    <div\n      className=\"group peer text-sidebar-foreground hidden md:block\"\n      data-state={state}\n      data-collapsible={state === \"collapsed\" ? collapsible : \"\"}\n      data-variant={variant}\n      data-side={side}\n      data-slot=\"sidebar\"\n    >\n      {/* This is what handles the sidebar gap on desktop */}\n      <div\n        data-slot=\"sidebar-gap\"\n        className={cn(\n          \"relative w-(--sidebar-width) bg-transparent transition-[width] duration-200 ease-linear\",\n          \"group-data-[collapsible=offcanvas]:w-0\",\n          \"group-data-[side=right]:rotate-180\",\n          variant === \"floating\" || variant === \"inset\"\n            ? \"group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4)))]\"\n            : \"group-data-[collapsible=icon]:w-(--sidebar-width-icon)\",\n        )}\n      />\n      <div\n        data-slot=\"sidebar-container\"\n        className={cn(\n          \"fixed inset-y-0 z-10 hidden h-svh w-(--sidebar-width) transition-[left,right,width] duration-200 ease-linear md:flex\",\n          side === \"left\"\n            ? \"left-0 group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)]\"\n            : \"right-0 group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)]\",\n          // Adjust the padding for floating and inset variants.\n          variant === \"floating\" || variant === \"inset\"\n            ? \"p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4))+2px)]\"\n            : \"group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l\",\n          className,\n        )}\n        {...props}\n      >\n        <div\n          data-sidebar=\"sidebar\"\n          data-slot=\"sidebar-inner\"\n          className=\"bg-sidebar group-data-[variant=floating]:border-sidebar-border flex h-full w-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:shadow-sm\"\n        >\n          {children}\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction SidebarTrigger({\n  className,\n  onClick,\n  ...props\n}: React.ComponentProps<typeof Button>) {\n  const { toggleSidebar } = useSidebar();\n\n  return (\n    <Button\n      data-sidebar=\"trigger\"\n      data-slot=\"sidebar-trigger\"\n      variant=\"ghost\"\n      size=\"icon\"\n      className={cn(\"size-7\", className)}\n      onClick={(event) => {\n        onClick?.(event);\n        toggleSidebar();\n      }}\n      {...props}\n    >\n      <PanelLeftIcon />\n      <span className=\"sr-only\">Toggle Sidebar</span>\n    </Button>\n  );\n}\n\nfunction SidebarRail({ className, ...props }: React.ComponentProps<\"button\">) {\n  const { toggleSidebar } = useSidebar();\n\n  return (\n    <button\n      data-sidebar=\"rail\"\n      data-slot=\"sidebar-rail\"\n      aria-label=\"Toggle Sidebar\"\n      tabIndex={-1}\n      onClick={toggleSidebar}\n      title=\"Toggle Sidebar\"\n      className={cn(\n        \"hover:after:bg-sidebar-border absolute inset-y-0 z-20 hidden w-4 -translate-x-1/2 transition-all ease-linear group-data-[side=left]:-right-4 group-data-[side=right]:left-0 after:absolute after:inset-y-0 after:left-1/2 after:w-[2px] sm:flex\",\n        \"in-data-[side=left]:cursor-w-resize in-data-[side=right]:cursor-e-resize\",\n        \"[[data-side=left][data-state=collapsed]_&]:cursor-e-resize [[data-side=right][data-state=collapsed]_&]:cursor-w-resize\",\n        \"hover:group-data-[collapsible=offcanvas]:bg-sidebar group-data-[collapsible=offcanvas]:translate-x-0 group-data-[collapsible=offcanvas]:after:left-full\",\n        \"[[data-side=left][data-collapsible=offcanvas]_&]:-right-2\",\n        \"[[data-side=right][data-collapsible=offcanvas]_&]:-left-2\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarInset({ className, ...props }: React.ComponentProps<\"main\">) {\n  return (\n    <main\n      data-slot=\"sidebar-inset\"\n      className={cn(\n        \"bg-background relative flex w-full flex-1 flex-col\",\n        \"md:peer-data-[variant=inset]:m-2 md:peer-data-[variant=inset]:ml-0 md:peer-data-[variant=inset]:rounded-xl md:peer-data-[variant=inset]:shadow-sm md:peer-data-[variant=inset]:peer-data-[state=collapsed]:ml-2\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarInput({\n  className,\n  ...props\n}: React.ComponentProps<typeof Input>) {\n  return (\n    <Input\n      data-slot=\"sidebar-input\"\n      data-sidebar=\"input\"\n      className={cn(\"bg-background h-8 w-full shadow-none\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarHeader({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-header\"\n      data-sidebar=\"header\"\n      className={cn(\"flex flex-col gap-2 p-2\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarFooter({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-footer\"\n      data-sidebar=\"footer\"\n      className={cn(\"flex flex-col gap-2 p-2\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarSeparator({\n  className,\n  ...props\n}: React.ComponentProps<typeof Separator>) {\n  return (\n    <Separator\n      data-slot=\"sidebar-separator\"\n      data-sidebar=\"separator\"\n      className={cn(\"bg-sidebar-border mx-2 w-auto\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarContent({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-content\"\n      data-sidebar=\"content\"\n      className={cn(\n        \"flex min-h-0 flex-1 flex-col gap-2 overflow-auto group-data-[collapsible=icon]:overflow-hidden\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarGroup({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-group\"\n      data-sidebar=\"group\"\n      className={cn(\"relative flex w-full min-w-0 flex-col p-2\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarGroupLabel({\n  className,\n  asChild = false,\n  ...props\n}: React.ComponentProps<\"div\"> & { asChild?: boolean }) {\n  const Comp = asChild ? Slot : \"div\";\n\n  return (\n    <Comp\n      data-slot=\"sidebar-group-label\"\n      data-sidebar=\"group-label\"\n      className={cn(\n        \"text-sidebar-foreground/70 ring-sidebar-ring flex h-8 shrink-0 items-center rounded-md px-2 text-xs font-medium outline-hidden transition-[margin,opacity] duration-200 ease-linear focus-visible:ring-2 [&>svg]:size-4 [&>svg]:shrink-0\",\n        \"group-data-[collapsible=icon]:-mt-8 group-data-[collapsible=icon]:opacity-0\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarGroupAction({\n  className,\n  asChild = false,\n  ...props\n}: React.ComponentProps<\"button\"> & { asChild?: boolean }) {\n  const Comp = asChild ? Slot : \"button\";\n\n  return (\n    <Comp\n      data-slot=\"sidebar-group-action\"\n      data-sidebar=\"group-action\"\n      className={cn(\n        \"text-sidebar-foreground ring-sidebar-ring hover:bg-sidebar-accent hover:text-sidebar-accent-foreground absolute top-3.5 right-3 flex aspect-square w-5 items-center justify-center rounded-md p-0 outline-hidden transition-transform focus-visible:ring-2 [&>svg]:size-4 [&>svg]:shrink-0\",\n        // Increases the hit area of the button on mobile.\n        \"after:absolute after:-inset-2 md:after:hidden\",\n        \"group-data-[collapsible=icon]:hidden\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarGroupContent({\n  className,\n  ...props\n}: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-group-content\"\n      data-sidebar=\"group-content\"\n      className={cn(\"w-full text-sm\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenu({ className, ...props }: React.ComponentProps<\"ul\">) {\n  return (\n    <ul\n      data-slot=\"sidebar-menu\"\n      data-sidebar=\"menu\"\n      className={cn(\"flex w-full min-w-0 flex-col gap-1\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenuItem({ className, ...props }: React.ComponentProps<\"li\">) {\n  return (\n    <li\n      data-slot=\"sidebar-menu-item\"\n      data-sidebar=\"menu-item\"\n      className={cn(\"group/menu-item relative\", className)}\n      {...props}\n    />\n  );\n}\n\nconst sidebarMenuButtonVariants = cva(\n  \"peer/menu-button flex w-full items-center gap-2 overflow-hidden rounded-md p-2 text-left text-sm outline-hidden ring-sidebar-ring transition-[width,height,padding] hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 active:bg-sidebar-accent active:text-sidebar-accent-foreground disabled:pointer-events-none disabled:opacity-50 group-has-data-[sidebar=menu-action]/menu-item:pr-8 aria-disabled:pointer-events-none aria-disabled:opacity-50 data-[active=true]:bg-sidebar-accent data-[active=true]:font-medium data-[active=true]:text-sidebar-accent-foreground data-[state=open]:hover:bg-sidebar-accent data-[state=open]:hover:text-sidebar-accent-foreground group-data-[collapsible=icon]:size-8! group-data-[collapsible=icon]:p-2! [&>span:last-child]:truncate [&>svg]:size-4 [&>svg]:shrink-0\",\n  {\n    variants: {\n      variant: {\n        default: \"hover:bg-sidebar-accent hover:text-sidebar-accent-foreground\",\n        outline:\n          \"bg-background shadow-[0_0_0_1px_hsl(var(--sidebar-border))] hover:bg-sidebar-accent hover:text-sidebar-accent-foreground hover:shadow-[0_0_0_1px_hsl(var(--sidebar-accent))]\",\n      },\n      size: {\n        default: \"h-8 text-sm\",\n        sm: \"h-7 text-xs\",\n        lg: \"h-12 text-sm group-data-[collapsible=icon]:p-0!\",\n      },\n    },\n    defaultVariants: {\n      variant: \"default\",\n      size: \"default\",\n    },\n  },\n);\n\nfunction SidebarMenuButton({\n  asChild = false,\n  isActive = false,\n  variant = \"default\",\n  size = \"default\",\n  tooltip,\n  className,\n  ...props\n}: React.ComponentProps<\"button\"> & {\n  asChild?: boolean;\n  isActive?: boolean;\n  tooltip?: string | React.ComponentProps<typeof TooltipContent>;\n} & VariantProps<typeof sidebarMenuButtonVariants>) {\n  const Comp = asChild ? Slot : \"button\";\n  const { isMobile, state } = useSidebar();\n\n  const button = (\n    <Comp\n      data-slot=\"sidebar-menu-button\"\n      data-sidebar=\"menu-button\"\n      data-size={size}\n      data-active={isActive}\n      className={cn(sidebarMenuButtonVariants({ variant, size }), className)}\n      {...props}\n    />\n  );\n\n  if (!tooltip) {\n    return button;\n  }\n\n  if (typeof tooltip === \"string\") {\n    tooltip = {\n      children: tooltip,\n    };\n  }\n\n  return (\n    <Tooltip>\n      <TooltipTrigger asChild>{button}</TooltipTrigger>\n      <TooltipContent\n        side=\"right\"\n        align=\"center\"\n        hidden={state !== \"collapsed\" || isMobile}\n        {...tooltip}\n      />\n    </Tooltip>\n  );\n}\n\nfunction SidebarMenuAction({\n  className,\n  asChild = false,\n  showOnHover = false,\n  ...props\n}: React.ComponentProps<\"button\"> & {\n  asChild?: boolean;\n  showOnHover?: boolean;\n}) {\n  const Comp = asChild ? Slot : \"button\";\n\n  return (\n    <Comp\n      data-slot=\"sidebar-menu-action\"\n      data-sidebar=\"menu-action\"\n      className={cn(\n        \"text-sidebar-foreground ring-sidebar-ring hover:bg-sidebar-accent hover:text-sidebar-accent-foreground peer-hover/menu-button:text-sidebar-accent-foreground absolute top-1.5 right-1 flex aspect-square w-5 items-center justify-center rounded-md p-0 outline-hidden transition-transform focus-visible:ring-2 [&>svg]:size-4 [&>svg]:shrink-0\",\n        // Increases the hit area of the button on mobile.\n        \"after:absolute after:-inset-2 md:after:hidden\",\n        \"peer-data-[size=sm]/menu-button:top-1\",\n        \"peer-data-[size=default]/menu-button:top-1.5\",\n        \"peer-data-[size=lg]/menu-button:top-2.5\",\n        \"group-data-[collapsible=icon]:hidden\",\n        showOnHover &&\n          \"peer-data-[active=true]/menu-button:text-sidebar-accent-foreground group-focus-within/menu-item:opacity-100 group-hover/menu-item:opacity-100 data-[state=open]:opacity-100 md:opacity-0\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenuBadge({\n  className,\n  ...props\n}: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"sidebar-menu-badge\"\n      data-sidebar=\"menu-badge\"\n      className={cn(\n        \"text-sidebar-foreground pointer-events-none absolute right-1 flex h-5 min-w-5 items-center justify-center rounded-md px-1 text-xs font-medium tabular-nums select-none\",\n        \"peer-hover/menu-button:text-sidebar-accent-foreground peer-data-[active=true]/menu-button:text-sidebar-accent-foreground\",\n        \"peer-data-[size=sm]/menu-button:top-1\",\n        \"peer-data-[size=default]/menu-button:top-1.5\",\n        \"peer-data-[size=lg]/menu-button:top-2.5\",\n        \"group-data-[collapsible=icon]:hidden\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenuSkeleton({\n  className,\n  showIcon = false,\n  ...props\n}: React.ComponentProps<\"div\"> & {\n  showIcon?: boolean;\n}) {\n  // Random width between 50 to 90%.\n  const width = React.useMemo(() => {\n    return `${Math.floor(Math.random() * 40) + 50}%`;\n  }, []);\n\n  return (\n    <div\n      data-slot=\"sidebar-menu-skeleton\"\n      data-sidebar=\"menu-skeleton\"\n      className={cn(\"flex h-8 items-center gap-2 rounded-md px-2\", className)}\n      {...props}\n    >\n      {showIcon && (\n        <Skeleton\n          className=\"size-4 rounded-md\"\n          data-sidebar=\"menu-skeleton-icon\"\n        />\n      )}\n      <Skeleton\n        className=\"h-4 max-w-(--skeleton-width) flex-1\"\n        data-sidebar=\"menu-skeleton-text\"\n        style={\n          {\n            \"--skeleton-width\": width,\n          } as React.CSSProperties\n        }\n      />\n    </div>\n  );\n}\n\nfunction SidebarMenuSub({ className, ...props }: React.ComponentProps<\"ul\">) {\n  return (\n    <ul\n      data-slot=\"sidebar-menu-sub\"\n      data-sidebar=\"menu-sub\"\n      className={cn(\n        \"border-sidebar-border mx-3.5 flex min-w-0 translate-x-px flex-col gap-1 border-l px-2.5 py-0.5\",\n        \"group-data-[collapsible=icon]:hidden\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenuSubItem({\n  className,\n  ...props\n}: React.ComponentProps<\"li\">) {\n  return (\n    <li\n      data-slot=\"sidebar-menu-sub-item\"\n      data-sidebar=\"menu-sub-item\"\n      className={cn(\"group/menu-sub-item relative\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction SidebarMenuSubButton({\n  asChild = false,\n  size = \"md\",\n  isActive = false,\n  className,\n  ...props\n}: React.ComponentProps<\"a\"> & {\n  asChild?: boolean;\n  size?: \"sm\" | \"md\";\n  isActive?: boolean;\n}) {\n  const Comp = asChild ? Slot : \"a\";\n\n  return (\n    <Comp\n      data-slot=\"sidebar-menu-sub-button\"\n      data-sidebar=\"menu-sub-button\"\n      data-size={size}\n      data-active={isActive}\n      className={cn(\n        \"text-sidebar-foreground ring-sidebar-ring hover:bg-sidebar-accent hover:text-sidebar-accent-foreground active:bg-sidebar-accent active:text-sidebar-accent-foreground [&>svg]:text-sidebar-accent-foreground flex h-7 min-w-0 -translate-x-px items-center gap-2 overflow-hidden rounded-md px-2 outline-hidden focus-visible:ring-2 disabled:pointer-events-none disabled:opacity-50 aria-disabled:pointer-events-none aria-disabled:opacity-50 [&>span:last-child]:truncate [&>svg]:size-4 [&>svg]:shrink-0\",\n        \"data-[active=true]:bg-sidebar-accent data-[active=true]:text-sidebar-accent-foreground\",\n        size === \"sm\" && \"text-xs\",\n        size === \"md\" && \"text-sm\",\n        \"group-data-[collapsible=icon]:hidden\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nexport {\n  Sidebar,\n  SidebarContent,\n  SidebarFooter,\n  SidebarGroup,\n  SidebarGroupAction,\n  SidebarGroupContent,\n  SidebarGroupLabel,\n  SidebarHeader,\n  SidebarInput,\n  SidebarInset,\n  SidebarMenu,\n  SidebarMenuAction,\n  SidebarMenuBadge,\n  SidebarMenuButton,\n  SidebarMenuItem,\n  SidebarMenuSkeleton,\n  SidebarMenuSub,\n  SidebarMenuSubButton,\n  SidebarMenuSubItem,\n  SidebarProvider,\n  SidebarRail,\n  SidebarSeparator,\n  SidebarTrigger,\n  useSidebar,\n};\n"},{"path":"src/app/components/ui/skeleton.tsx","content":"import { cn } from \"./utils\";\n\nfunction Skeleton({ className, ...props }: React.ComponentProps<\"div\">) {\n  return (\n    <div\n      data-slot=\"skeleton\"\n      className={cn(\"bg-accent animate-pulse rounded-md\", className)}\n      {...props}\n    />\n  );\n}\n\nexport { Skeleton };\n"},{"path":"src/app/components/ui/slider.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as SliderPrimitive from \"@radix-ui/react-slider\";\n\nimport { cn } from \"./utils\";\n\nfunction Slider({\n  className,\n  defaultValue,\n  value,\n  min = 0,\n  max = 100,\n  ...props\n}: React.ComponentProps<typeof SliderPrimitive.Root>) {\n  const _values = React.useMemo(\n    () =>\n      Array.isArray(value)\n        ? value\n        : Array.isArray(defaultValue)\n          ? defaultValue\n          : [min, max],\n    [value, defaultValue, min, max],\n  );\n\n  return (\n    <SliderPrimitive.Root\n      data-slot=\"slider\"\n      defaultValue={defaultValue}\n      value={value}\n      min={min}\n      max={max}\n      className={cn(\n        \"relative flex w-full touch-none items-center select-none data-[disabled]:opacity-50 data-[orientation=vertical]:h-full data-[orientation=vertical]:min-h-44 data-[orientation=vertical]:w-auto data-[orientation=vertical]:flex-col\",\n        className,\n      )}\n      {...props}\n    >\n      <SliderPrimitive.Track\n        data-slot=\"slider-track\"\n        className={cn(\n          \"bg-muted relative grow overflow-hidden rounded-full data-[orientation=horizontal]:h-4 data-[orientation=horizontal]:w-full data-[orientation=vertical]:h-full data-[orientation=vertical]:w-1.5\",\n        )}\n      >\n        <SliderPrimitive.Range\n          data-slot=\"slider-range\"\n          className={cn(\n            \"bg-primary absolute data-[orientation=horizontal]:h-full data-[orientation=vertical]:w-full\",\n          )}\n        />\n      </SliderPrimitive.Track>\n      {Array.from({ length: _values.length }, (_, index) => (\n        <SliderPrimitive.Thumb\n          data-slot=\"slider-thumb\"\n          key={index}\n          className=\"border-primary bg-background ring-ring/50 block size-4 shrink-0 rounded-full border shadow-sm transition-[color,box-shadow] hover:ring-4 focus-visible:ring-4 focus-visible:outline-hidden disabled:pointer-events-none disabled:opacity-50\"\n        />\n      ))}\n    </SliderPrimitive.Root>\n  );\n}\n\nexport { Slider };\n"},{"path":"src/app/components/ui/sonner.tsx","content":"\"use client\";\n\nimport { useTheme } from \"next-themes\";\nimport { Toaster as Sonner, ToasterProps } from \"sonner\";\n\nconst Toaster = ({ ...props }: ToasterProps) => {\n  const { theme = \"system\" } = useTheme();\n\n  return (\n    <Sonner\n      theme={theme as ToasterProps[\"theme\"]}\n      className=\"toaster group\"\n      style={\n        {\n          \"--normal-bg\": \"var(--popover)\",\n          \"--normal-text\": \"var(--popover-foreground)\",\n          \"--normal-border\": \"var(--border)\",\n        } as React.CSSProperties\n      }\n      {...props}\n    />\n  );\n};\n\nexport { Toaster };\n"},{"path":"src/app/components/ui/switch.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as SwitchPrimitive from \"@radix-ui/react-switch\";\n\nimport { cn } from \"./utils\";\n\nfunction Switch({\n  className,\n  ...props\n}: React.ComponentProps<typeof SwitchPrimitive.Root>) {\n  return (\n    <SwitchPrimitive.Root\n      data-slot=\"switch\"\n      className={cn(\n        \"peer data-[state=checked]:bg-primary data-[state=unchecked]:bg-switch-background focus-visible:border-ring focus-visible:ring-ring/50 dark:data-[state=unchecked]:bg-input/80 inline-flex h-[1.15rem] w-8 shrink-0 items-center rounded-full border border-transparent transition-all outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50\",\n        className,\n      )}\n      {...props}\n    >\n      <SwitchPrimitive.Thumb\n        data-slot=\"switch-thumb\"\n        className={cn(\n          \"bg-card dark:data-[state=unchecked]:bg-card-foreground dark:data-[state=checked]:bg-primary-foreground pointer-events-none block size-4 rounded-full ring-0 transition-transform data-[state=checked]:translate-x-[calc(100%-2px)] data-[state=unchecked]:translate-x-0\",\n        )}\n      />\n    </SwitchPrimitive.Root>\n  );\n}\n\nexport { Switch };\n"},{"path":"src/app/components/ui/table.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\n\nimport { cn } from \"./utils\";\n\nfunction Table({ className, ...props }: React.ComponentProps<\"table\">) {\n  return (\n    <div\n      data-slot=\"table-container\"\n      className=\"relative w-full overflow-x-auto\"\n    >\n      <table\n        data-slot=\"table\"\n        className={cn(\"w-full caption-bottom text-sm\", className)}\n        {...props}\n      />\n    </div>\n  );\n}\n\nfunction TableHeader({ className, ...props }: React.ComponentProps<\"thead\">) {\n  return (\n    <thead\n      data-slot=\"table-header\"\n      className={cn(\"[&_tr]:border-b\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction TableBody({ className, ...props }: React.ComponentProps<\"tbody\">) {\n  return (\n    <tbody\n      data-slot=\"table-body\"\n      className={cn(\"[&_tr:last-child]:border-0\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction TableFooter({ className, ...props }: React.ComponentProps<\"tfoot\">) {\n  return (\n    <tfoot\n      data-slot=\"table-footer\"\n      className={cn(\n        \"bg-muted/50 border-t font-medium [&>tr]:last:border-b-0\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TableRow({ className, ...props }: React.ComponentProps<\"tr\">) {\n  return (\n    <tr\n      data-slot=\"table-row\"\n      className={cn(\n        \"hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TableHead({ className, ...props }: React.ComponentProps<\"th\">) {\n  return (\n    <th\n      data-slot=\"table-head\"\n      className={cn(\n        \"text-foreground h-10 px-2 text-left align-middle font-medium whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TableCell({ className, ...props }: React.ComponentProps<\"td\">) {\n  return (\n    <td\n      data-slot=\"table-cell\"\n      className={cn(\n        \"p-2 align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TableCaption({\n  className,\n  ...props\n}: React.ComponentProps<\"caption\">) {\n  return (\n    <caption\n      data-slot=\"table-caption\"\n      className={cn(\"text-muted-foreground mt-4 text-sm\", className)}\n      {...props}\n    />\n  );\n}\n\nexport {\n  Table,\n  TableHeader,\n  TableBody,\n  TableFooter,\n  TableHead,\n  TableRow,\n  TableCell,\n  TableCaption,\n};\n"},{"path":"src/app/components/ui/tabs.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as TabsPrimitive from \"@radix-ui/react-tabs\";\n\nimport { cn } from \"./utils\";\n\nfunction Tabs({\n  className,\n  ...props\n}: React.ComponentProps<typeof TabsPrimitive.Root>) {\n  return (\n    <TabsPrimitive.Root\n      data-slot=\"tabs\"\n      className={cn(\"flex flex-col gap-2\", className)}\n      {...props}\n    />\n  );\n}\n\nfunction TabsList({\n  className,\n  ...props\n}: React.ComponentProps<typeof TabsPrimitive.List>) {\n  return (\n    <TabsPrimitive.List\n      data-slot=\"tabs-list\"\n      className={cn(\n        \"bg-muted text-muted-foreground inline-flex h-9 w-fit items-center justify-center rounded-xl p-[3px] flex\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TabsTrigger({\n  className,\n  ...props\n}: React.ComponentProps<typeof TabsPrimitive.Trigger>) {\n  return (\n    <TabsPrimitive.Trigger\n      data-slot=\"tabs-trigger\"\n      className={cn(\n        \"data-[state=active]:bg-card dark:data-[state=active]:text-foreground focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:outline-ring dark:data-[state=active]:border-input dark:data-[state=active]:bg-input/30 text-foreground dark:text-muted-foreground inline-flex h-[calc(100%-1px)] flex-1 items-center justify-center gap-1.5 rounded-xl border border-transparent px-2 py-1 text-sm font-medium whitespace-nowrap transition-[color,box-shadow] focus-visible:ring-[3px] focus-visible:outline-1 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*=''size-''])]:size-4\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nfunction TabsContent({\n  className,\n  ...props\n}: React.ComponentProps<typeof TabsPrimitive.Content>) {\n  return (\n    <TabsPrimitive.Content\n      data-slot=\"tabs-content\"\n      className={cn(\"flex-1 outline-none\", className)}\n      {...props}\n    />\n  );\n}\n\nexport { Tabs, TabsList, TabsTrigger, TabsContent };\n"},{"path":"src/app/components/ui/textarea.tsx","content":"import * as React from \"react\";\n\nimport { cn } from \"./utils\";\n\nfunction Textarea({ className, ...props }: React.ComponentProps<\"textarea\">) {\n  return (\n    <textarea\n      data-slot=\"textarea\"\n      className={cn(\n        \"resize-none border-input placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:bg-input/30 flex field-sizing-content min-h-16 w-full rounded-md border bg-input-background px-3 py-2 text-base transition-[color,box-shadow] outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50 md:text-sm\",\n        className,\n      )}\n      {...props}\n    />\n  );\n}\n\nexport { Textarea };\n"},{"path":"src/app/components/ui/toggle-group.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as ToggleGroupPrimitive from \"@radix-ui/react-toggle-group\";\nimport { type VariantProps } from \"class-variance-authority\";\n\nimport { cn } from \"./utils\";\nimport { toggleVariants } from \"./toggle\";\n\nconst ToggleGroupContext = React.createContext<\n  VariantProps<typeof toggleVariants>\n>({\n  size: \"default\",\n  variant: \"default\",\n});\n\nfunction ToggleGroup({\n  className,\n  variant,\n  size,\n  children,\n  ...props\n}: React.ComponentProps<typeof ToggleGroupPrimitive.Root> &\n  VariantProps<typeof toggleVariants>) {\n  return (\n    <ToggleGroupPrimitive.Root\n      data-slot=\"toggle-group\"\n      data-variant={variant}\n      data-size={size}\n      className={cn(\n        \"group/toggle-group flex w-fit items-center rounded-md data-[variant=outline]:shadow-xs\",\n        className,\n      )}\n      {...props}\n    >\n      <ToggleGroupContext.Provider value={{ variant, size }}>\n        {children}\n      </ToggleGroupContext.Provider>\n    </ToggleGroupPrimitive.Root>\n  );\n}\n\nfunction ToggleGroupItem({\n  className,\n  children,\n  variant,\n  size,\n  ...props\n}: React.ComponentProps<typeof ToggleGroupPrimitive.Item> &\n  VariantProps<typeof toggleVariants>) {\n  const context = React.useContext(ToggleGroupContext);\n\n  return (\n    <ToggleGroupPrimitive.Item\n      data-slot=\"toggle-group-item\"\n      data-variant={context.variant || variant}\n      data-size={context.size || size}\n      className={cn(\n        toggleVariants({\n          variant: context.variant || variant,\n          size: context.size || size,\n        }),\n        \"min-w-0 flex-1 shrink-0 rounded-none shadow-none first:rounded-l-md last:rounded-r-md focus:z-10 focus-visible:z-10 data-[variant=outline]:border-l-0 data-[variant=outline]:first:border-l\",\n        className,\n      )}\n      {...props}\n    >\n      {children}\n    </ToggleGroupPrimitive.Item>\n  );\n}\n\nexport { ToggleGroup, ToggleGroupItem };\n"},{"path":"src/app/components/ui/toggle.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as TogglePrimitive from \"@radix-ui/react-toggle\";\nimport { cva, type VariantProps } from \"class-variance-authority\";\n\nimport { cn } from \"./utils\";\n\nconst toggleVariants = cva(\n  \"inline-flex items-center justify-center gap-2 rounded-md text-sm font-medium hover:bg-muted hover:text-muted-foreground disabled:pointer-events-none disabled:opacity-50 data-[state=on]:bg-accent data-[state=on]:text-accent-foreground [&_svg]:pointer-events-none [&_svg:not([class*=''size-''])]:size-4 [&_svg]:shrink-0 focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] outline-none transition-[color,box-shadow] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive whitespace-nowrap\",\n  {\n    variants: {\n      variant: {\n        default: \"bg-transparent\",\n        outline:\n          \"border border-input bg-transparent hover:bg-accent hover:text-accent-foreground\",\n      },\n      size: {\n        default: \"h-9 px-2 min-w-9\",\n        sm: \"h-8 px-1.5 min-w-8\",\n        lg: \"h-10 px-2.5 min-w-10\",\n      },\n    },\n    defaultVariants: {\n      variant: \"default\",\n      size: \"default\",\n    },\n  },\n);\n\nfunction Toggle({\n  className,\n  variant,\n  size,\n  ...props\n}: React.ComponentProps<typeof TogglePrimitive.Root> &\n  VariantProps<typeof toggleVariants>) {\n  return (\n    <TogglePrimitive.Root\n      data-slot=\"toggle\"\n      className={cn(toggleVariants({ variant, size, className }))}\n      {...props}\n    />\n  );\n}\n\nexport { Toggle, toggleVariants };\n"},{"path":"src/app/components/ui/tooltip.tsx","content":"\"use client\";\n\nimport * as React from \"react\";\nimport * as TooltipPrimitive from \"@radix-ui/react-tooltip\";\n\nimport { cn } from \"./utils\";\n\nfunction TooltipProvider({\n  delayDuration = 0,\n  ...props\n}: React.ComponentProps<typeof TooltipPrimitive.Provider>) {\n  return (\n    <TooltipPrimitive.Provider\n      data-slot=\"tooltip-provider\"\n      delayDuration={delayDuration}\n      {...props}\n    />\n  );\n}\n\nfunction Tooltip({\n  ...props\n}: React.ComponentProps<typeof TooltipPrimitive.Root>) {\n  return (\n    <TooltipProvider>\n      <TooltipPrimitive.Root data-slot=\"tooltip\" {...props} />\n    </TooltipProvider>\n  );\n}\n\nfunction TooltipTrigger({\n  ...props\n}: React.ComponentProps<typeof TooltipPrimitive.Trigger>) {\n  return <TooltipPrimitive.Trigger data-slot=\"tooltip-trigger\" {...props} />;\n}\n\nfunction TooltipContent({\n  className,\n  sideOffset = 0,\n  children,\n  ...props\n}: React.ComponentProps<typeof TooltipPrimitive.Content>) {\n  return (\n    <TooltipPrimitive.Portal>\n      <TooltipPrimitive.Content\n        data-slot=\"tooltip-content\"\n        sideOffset={sideOffset}\n        className={cn(\n          \"bg-primary text-primary-foreground animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 z-50 w-fit origin-(--radix-tooltip-content-transform-origin) rounded-md px-3 py-1.5 text-xs text-balance\",\n          className,\n        )}\n        {...props}\n      >\n        {children}\n        <TooltipPrimitive.Arrow className=\"bg-primary fill-primary z-50 size-2.5 translate-y-[calc(-50%_-_2px)] rotate-45 rounded-[2px]\" />\n      </TooltipPrimitive.Content>\n    </TooltipPrimitive.Portal>\n  );\n}\n\nexport { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider };\n"},{"path":"src/app/components/ui/use-mobile.ts","content":"import * as React from \"react\";\n\nconst MOBILE_BREAKPOINT = 768;\n\nexport function useIsMobile() {\n  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(\n    undefined,\n  );\n\n  React.useEffect(() => {\n    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);\n    const onChange = () => {\n      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);\n    };\n    mql.addEventListener(\"change\", onChange);\n    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);\n    return () => mql.removeEventListener(\"change\", onChange);\n  }, []);\n\n  return !!isMobile;\n}\n"},{"path":"src/app/components/ui/utils.ts","content":"import { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nexport function cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n"},{"path":"src/app/pages/about.tsx","content":"import { ImageWithFallback } from \"../components/figma/ImageWithFallback\";\nimport { Seo } from \"../components/seo\";\nimport { createPageUrl, siteConfig } from \"../content/site\";\nimport katyPhoto from \"../../assets/Katy Kimball Windsor.jpg\";\nimport markPhoto from \"../../assets/Mark Windsor.jpg\";\n\nconst aboutDescription =\n  \"Learn about Windsor Kimball APC, a Pasadena federal criminal defense firm led by Mark Windsor and Katy Kimball Windsor with decades of experience in trials, sentencing, and appeals.\";\n\nconst aboutStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"AboutPage\",\n  name: \"About Windsor Kimball APC\",\n  url: createPageUrl(\"/about\"),\n  description: aboutDescription,\n  mainEntity: {\n    \"@type\": \"LegalService\",\n    name: siteConfig.legalName,\n    telephone: siteConfig.telephone,\n    email: siteConfig.email,\n    address: {\n      \"@type\": \"PostalAddress\",\n      ...siteConfig.address,\n    },\n    employee: [\n      {\n        \"@type\": \"Attorney\",\n        name: \"Mark Windsor\",\n        jobTitle: \"Partner\",\n      },\n      {\n        \"@type\": \"Attorney\",\n        name: \"Katy Kimball Windsor\",\n        jobTitle: \"Partner\",\n      },\n    ],\n  },\n};\n\nexport function AboutPage() {\n  return (\n    <div>\n      <Seo\n        title=\"About Windsor Kimball APC | Federal Criminal Defense Lawyers\"\n        description={aboutDescription}\n        path=\"/about\"\n        image={markPhoto}\n        structuredData={aboutStructuredData}\n      />\n\n      {/* Header Section */}\n      <section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            About Windsor Kimball APC\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            We are a boutique criminal defense firm serving clients in federal district court, California state court, and throughout the Ninth Circuit. Our practice is built on individualized attention, disciplined preparation, creative strategy, and direct client access at every stage of the case.\n          </p>\n        </div>\n      </section>\n\n      {/* Our Approach */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-12 items-center\">\n            <div>\n              <h2 className=\"text-3xl mb-6 text-foreground\">\n                Our Approach\n              </h2>\n              <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                <p>\n                  Federal criminal cases are among the most serious matters an individual can face. The government has vast resources at its disposal, and the stakes are extraordinarily high. We understand that reality and approach each case with urgency, creativity, and a full appreciation of what is on the line.\n                </p>\n                <p>\n                  Our practice is intentionally small. We do not rely on associates or farm out the work. We keep our caseload at a level that allows us to devote substantial time to each client, thoroughly investigate the facts, and build a defense strategy that accounts for trial, sentencing, and appellate issues from the outset.\n                </p>\n                <p>\n                  We believe in open communication with our clients and their families. Our clients receive direct access to us, personalized attention, and practical guidance about every phase of the federal process, from pre-indictment investigation through appeal.\n                </p>\n                <p>\n                  We also understand that fee structure affects strategy. Rather than defaulting to a flat-fee model that can discourage work-intensive defense, we remain flexible in how we work with a client''s budget so they can obtain the strongest possible representation.\n                </p>\n              </div>\n            </div>\n            <div className=\"relative h-[400px]\">\n              <ImageWithFallback\n                src=\"https://images.unsplash.com/photo-1740933084077-edca148dbd5a?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxtb2Rlcm4lMjBjb25mZXJlbmNlJTIwcm9vbSUyMHByb2Zlc3Npb25hbHxlbnwxfHx8fDE3NzA4NTQxMTF8MA&ixlib=rb-4.1.0&q=80&w=1080\"\n                alt=\"Conference room\"\n                className=\"w-full h-full object-cover rounded\"\n              />\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Attorney Profiles */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-12 text-foreground text-center\">\n            Our Attorneys\n          </h2>\n          \n          {/* Rebecca Windsor */}\n          <div className=\"mb-20\">\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={markPhoto}\n                    alt=\"Portrait of Mark Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Mark Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  mark@windsorlaw.us<br />\n                  (626) 792-6700\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had &quot;fought like tigers&quot; for his client in an alien smuggling trial.\n                  </p>\n                  <p>\n                    Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\n                  </p>\n                  <p>\n                    Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\n                  </p>\n                  <p>\n                    Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\n                  </p>\n                  \n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Bar Admissions</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>State Bar of California</li>\n                      <li>California State Courts</li>\n                      <li>U.S. District Court, Northern District of California</li>\n                      <li>U.S. District Court, Central District of California</li>\n                      <li>U.S. District Court, Southern District of California</li>\n                      <li>U.S. Court of Appeals, Ninth Circuit</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A. in History, Brown University</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Michael Kimball */}\n          <div>\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={katyPhoto}\n                    alt=\"Portrait of Katy Kimball Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Katy Kimball Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  katy@windsorlaw.us<br />\n                  (213) 663-9219\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\n                  </p>\n                  <p>\n                    She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\n                  </p>\n                  <p>\n                    Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\n                  </p>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A., Vassar College</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Experience</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)</li>\n                      <li>Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)</li>\n                      <li>Private practice focused on federal criminal defense and appeals</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Jurisdictions */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n            Jurisdictions Served\n          </h2>\n          <div className=\"max-w-3xl mx-auto\">\n            <p className=\"text-center text-muted-foreground leading-relaxed mb-8\">\n              We are admitted to practice and regularly appear in the following courts:\n            </p>\n            <div className=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Trial Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. District Court, Central District of California</li>\n                  <li>• U.S. District Court, Southern District of California</li>\n                  <li>• Northern District of California</li>\n                  <li>• Superior Court of California</li>\n                </ul>\n              </div>\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Appellate Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. Court of Appeals, Ninth Circuit</li>\n                </ul>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n"},{"path":"src/app/pages/contact.tsx","content":"import { useState } from \"react\";\nimport { Seo } from \"../components/seo\";\nimport { createPageUrl, siteConfig } from \"../content/site\";\nimport { Input } from \"../components/ui/input\";\nimport { Textarea } from \"../components/ui/textarea\";\nimport { Label } from \"../components/ui/label\";\n\nconst contactDescription =\n  \"Contact Windsor Kimball APC in Pasadena for a confidential consultation about a federal investigation, indictment, trial, sentencing issue, or appeal.\";\n\nconst contactStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"ContactPage\",\n  name: \"Contact Windsor Kimball APC\",\n  url: createPageUrl(\"/contact\"),\n  description: contactDescription,\n  mainEntity: {\n    \"@type\": \"LegalService\",\n    name: siteConfig.legalName,\n    telephone: siteConfig.telephone,\n    email: siteConfig.email,\n    address: {\n      \"@type\": \"PostalAddress\",\n      ...siteConfig.address,\n    },\n    areaServed: siteConfig.areaServed,\n    openingHours: \"Mo-Fr 09:00-18:00\",\n  },\n};\n\nexport function ContactPage() {\n  const [formData, setFormData] = useState({\n    name: \"\",\n    email: \"\",\n    phone: \"\",\n    message: \"\"\n  });\n\n  const [submitted, setSubmitted] = useState(false);\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n    // In a real application, this would send data to a backend\n    setSubmitted(true);\n  };\n\n  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {\n    setFormData({\n      ...formData,\n      [e.target.name]: e.target.value\n    });\n  };\n\n  return (\n    <div>\n      <Seo\n        title=\"Contact Windsor Kimball APC | Federal Criminal Defense Consultation\"\n        description={contactDescription}\n        path=\"/contact\"\n        structuredData={contactStructuredData}\n      />\n\n      {/* Header Section */}\n      <section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Contact Us\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            If you are under federal investigation or have been charged with a federal crime, time is critical. Contact us for a confidential consultation about pre-indictment strategy, trial, sentencing, or appeal.\n          </p>\n        </div>\n      </section>\n\n      {/* Contact Form and Info */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-12\">\n            {/* Contact Information */}\n            <div className=\"lg:col-span-1\">\n              <div className=\"bg-white p-8 rounded\">\n                <h2 className=\"text-2xl mb-6 text-foreground\">\n                  Office Information\n                </h2>\n                \n                <div className=\"space-y-6\">\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Address</h3>\n                    <p className=\"text-foreground\">\n                      65 N. Raymond Avenue, Suite 320<br />\n                      Pasadena, California 91103\n                    </p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Phone</h3>\n                    <p className=\"text-foreground\">(626) 792-6700</p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Email</h3>\n                    <p className=\"text-foreground\">mark@windsorlaw.us</p>\n                    <p className=\"text-foreground\">katy@windsorlaw.us</p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Hours</h3>\n                    <p className=\"text-foreground\">\n                      Monday – Friday: 9:00 AM – 6:00 PM<br />\n                      Emergency consultations available\n                    </p>\n                  </div>\n                </div>\n              </div>\n\n              <div className=\"bg-primary text-primary-foreground p-6 rounded mt-6\">\n                <h3 className=\"mb-3\">What To Expect</h3>\n                <p className=\"text-sm leading-relaxed text-primary-foreground/90\">\n                  Clients work directly with us. We keep our caseload selective, provide individualized attention, and discuss fee arrangements with flexibility so strong representation can begin quickly.\n                </p>\n              </div>\n            </div>\n\n            {/* Contact Form */}\n            <div className=\"lg:col-span-2\">\n              <div className=\"bg-white p-8 lg:p-12 rounded\">\n                <h2 className=\"text-2xl mb-6 text-foreground\">\n                  Request a Consultation\n                </h2>\n\n                {submitted ? (\n                  <div className=\"bg-primary/10 border border-primary/20 rounded p-6\">\n                    <h3 className=\"text-lg mb-2 text-foreground\">Thank you for contacting us.</h3>\n                    <p className=\"text-muted-foreground\">\n                      We have received your message and will respond as soon as possible, typically within 24 hours. If your matter is urgent, please call us directly at (626) 792-6700.\n                    </p>\n                  </div>\n                ) : (\n                  <form onSubmit={handleSubmit} className=\"space-y-6\">\n                    <div>\n                      <Label htmlFor=\"name\">Name *</Label>\n                      <Input\n                        id=\"name\"\n                        name=\"name\"\n                        type=\"text\"\n                        required\n                        value={formData.name}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"email\">Email *</Label>\n                      <Input\n                        id=\"email\"\n                        name=\"email\"\n                        type=\"email\"\n                        required\n                        value={formData.email}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"phone\">Phone</Label>\n                      <Input\n                        id=\"phone\"\n                        name=\"phone\"\n                        type=\"tel\"\n                        value={formData.phone}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"message\">Message *</Label>\n                      <Textarea\n                        id=\"message\"\n                        name=\"message\"\n                        required\n                        rows={6}\n                        value={formData.message}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                        placeholder=\"Please provide a brief description of your legal matter. Do not include highly sensitive details in this form.\"\n                      />\n                    </div>\n\n                    <div className=\"text-sm text-muted-foreground leading-relaxed\">\n                      <p className=\"mb-4\">\n                        * Required fields\n                      </p>\n                      <p>\n                        By submitting this form, you acknowledge that contacting Windsor Kimball APC through this website does not create an attorney-client relationship. Please do not include confidential or sensitive information in your message. An attorney-client relationship is not formed until we have agreed to represent you and you have signed an engagement agreement.\n                      </p>\n                    </div>\n\n                    <button\n                      type=\"submit\"\n                      className=\"w-full sm:w-auto px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n                    >\n                      Submit\n                    </button>\n                  </form>\n                )}\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Jurisdictions */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Areas We Serve\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto leading-relaxed\">\n              We represent clients throughout Southern California and the Ninth Circuit. Our practice includes the following federal courts:\n            </p>\n          </div>\n\n          <div className=\"grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto\">\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Central District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Central District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• Los Angeles County</li>\n                <li>• Orange County</li>\n                <li>• Riverside County</li>\n                <li>• San Bernardino County</li>\n                <li>• San Luis Obispo County</li>\n                <li>• Santa Barbara County</li>\n                <li>• Ventura County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Southern District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Southern District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• San Diego County</li>\n                <li>• Imperial County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded md:col-span-2\">\n              <h3 className=\"mb-4 text-lg\">U.S. Court of Appeals, Ninth Circuit</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We handle appeals throughout the Ninth Circuit Court of Appeals, which covers federal appeals from California, Oregon, Washington, Arizona, Nevada, Idaho, Montana, Alaska, and Hawaii.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n"},{"path":"src/app/pages/faq.tsx","content":"import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from \"../components/ui/accordion\";\nimport { Seo } from \"../components/seo\";\nimport { createPageUrl } from \"../content/site\";\n\nconst faqDescription =\n  \"Get answers to common questions about federal investigations, grand jury subpoenas, bail, sentencing guidelines, plea decisions, and the federal criminal process.\";\n\nexport function FAQPage() {\n  return (\n    <div>\n      <Seo\n        title=\"Federal Criminal Defense FAQ | Windsor Kimball APC\"\n        description={faqDescription}\n        path=\"/faq\"\n        structuredData={faqStructuredData}\n      />\n\n      {/* Header Section */}\n      <section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Frequently Asked Questions\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            We understand that facing federal criminal charges is stressful and confusing. Below are answers to some common questions we receive from clients and their families.\n          </p>\n        </div>\n      </section>\n\n      {/* FAQ Content */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8\">\n          <Accordion type=\"single\" collapsible className=\"space-y-4\">\n            {faqs.map((faq, index) => (\n              <AccordionItem \n                key={index} \n                value={`item-${index}`}\n                className=\"bg-white border border-border rounded px-6\"\n              >\n                <AccordionTrigger className=\"text-left hover:no-underline py-6\">\n                  <span className=\"pr-4\">{faq.question}</span>\n                </AccordionTrigger>\n                <AccordionContent className=\"text-muted-foreground leading-relaxed pb-6\">\n                  {faq.answer}\n                </AccordionContent>\n              </AccordionItem>\n            ))}\n          </Accordion>\n        </div>\n      </section>\n\n      {/* CTA Section */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Have More Questions?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Every case is unique. Contact us for a confidential consultation to discuss your specific situation.\n          </p>\n          <a \n            href=\"/contact\" \n            className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n          >\n            Contact Us Today\n          </a>\n        </div>\n      </section>\n    </div>\n  );\n}\n\nconst faqs = [\n  {\n    question: \"What should I do if federal agents contact me?\",\n    answer: \"If federal agents contact you—whether at your home, workplace, or by phone—you should politely decline to speak with them and immediately contact an attorney. You have a constitutional right not to answer questions. Anything you say can and will be used against you, even if you believe you are innocent or are trying to explain your side of the story. Federal agents are trained interrogators. It is critical to have legal counsel before engaging with them.\"\n  },\n  {\n    question: \"What is the difference between being a ''target'' and a ''subject'' of an investigation?\",\n    answer: \"A ''target'' is someone the government believes committed a crime and is likely to be indicted. A ''subject'' is someone whose conduct is within the scope of the investigation but who is not currently a target. These designations can change as an investigation progresses. If you have been designated a target or subject, you should consult with an attorney immediately.\"\n  },\n  {\n    question: \"How long do federal investigations take?\",\n    answer: \"Federal investigations can last months or even years. Unlike state cases, federal prosecutors typically do not file charges until they have thoroughly investigated the case. This means that by the time you are indicted, the government has often already built a substantial case. This is why pre-indictment representation is so valuable—engaging counsel early can sometimes prevent charges from being filed.\"\n  },\n  {\n    question: \"What is a federal grand jury?\",\n    answer: \"A federal grand jury is a group of citizens who review evidence presented by prosecutors to determine whether there is probable cause to believe a crime was committed. Grand jury proceedings are secret, and you do not have a right to have your attorney present if you are called to testify. If you receive a grand jury subpoena, contact an attorney immediately before responding or appearing.\"\n  },\n  {\n    question: \"Should I cooperate with the government?\",\n    answer: \"The decision to cooperate with federal prosecutors is complex and must be made carefully with the advice of counsel. Cooperation can sometimes result in substantial sentence reductions, but it also carries risks and obligations. We can advise you on whether cooperation is appropriate in your case and, if so, negotiate the terms of any cooperation agreement.\"\n  },\n  {\n    question: \"What are the federal sentencing guidelines?\",\n    answer: \"The federal sentencing guidelines are a complex set of rules that judges use to determine an appropriate sentence. While the guidelines are no longer mandatory, judges still use them as a starting point. The guidelines calculate a sentencing range based on the offense conduct and the defendant''s criminal history. An experienced attorney can identify legal and factual arguments to advocate for a lower guideline calculation or a variance from the guidelines.\"\n  },\n  {\n    question: \"What is a mandatory minimum sentence?\",\n    answer: \"A mandatory minimum is a statutorily required minimum prison sentence for certain offenses. For example, some drug and firearms offenses carry mandatory minimum sentences of 5, 10, or even 20 years. In limited circumstances, mandatory minimums can be avoided through substantial assistance departures or the federal ''safety valve'' provision. This is another reason why experienced counsel is critical.\"\n  },\n  {\n    question: \"Can I be charged in federal court for something that is legal under California law?\",\n    answer: \"Yes. Federal law operates independently of state law. For example, marijuana remains illegal under federal law even though it is legal in California. Immigration violations, federal firearms offenses, and other crimes may be prosecuted in federal court regardless of state law. If you are unsure whether your conduct could constitute a federal offense, consult with an attorney.\"\n  },\n  {\n    question: \"What is the difference between federal and state criminal cases?\",\n    answer: \"Federal cases are prosecuted by Assistant United States Attorneys and heard in federal court. They typically involve violations of federal statutes, such as drug trafficking, white collar crimes, immigration offenses, and firearms violations. Federal cases generally involve more complex investigations, more severe penalties, and different procedures than state cases. Federal prosecutors also tend to have more resources than state prosecutors.\"\n  },\n  {\n    question: \"What happens at an initial appearance or arraignment?\",\n    answer: \"An initial appearance is typically your first court appearance after being arrested or charged. At this hearing, the judge will inform you of the charges, advise you of your rights, and determine whether you will be released or detained pending trial. You will also be assigned counsel if you cannot afford an attorney. It is critical to have an attorney represent you at this hearing, particularly if detention is a possibility.\"\n  },\n  {\n    question: \"Can I get bail in a federal case?\",\n    answer: \"Federal detention decisions are governed by the Bail Reform Act. Unlike state court, there is a presumption of detention for certain offenses, including serious drug offenses and crimes of violence. To secure release, your attorney must demonstrate that you are not a danger to the community and that you will appear for court. This often requires presenting a detailed release plan, including housing, employment, and family support.\"\n  },\n  {\n    question: \"How long does a federal criminal case take?\",\n    answer: \"The timeline varies significantly depending on the complexity of the case and whether it goes to trial. Under the Speedy Trial Act, a federal trial must generally commence within 70 days of indictment or initial appearance, but there are many excludable delays. In reality, most federal cases take several months from indictment to resolution, and complex cases can take a year or more.\"\n  },\n  {\n    question: \"Should I plead guilty or go to trial?\",\n    answer: \"This is one of the most important decisions you will make in your case, and it depends entirely on the specific facts and circumstances. We will thoroughly review the government''s evidence, investigate potential defenses, and discuss the strengths and weaknesses of your case with you. The decision is ultimately yours, but we will provide candid advice to help you make an informed choice.\"\n  },\n  {\n    question: \"What is discovery in a federal case?\",\n    answer: \"Discovery is the process by which the government provides the defense with evidence. Federal prosecutors are required to disclose certain evidence, including exculpatory evidence (evidence that tends to show innocence) and impeachment evidence (evidence that could be used to challenge the credibility of government witnesses). We will carefully review all discovery to identify weaknesses in the government''s case and develop a defense strategy.\"\n  },\n  {\n    question: \"How much does federal criminal defense cost?\",\n    answer: \"Legal fees vary depending on the complexity of the case, the stage of the proceedings, and the amount of work required. We discuss fees candidly during the initial consultation and remain flexible in how we work with a client''s budget so that strong representation is not undermined by an incentive to do as little work as possible. Many firms rely on flat fees, which can create the wrong incentives in a serious federal case. Our focus is building the defense your case requires.\"\n  },\n  {\n    question: \"What is a proffer or ''queen for a day'' agreement?\",\n    answer: \"A proffer agreement allows you to meet with prosecutors and provide information about your case or others'' involvement in criminal activity. In exchange, the government generally agrees not to use your statements directly against you, though there are important exceptions. Proffer sessions are high-stakes and should never be conducted without experienced counsel. We can advise you on whether to participate in a proffer and will prepare you thoroughly if you do.\"\n  }\n];\n\nconst faqStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"FAQPage\",\n  name: \"Federal Criminal Defense FAQ\",\n  url: createPageUrl(\"/faq\"),\n  description: faqDescription,\n  mainEntity: faqs.map((faq) => ({\n    \"@type\": \"Question\",\n    name: faq.question,\n    acceptedAnswer: {\n      \"@type\": \"Answer\",\n      text: faq.answer,\n    },\n  })),\n};\n"},{"path":"src/app/pages/home.tsx","content":"import { useState } from \"react\";\nimport { Link } from \"react-router\";\nimport heroImage from \"../../assets/cropped-bridgebw-4-e1488258813260.jpg\";\nimport { Seo } from \"../components/seo\";\nimport { practiceAreas } from \"../content/practice-areas\";\nimport { siteConfig } from \"../content/site\";\nimport { getRandomSuccessResults } from \"../content/successes\";\n\nconst homeDescription =\n  \"Federal criminal defense attorneys in Pasadena representing clients in investigations, trial, sentencing, appeals, and complex state criminal matters across Southern California and the Ninth Circuit.\";\n\nconst homeStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"LegalService\",\n  \"@id\": `${siteConfig.siteUrl}#legal-service`,\n  name: siteConfig.legalName,\n  url: siteConfig.siteUrl,\n  image: `${siteConfig.siteUrl}${heroImage}`,\n  logo: `${siteConfig.siteUrl}${siteConfig.defaultOgImage}`,\n  description: homeDescription,\n  telephone: siteConfig.telephone,\n  email: siteConfig.email,\n  areaServed: siteConfig.areaServed,\n  address: {\n    \"@type\": \"PostalAddress\",\n    ...siteConfig.address,\n  },\n  hasOfferCatalog: {\n    \"@type\": \"OfferCatalog\",\n    name: \"Federal Criminal Defense Services\",\n    itemListElement: practiceAreas.map((area) => ({\n      \"@type\": \"Offer\",\n      itemOffered: {\n        \"@type\": \"Service\",\n        name: area.title,\n        description: area.description,\n      },\n    })),\n  },\n};\n\nexport function HomePage() {\n  const [featuredResults] = useState(() => getRandomSuccessResults(4));\n\n  return (\n    <div>\n      <Seo\n        title=\"Federal Criminal Defense Attorneys in Pasadena, CA | Windsor Kimball APC\"\n        description={homeDescription}\n        path=\"/\"\n        image={heroImage}\n        structuredData={homeStructuredData}\n      />\n\n      {/* Hero Section */}\n      <section\n        className=\"relative isolate overflow-hidden\"\n        style={{\n          backgroundImage: `linear-gradient(rgba(66,104,135,0.82), rgba(66,104,135,0.82)), url(${heroImage})`,\n          backgroundPosition: \"center\",\n          backgroundSize: \"cover\",\n        }}\n      >\n        <div className=\"absolute inset-0 bg-[linear-gradient(90deg,rgba(66,104,135,0.14)_0%,rgba(66,104,135,0.08)_45%,rgba(66,104,135,0.02)_100%)]\" />\n        <div className=\"relative max-w-7xl mx-auto px-6 lg:px-8 py-28 lg:py-40\">\n          <div className=\"max-w-3xl\">\n            <div className=\"inline-flex items-center rounded-full border border-white/20 bg-white/10 px-4 py-2 text-xs uppercase tracking-[0.28em] text-white/80 backdrop-blur-sm\">\n              Criminal Defense in Downtown Los Angeles\n            </div>\n            <div className=\"mt-8 rounded-lg border border-white/12 bg-black/16 p-8 shadow-2xl backdrop-blur-[2px] lg:p-12\">\n              <p className=\"mb-4 text-sm uppercase tracking-[0.24em] text-white/70\">\n                Strategic defense from pre-indictment investigations through appeal\n              </p>\n              <h1 className=\"text-4xl leading-tight text-white lg:text-6xl\">\n                Federal Criminal Defense in Southern California\n              </h1>\n              <p className=\"mt-6 max-w-2xl text-lg leading-relaxed text-white/82 lg:text-xl\">\n                Windsor Kimball APC is a boutique criminal defense firm serving clients in federal district court, California state court, and throughout the Ninth Circuit with direct attorney access and strategic representation from pre-indictment investigation through appeal.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Credentials Section */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Experience You Can Trust\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              With more than 50 years of combined experience in federal criminal defense, we bring deep knowledge of federal investigations, trial practice, sentencing, and appeals to every case.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-3 gap-8\">\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>50+</div>\n              <h3 className=\"text-lg mb-2\">Years Combined Experience</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                More than five decades focused on the niche area of federal criminal defense in California federal courts and the Ninth Circuit.\n              </p>\n            </div>\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>1:1</div>\n              <h3 className=\"text-lg mb-2\">Direct Attorney Attention</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We do not farm out work to associates. Clients work directly with us, receive personalized attention, and can reach us when urgent issues arise.\n              </p>\n            </div>\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>360°</div>\n              <h3 className=\"text-lg mb-2\">Full-Scope Representation</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We handle matters from pre-indictment investigation through trial, sentencing, and appeal, with strategy built for every stage of the case.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Practice Areas Overview */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Areas of Practice\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              We handle a wide range of federal criminal matters with precision and dedication.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n            {practiceAreas.map((area) => (\n              <div key={area.title} className=\"border border-border p-6 rounded hover:border-primary/30 transition-colors\">\n                <h3 className=\"text-lg mb-3\">{area.title}</h3>\n                <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                  {area.description}\n                </p>\n              </div>\n            ))}\n          </div>\n          <div className=\"text-center mt-12\">\n            <Link \n              to=\"/practice-areas\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              View All Practice Areas\n            </Link>\n          </div>\n        </div>\n      </section>\n\n      {/* Notable Results */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Representative Results\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              Our track record speaks to our commitment to zealous advocacy and client service.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-2 gap-8\">\n            {featuredResults.map((result) => (\n              <div key={result.title} className=\"bg-white p-8 rounded\">\n                <div className=\"mb-4\">\n                  <span className=\"inline-block rounded bg-primary/10 px-3 py-1 text-xs uppercase tracking-wider text-primary\">\n                    {result.charge}\n                  </span>\n                </div>\n                <h3 className=\"text-lg mb-4 text-primary\">{result.title}</h3>\n                <div className=\"text-sm text-muted-foreground leading-relaxed\">\n                  {result.summary}\n                </div>\n              </div>\n            ))}\n          </div>\n          <div className=\"text-center mt-12\">\n            <Link \n              to=\"/successes\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              View More Results\n            </Link>\n          </div>\n        </div>\n      </section>\n\n      {/* CTA Section */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Facing Criminal Charges?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Time is critical in federal or California state criminal matters. We keep our caseload selective, evaluate cases creatively, and work flexibly with a client''s budget so they can receive strong representation.\n          </p>\n          <div className=\"flex flex-col sm:flex-row gap-4 justify-center\">\n            <Link \n              to=\"/contact\" \n              className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n            >\n              Contact Us Today\n            </Link>\n            <Link \n              to=\"/faq\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              Frequently Asked Questions\n            </Link>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n"},{"path":"src/app/pages/not-found.tsx","content":"import { Link, useLocation } from \"react-router\";\nimport { Seo } from \"../components/seo\";\n\nexport function NotFound() {\n  const location = useLocation();\n\n  return (\n    <div className=\"min-h-[60vh] flex items-center justify-center bg-secondary\">\n      <Seo\n        title=\"Page Not Found | Windsor Kimball APC\"\n        description=\"The requested page could not be found.\"\n        path={location.pathname}\n        robots=\"noindex, nofollow\"\n      />\n      <div className=\"text-center px-6\">\n        <h1 className=\"text-6xl mb-4 text-foreground\">\n          404\n        </h1>\n        <h2 className=\"text-2xl mb-6 text-foreground\">Page Not Found</h2>\n        <p className=\"text-muted-foreground mb-8 max-w-md mx-auto\">\n          The page you are looking for does not exist or has been moved.\n        </p>\n        <Link \n          to=\"/\" \n          className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n        >\n          Return Home\n        </Link>\n      </div>\n    </div>\n  );\n}\n"},{"path":"src/app/pages/practice-areas.tsx","content":"import { Seo } from \"../components/seo\";\nimport { practiceAreas } from \"../content/practice-areas\";\nimport { createPageUrl } from \"../content/site\";\n\nconst practiceAreasDescription =\n  \"Explore Windsor Kimball APC''s federal criminal defense practice areas, including white collar cases, drug offenses, immigration-related crimes, firearms charges, appeals, and other federal prosecutions.\";\n\nconst practiceAreasStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"CollectionPage\",\n  name: \"Federal Criminal Defense Practice Areas\",\n  url: createPageUrl(\"/practice-areas\"),\n  description: practiceAreasDescription,\n  mainEntity: {\n    \"@type\": \"ItemList\",\n    itemListElement: practiceAreas.map((area, index) => ({\n      \"@type\": \"ListItem\",\n      position: index + 1,\n      name: area.title,\n      description: area.description,\n    })),\n  },\n};\n\nexport function PracticeAreasPage() {\n  return (\n    <div>\n      <Seo\n        title=\"Federal Criminal Defense Practice Areas | Windsor Kimball APC\"\n        description={practiceAreasDescription}\n        path=\"/practice-areas\"\n        structuredData={practiceAreasStructuredData}\n      />\n\n      {/* Header Section */}\n      <section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Practice Areas\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            Windsor Kimball APC represents clients in all stages of federal criminal matters, from pre-indictment investigations through trial and appeal. Our experience spans a wide range of federal offenses.\n          </p>\n        </div>\n      </section>\n\n      {/* Practice Areas */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"space-y-12\">\n            {practiceAreas.map((area, index) => (\n              <div key={index} className=\"bg-white p-8 lg:p-12 rounded\">\n                <h2 className=\"text-2xl mb-4 text-foreground\">\n                  {area.title}\n                </h2>\n                <p className=\"text-muted-foreground leading-relaxed mb-6\">\n                  {area.description}\n                </p>\n                {area.details && (\n                  <div className=\"space-y-4\">\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground\">\n                      Common Charges We Handle:\n                    </h3>\n                    <ul className=\"grid grid-cols-1 md:grid-cols-2 gap-3\">\n                      {area.details.map((detail, idx) => (\n                        <li key={idx} className=\"flex items-start\">\n                          <span className=\"text-primary mr-2\">•</span>\n                          <span className=\"text-sm text-muted-foreground\">{detail}</span>\n                        </li>\n                      ))}\n                    </ul>\n                  </div>\n                )}\n              </div>\n            ))}\n          </div>\n        </div>\n      </section>\n\n      {/* Federal Court Info */}\n      <section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto\">\n            <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n              Understanding Federal Criminal Defense\n            </h2>\n            <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n              <p>\n                Federal criminal cases are fundamentally different from state prosecutions. They are typically more complex, involve more sophisticated investigation techniques, and carry harsher penalties. The federal criminal justice system has its own set of rules, procedures, and sentencing guidelines.\n              </p>\n              <p>\n                Federal prosecutors are well-resourced and highly skilled. By the time charges are filed, the government has often been investigating for months or years. This is why having experienced federal defense counsel is critical—not just after charges are filed, but ideally during the investigation phase when strategic intervention can sometimes prevent charges altogether.\n              </p>\n              <p>\n                We practice primarily in the U.S. District Courts for the Central District of California (which includes Los Angeles, Orange County, Riverside, San Bernardino, San Luis Obispo, Santa Barbara, and Ventura Counties) and the Southern District of California (which includes San Diego and Imperial Counties). We also handle appeals in the Ninth Circuit Court of Appeals.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Pre-Indictment Section */}\n      <section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto text-center\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Pre-Indictment Representation\n            </h2>\n            <p className=\"text-muted-foreground leading-relaxed mb-8\">\n              If you are under federal investigation but have not yet been charged, early legal intervention is crucial. We can work with prosecutors and agents during the investigation phase, potentially avoiding charges or significantly reducing their severity.\n            </p>\n            <p className=\"text-muted-foreground leading-relaxed\">\n              Common signs you may be under federal investigation include contact from federal agents, subpoenas for documents or testimony, or notification that you are a \"target\" or \"subject\" of an investigation.\n            </p>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n"},{"path":"src/app/pages/successes.tsx","content":"import { Seo } from \"../components/seo\";\nimport { createPageUrl } from \"../content/site\";\nimport { appellateResults } from \"../content/successes\";\n\nconst successesDescription =\n  \"Review representative appellate and post-conviction victories achieved by Windsor Kimball APC in federal criminal defense matters in the Ninth Circuit and California federal courts.\";\n\nconst successesStructuredData = {\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"CollectionPage\",\n  name: \"Representative Results\",\n  url: createPageUrl(\"/successes\"),\n  description: successesDescription,\n  mainEntity: {\n    \"@type\": \"ItemList\",\n    itemListElement: appellateResults.map((result, index) => ({\n      \"@type\": \"ListItem\",\n      position: index + 1,\n      name: result.title,\n      description: result.summary,\n    })),\n  },\n};\n\nexport function SuccessesPage() {\n  return (\n    <div>\n      <Seo\n        title=\"Representative Results | Windsor Kimball APC\"\n        description={successesDescription}\n        path=\"/successes\"\n        structuredData={successesStructuredData}\n      />\n\n      <section className=\"border-b border-border bg-white py-16\">\n        <div className=\"mx-auto max-w-7xl px-6 lg:px-8\">\n          <h1 className=\"mb-6 text-4xl text-foreground lg:text-5xl\">\n            Representative Results\n          </h1>\n          <p className=\"max-w-3xl text-lg leading-relaxed text-muted-foreground\">\n            While past results do not guarantee future outcomes, we are proud of\n            our track record of success in federal criminal defense. Below are\n            select examples of results we have achieved for our clients.\n          </p>\n        </div>\n      </section>\n\n      <section className=\"bg-secondary py-20\">\n        <div className=\"mx-auto max-w-7xl px-6 lg:px-8\">\n          <div>\n            <h2 className=\"mb-8 text-3xl text-foreground\">\n              Appellate and Post-Conviction Victories\n            </h2>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2\">\n              {appellateResults.map((result) => (\n                <div key={result.title} className=\"rounded bg-white p-8\">\n                  <div className=\"mb-4\">\n                    <span className=\"inline-block rounded bg-primary/10 px-3 py-1 text-xs uppercase tracking-wider text-primary\">\n                      {result.charge}\n                    </span>\n                  </div>\n                  <h3 className=\"mb-3 text-xl text-foreground\">{result.title}</h3>\n                  <div className=\"space-y-4\">\n                    <p className=\"text-sm leading-relaxed text-muted-foreground\">\n                      {result.description}\n                    </p>\n                    {result.citations && result.citations.length > 0 ? (\n                      <div className=\"border-t border-border pt-4 text-sm leading-relaxed text-muted-foreground\">\n                        {result.citations.map((citation) => (\n                          <p key={citation}>{citation}</p>\n                        ))}\n                      </div>\n                    ) : null}\n                  </div>\n                </div>\n              ))}\n            </div>\n          </div>\n        </div>\n      </section>\n\n      <section className=\"bg-white py-16\">\n        <div className=\"mx-auto max-w-4xl px-6 lg:px-8\">\n          <div className=\"border-l-4 border-primary/30 pl-6\">\n            <p className=\"text-sm italic leading-relaxed text-muted-foreground\">\n              The results described above were achieved in specific cases and do\n              not guarantee or predict a similar result in any future case.\n              Every case is unique and must be evaluated on its own facts and\n              circumstances. Client results depend on a variety of factors\n              including the facts of the case, applicable law, venue, and the\n              skill and preparation of all parties involved.\n            </p>\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n"},{"path":"src/styles/fonts.css","content":"@import url(''https://fonts.googleapis.com/css2?family=Montserrat:wght@400&family=Merriweather:wght@300;400;700&family=Inter:wght@300;400;500;600&display=swap'');\n"},{"path":"src/styles/index.css","content":"@import ''./fonts.css'';\n@import ''./tailwind.css'';\n@import ''./theme.css'';\n"},{"path":"src/styles/tailwind.css","content":"@import ''tailwindcss'' source(none);\n@source ''../**/*.{js,ts,jsx,tsx}'';\n\n@import ''tw-animate-css'';\n"},{"path":"src/styles/theme.css","content":"@custom-variant dark (&:is(.dark *));\n\n:root {\n  --font-size: 16px;\n  --font-heading: ''Montserrat'', sans-serif;\n  --font-heading-weight: 400;\n  --font-serif: ''Merriweather'', serif;\n  --font-sans: ''Inter'', sans-serif;\n  --background: #fafafa;\n  --foreground: #1a1a1a;\n  --card: #ffffff;\n  --card-foreground: #1a1a1a;\n  --popover: #ffffff;\n  --popover-foreground: #1a1a1a;\n  --primary: #426887;\n  --primary-foreground: #ffffff;\n  --secondary: #f5f5f5;\n  --secondary-foreground: #2c3e50;\n  --muted: #e8e8e8;\n  --muted-foreground: #666666;\n  --accent: #34495e;\n  --accent-foreground: #ffffff;\n  --destructive: #d4183d;\n  --destructive-foreground: #ffffff;\n  --border: rgba(0, 0, 0, 0.08);\n  --input: transparent;\n  --input-background: #ffffff;\n  --switch-background: #cbced4;\n  --font-weight-medium: 500;\n  --font-weight-normal: 400;\n  --ring: rgba(66, 104, 135, 0.3);\n  --chart-1: oklch(0.646 0.222 41.116);\n  --chart-2: oklch(0.6 0.118 184.704);\n  --chart-3: oklch(0.398 0.07 227.392);\n  --chart-4: oklch(0.828 0.189 84.429);\n  --chart-5: oklch(0.769 0.188 70.08);\n  --radius: 0.25rem;\n  --sidebar: #fafafa;\n  --sidebar-foreground: #1a1a1a;\n  --sidebar-primary: #426887;\n  --sidebar-primary-foreground: #fafafa;\n  --sidebar-accent: #f5f5f5;\n  --sidebar-accent-foreground: #1a1a1a;\n  --sidebar-border: rgba(0, 0, 0, 0.08);\n  --sidebar-ring: rgba(66, 104, 135, 0.3);\n}\n\n.dark {\n  --background: oklch(0.145 0 0);\n  --foreground: oklch(0.985 0 0);\n  --card: oklch(0.145 0 0);\n  --card-foreground: oklch(0.985 0 0);\n  --popover: oklch(0.145 0 0);\n  --popover-foreground: oklch(0.985 0 0);\n  --primary: oklch(0.985 0 0);\n  --primary-foreground: oklch(0.205 0 0);\n  --secondary: oklch(0.269 0 0);\n  --secondary-foreground: oklch(0.985 0 0);\n  --muted: oklch(0.269 0 0);\n  --muted-foreground: oklch(0.708 0 0);\n  --accent: oklch(0.269 0 0);\n  --accent-foreground: oklch(0.985 0 0);\n  --destructive: oklch(0.396 0.141 25.723);\n  --destructive-foreground: oklch(0.637 0.237 25.331);\n  --border: oklch(0.269 0 0);\n  --input: oklch(0.269 0 0);\n  --ring: oklch(0.439 0 0);\n  --font-weight-medium: 500;\n  --font-weight-normal: 400;\n  --chart-1: oklch(0.488 0.243 264.376);\n  --chart-2: oklch(0.696 0.17 162.48);\n  --chart-3: oklch(0.769 0.188 70.08);\n  --chart-4: oklch(0.627 0.265 303.9);\n  --chart-5: oklch(0.645 0.246 16.439);\n  --sidebar: oklch(0.205 0 0);\n  --sidebar-foreground: oklch(0.985 0 0);\n  --sidebar-primary: oklch(0.488 0.243 264.376);\n  --sidebar-primary-foreground: oklch(0.985 0 0);\n  --sidebar-accent: oklch(0.269 0 0);\n  --sidebar-accent-foreground: oklch(0.985 0 0);\n  --sidebar-border: oklch(0.269 0 0);\n  --sidebar-ring: oklch(0.439 0 0);\n}\n\n@theme inline {\n  --color-background: var(--background);\n  --color-foreground: var(--foreground);\n  --color-card: var(--card);\n  --color-card-foreground: var(--card-foreground);\n  --color-popover: var(--popover);\n  --color-popover-foreground: var(--popover-foreground);\n  --color-primary: var(--primary);\n  --color-primary-foreground: var(--primary-foreground);\n  --color-secondary: var(--secondary);\n  --color-secondary-foreground: var(--secondary-foreground);\n  --color-muted: var(--muted);\n  --color-muted-foreground: var(--muted-foreground);\n  --color-accent: var(--accent);\n  --color-accent-foreground: var(--accent-foreground);\n  --color-destructive: var(--destructive);\n  --color-destructive-foreground: var(--destructive-foreground);\n  --color-border: var(--border);\n  --color-input: var(--input);\n  --color-input-background: var(--input-background);\n  --color-switch-background: var(--switch-background);\n  --color-ring: var(--ring);\n  --color-chart-1: var(--chart-1);\n  --color-chart-2: var(--chart-2);\n  --color-chart-3: var(--chart-3);\n  --color-chart-4: var(--chart-4);\n  --color-chart-5: var(--chart-5);\n  --radius-sm: calc(var(--radius) - 4px);\n  --radius-md: calc(var(--radius) - 2px);\n  --radius-lg: var(--radius);\n  --radius-xl: calc(var(--radius) + 4px);\n  --color-sidebar: var(--sidebar);\n  --color-sidebar-foreground: var(--sidebar-foreground);\n  --color-sidebar-primary: var(--sidebar-primary);\n  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);\n  --color-sidebar-accent: var(--sidebar-accent);\n  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);\n  --color-sidebar-border: var(--sidebar-border);\n  --color-sidebar-ring: var(--sidebar-ring);\n}\n\n@layer base {\n  * {\n    @apply border-border outline-ring/50;\n  }\n\n  body {\n    @apply bg-background text-foreground;\n  }\n\n  /**\n  * Default typography styles for HTML elements (h1-h4, p, label, button, input).\n  * These are in @layer base, so Tailwind utility classes (like text-sm, text-lg) automatically override them.\n  */\n\n  html {\n    font-size: var(--font-size);\n  }\n\n  h1 {\n    font-family: var(--font-heading);\n    font-size: var(--text-2xl);\n    font-weight: var(--font-heading-weight);\n    line-height: 1.5;\n  }\n\n  h2 {\n    font-family: var(--font-heading);\n    font-size: var(--text-xl);\n    font-weight: var(--font-heading-weight);\n    line-height: 1.5;\n  }\n\n  h3 {\n    font-family: var(--font-heading);\n    font-size: var(--text-lg);\n    font-weight: var(--font-heading-weight);\n    line-height: 1.5;\n  }\n\n  h4 {\n    font-family: var(--font-heading);\n    font-size: var(--text-base);\n    font-weight: var(--font-heading-weight);\n    line-height: 1.5;\n  }\n\n  label {\n    font-size: var(--text-base);\n    font-weight: var(--font-weight-medium);\n    line-height: 1.5;\n  }\n\n  button {\n    font-size: var(--text-base);\n    font-weight: var(--font-weight-medium);\n    line-height: 1.5;\n  }\n\n  input {\n    font-size: var(--text-base);\n    font-weight: var(--font-weight-normal);\n    line-height: 1.5;\n  }\n}\n"}],"owner":"misinc","commitSha":"46aa3c5bb64ed6683c950bf93d07ae45d665e9fe","defaultBranch":"main"}', 1780194675437);
INSERT OR REPLACE INTO app_blobs (key, value_json, updated_at) VALUES ('repos/6214c13d4994a673/syncs/46aa3c5bb64ed6683c950bf93d07ae45d665e9fe/tree.json', '{"pages":[{"id":"928cbe9e54d8c24f","name":"About","route":"/about","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":0,"sourceFile":"src/app/pages/about.tsx"},{"id":"9e4a7e6abffd2938","name":"Contact","route":"/contact","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":1,"sourceFile":"src/app/pages/contact.tsx"},{"id":"a5036340ba4de876","name":"Faq","route":"/faq","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":2,"sourceFile":"src/app/pages/faq.tsx"},{"id":"5aafb0c755ce76ec","name":"Home","route":"/home","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":3,"sourceFile":"src/app/pages/home.tsx"},{"id":"e7b0d18e32388a09","name":"Not Found","route":"/not-found","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":4,"sourceFile":"src/app/pages/not-found.tsx"},{"id":"159beb30efd4673f","name":"Practice Areas","route":"/practice-areas","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":5,"sourceFile":"src/app/pages/practice-areas.tsx"},{"id":"3aa7c9b56e48fbe3","name":"Successes","route":"/successes","repoId":"6214c13d4994a673","metadata":{"confidence":0.95,"parseStatus":"parsed"},"sortOrder":6,"sourceFile":"src/app/pages/successes.tsx"}],"sections":[{"id":"eb95636db4ddc198","name":"Header","pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            About Windsor Kimball APC\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            We are a boutique criminal defense firm serving clients in federal district court, California state court, and throughout the Ninth Circuit. Our practice is built on individualized attention, disciplined preparation, creative strategy, and direct client access at every stage of the case.\n          </p>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/about.tsx","sectionKey":"header","sourceFile":"src/app/pages/about.tsx","componentName":"HeaderSection"},{"id":"9de9ce7e1b250369","name":"Our Approach","pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-12 items-center\">\n            <div>\n              <h2 className=\"text-3xl mb-6 text-foreground\">\n                Our Approach\n              </h2>\n              <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                <p>\n                  Federal criminal cases are among the most serious matters an individual can face. The government has vast resources at its disposal, and the stakes are extraordinarily high. We understand that reality and approach each case with urgency, creativity, and a full appreciation of what is on the line.\n                </p>\n                <p>\n                  Our practice is intentionally small. We do not rely on associates or farm out the work. We keep our caseload at a level that allows us to devote substantial time to each client, thoroughly investigate the facts, and build a defense strategy that accounts for trial, sentencing, and appellate issues from the outset.\n                </p>\n                <p>\n                  We believe in open communication with our clients and their families. Our clients receive direct access to us, personalized attention, and practical guidance about every phase of the federal process, from pre-indictment investigation through appeal.\n                </p>\n                <p>\n                  We also understand that fee structure affects strategy. Rather than defaulting to a flat-fee model that can discourage work-intensive defense, we remain flexible in how we work with a client''s budget so they can obtain the strongest possible representation.\n                </p>\n              </div>\n            </div>\n            <div className=\"relative h-[400px]\">\n              <ImageWithFallback\n                src=\"https://images.unsplash.com/photo-1740933084077-edca148dbd5a?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxtb2Rlcm4lMjBjb25mZXJlbmNlJTIwcm9vbSUyMHByb2Zlc3Npb25hbHxlbnwxfHx8fDE3NzA4NTQxMTF8MA&ixlib=rb-4.1.0&q=80&w=1080\"\n                alt=\"Conference room\"\n                className=\"w-full h-full object-cover rounded\"\n              />\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/about.tsx","sectionKey":"our-approach","sourceFile":"src/app/pages/about.tsx","componentName":"OurApproachSection"},{"id":"0a9f7c5f8595ea33","name":"Attorney Profiles","pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-12 text-foreground text-center\">\n            Our Attorneys\n          </h2>\n          \n          {/* Rebecca Windsor */}\n          <div className=\"mb-20\">\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={markPhoto}\n                    alt=\"Portrait of Mark Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Mark Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  mark@windsorlaw.us<br />\n                  (626) 792-6700\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had &quot;fought like tigers&quot; for his client in an alien smuggling trial.\n                  </p>\n                  <p>\n                    Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\n                  </p>\n                  <p>\n                    Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\n                  </p>\n                  <p>\n                    Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\n                  </p>\n                  \n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Bar Admissions</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>State Bar of California</li>\n                      <li>California State Courts</li>\n                      <li>U.S. District Court, Northern District of California</li>\n                      <li>U.S. District Court, Central District of California</li>\n                      <li>U.S. District Court, Southern District of California</li>\n                      <li>U.S. Court of Appeals, Ninth Circuit</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A. in History, Brown University</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Michael Kimball */}\n          <div>\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={katyPhoto}\n                    alt=\"Portrait of Katy Kimball Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Katy Kimball Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  katy@windsorlaw.us<br />\n                  (213) 663-9219\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\n                  </p>\n                  <p>\n                    She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\n                  </p>\n                  <p>\n                    Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\n                  </p>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A., Vassar College</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Experience</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)</li>\n                      <li>Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)</li>\n                      <li>Private practice focused on federal criminal defense and appeals</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/about.tsx","sectionKey":"attorney-profiles","sourceFile":"src/app/pages/about.tsx","componentName":"AttorneyProfilesSection"},{"id":"5c0f83636ab8632f","name":"Jurisdictions","pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":3,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n            Jurisdictions Served\n          </h2>\n          <div className=\"max-w-3xl mx-auto\">\n            <p className=\"text-center text-muted-foreground leading-relaxed mb-8\">\n              We are admitted to practice and regularly appear in the following courts:\n            </p>\n            <div className=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Trial Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. District Court, Central District of California</li>\n                  <li>• U.S. District Court, Southern District of California</li>\n                  <li>• Northern District of California</li>\n                  <li>• Superior Court of California</li>\n                </ul>\n              </div>\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Appellate Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. Court of Appeals, Ninth Circuit</li>\n                </ul>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":3,"importPath":"src/app/pages/about.tsx","sectionKey":"jurisdictions","sourceFile":"src/app/pages/about.tsx","componentName":"JurisdictionsSection"},{"id":"d8bf5def375fa224","name":"Header","pageId":"9e4a7e6abffd2938","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Contact Us\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            If you are under federal investigation or have been charged with a federal crime, time is critical. Contact us for a confidential consultation about pre-indictment strategy, trial, sentencing, or appeal.\n          </p>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/contact.tsx","sectionKey":"header","sourceFile":"src/app/pages/contact.tsx","componentName":"HeaderSection"},{"id":"2b570332348bcdf7","name":"Contact Form And Info","pageId":"9e4a7e6abffd2938","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-12\">\n            {/* Contact Information */}\n            <div className=\"lg:col-span-1\">\n              <div className=\"bg-white p-8 rounded\">\n                <h2 className=\"text-2xl mb-6 text-foreground\">\n                  Office Information\n                </h2>\n                \n                <div className=\"space-y-6\">\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Address</h3>\n                    <p className=\"text-foreground\">\n                      65 N. Raymond Avenue, Suite 320<br />\n                      Pasadena, California 91103\n                    </p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Phone</h3>\n                    <p className=\"text-foreground\">(626) 792-6700</p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Email</h3>\n                    <p className=\"text-foreground\">mark@windsorlaw.us</p>\n                    <p className=\"text-foreground\">katy@windsorlaw.us</p>\n                  </div>\n\n                  <div>\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground mb-2\">Hours</h3>\n                    <p className=\"text-foreground\">\n                      Monday – Friday: 9:00 AM – 6:00 PM<br />\n                      Emergency consultations available\n                    </p>\n                  </div>\n                </div>\n              </div>\n\n              <div className=\"bg-primary text-primary-foreground p-6 rounded mt-6\">\n                <h3 className=\"mb-3\">What To Expect</h3>\n                <p className=\"text-sm leading-relaxed text-primary-foreground/90\">\n                  Clients work directly with us. We keep our caseload selective, provide individualized attention, and discuss fee arrangements with flexibility so strong representation can begin quickly.\n                </p>\n              </div>\n            </div>\n\n            {/* Contact Form */}\n            <div className=\"lg:col-span-2\">\n              <div className=\"bg-white p-8 lg:p-12 rounded\">\n                <h2 className=\"text-2xl mb-6 text-foreground\">\n                  Request a Consultation\n                </h2>\n\n                {submitted ? (\n                  <div className=\"bg-primary/10 border border-primary/20 rounded p-6\">\n                    <h3 className=\"text-lg mb-2 text-foreground\">Thank you for contacting us.</h3>\n                    <p className=\"text-muted-foreground\">\n                      We have received your message and will respond as soon as possible, typically within 24 hours. If your matter is urgent, please call us directly at (626) 792-6700.\n                    </p>\n                  </div>\n                ) : (\n                  <form onSubmit={handleSubmit} className=\"space-y-6\">\n                    <div>\n                      <Label htmlFor=\"name\">Name *</Label>\n                      <Input\n                        id=\"name\"\n                        name=\"name\"\n                        type=\"text\"\n                        required\n                        value={formData.name}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"email\">Email *</Label>\n                      <Input\n                        id=\"email\"\n                        name=\"email\"\n                        type=\"email\"\n                        required\n                        value={formData.email}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"phone\">Phone</Label>\n                      <Input\n                        id=\"phone\"\n                        name=\"phone\"\n                        type=\"tel\"\n                        value={formData.phone}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                      />\n                    </div>\n\n                    <div>\n                      <Label htmlFor=\"message\">Message *</Label>\n                      <Textarea\n                        id=\"message\"\n                        name=\"message\"\n                        required\n                        rows={6}\n                        value={formData.message}\n                        onChange={handleChange}\n                        className=\"mt-2 bg-input-background border-border\"\n                        placeholder=\"Please provide a brief description of your legal matter. Do not include highly sensitive details in this form.\"\n                      />\n                    </div>\n\n                    <div className=\"text-sm text-muted-foreground leading-relaxed\">\n                      <p className=\"mb-4\">\n                        * Required fields\n                      </p>\n                      <p>\n                        By submitting this form, you acknowledge that contacting Windsor Kimball APC through this website does not create an attorney-client relationship. Please do not include confidential or sensitive information in your message. An attorney-client relationship is not formed until we have agreed to represent you and you have signed an engagement agreement.\n                      </p>\n                    </div>\n\n                    <button\n                      type=\"submit\"\n                      className=\"w-full sm:w-auto px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n                    >\n                      Submit\n                    </button>\n                  </form>\n                )}\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/contact.tsx","sectionKey":"contact-form-and-info","sourceFile":"src/app/pages/contact.tsx","componentName":"ContactFormAndInfoSection"},{"id":"e6af3e9046fa03b1","name":"Jurisdictions","pageId":"9e4a7e6abffd2938","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Areas We Serve\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto leading-relaxed\">\n              We represent clients throughout Southern California and the Ninth Circuit. Our practice includes the following federal courts:\n            </p>\n          </div>\n\n          <div className=\"grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto\">\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Central District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Central District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• Los Angeles County</li>\n                <li>• Orange County</li>\n                <li>• Riverside County</li>\n                <li>• San Bernardino County</li>\n                <li>• San Luis Obispo County</li>\n                <li>• Santa Barbara County</li>\n                <li>• Ventura County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded\">\n              <h3 className=\"mb-4 text-lg\">U.S. District Court, Southern District of California</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed mb-4\">\n                The Southern District includes the following counties:\n              </p>\n              <ul className=\"text-sm text-muted-foreground space-y-1\">\n                <li>• San Diego County</li>\n                <li>• Imperial County</li>\n              </ul>\n            </div>\n\n            <div className=\"border border-border p-8 rounded md:col-span-2\">\n              <h3 className=\"mb-4 text-lg\">U.S. Court of Appeals, Ninth Circuit</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We handle appeals throughout the Ninth Circuit Court of Appeals, which covers federal appeals from California, Oregon, Washington, Arizona, Nevada, Idaho, Montana, Alaska, and Hawaii.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/contact.tsx","sectionKey":"jurisdictions","sourceFile":"src/app/pages/contact.tsx","componentName":"JurisdictionsSection"},{"id":"2c990c1118cc7fb4","name":"Header","pageId":"a5036340ba4de876","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Frequently Asked Questions\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            We understand that facing federal criminal charges is stressful and confusing. Below are answers to some common questions we receive from clients and their families.\n          </p>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/faq.tsx","sectionKey":"header","sourceFile":"src/app/pages/faq.tsx","componentName":"HeaderSection"},{"id":"ed65386a6d2ee357","name":"FAQ Content","pageId":"a5036340ba4de876","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8\">\n          <Accordion type=\"single\" collapsible className=\"space-y-4\">\n            {faqs.map((faq, index) => (\n              <AccordionItem \n                key={index} \n                value={`item-${index}`}\n                className=\"bg-white border border-border rounded px-6\"\n              >\n                <AccordionTrigger className=\"text-left hover:no-underline py-6\">\n                  <span className=\"pr-4\">{faq.question}</span>\n                </AccordionTrigger>\n                <AccordionContent className=\"text-muted-foreground leading-relaxed pb-6\">\n                  {faq.answer}\n                </AccordionContent>\n              </AccordionItem>\n            ))}\n          </Accordion>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/faq.tsx","sectionKey":"faq-content","sourceFile":"src/app/pages/faq.tsx","componentName":"FAQContentSection"},{"id":"94a9092ff104c344","name":"CTA","pageId":"a5036340ba4de876","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Have More Questions?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Every case is unique. Contact us for a confidential consultation to discuss your specific situation.\n          </p>\n          <a \n            href=\"/contact\" \n            className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n          >\n            Contact Us Today\n          </a>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/faq.tsx","sectionKey":"cta","sourceFile":"src/app/pages/faq.tsx","componentName":"CTASection"},{"id":"a9f2e1b52fb262fa","name":"Hero","pageId":"5aafb0c755ce76ec","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section\n        className=\"relative isolate overflow-hidden\"\n        style={{\n          backgroundImage: `linear-gradient(rgba(66,104,135,0.82), rgba(66,104,135,0.82)), url(${heroImage})`,\n          backgroundPosition: \"center\",\n          backgroundSize: \"cover\",\n        }}\n      >\n        <div className=\"absolute inset-0 bg-[linear-gradient(90deg,rgba(66,104,135,0.14)_0%,rgba(66,104,135,0.08)_45%,rgba(66,104,135,0.02)_100%)]\" />\n        <div className=\"relative max-w-7xl mx-auto px-6 lg:px-8 py-28 lg:py-40\">\n          <div className=\"max-w-3xl\">\n            <div className=\"inline-flex items-center rounded-full border border-white/20 bg-white/10 px-4 py-2 text-xs uppercase tracking-[0.28em] text-white/80 backdrop-blur-sm\">\n              Criminal Defense in Downtown Los Angeles\n            </div>\n            <div className=\"mt-8 rounded-lg border border-white/12 bg-black/16 p-8 shadow-2xl backdrop-blur-[2px] lg:p-12\">\n              <p className=\"mb-4 text-sm uppercase tracking-[0.24em] text-white/70\">\n                Strategic defense from pre-indictment investigations through appeal\n              </p>\n              <h1 className=\"text-4xl leading-tight text-white lg:text-6xl\">\n                Federal Criminal Defense in Southern California\n              </h1>\n              <p className=\"mt-6 max-w-2xl text-lg leading-relaxed text-white/82 lg:text-xl\">\n                Windsor Kimball APC is a boutique criminal defense firm serving clients in federal district court, California state court, and throughout the Ninth Circuit with direct attorney access and strategic representation from pre-indictment investigation through appeal.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/home.tsx","sectionKey":"hero","sourceFile":"src/app/pages/home.tsx","componentName":"HeroSection"},{"id":"65d687b2d0d4ddb7","name":"Credentials","pageId":"5aafb0c755ce76ec","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Experience You Can Trust\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              With more than 50 years of combined experience in federal criminal defense, we bring deep knowledge of federal investigations, trial practice, sentencing, and appeals to every case.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-3 gap-8\">\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>50+</div>\n              <h3 className=\"text-lg mb-2\">Years Combined Experience</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                More than five decades focused on the niche area of federal criminal defense in California federal courts and the Ninth Circuit.\n              </p>\n            </div>\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>1:1</div>\n              <h3 className=\"text-lg mb-2\">Direct Attorney Attention</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We do not farm out work to associates. Clients work directly with us, receive personalized attention, and can reach us when urgent issues arise.\n              </p>\n            </div>\n            <div className=\"bg-white p-8 rounded\">\n              <div className=\"text-4xl mb-4 text-primary\" style={{ fontFamily: ''var(--font-serif)'' }}>360°</div>\n              <h3 className=\"text-lg mb-2\">Full-Scope Representation</h3>\n              <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                We handle matters from pre-indictment investigation through trial, sentencing, and appeal, with strategy built for every stage of the case.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/home.tsx","sectionKey":"credentials","sourceFile":"src/app/pages/home.tsx","componentName":"CredentialsSection"},{"id":"69c138aef5a67859","name":"Practice Areas Overview","pageId":"5aafb0c755ce76ec","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"text-center mb-12\">\n            <h2 className=\"text-3xl mb-4 text-foreground\">\n              Areas of Practice\n            </h2>\n            <p className=\"text-muted-foreground max-w-2xl mx-auto\">\n              We handle a wide range of federal criminal matters with precision and dedication.\n            </p>\n          </div>\n          <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n            {practiceAreas.map((area) => (\n              <div key={area.title} className=\"border border-border p-6 rounded hover:border-primary/30 transition-colors\">\n                <h3 className=\"text-lg mb-3\">{area.title}</h3>\n                <p className=\"text-sm text-muted-foreground leading-relaxed\">\n                  {area.description}\n                </p>\n              </div>\n            ))}\n          </div>\n          <div className=\"text-center mt-12\">\n            <Link \n              to=\"/practice-areas\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              View All Practice Areas\n            </Link>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/home.tsx","sectionKey":"practice-areas-overview","sourceFile":"src/app/pages/home.tsx","componentName":"PracticeAreasOverviewSection"},{"id":"41a0628f635681d8","name":"Notable Results","pageId":"5aafb0c755ce76ec","repoId":"6214c13d4994a673","