eStatus":"parsed","displayOrder":4,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-4xl mx-auto px-6 lg:px-8 text-center\">\n          <h2 className=\"text-3xl mb-6 text-foreground\">\n            Facing Criminal Charges?\n          </h2>\n          <p className=\"text-lg text-muted-foreground leading-relaxed mb-8\">\n            Time is critical in federal or California state criminal matters. We keep our caseload selective, evaluate cases creatively, and work flexibly with a client''s budget so they can receive strong representation.\n          </p>\n          <div className=\"flex flex-col sm:flex-row gap-4 justify-center\">\n            <Link \n              to=\"/contact\" \n              className=\"inline-block px-8 py-3 bg-primary text-primary-foreground rounded transition-all hover:bg-accent\"\n            >\n              Contact Us Today\n            </Link>\n            <Link \n              to=\"/faq\" \n              className=\"inline-block px-8 py-3 border border-primary text-primary rounded transition-all hover:bg-primary hover:text-primary-foreground\"\n            >\n              Frequently Asked Questions\n            </Link>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":4,"importPath":"src/app/pages/home.tsx","sectionKey":"cta","sourceFile":"src/app/pages/home.tsx","componentName":"CTASection"},{"id":"c8e7e38bae14c924","name":"Not Found","pageId":"e7b0d18e32388a09","repoId":"6214c13d4994a673","metadata":{"confidence":0.55,"parseStatus":"parsed","displayOrder":0,"inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/not-found.tsx","sectionKey":"not-found","sourceFile":"src/app/pages/not-found.tsx","componentName":"NotFoundPage"},{"id":"5a6d679f5a667cb8","name":"Header","pageId":"159beb30efd4673f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section className=\"bg-white py-16 border-b border-border\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h1 className=\"text-4xl lg:text-5xl mb-6 text-foreground\">\n            Practice Areas\n          </h1>\n          <p className=\"text-lg text-muted-foreground leading-relaxed max-w-3xl\">\n            Windsor Kimball APC represents clients in all stages of federal criminal matters, from pre-indictment investigations through trial and appeal. Our experience spans a wide range of federal offenses.\n          </p>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/practice-areas.tsx","sectionKey":"header","sourceFile":"src/app/pages/practice-areas.tsx","componentName":"HeaderSection"},{"id":"9b1e38e60ac48248","name":"Practice Areas","pageId":"159beb30efd4673f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"space-y-12\">\n            {practiceAreas.map((area, index) => (\n              <div key={index} className=\"bg-white p-8 lg:p-12 rounded\">\n                <h2 className=\"text-2xl mb-4 text-foreground\">\n                  {area.title}\n                </h2>\n                <p className=\"text-muted-foreground leading-relaxed mb-6\">\n                  {area.description}\n                </p>\n                {area.details && (\n                  <div className=\"space-y-4\">\n                    <h3 className=\"text-sm uppercase tracking-wider text-muted-foreground\">\n                      Common Charges We Handle:\n                    </h3>\n                    <ul className=\"grid grid-cols-1 md:grid-cols-2 gap-3\">\n                      {area.details.map((detail, idx) => (\n                        <li key={idx} className=\"flex items-start\">\n                          <span className=\"text-primary mr-2\">•</span>\n                          <span className=\"text-sm text-muted-foreground\">{detail}</span>\n                        </li>\n                      ))}\n                    </ul>\n                  </div>\n                )}\n              </div>\n            ))}\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/practice-areas.tsx","sectionKey":"practice-areas","sourceFile":"src/app/pages/practice-areas.tsx","componentName":"PracticeAreasSection"},{"id":"f0418e8f5f6488f1","name":"Federal Court Info","pageId":"159beb30efd4673f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto\">\n            <h2 className=\"text-3xl mb-8 text-foreground text-center\">\n              Understanding Federal Criminal Defense\n            </h2>\n            <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n              <p>\n                Federal criminal cases are fundamentally different from state prosecutions. They are typically more complex, involve more sophisticated investigation techniques, and carry harsher penalties. The federal criminal justice system has its own set of rules, procedures, and sentencing guidelines.\n              </p>\n              <p>\n                Federal prosecutors are well-resourced and highly skilled. By the time charges are filed, the government has often been investigating for months or years. This is why having experienced federal defense counsel is critical—not just after charges are filed, but ideally during the investigation phase when strategic intervention can sometimes prevent charges altogether.\n              </p>\n              <p>\n                We practice primarily in the U.S. District Courts for the Central District of California (which includes Los Angeles, Orange County, Riverside, San Bernardino, San Luis Obispo, Santa Barbara, and Ventura Counties) and the Southern District of California (which includes San Diego and Imperial Counties). We also handle appeals in the Ninth Circuit Court of Appeals.\n              </p>\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/practice-areas.tsx","sectionKey":"federal-court-info","sourceFile":"src/app/pages/practice-areas.tsx","componentName":"FederalCourtInfoSection"},{"id":"e81e788cd1e2e8af","name":"Pre Indictment","pageId":"159beb30efd4673f","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":3,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <div className=\"max-w-3xl mx-auto text-center\">\n            <h2 className=\"text-3xl mb-6 text-foreground\">\n              Pre-Indictment Representation\n            </h2>\n            <p className=\"text-muted-foreground leading-relaxed mb-8\">\n              If you are under federal investigation but have not yet been charged, early legal intervention is crucial. We can work with prosecutors and agents during the investigation phase, potentially avoiding charges or significantly reducing their severity.\n            </p>\n            <p className=\"text-muted-foreground leading-relaxed\">\n              Common signs you may be under federal investigation include contact from federal agents, subpoenas for documents or testimony, or notification that you are a \"target\" or \"subject\" of an investigation.\n            </p>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":3,"importPath":"src/app/pages/practice-areas.tsx","sectionKey":"pre-indictment","sourceFile":"src/app/pages/practice-areas.tsx","componentName":"PreIndictmentSection"},{"id":"5f3e45978216c9ac","name":"Representative Results","pageId":"3aa7c9b56e48fbe3","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":0,"inlineSourceCode":"<section className=\"border-b border-border bg-white py-16\">\n        <div className=\"mx-auto max-w-7xl px-6 lg:px-8\">\n          <h1 className=\"mb-6 text-4xl text-foreground lg:text-5xl\">\n            Representative Results\n          </h1>\n          <p className=\"max-w-3xl text-lg leading-relaxed text-muted-foreground\">\n            While past results do not guarantee future outcomes, we are proud of\n            our track record of success in federal criminal defense. Below are\n            select examples of results we have achieved for our clients.\n          </p>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":0,"importPath":"src/app/pages/successes.tsx","sectionKey":"representative-results","sourceFile":"src/app/pages/successes.tsx","componentName":"RepresentativeResultsSection"},{"id":"633e00858f97e70a","name":"Appellate And Post Conviction Victories","pageId":"3aa7c9b56e48fbe3","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":1,"inlineSourceCode":"<section className=\"bg-secondary py-20\">\n        <div className=\"mx-auto max-w-7xl px-6 lg:px-8\">\n          <div>\n            <h2 className=\"mb-8 text-3xl text-foreground\">\n              Appellate and Post-Conviction Victories\n            </h2>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2\">\n              {appellateResults.map((result) => (\n                <div key={result.title} className=\"rounded bg-white p-8\">\n                  <div className=\"mb-4\">\n                    <span className=\"inline-block rounded bg-primary/10 px-3 py-1 text-xs uppercase tracking-wider text-primary\">\n                      {result.charge}\n                    </span>\n                  </div>\n                  <h3 className=\"mb-3 text-xl text-foreground\">{result.title}</h3>\n                  <div className=\"space-y-4\">\n                    <p className=\"text-sm leading-relaxed text-muted-foreground\">\n                      {result.description}\n                    </p>\n                    {result.citations && result.citations.length > 0 ? (\n                      <div className=\"border-t border-border pt-4 text-sm leading-relaxed text-muted-foreground\">\n                        {result.citations.map((citation) => (\n                          <p key={citation}>{citation}</p>\n                        ))}\n                      </div>\n                    ) : null}\n                  </div>\n                </div>\n              ))}\n            </div>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":1,"importPath":"src/app/pages/successes.tsx","sectionKey":"appellate-and-post-conviction-victories","sourceFile":"src/app/pages/successes.tsx","componentName":"AppellateAndPostConvictionVictoriesSection"},{"id":"9465cabf3163ae40","name":"Section 3","pageId":"3aa7c9b56e48fbe3","repoId":"6214c13d4994a673","metadata":{"confidence":0.88,"parseStatus":"parsed","displayOrder":2,"inlineSourceCode":"<section className=\"bg-white py-16\">\n        <div className=\"mx-auto max-w-4xl px-6 lg:px-8\">\n          <div className=\"border-l-4 border-primary/30 pl-6\">\n            <p className=\"text-sm italic leading-relaxed text-muted-foreground\">\n              The results described above were achieved in specific cases and do\n              not guarantee or predict a similar result in any future case.\n              Every case is unique and must be evaluated on its own facts and\n              circumstances. Client results depend on a variety of factors\n              including the facts of the case, applicable law, venue, and the\n              skill and preparation of all parties involved.\n            </p>\n          </div>\n        </div>\n      </section>","inferredFromPageFile":true},"sortOrder":2,"importPath":"src/app/pages/successes.tsx","sectionKey":"section-3","sourceFile":"src/app/pages/successes.tsx","componentName":"Section3Section"}]}', 1780194676221);
