INSERT OR REPLACE INTO app_blobs (key, value_json, updated_at) VALUES ('repos/78a43a7ac135d5d7/snapshots/latest.json', '{"name":"misinc-2026","files":[{"path":"src/app/components/sections/AuthorityOrbitSection.tsx","content":"import { motion } from \"motion/react\";\nimport type { ReactNode } from \"react\";\nimport \"@/styles/authority-orbit-section.css\";\n\nexport type AuthorityOrbitSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  orbitValue?: string;\n  orbitLabel?: ReactNode;\n  backgroundStyle?: string;\n};\n\nexport function AuthorityOrbitSection({\n  sectionId = \"authority-orbit\",\n  eyebrow = \"Founded in 1995\",\n  title = (\n    <>\n      30 Years of Innovation.\n      <br />\n      Built for What&apos;s Next.\n    </>\n  ),\n  description = \"Since 1995, we’ve helped businesses navigate every major shift in web technology — from the early web to mobile-first design to AI-powered optimization.\",\n  orbitValue = \"30\",\n  orbitLabel = \"Years of innovation\",\n  backgroundStyle = \"radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%), linear-gradient(180deg, #451b17 0%, #261614 100%)\",\n}: AuthorityOrbitSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"aos-section\"\n      style={{ background: backgroundStyle }}\n    >\n      <div className=\"aos-shell\">\n        <motion.div\n          className=\"aos-copy\"\n          initial={{ opacity: 0, y: 28 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          {eyebrow ? <p className=\"aos-eyebrow\">{eyebrow}</p> : null}\n          <h2>{title}</h2>\n          {description ? <p className=\"aos-description\">{description}</p> : null}\n        </motion.div>\n\n        <motion.div\n          className=\"aos-orbit\"\n          initial={{ opacity: 0, scale: 0.92 }}\n          whileInView={{ opacity: 1, scale: 1 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.65 }}\n        >\n          <span className=\"aos-orbit__ripple aos-orbit__ripple--1\" aria-hidden=\"true\" />\n          <span className=\"aos-orbit__ripple aos-orbit__ripple--2\" aria-hidden=\"true\" />\n          <span className=\"aos-orbit__ripple aos-orbit__ripple--3\" aria-hidden=\"true\" />\n          <div className=\"aos-orbit__core\">\n            <span>{orbitValue}</span>\n            <p>{orbitLabel}</p>\n          </div>\n        </motion.div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/AuthoritySection.tsx","content":"import { motion } from \"motion/react\";\nimport type { ReactNode } from \"react\";\nimport { Bot, BriefcaseBusiness, CalendarRange, Sparkles, type LucideIcon } from \"lucide-react\";\nimport \"@/styles/authority-section-variants.css\";\n\nexport type AuthorityMilestone = {\n  value: string;\n  label: string;\n  detail: string;\n  icon: LucideIcon;\n  accent: string;\n};\n\nexport type AuthoritySectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  orbitValue?: string;\n  orbitLabel?: string;\n  backgroundStyle?: string;\n  milestones?: AuthorityMilestone[];\n};\n\nconst defaultMilestones: AuthorityMilestone[] = [\n  {\n    value: \"1995\",\n    label: \"Founded\",\n    detail: \"Built in Albuquerque at the first big wave of the web.\",\n    icon: CalendarRange,\n    accent: \"#A62025\",\n  },\n  {\n    value: \"30+\",\n    label: \"Years Experience\",\n    detail: \"Three decades across strategy, design, systems, and delivery.\",\n    icon: Sparkles,\n    accent: \"#FF9902\",\n  },\n  {\n    value: \"500+\",\n    label: \"Projects Delivered\",\n    detail: \"Launches, rebuilds, migrations, apps, and growth-focused iterations.\",\n    icon: BriefcaseBusiness,\n    accent: \"#C9923D\",\n  },\n  {\n    value: \"2025\",\n    label: \"AI Development\",\n    detail: \"A new chapter in automation, AI search, and internal tooling.\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n  },\n];\n\nexport function AuthoritySection({\n  sectionId = \"authority\",\n  eyebrow = \"FOUNDED IN 1995\",\n  title = (\n    <>\n      30 Years of Innovation.\n      <br />\n      Built for What&apos;s Next.\n    </>\n  ),\n  description = \"Since 1995, we’ve helped businesses navigate every major shift in web technology — from the early web to mobile-first design to AI-powered optimization.\",\n  orbitValue = \"30\",\n  orbitLabel = \"Years of innovation\",\n  backgroundStyle = \"radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%), linear-gradient(180deg, #451b17 0%, #261614 100%)\",\n  milestones = defaultMilestones,\n}: AuthoritySectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"authority-variant authority-variant--midnight content-stretch flex flex-col items-center relative shrink-0 w-full\"\n      style={{ background: backgroundStyle }}\n    >\n      <div className=\"content-stretch flex flex-col relative shrink-0 w-full max-w-[1200px]\">\n        <motion.div\n          className=\"authority-variant-header content-stretch flex flex-col items-center relative shrink-0 w-full text-center\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <p className=\"authority-lab-eyebrow\">{eyebrow}</p>\n          <h2 className=\"w-full max-w-[800px]\">{title}</h2>\n          <p className=\"max-w-[700px]\">{description}</p>\n        </motion.div>\n\n        <div className=\"midnight-shell\">\n          <motion.div\n            className=\"midnight-orbit\"\n            initial={{ opacity: 0, scale: 0.92 }}\n            whileInView={{ opacity: 1, scale: 1 }}\n            viewport={{ once: true, margin: \"-100px\" }}\n            transition={{ duration: 0.65 }}\n          >\n            <span className=\"midnight-orbit__ripple midnight-orbit__ripple--1\" aria-hidden=\"true\" />\n            <span className=\"midnight-orbit__ripple midnight-orbit__ripple--2\" aria-hidden=\"true\" />\n            <span className=\"midnight-orbit__ripple midnight-orbit__ripple--3\" aria-hidden=\"true\" />\n            <div className=\"midnight-orbit__core\">\n              <span>{orbitValue}</span>\n              <p>{orbitLabel}</p>\n            </div>\n          </motion.div>\n\n          <div className=\"midnight-grid\">\n            {milestones.map((milestone, index) => {\n              const Icon = milestone.icon;\n\n              return (\n                <motion.article\n                  key={`${milestone.label}-${index}`}\n                  className=\"midnight-card\"\n                  style={{ [\"--accent\" as string]: milestone.accent }}\n                  initial={{ opacity: 0, y: 28 }}\n                  whileInView={{ opacity: 1, y: 0 }}\n                  whileHover={{\n                    y: -10,\n                    scale: 1.022,\n                    boxShadow: \"0 34px 72px rgba(0, 0, 0, 0.32)\",\n                    transition: { type: \"spring\", stiffness: 300, damping: 20 },\n                  }}\n                  viewport={{ once: true, margin: \"-100px\" }}\n                  transition={{ duration: 0.5, delay: index * 0.08 }}\n                >\n                  <div className=\"midnight-card__header\">\n                    <span className=\"authority-mini-label\">Milestone</span>\n                    <Icon size={18} />\n                  </div>\n                  <p className=\"midnight-card__value\">{milestone.value}</p>\n                  <p className=\"midnight-card__label\">{milestone.label}</p>\n                  <p className=\"midnight-card__detail\">{milestone.detail}</p>\n                </motion.article>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/BlogLatestGridSection.tsx","content":"import { ArrowRight, CalendarDays } from \"lucide-react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport \"@/styles/blog-section-variants.css\";\n\nexport type BlogLatestGridItem = {\n  title: string;\n  excerpt: string;\n  href: string;\n  image: string;\n  category: string;\n  published: string;\n};\n\nexport type BlogLatestGridSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title: ReactNode;\n  description: ReactNode;\n  posts: BlogLatestGridItem[];\n  viewAllHref?: string;\n  viewAllLabel?: string;\n  backgroundColor?: string;\n};\n\nfunction ArticleMeta({ post }: { post: BlogLatestGridItem }) {\n  return (\n    <div className=\"bsv-meta-row\">\n      <span className=\"bsv-chip\">{post.category}</span>\n      <span className=\"bsv-meta-item\">\n        <CalendarDays />\n        {post.published}\n      </span>\n    </div>\n  );\n}\n\nexport function BlogLatestGridSection({\n  sectionId,\n  eyebrow,\n  title,\n  description,\n  posts,\n  viewAllHref,\n  viewAllLabel = \"View All Blog Posts\",\n  backgroundColor,\n}: BlogLatestGridSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"bsv-section bsv-section--latest-grid\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <header className=\"bsv-header\">\n        {eyebrow ? <p className=\"bsv-eyebrow\">{eyebrow}</p> : null}\n        <h2>{title}</h2>\n        <p>{description}</p>\n      </header>\n      <div className=\"bsv-grid\">\n        {posts.map((post) => (\n          <article key={post.title} className=\"bsv-card bsv-card--article\">\n            <div className=\"bsv-media\">\n              <img src={post.image} alt={post.title} loading=\"lazy\" />\n            </div>\n            <div className=\"bsv-card-body\">\n              <ArticleMeta post={post} />\n              <h3>{post.title}</h3>\n              <p>{post.excerpt}</p>\n              <Link to={post.href} className=\"bsv-link\">\n                Read article\n                <ArrowRight />\n              </Link>\n            </div>\n          </article>\n        ))}\n      </div>\n      {viewAllHref ? (\n        <div className=\"bsv-section-footer\">\n          <Link to={viewAllHref} className=\"bsv-link\">\n            {viewAllLabel}\n            <ArrowRight />\n          </Link>\n        </div>\n      ) : null}\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/CapabilitiesBridgeSection.tsx","content":"import { ArrowRight, Bot, Globe, Layers3, type LucideIcon } from \"lucide-react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport \"@/styles/capabilities-bridge-section.css\";\n\nexport type CapabilityBridgeItem = {\n  title: string;\n  description: string;\n  href: string;\n  icon: LucideIcon;\n  accent: string;\n  eyebrow: string;\n  ctaLabel?: string;\n};\n\nexport type CapabilitiesBridgeSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  capabilities?: CapabilityBridgeItem[];\n  defaultCtaLabel?: string;\n  backgroundColor?: string;\n};\n\nconst defaultCapabilities: CapabilityBridgeItem[] = [\n  {\n    title: \"Web Design & Development\",\n    description:\n      \"Conversion-focused websites with strong messaging, scalable architecture, and polished implementation.\",\n    href: \"/services/web-design\",\n    icon: Globe,\n    accent: \"#A62025\",\n    eyebrow: \"Digital Foundation\",\n  },\n  {\n    title: \"Custom Applications\",\n    description:\n      \"Purpose-built tools, workflows, and integrations that reduce friction and support real operations.\",\n    href: \"/services/custom-applications\",\n    icon: Layers3,\n    accent: \"#FF9902\",\n    eyebrow: \"Operational Systems\",\n  },\n  {\n    title: \"AI Solutions\",\n    description:\n      \"Practical AI strategy, automation, and implementation that create leverage without adding noise.\",\n    href: \"/services/ai-consulting\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n    eyebrow: \"Efficiency Multiplier\",\n  },\n];\n\nexport function CapabilitiesBridgeSection({\n  sectionId = \"capabilities-bridge\",\n  eyebrow = \"Capabilities Bridge\",\n  title = \"Core capabilities that power every solution path.\",\n  description = \"These three capability areas work together to support strategy, design, engineering, and measurable operational improvement.\",\n  capabilities = defaultCapabilities,\n  defaultCtaLabel = \"Explore capability\",\n  backgroundColor,\n}: CapabilitiesBridgeSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"cbs-section\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <div className=\"cbs-shell\">\n        <header className=\"cbs-header\">\n          <p className=\"cbs-eyebrow\">{eyebrow}</p>\n          <h2>{title}</h2>\n          <p>{description}</p>\n        </header>\n\n        <div className=\"cbs-editorial-grid\">\n          {capabilities.map((capability, index) => {\n            const Icon = capability.icon;\n\n            return (\n              <Link\n                key={capability.title}\n                to={capability.href}\n                className={`cbs-editorial-card cbs-editorial-card--${index + 1}`}\n                style={{ [\"--accent\" as string]: capability.accent }}\n              >\n                <span className=\"cbs-chip\">{capability.eyebrow}</span>\n                <div className=\"cbs-icon-wrap\">\n                  <Icon />\n                </div>\n                <h3>{capability.title}</h3>\n                <p>{capability.description}</p>\n                <div className=\"cbs-inline-link\">\n                  {capability.ctaLabel ?? defaultCtaLabel}\n                  <ArrowRight size={16} />\n                </div>\n              </Link>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/CaseStudiesSection.tsx","content":"import { motion } from \"motion/react\";\nimport { Link } from \"react-router\";\nimport { ImageWithFallback } from \"@/app/components/figma/ImageWithFallback\";\n\nexport type CaseStudyCard = {\n  image: string;\n  industry: string;\n  title: string;\n  outcome: string;\n  to?: string;\n};\n\nexport type CaseStudiesSectionProps = {\n  sectionId?: string;\n  title?: string;\n  caseStudies?: CaseStudyCard[];\n  backgroundColor?: string;\n};\n\nconst defaultCaseStudies: CaseStudyCard[] = [\n  {\n    image:\n      \"https://images.unsplash.com/photo-1460925895917-afdab827c52f?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxidXNpbmVzcyUyMGRhc2hib2FyZCUyMGFuYWx5dGljc3xlbnwxfHx8fDE3NjkyNzk2NDB8MA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\",\n    industry: \"Healthcare\",\n    title: \"Regional Medical Practice\",\n    outcome: \"300% increase in online appointment bookings within 6 months\",\n  },\n  {\n    image:\n      \"https://images.unsplash.com/photo-1553877522-43269d4ea984?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxub25wcm9maXQlMjBjb21tdW5pdHklMjBzZXJ2aWNlfGVufDF8fHx8MTc2OTI3OTY0MXww&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\",\n    industry: \"Nonprofit\",\n    title: \"Community Foundation\",\n    outcome: \"Streamlined donation process increased contributions by 85%\",\n  },\n  {\n    image:\n      \"https://images.unsplash.com/photo-1556761175-b413da4baf72?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxwcm9mZXNzaW9uYWwlMjBzZXJ2aWNlcyUyMG9mZmljZXxlbnwxfHx8fDE3NjkyNzk2NDF8MA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\",\n    industry: \"Professional Services\",\n    title: \"Legal Association\",\n    outcome: \"Custom member portal reduced admin time by 60%\",\n  },\n];\n\nexport function CaseStudiesSection({\n  sectionId = \"case-studies\",\n  title = \"Recent Client Success Stories\",\n  caseStudies = defaultCaseStudies,\n  backgroundColor = \"#fafafa\",\n}: CaseStudiesSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"content-stretch flex flex-col items-center py-[80px] md:py-[120px] relative shrink-0 w-full\"\n      style={{ backgroundColor }}\n    >\n      <div className=\"content-stretch flex flex-col gap-[48px] md:gap-[64px] items-start relative shrink-0 w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n        <motion.div\n          className=\"content-stretch flex flex-col gap-[16px] items-start relative shrink-0 w-full\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <h2 className=\"font-[''Manrope:Light'',sans-serif] font-light leading-[1.2] text-[#151515] text-[32px] md:text-[40px] lg:text-[48px] w-full\">\n            {title}\n          </h2>\n        </motion.div>\n\n        <div className=\"grid grid-cols-1 md:grid-cols-3 gap-[24px] md:gap-[32px] w-full\">\n          {caseStudies.map((study, index) => {\n            const card = (\n              <>\n                <div className=\"h-[240px] overflow-hidden relative bg-gray-100\">\n                  <ImageWithFallback\n                    src={study.image}\n                    alt={study.title}\n                    className=\"absolute inset-0 w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\"\n                  />\n                </div>\n                <div className=\"p-[24px] md:p-[32px] flex flex-col gap-[12px]\">\n                  <div className=\"flex items-center gap-[8px]\">\n                    <div className=\"content-stretch flex items-center px-[10px] py-[4px] relative rounded-[500px] shrink-0 bg-[#FFAA1D]/10\">\n                      <p className=\"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-[#9B3139] text-[11px] tracking-[0.5px] uppercase\">\n                        {study.industry}\n                      </p>\n                    </div>\n                  </div>\n                  <h3 className=\"font-[''Manrope:Medium'',sans-serif] font-medium text-[#151515] text-[20px] md:text-[22px] leading-[1.3]\">\n                    {study.title}\n                  </h3>\n                  <p className=\"font-[''Manrope:Light'',sans-serif] font-light text-[#777] text-[15px] leading-[1.6]\">\n                    {study.outcome}\n                  </p>\n                </div>\n              </>\n            );\n\n            return (\n              <motion.div\n                key={study.title}\n                initial={{ opacity: 0, y: 40 }}\n                whileInView={{ opacity: 1, y: 0 }}\n                viewport={{ once: true, margin: \"-100px\" }}\n                transition={{ duration: 0.5, delay: index * 0.1 }}\n                whileHover={{ y: -8, boxShadow: \"0 20px 40px rgba(0,0,0,0.08)\" }}\n              >\n                {study.to ? (\n                  <Link to={study.to} className=\"bg-white flex flex-col overflow-hidden rounded-[28px] group cursor-pointer\">\n                    {card}\n                  </Link>\n                ) : (\n                  <div className=\"bg-white flex flex-col overflow-hidden rounded-[28px] group cursor-pointer\">{card}</div>\n                )}\n              </motion.div>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/FinalCTASection.tsx","content":"import { motion } from \"motion/react\";\nimport { Link } from \"react-router\";\nimport type { ReactNode } from \"react\";\n\nexport type FinalCTASectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  actionLabel?: string;\n  actionTo?: string;\n  actionScrollToId?: string;\n  footnote?: ReactNode;\n  backgroundColor?: string;\n};\n\nexport function FinalCTASection({\n  sectionId = \"contact\",\n  eyebrow = \"Free Strategy Call\",\n  title = \"Ready to Talk Through Your Next Project?\",\n  description = \"Get practical guidance on web design, custom development, and AI strategy tailored to your business, goals, and stage of growth.\",\n  actionLabel = \"Book a Free Strategy Call\",\n  actionTo,\n  actionScrollToId = \"contact\",\n  footnote = \"No pressure. Clear recommendations.\",\n  backgroundColor = \"#fafafa\",\n}: FinalCTASectionProps) {\n  const handleAction = () => {\n    const element = document.getElementById(actionScrollToId);\n    if (element) {\n      element.scrollIntoView({ behavior: \"smooth\" });\n    }\n  };\n\n  const actionContent = (\n    <p className=\"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-white text-[15px] md:text-[16px] tracking-[1px]\">\n      {actionLabel}\n    </p>\n  );\n\n  return (\n    <section\n      id={sectionId}\n      className=\"content-stretch flex flex-col items-center py-[100px] md:py-[140px] relative shrink-0 w-full\"\n      style={{ backgroundColor }}\n    >\n      <div className=\"content-stretch flex flex-col gap-[40px] md:gap-[48px] items-center relative shrink-0 w-full max-w-[900px] px-5 md:px-8 lg:px-12 text-center\">\n        <motion.div\n          className=\"content-stretch flex flex-col gap-[20px] items-center\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <p className=\"font-[''Manrope:Medium'',sans-serif] font-medium uppercase tracking-[1.5px] text-[12px] md:text-[13px] text-[#9B3139]\">\n            {eyebrow}\n          </p>\n          <h2 className=\"font-[''Manrope:Light'',sans-serif] font-light leading-[1.1] text-[#151515] text-[36px] md:text-[48px] lg:text-[56px] w-full\">\n            {title}\n          </h2>\n          <p className=\"font-[''Manrope:Light'',sans-serif] font-light text-[#777] text-[16px] md:text-[18px] lg:text-[20px] leading-[1.6] max-w-[700px]\">\n            {description}\n          </p>\n        </motion.div>\n\n        {actionTo ? (\n          <motion.div\n            initial={{ opacity: 0, y: 20 }}\n            whileInView={{ opacity: 1, y: 0 }}\n            viewport={{ once: true }}\n            transition={{ duration: 0.6, delay: 0.2 }}\n            whileHover={{ scale: 1.05 }}\n            whileTap={{ scale: 0.95 }}\n          >\n            <Link\n              to={actionTo}\n              className=\"bg-[#9B3139] content-stretch flex items-center justify-center px-[36px] py-[18px] md:px-[42px] md:py-[20px] relative rounded-[500px] shrink-0\"\n            >\n              {actionContent}\n            </Link>\n          </motion.div>\n        ) : (\n          <motion.button\n            type=\"button\"\n            className=\"bg-[#9B3139] content-stretch flex items-center justify-center px-[36px] py-[18px] md:px-[42px] md:py-[20px] relative rounded-[500px] shrink-0\"\n            initial={{ opacity: 0, y: 20 }}\n            whileInView={{ opacity: 1, y: 0 }}\n            viewport={{ once: true }}\n            transition={{ duration: 0.6, delay: 0.2 }}\n            whileHover={{ scale: 1.05, backgroundColor: \"#7A2730\" }}\n            whileTap={{ scale: 0.95 }}\n            onClick={handleAction}\n          >\n            {actionContent}\n          </motion.button>\n        )}\n\n        <motion.p\n          className=\"max-w-[560px] text-[14px] md:text-[15px] leading-[1.7] text-[#777]\"\n          initial={{ opacity: 0, y: 18 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true }}\n          transition={{ duration: 0.6, delay: 0.28 }}\n        >\n          {footnote}\n        </motion.p>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/GuidesEditorialSection.tsx","content":"import { ArrowRight } from \"lucide-react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport \"@/styles/guides-section-variants.css\";\n\nexport type GuidesEditorialItem = {\n  title: string;\n  description: string;\n  href: string;\n  eyebrow: string;\n  accent: string;\n};\n\nexport type GuidesEditorialSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title: ReactNode;\n  description: ReactNode;\n  guides: GuidesEditorialItem[];\n  backgroundColor?: string;\n};\n\nexport function GuidesEditorialSection({\n  sectionId,\n  eyebrow,\n  title,\n  description,\n  guides,\n  backgroundColor,\n}: GuidesEditorialSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"gsv-section gsv-section--grid\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <header className=\"gsv-header\">\n        {eyebrow ? <p className=\"gsv-eyebrow\">{eyebrow}</p> : null}\n        <h2>{title}</h2>\n        <p>{description}</p>\n      </header>\n      <div className=\"gsv-grid\">\n        {guides.map((guide) => (\n          <article key={guide.title} className=\"gsv-card gsv-card--editorial\">\n            <div className=\"gsv-card-top\">\n              <span className=\"gsv-chip\" style={{ color: guide.accent }}>\n                {guide.eyebrow}\n              </span>\n            </div>\n            <h3>{guide.title}</h3>\n            <p>{guide.description}</p>\n            <Link to={guide.href} className=\"gsv-link\">\n              Open guide\n              <ArrowRight />\n            </Link>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/HeroSection.tsx","content":"import { motion } from \"motion/react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport heroBackgroundVideo from \"@/assets/MIS 30th anniversary Video April 09, 2026 - 12_17PM.mp4\";\nimport { cn } from \"@/app/components/ui/utils\";\n\nconst fadeInUp = {\n  hidden: { opacity: 0, y: 60 },\n  visible: {\n    opacity: 1,\n    y: 0,\n    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },\n  },\n};\n\nconst staggerContainer = {\n  hidden: { opacity: 0 },\n  visible: {\n    opacity: 1,\n    transition: {\n      staggerChildren: 0.12,\n      delayChildren: 0.1,\n    },\n  },\n};\n\nexport type HeroSectionAction = {\n  label: string;\n  to?: string;\n  scrollToId?: string;\n  variant?: \"primary\" | \"secondary\";\n};\n\nexport type HeroSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  backgroundVideoSrc?: string;\n  primaryAction?: HeroSectionAction;\n  secondaryAction?: HeroSectionAction;\n  supplemental?: ReactNode;\n  className?: string;\n};\n\nconst defaultPrimaryAction: HeroSectionAction = {\n  label: \"Book a Free Strategy Call\",\n  scrollToId: \"contact\",\n  variant: \"primary\",\n};\n\nconst defaultSecondaryAction: HeroSectionAction = {\n  label: \"View Case Studies\",\n  scrollToId: \"case-studies\",\n  variant: \"secondary\",\n};\n\nfunction HeroAction({\n  action,\n  onScroll,\n}: {\n  action: HeroSectionAction;\n  onScroll: (id: string) => void;\n}) {\n  const variant = action.variant ?? \"primary\";\n  const className =\n    variant === \"primary\"\n      ? \"bg-[#9B3139] content-stretch flex items-center justify-center px-[28px] py-[16px] relative rounded-[500px] shrink-0 z-[1]\"\n      : \"content-stretch flex items-center justify-center px-[28px] py-[16px] relative rounded-[500px] shrink-0 transition-all hover:bg-black/5\";\n  const textClassName =\n    variant === \"primary\"\n      ? \"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-[15px] text-white tracking-[1px]\"\n      : \"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-[#151515] text-[15px] tracking-[1px]\";\n  const content = (\n    <>\n      {variant === \"secondary\" ? (\n        <div\n          aria-hidden=\"true\"\n          className=\"absolute border border-[rgba(21,21,21,0.6)] border-solid inset-0 pointer-events-none rounded-[500px]\"\n        />\n      ) : null}\n      <span className={textClassName}>{action.label}</span>\n    </>\n  );\n\n  if (action.to) {\n    return (\n      <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>\n        <Link to={action.to} className={className}>\n          {content}\n        </Link>\n      </motion.div>\n    );\n  }\n\n  return (\n    <motion.button\n      type=\"button\"\n      onClick={() => {\n        if (action.scrollToId) {\n          onScroll(action.scrollToId);\n        }\n      }}\n      className={className}\n      whileHover={variant === \"primary\" ? { scale: 1.05, backgroundColor: \"#7A2730\" } : { scale: 1.05 }}\n      whileTap={{ scale: 0.95 }}\n    >\n      {content}\n    </motion.button>\n  );\n}\n\nexport function HeroSection({\n  sectionId = \"hero\",\n  eyebrow,\n  title = (\n    <>\n      Strategic Web Design & <br />\n      AI Solutions That Drive Business Growth\n    </>\n  ),\n  description = \"We design websites, build custom tools, and use AI to help you attract more customers and grow your business.\",\n  backgroundVideoSrc = heroBackgroundVideo,\n  primaryAction = defaultPrimaryAction,\n  secondaryAction = defaultSecondaryAction,\n  supplemental,\n  className,\n}: HeroSectionProps) {\n  const scrollToSection = (id: string) => {\n    const element = document.getElementById(id);\n    if (element) {\n      element.scrollIntoView({ behavior: \"smooth\" });\n    }\n  };\n\n  return (\n    <section\n      id={sectionId}\n      className={cn(\n        \"content-stretch flex flex-col items-center pb-[80px] md:pb-[120px] pt-[64px] md:pt-[100px] relative shrink-0 w-full overflow-hidden\",\n        className,\n      )}\n      data-name=\"Section Hero\"\n    >\n      <div className=\"hero-video-layer\" aria-hidden=\"true\">\n        <video autoPlay muted loop playsInline preload=\"metadata\">\n          <source src={backgroundVideoSrc} type=\"video/mp4\" />\n        </video>\n      </div>\n      <div className=\"hero-video-scrim\" aria-hidden=\"true\" />\n\n      <div\n        className=\"absolute inset-0 opacity-[0.03] pointer-events-none z-[2]\"\n        style={{\n          backgroundImage:\n            \"linear-gradient(#9B3139 1px, transparent 1px), linear-gradient(90deg, #9B3139 1px, transparent 1px)\",\n          backgroundSize: \"60px 60px\",\n        }}\n      />\n\n      <div className=\"content-stretch flex items-start relative shrink-0 w-full max-w-[1200px] px-5 md:px-8 lg:px-12 z-10\" data-name=\"Container\">\n        <motion.div\n          className=\"content-stretch flex flex-[1_0_0] flex-col gap-[32px] md:gap-[40px] isolate items-start min-h-px min-w-0 relative w-full\"\n          initial=\"hidden\"\n          animate=\"visible\"\n          variants={staggerContainer}\n        >\n          <motion.div\n            className=\"content-stretch flex flex-col font-[''Manrope:Light'',sans-serif] font-light gap-[20px] items-start relative shrink-0 text-[#2A2420] w-full z-[2]\"\n            variants={fadeInUp}\n          >\n            {eyebrow ? (\n              <motion.p\n                className=\"text-[12px] font-normal uppercase tracking-[1px] text-[#9B3139]\"\n                initial={{ opacity: 0, y: 24 }}\n                animate={{ opacity: 1, y: 0 }}\n                transition={{ duration: 0.6, delay: 0.12, ease: [0.22, 1, 0.36, 1] }}\n              >\n                {eyebrow}\n              </motion.p>\n            ) : null}\n            <motion.h1\n              className=\"leading-[1.1] relative shrink-0 text-[32px] sm:text-[48px] md:text-[56px] lg:text-[72px] w-full max-w-[900px]\"\n              initial={{ opacity: 0, y: 40 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.8, delay: 0.2, ease: [0.22, 1, 0.36, 1] }}\n            >\n              {title}\n            </motion.h1>\n            <motion.p\n              className=\"leading-[1.6] relative shrink-0 text-[16px] sm:text-[18px] md:text-[20px] max-w-[700px] text-[#4A3F37]\"\n              initial={{ opacity: 0, y: 30 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.8, delay: 0.4, ease: [0.22, 1, 0.36, 1] }}\n            >\n              {description}\n            </motion.p>\n          </motion.div>\n          <motion.div\n            className=\"flex flex-col sm:flex-row gap-[16px] items-start\"\n            initial={{ opacity: 0, y: 20 }}\n            animate={{ opacity: 1, y: 0 }}\n            transition={{ duration: 0.6, delay: 0.6 }}\n          >\n            <HeroAction action={primaryAction} onScroll={scrollToSection} />\n            <HeroAction action={secondaryAction} onScroll={scrollToSection} />\n          </motion.div>\n          {supplemental ? (\n            <motion.div\n              className=\"w-full\"\n              initial={{ opacity: 0, y: 20 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.6, delay: 0.72 }}\n            >\n              {supplemental}\n            </motion.div>\n          ) : null}\n        </motion.div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/index.ts","content":"export { AuthoritySection } from \"./AuthoritySection\";\nexport type { AuthorityMilestone, AuthoritySectionProps } from \"./AuthoritySection\";\nexport { AuthorityOrbitSection } from \"./AuthorityOrbitSection\";\nexport type { AuthorityOrbitSectionProps } from \"./AuthorityOrbitSection\";\nexport { BlogLatestGridSection } from \"./BlogLatestGridSection\";\nexport type {\n  BlogLatestGridItem,\n  BlogLatestGridSectionProps,\n} from \"./BlogLatestGridSection\";\nexport { CapabilitiesBridgeSection } from \"./CapabilitiesBridgeSection\";\nexport type { CapabilitiesBridgeSectionProps, CapabilityBridgeItem } from \"./CapabilitiesBridgeSection\";\nexport { CaseStudiesSection } from \"./CaseStudiesSection\";\nexport type { CaseStudyCard, CaseStudiesSectionProps } from \"./CaseStudiesSection\";\nexport { FinalCTASection } from \"./FinalCTASection\";\nexport type { FinalCTASectionProps } from \"./FinalCTASection\";\nexport { GuidesEditorialSection } from \"./GuidesEditorialSection\";\nexport type {\n  GuidesEditorialItem,\n  GuidesEditorialSectionProps,\n} from \"./GuidesEditorialSection\";\nexport { HeroSection } from \"./HeroSection\";\nexport { OurApproachSection } from \"./OurApproachSection\";\nexport type { ApproachMetricItem, ApproachStepItem, OurApproachSectionProps } from \"./OurApproachSection\";\nexport { ResourcesFaqCollectionsSection } from \"./ResourcesFaqCollectionsSection\";\nexport type {\n  ResourcesFaqCollectionItem,\n  ResourcesFaqCollectionsSectionProps,\n} from \"./ResourcesFaqCollectionsSection\";\nexport { SolutionsSection } from \"./SolutionsSection\";\nexport type { SolutionIndustryItem, SolutionsSectionProps } from \"./SolutionsSection\";\nexport { StrategicServicesSection } from \"./StrategicServicesSection\";\nexport type { StrategicServiceItem, StrategicServicesSectionProps } from \"./StrategicServicesSection\";\n"},{"path":"src/app/components/sections/OurApproachSection.tsx","content":"import type { ReactNode } from \"react\";\nimport { BarChart3, Compass, DraftingCompass, Wrench, type LucideIcon } from \"lucide-react\";\nimport \"@/styles/our-approach-section.css\";\n\nexport type ApproachStepItem = {\n  title: string;\n  description: string;\n  icon: LucideIcon;\n  accent: string;\n};\n\nexport type ApproachMetricItem = {\n  value: string;\n  label: string;\n};\n\nexport type OurApproachSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  featureEyebrow?: ReactNode;\n  featureTitle?: ReactNode;\n  featureDescription?: ReactNode;\n  metrics?: ApproachMetricItem[];\n  steps?: ApproachStepItem[];\n  backgroundColor?: string;\n};\n\nconst defaultMetrics: ApproachMetricItem[] = [\n  { value: \"4\", label: \"Clear phases\" },\n  { value: \"1\", label: \"Continuous system\" },\n];\n\nconst defaultSteps: ApproachStepItem[] = [\n  {\n    title: \"Discover\",\n    description:\n      \"We align business goals, audience needs, and constraints before design or development begins.\",\n    icon: Compass,\n    accent: \"#A62025\",\n  },\n  {\n    title: \"Design\",\n    description:\n      \"We shape clear user journeys, messaging hierarchy, and interface systems built for trust and conversion.\",\n    icon: DraftingCompass,\n    accent: \"#C9923D\",\n  },\n  {\n    title: \"Build\",\n    description:\n      \"We implement with performance, maintainability, CMS governance, and real operational use in mind.\",\n    icon: Wrench,\n    accent: \"#FF9902\",\n  },\n  {\n    title: \"Optimize\",\n    description:\n      \"We improve continuously through analytics, testing, search visibility, and iterative UX refinement.\",\n    icon: BarChart3,\n    accent: \"#6B4A1E\",\n  },\n];\n\nexport function OurApproachSection({\n  sectionId = \"our-approach\",\n  eyebrow = \"Our Approach\",\n  title = \"A process designed to create momentum, not just deliverables.\",\n  description = \"Good outcomes come from disciplined sequencing. Each phase sharpens the next, so strategy, execution, and optimization work as one continuous system.\",\n  featureEyebrow = \"Flagship message\",\n  featureTitle = \"Good outcomes come from disciplined sequencing.\",\n  featureDescription = \"Instead of treating every phase as equal visual weight, this version emphasizes the overall promise and lets the steps cascade beside it.\",\n  metrics = defaultMetrics,\n  steps = defaultSteps,\n  backgroundColor,\n}: OurApproachSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"oas-section\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <div className=\"oas-shell\">\n        <header className=\"oas-header\">\n          <p className=\"oas-eyebrow\">{eyebrow}</p>\n          <h2>{title}</h2>\n          <p>{description}</p>\n        </header>\n\n        <div className=\"oas-editorial-shell\">\n          <article className=\"oas-editorial-feature\">\n            <p className=\"oas-mini-label\">{featureEyebrow}</p>\n            <h3>{featureTitle}</h3>\n            <p>{featureDescription}</p>\n            <div className=\"oas-feature-metrics\">\n              {metrics.map((metric) => (\n                <div key={`${metric.value}-${metric.label}`}>\n                  <span>{metric.value}</span>\n                  <p>{metric.label}</p>\n                </div>\n              ))}\n            </div>\n          </article>\n\n          <div className=\"oas-editorial-ladder\">\n            {steps.map((step, index) => {\n              const Icon = step.icon;\n\n              return (\n                <article\n                  key={step.title}\n                  className={`oas-ladder-card oas-ladder-card--${index + 1}`}\n                  style={{ [\"--accent\" as string]: step.accent }}\n                >\n                  <div className=\"oas-ladder-card__title\">\n                    <Icon />\n                    <h3>{step.title}</h3>\n                  </div>\n                  <p>{step.description}</p>\n                  <div className=\"oas-ladder-card__rail\" />\n                </article>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/ResourcesFaqCollectionsSection.tsx","content":"import { ArrowRight } from \"lucide-react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport \"@/styles/resources-faq-variants.css\";\n\nexport type ResourcesFaqCollectionItem = {\n  title: string;\n  href: string;\n  preview: string[];\n  eyebrow: string;\n  accent: string;\n};\n\nexport type ResourcesFaqCollectionsSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title: ReactNode;\n  description: ReactNode;\n  collections: ResourcesFaqCollectionItem[];\n  backgroundColor?: string;\n};\n\nexport function ResourcesFaqCollectionsSection({\n  sectionId,\n  eyebrow,\n  title,\n  description,\n  collections,\n  backgroundColor,\n}: ResourcesFaqCollectionsSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"rfv-section rfv-section--grid\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <header className=\"rfv-header\">\n        {eyebrow ? <p className=\"rfv-eyebrow\">{eyebrow}</p> : null}\n        <h2>{title}</h2>\n        <p>{description}</p>\n      </header>\n      <div className=\"rfv-grid\">\n        {collections.map((collection) => (\n          <article key={collection.title} className=\"rfv-card rfv-card--editorial\">\n            <span className=\"rfv-chip\" style={{ color: collection.accent }}>\n              {collection.eyebrow}\n            </span>\n            <h3>{collection.title}</h3>\n            <ul>\n              {collection.preview.map((item) => (\n                <li key={item}>{item}</li>\n              ))}\n            </ul>\n            <Link to={collection.href} className=\"rfv-link\">\n              View full FAQ\n              <ArrowRight />\n            </Link>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/SolutionsSection.tsx","content":"import { motion } from \"motion/react\";\nimport { Link } from \"react-router\";\nimport type { ReactNode } from \"react\";\nimport { defaultSolutionIndustries, type SolutionIndustryItem } from \"@/app/data/solutionIndustries\";\nimport \"@/styles/solutions-section-variants.css\";\nexport type { SolutionIndustryItem } from \"@/app/data/solutionIndustries\";\n\nexport type SolutionsSectionProps = {\n  sectionId?: string;\n  title?: ReactNode;\n  leadTitle?: ReactNode;\n  leadDescription?: ReactNode;\n  industries?: SolutionIndustryItem[];\n  backgroundColor?: string;\n};\n\nexport function SolutionsSection({\n  sectionId = \"solutions\",\n  title = \"Solutions Tailored to Your Industry\",\n  leadTitle = \"Solutions designed around how each industry actually operates.\",\n  leadDescription = \"Instead of presenting every audience at the same weight, this version creates a stronger entry point and a more editorial scan path.\",\n  industries = defaultSolutionIndustries,\n  backgroundColor,\n}: SolutionsSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"solv-section content-stretch flex flex-col items-center relative shrink-0 w-full\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <div className=\"content-stretch flex flex-col gap-[48px] md:gap-[64px] items-start relative shrink-0 w-full max-w-[1200px]\">\n        <motion.div\n          className=\"content-stretch flex flex-col gap-[16px] items-start relative shrink-0 w-full\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <h2 className=\"font-[''Manrope:Light'',sans-serif] font-light leading-[1.2] text-[#151515] text-[32px] md:text-[40px] lg:text-[48px] w-full\">\n            {title}\n          </h2>\n        </motion.div>\n\n        <div className=\"solv-mosaic-grid w-full\">\n          <motion.article\n            className=\"solv-mosaic-lead\"\n            initial={{ opacity: 0, y: 36 }}\n            whileInView={{ opacity: 1, y: 0 }}\n            viewport={{ once: true, margin: \"-100px\" }}\n            transition={{ duration: 0.6 }}\n          >\n            <h3>{leadTitle}</h3>\n            <p>{leadDescription}</p>\n            <div className=\"solv-mini-stack\">\n              {industries.map((industry) => {\n                const Icon = industry.icon;\n\n                return (\n                  <Link key={`solutions-pill-${industry.title}`} to={industry.to ?? \"#\"} className=\"solv-mini-pill\">\n                    <Icon />\n                    <span>{industry.title}</span>\n                  </Link>\n                );\n              })}\n            </div>\n          </motion.article>\n\n          <div className=\"solv-mosaic-cards\">\n            {industries.map((industry, index) => {\n              const Icon = industry.icon;\n\n              return (\n                <motion.div\n                  key={industry.title}\n                  initial={{ opacity: 0, y: 40 }}\n                  whileInView={{ opacity: 1, y: 0 }}\n                  viewport={{ once: true, margin: \"-100px\" }}\n                  transition={{ duration: 0.5, delay: index * 0.08 }}\n                >\n                  <Link\n                    to={industry.to ?? \"#\"}\n                    className={`solv-card solv-mosaic-card solv-mosaic-card--${index + 1}`}\n                    style={{ [\"--accent\" as string]: industry.accent }}\n                  >\n                    <div className=\"solv-mosaic-card__title\">\n                      <Icon />\n                      <h3>{industry.title}</h3>\n                    </div>\n                    <p>{industry.description}</p>\n                  </Link>\n                </motion.div>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/components/sections/StrategicServicesSection.tsx","content":"import { useEffect, useRef, useState } from \"react\";\nimport { motion, useScroll, useTransform } from \"motion/react\";\nimport { ArrowRight, Bot, Globe, Layers3, type LucideIcon } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport \"@/styles/services-section-variants.css\";\n\nexport type StrategicServiceItem = {\n  title: string;\n  description: string;\n  eyebrow: string;\n  icon: LucideIcon;\n  accent: string;\n};\n\nexport type StrategicServicesSectionProps = {\n  sectionId?: string;\n  title?: string;\n  description?: string;\n  ctaLabel?: string;\n  ctaTo?: string;\n  ctaScrollToId?: string;\n  services?: StrategicServiceItem[];\n};\n\nconst defaultServices: StrategicServiceItem[] = [\n  {\n    title: \"Websites That Convert\",\n    description:\n      \"Modern, conversion-optimized websites built on Webflow and Square Online that grow with your business and adapt to changing needs.\",\n    eyebrow: \"Growth Foundation\",\n    icon: Globe,\n    accent: \"var(--mis-primary)\",\n  },\n  {\n    title: \"Custom Applications\",\n    description:\n      \"Tailored web applications and integrations designed to solve your specific business challenges and streamline operations.\",\n    eyebrow: \"Operational Systems\",\n    icon: Layers3,\n    accent: \"var(--mis-brand-red)\",\n  },\n  {\n    title: \"AI & AEO Optimization\",\n    description:\n      \"Forward-thinking AI integration and Answer Engine Optimization to ensure your business is found by both search engines and AI assistants.\",\n    eyebrow: \"Visibility Multiplier\",\n    icon: Bot,\n    accent: \"#c9923d\",\n  },\n];\n\nexport function StrategicServicesSection({\n  sectionId = \"services\",\n  title = \"Technology Solutions for Growing Businesses\",\n  description = \"We design, develop, and optimize digital systems that help small businesses grow, simplify operations, and stay visible as the web shifts toward AI-assisted discovery.\",\n  ctaLabel = \"Book a Free Strategy Call\",\n  ctaTo,\n  ctaScrollToId = \"contact\",\n  services = defaultServices,\n}: StrategicServicesSectionProps) {\n  const sectionRef = useRef<HTMLElement | null>(null);\n  const [isDesktop, setIsDesktop] = useState(() => {\n    if (typeof window === \"undefined\") {\n      return true;\n    }\n\n    return window.innerWidth > 980;\n  });\n\n  useEffect(() => {\n    const mediaQuery = window.matchMedia(\"(min-width: 981px)\");\n    const syncDesktopState = () => setIsDesktop(mediaQuery.matches);\n\n    syncDesktopState();\n    mediaQuery.addEventListener(\"change\", syncDesktopState);\n\n    return () => mediaQuery.removeEventListener(\"change\", syncDesktopState);\n  }, []);\n\n  const { scrollYProgress } = useScroll({\n    target: sectionRef,\n    offset: [\"start start\", \"end end\"],\n  });\n\n  const cardTwoY = useTransform(scrollYProgress, [0, 0.26, 0.46, 1], [0, 0, -126, -126]);\n  const cardThreeY = useTransform(scrollYProgress, [0, 0.56, 0.8, 1], [0, 0, -262, -262]);\n\n  const handleCta = () => {\n    const element = document.getElementById(ctaScrollToId);\n    if (element) {\n      element.scrollIntoView({ behavior: \"smooth\" });\n    }\n  };\n\n  return (\n    <section ref={sectionRef} id={sectionId} className=\"ssv-section ssv-section--stacked home-services-section\">\n      <div className=\"ssv-stacked-shell home-services-shell\">\n        <motion.aside\n          className=\"ssv-stacked-aside home-services-aside\"\n          initial={{ opacity: 0, x: -24 }}\n          whileInView={{ opacity: 1, x: 0 }}\n          viewport={{ once: true, margin: \"-80px\" }}\n          transition={{ duration: 0.55 }}\n        >\n          <h2>{title}</h2>\n          <p>{description}</p>\n          {ctaTo ? (\n            <Link to={ctaTo} className=\"home-services-link\">\n              {ctaLabel}\n              <ArrowRight size={18} />\n            </Link>\n          ) : (\n            <button type=\"button\" onClick={handleCta} className=\"home-services-link\">\n              {ctaLabel}\n              <ArrowRight size={18} />\n            </button>\n          )}\n        </motion.aside>\n\n        <div className=\"ssv-stacked-list home-services-list\">\n          {services.map((service, index) => {\n            const Icon = service.icon;\n            const cardStyle =\n              !isDesktop\n                ? undefined\n                : index === 1\n                  ? { y: cardTwoY }\n                  : index === 2\n                    ? { y: cardThreeY }\n                    : undefined;\n\n            return (\n              <motion.article\n                key={service.title}\n                className={`ssv-stacked-card home-services-card home-services-card--${index + 1}`}\n                style={cardStyle}\n                initial={{ opacity: 0 }}\n                whileInView={{ opacity: 1 }}\n                viewport={{ once: true, margin: \"-100px\" }}\n                transition={{ duration: 0.55, delay: index * 0.08 }}\n              >\n                <div className=\"ssv-icon-wrap\" style={{ color: service.accent }}>\n                  <Icon />\n                </div>\n                <div>\n                  <p className=\"ssv-card-eyebrow\">{service.eyebrow}</p>\n                  <h3>{service.title}</h3>\n                  <p>{service.description}</p>\n                </div>\n              </motion.article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n"},{"path":"src/app/pages/AboutPage.tsx","content":"import { useEffect } from \"react\";\nimport { Link } from \"react-router\";\nimport {\n  Bot,\n  Database,\n  LayoutTemplate,\n  MonitorSmartphone,\n  Rocket,\n  Workflow,\n  Wrench,\n  type LucideIcon,\n} from \"lucide-react\";\nimport { Badge } from \"@/app/components/ui/badge\";\nimport { Button } from \"@/app/components/ui/button\";\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardHeader,\n  CardTitle,\n} from \"@/app/components/ui/card\";\nimport { Container, Section } from \"@/app/components/ui/layout\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport webflowLogo from \"@/assets/partner-webflow.svg\";\nimport squareLogo from \"@/assets/partner-square.svg\";\nimport mailchimpLogo from \"@/assets/partner-mailchimp.svg\";\n\ntype Principle = {\n  title: string;\n  description: string;\n};\n\ntype Partnership = {\n  name: string;\n  logo: string;\n  logoAlt: string;\n  summary: string;\n  benefit: string;\n};\n\ntype TechnologyItem = {\n  name: string;\n  description: string;\n  problemSolved: string;\n  note: string;\n  href?: string;\n};\n\ntype StoryMilestone = {\n  year: string;\n  title: string;\n  description: string;\n  icon: LucideIcon;\n};\n\nconst principles: Principle[] = [\n  {\n    title: \"Strategy Before Execution\",\n    description:\n      \"Every engagement starts with business goals, decision criteria, and risk context so delivery aligns with long-term priorities.\",\n  },\n  {\n    title: \"Systems, Not Just Websites\",\n    description:\n      \"We architect connected digital systems that support sales, operations, and customer experience instead of isolated page builds.\",\n  },\n  {\n    title: \"Measurable Outcomes\",\n    description:\n      \"Plans are tied to clear performance signals such as qualified leads, conversion lift, and operational efficiency.\",\n  },\n  {\n    title: \"Long-Term Partnerships\",\n    description:\n      \"Clients stay with us because we adapt through growth phases with consistent support, governance, and optimization.\",\n  },\n];\n\nconst partnerships: Partnership[] = [\n  {\n    name: \"Webflow Certified Partner\",\n    logo: webflowLogo,\n    logoAlt: \"Webflow Certified Partner logo\",\n    summary:\n      \"Certified implementation standards for scalable Webflow architecture, CMS governance, and performance.\",\n    benefit:\n      \"Clients get cleaner builds, faster iteration, and a platform foundation that supports growth.\",\n  },\n  {\n    name: \"Square Partner\",\n    logo: squareLogo,\n    logoAlt: \"Square Partner logo\",\n    summary:\n      \"Integrated website and commerce expertise for businesses operating on Square tools.\",\n    benefit:\n      \"Clients get aligned storefront, operations, and customer experience without fragmented systems.\",\n  },\n  {\n    name: \"Mailchimp Partner\",\n    logo: mailchimpLogo,\n    logoAlt: \"Mailchimp Partner logo\",\n    summary:\n      \"Lifecycle messaging and marketing automation alignment for lead nurture and retention.\",\n    benefit:\n      \"Clients get stronger follow-up systems that support measurable engagement over time.\",\n  },\n];\n\nconst technologies: TechnologyItem[] = [\n  {\n    name: \"Add On IDX\",\n    description:\n      \"A property-search and listing integration framework built to help real estate teams deliver modern digital search experiences.\",\n    problemSolved:\n      \"Solves disconnected listing data, inconsistent user experience, and limited lead capture workflows.\",\n    note:\n      \"Demonstrates deep product and integration capability beyond conventional marketing websites.\",\n  },\n  {\n    name: \"Add On AI Chat\",\n    description:\n      \"A conversational AI layer designed to provide instant guidance, qualification support, and service discovery for visitors.\",\n    problemSolved:\n      \"Solves delayed response times, repetitive inquiry handling, and missed opportunities from high-intent traffic.\",\n    note:\n      \"Shows practical AI implementation focused on business outcomes, not novelty.\",\n  },\n];\n\nconst differentiators = [\n  \"30 years of digital strategy and execution experience\",\n  \"Albuquerque-based team with New Mexico market insight\",\n  \"Proven Webflow Certified Partner and Square expertise\",\n  \"Practical AI consulting firm capabilities tied to outcomes\",\n  \"Long-term support model built for operational continuity\",\n];\n\nconst storyMilestones: StoryMilestone[] = [\n  {\n    year: \"1995\",\n    title: \"Founded & Early Web Phase\",\n    description:\n      \"MIS, Inc. launched in Albuquerque with a focus on practical web delivery for growing organizations. Early work established a reputation for reliability and technical depth.\",\n    icon: Rocket,\n  },\n  {\n    year: \"2000\",\n    title: \"Interactive & Database Era\",\n    description:\n      \"Projects moved beyond static pages into dynamic, data-driven websites. Database integration became a core capability for business workflows and digital operations.\",\n    icon: Database,\n  },\n  {\n    year: \"2005\",\n    title: \"Enterprise CMS\",\n    description:\n      \"The firm expanded into larger content ecosystems and structured publishing models. This period strengthened governance, scalability, and long-term maintainability.\",\n    icon: LayoutTemplate,\n  },\n  {\n    year: \"2010\",\n    title: \"Responsive Web\",\n    description:\n      \"As user behavior shifted, MIS adopted responsive standards across delivery. Mobile-first thinking became central to user experience and conversion performance.\",\n    icon: MonitorSmartphone,\n  },\n  {\n    year: \"2015\",\n    title: \"Webflow Transition\",\n    description:\n      \"The team standardized around modern visual development and cleaner CMS architecture. Webflow became a strategic platform for faster, more governable execution.\",\n    icon: Workflow,\n  },\n  {\n    year: \"2022\",\n    title: \"AI & AEO Focus\",\n    description:\n      \"MIS expanded into AI consulting and answer-engine optimization to match new discovery behavior. Services aligned strategy with both search and AI-driven visibility.\",\n    icon: Bot,\n  },\n  {\n    year: \"2026\",\n    title: \"Product Innovation\",\n    description:\n      \"Internal platforms such as Add On IDX and Add On AI Chat demonstrate product-level capability. Innovation now combines consulting, engineering, and reusable systems.\",\n    icon: Wrench,\n  },\n];\n\nfunction AboutPageMetadata() {\n  useEffect(() => {\n    document.title = \"About MIS, Inc. | 30 Years of Web & AI Innovation in Albuquerque\";\n\n    const description =\n      \"MIS, Inc. is a 30-year web design company in Albuquerque delivering Webflow, AI consulting, and digital strategy for New Mexico and regional businesses.\";\n\n    const upsertMeta = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\\\"${name}\\\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMeta(\"description\", description);\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", \"https://www.misinc.com/about\");\n  }, []);\n\n  return null;\n}\n\nexport default function AboutPage() {\n  const organizationStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"Organization\",\n    name: \"MIS, Inc.\",\n    foundingDate: \"1995\",\n    areaServed: \"New Mexico\",\n    url: \"https://www.misinc.com/about\",\n  };\n\n  const professionalServiceStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"ProfessionalService\",\n    name: \"MIS, Inc.\",\n    areaServed: \"New Mexico\",\n    address: {\n      \"@type\": \"PostalAddress\",\n      addressLocality: \"Albuquerque\",\n      addressRegion: \"NM\",\n      addressCountry: \"US\",\n    },\n    description:\n      \"New Mexico digital agency and AI consulting firm delivering web strategy, Webflow implementation, and systems-focused execution.\",\n    url: \"https://www.misinc.com/about\",\n  };\n\n  return (\n    <SiteShell>\n      <AboutPageMetadata />\n      <script type=\"application/ld+json\">{JSON.stringify(organizationStructuredData)}</script>\n      <script type=\"application/ld+json\">\n        {JSON.stringify(professionalServiceStructuredData)}\n      </script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <Section variant=\"hero\">\n          <Container size=\"standard\">\n            <div className=\"mx-auto flex max-w-4xl flex-col items-center gap-6 text-center\">\n              <Badge variant=\"secondary\" className=\"rounded-full px-3 py-1 text-xs tracking-wide\">\n                Founded in 1995\n              </Badge>\n              <h1 className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\">\n                30 Years of Innovation in Web, AI, and Digital Strategy\n              </h1>\n              <p className=\"text-base leading-loose text-muted-foreground md:text-lg\">\n                MIS, Inc. is a web design company in Albuquerque, New Mexico founded in\n                1995. We evolved from early web and database development into a modern\n                AI consulting firm with strategic depth and technical execution.\n              </p>\n              <div className=\"flex w-full flex-col justify-center gap-3 sm:w-auto sm:flex-row\">\n                <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                  <Link to=\"/#contact\">Schedule a Strategy Call</Link>\n                </Button>\n                <Button\n                  variant=\"outline\"\n                  className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                  asChild\n                >\n                  <Link to=\"/services\">Explore Our Services</Link>\n                </Button>\n              </div>\n              <p className=\"text-sm text-muted-foreground\">\n                Trusted by businesses across New Mexico and beyond.\n              </p>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mx-auto grid max-w-6xl grid-cols-1 gap-10 lg:grid-cols-12 lg:gap-12\">\n              <article className=\"space-y-4 lg:col-span-5 lg:sticky lg:top-24 lg:z-30 lg:self-start lg:bg-muted/30 lg:pb-6\">\n                <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                  Our Story\n                </h2>\n                <p className=\"text-base leading-loose text-muted-foreground\">\n                  MIS, Inc. was founded in 1995 in Albuquerque with a focus on early web\n                  development and database-backed business systems. As technology changed,\n                  we continuously adapted architecture, tooling, and delivery models.\n                </p>\n                <p className=\"text-base leading-loose text-muted-foreground\">\n                  Over three decades, we guided clients through major shifts in digital\n                  platforms, conversion strategy, and operations. Today, our work combines\n                  Webflow implementation, modern development practices, and AI consulting\n                  with outcome-focused strategy.\n                </p>\n                <p className=\"text-base leading-loose text-muted-foreground\">\n                  This combination is why organizations choose us as a New Mexico digital\n                  agency partner for long-term growth, not one-off execution.\n                </p>\n              </article>\n\n              <div className=\"relative lg:col-span-7 lg:pt-2\">\n                <div\n                  aria-hidden=\"true\"\n                  className=\"absolute bottom-0 left-6 top-0 w-px bg-border\"\n                />\n                <ol className=\"space-y-6 pb-24\">\n                  {storyMilestones.map((milestone, index) => {\n                    const Icon = milestone.icon;\n                    const zIndexClass = [\n                      \"z-10\",\n                      \"z-20\",\n                      \"z-30\",\n                      \"z-40\",\n                      \"z-50\",\n                      \"z-50\",\n                      \"z-50\",\n                    ][index];\n                    return (\n                      <li\n                        key={milestone.year}\n                        className={`sticky top-24 ${zIndexClass} ${index === storyMilestones.length - 1 ? \"\" : \"pb-8 md:pb-10\"}`}\n                      >\n                        <div className=\"relative\">\n                          <div className=\"relative pl-16\">\n                            <span className=\"absolute left-6 top-8 z-10 h-3 w-3 -translate-x-1/2 rounded-full bg-primary ring-4 ring-background\" />\n                            <Card className=\"border-border bg-card shadow-md\">\n                              <CardHeader>\n                                <div className=\"flex items-center gap-3\">\n                                  <span className=\"inline-flex size-9 items-center justify-center rounded-full border border-border bg-muted text-primary\">\n                                    <Icon className=\"size-4\" aria-hidden=\"true\" />\n                                  </span>\n                                  <div className=\"space-y-1\">\n                                    <p className=\"text-sm font-medium uppercase tracking-wide text-primary\">\n                                      {milestone.year}\n                                    </p>\n                                    <CardTitle className=\"text-xl leading-snug text-foreground\">\n                                      {milestone.title}\n                                    </CardTitle>\n                                  </div>\n                                </div>\n                              </CardHeader>\n                              <CardContent>\n                                <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                                  {milestone.description}\n                                </CardDescription>\n                              </CardContent>\n                            </Card>\n                          </div>\n                        </div>\n                      </li>\n                    );\n                  })}\n                </ol>\n              </div>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-10 flex flex-col gap-4\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                How We Think\n              </h2>\n              <p className=\"max-w-3xl text-base leading-loose text-muted-foreground\">\n                Our operating model keeps strategy, execution, and accountability tightly\n                connected from planning through optimization.\n              </p>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2\">\n              {principles.map((principle) => (\n                <Card key={principle.title} className=\"h-full border-border bg-card\">\n                  <CardHeader>\n                    <CardTitle className=\"text-xl leading-snug text-foreground md:text-2xl\">\n                      {principle.title}\n                    </CardTitle>\n                  </CardHeader>\n                  <CardContent>\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {principle.description}\n                    </CardDescription>\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mb-10 flex flex-col gap-4\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Trusted Technology Partnerships\n              </h2>\n              <p className=\"max-w-3xl text-base leading-loose text-muted-foreground\">\n                Partner relationships strengthen delivery quality, platform expertise, and\n                long-term reliability for client programs.\n              </p>\n            </div>\n\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-3\">\n              {partnerships.map((partnership) => (\n                <Card key={partnership.name} className=\"h-full border-border bg-card\">\n                  <CardHeader>\n                    <div className=\"flex items-center gap-3\">\n                      <img\n                        src={partnership.logo}\n                        alt={partnership.logoAlt}\n                        className=\"h-10 w-10 rounded-md border border-border\"\n                        loading=\"lazy\"\n                      />\n                      <CardTitle className=\"text-xl leading-snug text-foreground\">\n                        {partnership.name}\n                      </CardTitle>\n                    </div>\n                  </CardHeader>\n                  <CardContent className=\"space-y-4\">\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {partnership.summary}\n                    </CardDescription>\n                    <p className=\"text-sm leading-relaxed text-foreground/80\">\n                      {partnership.benefit}\n                    </p>\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-10 flex flex-col gap-4\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Technology We&apos;ve Developed\n              </h2>\n              <p className=\"max-w-3xl text-base leading-loose text-muted-foreground\">\n                We build proprietary systems when client outcomes require capabilities\n                beyond off-the-shelf solutions.\n              </p>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2\">\n              {technologies.map((technology) => (\n                <Card key={technology.name} className=\"h-full border-border bg-card\">\n                  <CardHeader>\n                    <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                      {technology.name}\n                    </CardTitle>\n                  </CardHeader>\n                  <CardContent className=\"space-y-4\">\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {technology.description}\n                    </CardDescription>\n                    <p className=\"text-sm leading-relaxed text-foreground/80\">\n                      <span className=\"font-medium text-foreground\">Problem solved:</span>{\" \"}\n                      {technology.problemSolved}\n                    </p>\n                    <p className=\"text-sm leading-relaxed text-foreground/80\">{technology.note}</p>\n                    {technology.href ? (\n                      <Link\n                        to={technology.href}\n                        className=\"inline-flex text-sm font-medium text-primary hover:underline\"\n                      >\n                        Learn more\n                      </Link>\n                    ) : null}\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mx-auto max-w-4xl\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                What Sets Us Apart\n              </h2>\n              <ul className=\"mt-6 space-y-3 text-base leading-relaxed text-muted-foreground\">\n                {differentiators.map((item) => (\n                  <li key={item} className=\"flex items-start gap-2\">\n                    <span aria-hidden=\"true\" className=\"mt-2 size-1.5 rounded-full bg-primary\" />\n                    <span>{item}</span>\n                  </li>\n                ))}\n              </ul>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"cta\">\n          <Container size=\"medium\">\n            <Card className=\"border-border bg-card\">\n              <CardHeader className=\"text-center\">\n                <CardTitle className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                  Let&apos;s Build What&apos;s Next\n                </CardTitle>\n                <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                  No-pressure consultation. Clear next steps.\n                </CardDescription>\n              </CardHeader>\n              <CardContent>\n                <div className=\"flex flex-col items-center justify-center gap-3 sm:flex-row\">\n                  <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                    <Link to=\"/#contact\">Schedule a Strategy Call</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to=\"/case-studies\">View Case Studies</Link>\n                  </Button>\n                </div>\n              </CardContent>\n            </Card>\n          </Container>\n        </Section>\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/AuthoritySectionVariantsPage.tsx","content":"import {\n  ArrowLeft,\n  ArrowRight,\n  Bot,\n  BriefcaseBusiness,\n  CalendarRange,\n  Sparkles,\n} from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/authority-section-variants.css\";\n\ntype Milestone = {\n  value: string;\n  label: string;\n  detail: string;\n  icon: typeof CalendarRange;\n  accent: string;\n};\n\nconst milestones: Milestone[] = [\n  {\n    value: \"1995\",\n    label: \"Founded\",\n    detail: \"Built in Albuquerque at the first big wave of the web.\",\n    icon: CalendarRange,\n    accent: \"#A62025\",\n  },\n  {\n    value: \"30+\",\n    label: \"Years Experience\",\n    detail: \"Three decades across strategy, design, systems, and delivery.\",\n    icon: Sparkles,\n    accent: \"#FF9902\",\n  },\n  {\n    value: \"500+\",\n    label: \"Projects Delivered\",\n    detail: \"Launches, rebuilds, migrations, apps, and growth-focused iterations.\",\n    icon: BriefcaseBusiness,\n    accent: \"#C9923D\",\n  },\n  {\n    value: \"2025\",\n    label: \"AI Development\",\n    detail: \"A new chapter in automation, AI search, and internal tooling.\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n  },\n];\n\nfunction LabHeader() {\n  return (\n    <section className=\"authority-lab-hero\">\n      <div className=\"authority-lab-hero__inner\">\n        <Link to=\"/\" className=\"authority-lab-back-link\">\n          <ArrowLeft size={18} />\n          Back to Home\n        </Link>\n        <p className=\"authority-lab-eyebrow\">Authority Section Explorations</p>\n        <h1>Five stronger directions for the 30-year credibility block.</h1>\n        <p className=\"authority-lab-hero-copy\">\n          These options keep the same message and milestones, but move away from four static boxes into layouts\n          with more hierarchy, texture, motion cues, and presence.\n        </p>\n      </div>\n    </section>\n  );\n}\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"authority-variant-header\">\n      <p className=\"authority-lab-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"authority-variant authority-variant--timeline\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Signal Timeline\"\n        body=\"A connected milestone rail that feels more like a story of accumulated momentum than a generic stat row.\"\n      />\n      <div className=\"timeline-rail\">\n        <div className=\"timeline-rail__line\" />\n        {milestones.map((milestone, index) => {\n          const Icon = milestone.icon;\n\n          return (\n            <article\n              key={milestone.label}\n              className={`timeline-card timeline-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: milestone.accent }}\n            >\n              <span className=\"timeline-card__dot\" />\n              <div className=\"timeline-card__icon\">\n                <Icon size={18} />\n              </div>\n              <p className=\"timeline-card__value\">{milestone.value}</p>\n              <p className=\"timeline-card__label\">{milestone.label}</p>\n              <p className=\"timeline-card__detail\">{milestone.detail}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"authority-variant authority-variant--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Founder-to-Future Split\"\n        body=\"A stronger left-right composition with a narrative panel on one side and more sculpted milestone cards on the other.\"\n      />\n      <div className=\"split-shell\">\n        <aside className=\"split-story\">\n          <p className=\"authority-mini-label\">Why it works</p>\n          <h3>It reads like a brand proof point, not a placeholder module.</h3>\n          <p>\n            The copy gets a dedicated narrative frame, while the milestones gain clearer hierarchy and more deliberate\n            pacing through scale and stagger.\n          </p>\n          <div className=\"split-story__note\">\n            <span>Built for homepage use</span>\n            <ArrowRight size={16} />\n            <span>High confidence and easy to scan</span>\n          </div>\n        </aside>\n        <div className=\"split-grid\">\n          {milestones.map((milestone, index) => {\n            const Icon = milestone.icon;\n\n            return (\n              <article\n                key={milestone.label}\n                className={`split-card split-card--${index + 1}`}\n                style={{ [\"--accent\" as string]: milestone.accent }}\n              >\n                <div className=\"split-card__topline\">\n                  <span className=\"authority-mini-label\">Signal 0{index + 1}</span>\n                  <Icon size={18} />\n                </div>\n                <p className=\"split-card__value\">{milestone.value}</p>\n                <p className=\"split-card__label\">{milestone.label}</p>\n                <p className=\"split-card__detail\">{milestone.detail}</p>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"authority-variant authority-variant--editorial\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Editorial Feature Stack\"\n        body=\"One large flagship proof card and a stacked side column, which gives the section a clear focal point and better visual rhythm.\"\n      />\n      <div className=\"editorial-shell\">\n        <article className=\"editorial-feature\">\n          <p className=\"authority-mini-label\">Flagship proof</p>\n          <div className=\"editorial-feature__headline\">\n            <span>30 Years of Innovation.</span>\n            <span>Built for What&apos;s Next.</span>\n          </div>\n          <p className=\"editorial-feature__copy\">\n            Since 1995, MIS has helped businesses navigate every major shift in web technology, from the early web to\n            mobile-first design to AI-powered optimization.\n          </p>\n          <div className=\"editorial-feature__metrics\">\n            {milestones.slice(0, 2).map((milestone) => (\n              <div key={milestone.label} className=\"editorial-feature__metric\">\n                <span>{milestone.value}</span>\n                <p>{milestone.label}</p>\n              </div>\n            ))}\n          </div>\n        </article>\n        <div className=\"editorial-stack\">\n          {milestones.slice(2).map((milestone, index) => {\n            const Icon = milestone.icon;\n\n            return (\n              <article\n                key={milestone.label}\n                className={`editorial-stack-card editorial-stack-card--${index + 1}`}\n                style={{ [\"--accent\" as string]: milestone.accent }}\n              >\n                <div className=\"editorial-stack-card__eyebrow\">\n                  <Icon size={18} />\n                  <span>{milestone.label}</span>\n                </div>\n                <p className=\"editorial-stack-card__value\">{milestone.value}</p>\n                <p className=\"editorial-stack-card__detail\">{milestone.detail}</p>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"authority-variant authority-variant--runway\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Runway Benchmarks\"\n        body=\"A more kinetic horizontal treatment with an implied path forward, useful if the section should feel more future-facing and less archival.\"\n      />\n      <div className=\"runway-shell\">\n        <div className=\"runway-shell__beam\" />\n        {milestones.map((milestone, index) => (\n          <article\n            key={milestone.label}\n            className={`runway-card runway-card--${index + 1}`}\n            style={{ [\"--accent\" as string]: milestone.accent }}\n          >\n            <span className=\"runway-card__step\">0{index + 1}</span>\n            <p className=\"runway-card__value\">{milestone.value}</p>\n            <p className=\"runway-card__label\">{milestone.label}</p>\n            <p className=\"runway-card__detail\">{milestone.detail}</p>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"authority-variant authority-variant--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Control Room\"\n        body=\"A darker premium option with more contrast and glow, useful if this credibility moment should break the page rhythm and feel more cinematic.\"\n      />\n      <div className=\"midnight-shell\">\n        <div className=\"midnight-orbit\">\n          <span className=\"midnight-orbit__ripple midnight-orbit__ripple--1\" aria-hidden=\"true\" />\n          <span className=\"midnight-orbit__ripple midnight-orbit__ripple--2\" aria-hidden=\"true\" />\n          <span className=\"midnight-orbit__ripple midnight-orbit__ripple--3\" aria-hidden=\"true\" />\n          <div className=\"midnight-orbit__core\">\n            <span>30</span>\n            <p>Years of innovation</p>\n          </div>\n        </div>\n        <div className=\"midnight-grid\">\n          {milestones.map((milestone) => {\n            const Icon = milestone.icon;\n\n            return (\n              <article\n                key={milestone.label}\n                className=\"midnight-card\"\n                style={{ [\"--accent\" as string]: milestone.accent }}\n              >\n                <div className=\"midnight-card__header\">\n                  <span className=\"authority-mini-label\">Milestone</span>\n                  <Icon size={18} />\n                </div>\n                <p className=\"midnight-card__value\">{milestone.value}</p>\n                <p className=\"midnight-card__label\">{milestone.label}</p>\n                <p className=\"midnight-card__detail\">{milestone.detail}</p>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function AuthoritySectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"authority-section-lab\">\n        <LabHeader />\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/BlogSectionVariantsPage.tsx","content":"import {\n  ArrowLeft,\n  ArrowRight,\n  BookMarked,\n  CalendarDays,\n  Newspaper,\n  RadioTower,\n} from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport {\n  BlogLatestGridSection,\n  type BlogLatestGridItem,\n} from \"@/app/components/sections\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport blogImageOne from \"@/assets/24a40fea387d6d870b36715ebf5f41ccc1196a04.png\";\nimport blogImageTwo from \"@/assets/53cf0a9d13b54d45ba6d8faaf8dde556b80e4b8f.png\";\nimport blogImageThree from \"@/assets/7345e90366d343ada99455fe5e0c1de849dd5f34.png\";\nimport blogImageFour from \"@/assets/8ed6481142f4588cada7b6b9a2dbaffa2a6b4855.png\";\nimport \"@/styles/blog-section-variants.css\";\n\nconst posts: BlogLatestGridItem[] = [\n  {\n    title: \"How To Improve Local Search Visibility for Service Businesses\",\n    excerpt:\n      \"A practical framework for increasing qualified local traffic with stronger intent alignment and trust cues.\",\n    href: \"/blog/improve-local-search-visibility\",\n    image: blogImageOne,\n    category: \"Local SEO\",\n    published: \"March 18, 2026\",\n  },\n  {\n    title: \"AEO Basics: Structuring Pages for AI-Powered Answers\",\n    excerpt:\n      \"Learn the page architecture and schema fundamentals that help content surface in answer-first experiences.\",\n    href: \"/blog/aeo-basics-structured-content\",\n    image: blogImageTwo,\n    category: \"AEO\",\n    published: \"March 10, 2026\",\n  },\n  {\n    title: \"When a Website Redesign Is Strategic, Not Cosmetic\",\n    excerpt:\n      \"Signals that your current site is holding back growth and how to scope redesign work around outcomes.\",\n    href: \"/blog/strategic-website-redesign-signals\",\n    image: blogImageThree,\n    category: \"Website Strategy\",\n    published: \"February 25, 2026\",\n  },\n  {\n    title: \"Using AI To Reduce Operational Bottlenecks\",\n    excerpt:\n      \"A measured approach to workflow automation that improves reliability without adding technical complexity.\",\n    href: \"/blog/ai-for-operations-workflows\",\n    image: blogImageFour,\n    category: \"Operations AI\",\n    published: \"February 11, 2026\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"bsv-header\">\n      <p className=\"bsv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction PostLink({ href, label = \"Read article\" }: { href: string; label?: string }) {\n  return (\n    <Link to={href} className=\"bsv-link\">\n      {label}\n      <ArrowRight />\n    </Link>\n  );\n}\n\nfunction ArticleMeta({ post }: { post: BlogLatestGridItem }) {\n  return (\n    <div className=\"bsv-meta-row\">\n      <span className=\"bsv-chip\">{post.category}</span>\n      <span className=\"bsv-meta-item\">\n        <CalendarDays />\n        {post.published}\n      </span>\n    </div>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <BlogLatestGridSection\n      eyebrow=\"Variant 1\"\n      title=\"Latest Articles Grid\"\n      description=\"A cleaner, upgraded version of the current blog section built specifically for recent posts, with clearer article metadata and stronger card rhythm.\"\n      posts={posts}\n    />\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"bsv-section bsv-section--feature-feed\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Featured Post With Recent Feed\"\n        body=\"A stronger editorial pattern that highlights one lead story while still letting recent posts read like an active, current publication feed.\"\n      />\n      <div className=\"bsv-feature-feed\">\n        <article className=\"bsv-card bsv-card--feature-post\">\n          <div className=\"bsv-media bsv-media--feature\">\n            <img src={posts[0].image} alt={posts[0].title} loading=\"lazy\" />\n          </div>\n          <div className=\"bsv-card-body\">\n            <div className=\"bsv-flag\">\n              <Newspaper />\n              Featured post\n            </div>\n            <ArticleMeta post={posts[0]} />\n            <h3>{posts[0].title}</h3>\n            <p>{posts[0].excerpt}</p>\n            <PostLink href={posts[0].href} label=\"Read featured article\" />\n          </div>\n        </article>\n        <div className=\"bsv-recent-feed\">\n          {posts.slice(1).map((post) => (\n            <article key={post.title} className=\"bsv-card bsv-card--feed-item\">\n              <div className=\"bsv-feed-thumb\">\n                <img src={post.image} alt={post.title} loading=\"lazy\" />\n              </div>\n              <div className=\"bsv-feed-copy\">\n                <ArticleMeta post={post} />\n                <h3>{post.title}</h3>\n                <p>{post.excerpt}</p>\n                <PostLink href={post.href} />\n              </div>\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"bsv-section bsv-section--timeline\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Signal Timeline\"\n        body=\"A more creative chronological layout that treats the blog as an ongoing stream of signals, updates, and perspective rather than just a stack of cards.\"\n      />\n      <div className=\"bsv-timeline\">\n        {posts.map((post, index) => (\n          <article\n            key={post.title}\n            className={`bsv-timeline-item ${index % 2 === 0 ? \"is-left\" : \"is-right\"}`}\n          >\n            <div className=\"bsv-timeline-date\">{post.published}</div>\n            <div className=\"bsv-timeline-node\" aria-hidden=\"true\" />\n            <div className=\"bsv-timeline-card\">\n              <div className=\"bsv-list-thumb\">\n                <img src={post.image} alt={post.title} loading=\"lazy\" />\n              </div>\n              <div className=\"bsv-list-copy\">\n                <ArticleMeta post={post} />\n                <h3>{post.title}</h3>\n                <p>{post.excerpt}</p>\n                <PostLink href={post.href} />\n              </div>\n            </div>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"bsv-section bsv-section--board\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Pinned Story Board\"\n        body=\"A more expressive concept that makes the blog feel like an active editorial wall, while still keeping each post visible and directly browseable.\"\n      />\n      <div className=\"bsv-board-intro\">\n        <div className=\"bsv-digest-note\">\n          <div className=\"bsv-flag\">\n            <BookMarked />\n            Story board\n          </div>\n          <h3>A more art-directed way to present recent posts.</h3>\n          <p>\n            This keeps the section grounded in real articles, but gives the content more personality than a standard grid or feed.\n          </p>\n        </div>\n        <div className=\"bsv-topic-row\">\n          {posts.map((post) => (\n            <span key={post.category} className=\"bsv-topic-pill\">\n              {post.category}\n            </span>\n          ))}\n        </div>\n      </div>\n      <div className=\"bsv-board\">\n        {posts.map((post, index) => (\n          <article\n            key={post.title}\n            className={`bsv-board-card bsv-board-card--${index + 1}`}\n          >\n            <div className=\"bsv-media bsv-media--board\">\n              <img src={post.image} alt={post.title} loading=\"lazy\" />\n            </div>\n            <div className=\"bsv-card-body\">\n              <ArticleMeta post={post} />\n              <h3>{post.title}</h3>\n              <p>{post.excerpt}</p>\n              <PostLink href={post.href} />\n            </div>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"bsv-section bsv-section--journal-board\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Journal Board\"\n        body=\"A darker publication-style board that still functions as a blog-post list, but gives the resources page a more distinctive editorial moment.\"\n      />\n      <div className=\"bsv-journal-board\">\n        <aside className=\"bsv-journal-aside\">\n          <div className=\"bsv-flag bsv-flag--light\">\n            <RadioTower />\n            MIS journal\n          </div>\n          <h3>Make timely posts feel more like a living publication.</h3>\n          <p>\n            This direction frames the blog as an active stream of insights while keeping the article cards familiar and easy to browse.\n          </p>\n        </aside>\n        <div className=\"bsv-journal-grid\">\n          {posts.map((post) => (\n            <article key={post.title} className=\"bsv-journal-card\">\n              <div className=\"bsv-journal-thumb\">\n                <img src={post.image} alt={post.title} loading=\"lazy\" />\n              </div>\n              <div className=\"bsv-card-body\">\n                <ArticleMeta post={post} />\n                <h3>{post.title}</h3>\n                <p>{post.excerpt}</p>\n                <PostLink href={post.href} />\n              </div>\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function BlogSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"blog-section-lab\">\n        <section className=\"bsv-hero\">\n          <div className=\"bsv-hero-inner\">\n            <Link to=\"/resources\" className=\"bsv-back-link\">\n              <ArrowLeft />\n              Back to Resources\n            </Link>\n            <p className=\"bsv-eyebrow\">Blog Section Explorations</p>\n            <h1>Five blog-specific directions for the Resources page article section.</h1>\n            <p>\n              These concepts are built around listing and browsing posts, not generic content blocks. They keep the MIS visual language, but mix in a few more exploratory editorial ideas alongside the more practical layouts.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/CapabilitiesBridgeVariantsPage.tsx","content":"import type { ComponentType, SVGProps } from \"react\";\nimport { ArrowLeft, ArrowRight, Bot, Globe, Layers3 } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { CapabilitiesBridgeSection } from \"@/app/components/sections\";\nimport \"@/styles/capabilities-bridge-variants.css\";\n\ntype IconComponent = ComponentType<SVGProps<SVGSVGElement>>;\n\ntype CapabilityCard = {\n  title: string;\n  description: string;\n  href: string;\n  icon: IconComponent;\n  accent: string;\n  eyebrow: string;\n};\n\nconst capabilities: CapabilityCard[] = [\n  {\n    title: \"Web Design & Development\",\n    description:\n      \"Conversion-focused websites with strong messaging, scalable architecture, and polished implementation.\",\n    href: \"/services/web-design\",\n    icon: Globe,\n    accent: \"#A62025\",\n    eyebrow: \"Digital Foundation\",\n  },\n  {\n    title: \"Custom Applications\",\n    description:\n      \"Purpose-built tools, workflows, and integrations that reduce friction and support real operations.\",\n    href: \"/services/custom-applications\",\n    icon: Layers3,\n    accent: \"#FF9902\",\n    eyebrow: \"Operational Systems\",\n  },\n  {\n    title: \"AI Solutions\",\n    description:\n      \"Practical AI strategy, automation, and implementation that create leverage without adding noise.\",\n    href: \"/services/ai-consulting\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n    eyebrow: \"Efficiency Multiplier\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"cbv-header\">\n      <p className=\"cbv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"cbv-section\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Editorial Triptych\"\n        body=\"Three capabilities with more weight, better spacing, and stronger iconography than the current pill-link stack.\"\n      />\n      <CapabilitiesBridgeSection\n        sectionId=\"capabilities-variant-one\"\n        eyebrow=\"Capabilities Bridge\"\n        title=\"Core capabilities that power every solution path.\"\n        description=\"These three capability areas work together to support strategy, design, engineering, and measurable operational improvement.\"\n        capabilities={capabilities}\n        backgroundColor=\"transparent\"\n      />\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"cbv-section cbv-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Narrative Split\"\n        body=\"A stronger story panel on the left and more sculpted capability cards on the right.\"\n      />\n      <div className=\"cbv-split-shell\">\n        <aside className=\"cbv-story\">\n          <p className=\"cbv-mini-label\">Why this works</p>\n          <h3>The section feels strategic instead of purely navigational.</h3>\n          <p>\n            This direction gives the capability links a clearer frame: these are the three core engines behind the\n            solution work, not just more pages to click.\n          </p>\n          <div className=\"cbv-story-note\">\n            <span>3 core capabilities</span>\n            <ArrowRight size={16} />\n            <span>One integrated delivery model</span>\n          </div>\n        </aside>\n        <div className=\"cbv-split-list\">\n          {capabilities.map((capability, index) => {\n            const Icon = capability.icon;\n\n            return (\n              <Link\n                key={capability.title}\n                to={capability.href}\n                className=\"cbv-split-card\"\n                style={{ [\"--accent\" as string]: capability.accent }}\n              >\n                <div className=\"cbv-split-card__top\">\n                  <span className=\"cbv-mini-label\">0{index + 1}</span>\n                  <Icon />\n                </div>\n                <h3>{capability.title}</h3>\n                <p>{capability.description}</p>\n                <strong>{capability.eyebrow}</strong>\n              </Link>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"cbv-section cbv-section--rail\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Bridge Rail\"\n        body=\"A directional layout with a lead panel and a connected rail of capabilities, so the section feels more like a system map.\"\n      />\n      <div className=\"cbv-rail-shell\">\n        <article className=\"cbv-rail-intro\">\n          <p className=\"cbv-mini-label\">Core capability map</p>\n          <h3>Three service lanes that support every solution path.</h3>\n          <p>\n            Web presence, operational systems, and AI leverage work together. This version makes that relationship much\n            clearer than a simple vertical list.\n          </p>\n        </article>\n        <div className=\"cbv-rail-line\" />\n        <div className=\"cbv-rail-list\">\n          {capabilities.map((capability, index) => {\n            const Icon = capability.icon;\n\n            return (\n              <Link\n                key={capability.title}\n                to={capability.href}\n                className=\"cbv-rail-card\"\n                style={{ [\"--accent\" as string]: capability.accent }}\n              >\n                <div className=\"cbv-rail-card__step\">0{index + 1}</div>\n                <div className=\"cbv-icon-wrap\">\n                  <Icon />\n                </div>\n                <h3>{capability.title}</h3>\n                <p>{capability.description}</p>\n              </Link>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"cbv-section cbv-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Mosaic Spotlight\"\n        body=\"A mixed-scale composition with one flagship card and two support cards, giving the section a clearer focal point.\"\n      />\n      <div className=\"cbv-mosaic-grid\">\n        <Link\n          to={capabilities[0].href}\n          className=\"cbv-mosaic-hero\"\n          style={{ [\"--accent\" as string]: capabilities[0].accent }}\n        >\n          <span className=\"cbv-chip\">{capabilities[0].eyebrow}</span>\n          <h3>{capabilities[0].title}</h3>\n          <p>{capabilities[0].description}</p>\n        </Link>\n        {capabilities.slice(1).map((capability) => {\n          const Icon = capability.icon;\n\n          return (\n            <Link\n              key={capability.title}\n              to={capability.href}\n              className=\"cbv-mosaic-card\"\n              style={{ [\"--accent\" as string]: capability.accent }}\n            >\n              <div className=\"cbv-mosaic-card__title\">\n                <Icon />\n                <h3>{capability.title}</h3>\n              </div>\n              <p>{capability.description}</p>\n            </Link>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"cbv-section cbv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Control Board\"\n        body=\"A darker premium direction that makes the bridge section feel more cinematic and more decisive.\"\n      />\n      <div className=\"cbv-midnight-shell\">\n        <aside className=\"cbv-midnight-aside\">\n          <span className=\"cbv-chip cbv-chip--light\">Delivery stack</span>\n          <h3>Three core capabilities. One coordinated growth system.</h3>\n          <p>\n            This direction breaks the page rhythm hard, which makes the bridge feel less like filler and more like a\n            point of strategic confidence.\n          </p>\n        </aside>\n        <div className=\"cbv-midnight-grid\">\n          {capabilities.map((capability) => {\n            const Icon = capability.icon;\n\n            return (\n              <Link\n                key={capability.title}\n                to={capability.href}\n                className=\"cbv-midnight-card\"\n                style={{ [\"--accent\" as string]: capability.accent }}\n              >\n                <div className=\"cbv-midnight-card__top\">\n                  <span className=\"cbv-chip cbv-chip--light\">{capability.eyebrow}</span>\n                  <Icon />\n                </div>\n                <h3>{capability.title}</h3>\n                <p>{capability.description}</p>\n              </Link>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function CapabilitiesBridgeVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"capabilities-bridge-lab\">\n        <section className=\"cbv-hero\">\n          <div className=\"cbv-hero-inner\">\n            <Link to=\"/solutions\" className=\"cbv-back-link\">\n              <ArrowLeft />\n              Back to Solutions\n            </Link>\n            <p className=\"cbv-eyebrow\">Capabilities Bridge Explorations</p>\n            <h1>Five stronger directions for the Solutions page capabilities bridge.</h1>\n            <p>\n              These variations keep the bridge focused on three core capabilities, but push the section far beyond a\n              neutral list of links.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/CaseStudiesPage.tsx","content":"import { useEffect } from \"react\";\nimport {\n  AuthorityOrbitSection,\n  CaseStudiesSection,\n  FinalCTASection,\n  HeroSection,\n} from \"@/app/components/sections\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\n\nfunction CaseStudiesMetadata() {\n  useEffect(() => {\n    document.title = \"Case Studies — Client Results & Success Stories | MIS, Inc.\";\n\n    const description =\n      \"Explore MIS case studies featuring measurable client results, success stories, and strategy outcomes across web, AI, SEO, and custom systems.\";\n\n    const upsertMetaByName = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\"${name}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    const upsertMetaByProperty = (property: string, content: string) => {\n      let meta = document.querySelector(`meta[property=\"${property}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"property\", property);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMetaByName(\"description\", description);\n    upsertMetaByProperty(\"og:title\", document.title);\n    upsertMetaByProperty(\"og:description\", description);\n    upsertMetaByProperty(\"og:type\", \"website\");\n    upsertMetaByProperty(\"og:url\", \"https://www.misinc.com/case-studies\");\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", \"https://www.misinc.com/case-studies\");\n  }, []);\n\n  return null;\n}\n\nexport default function CaseStudiesPage() {\n  const breadcrumbSchema = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"BreadcrumbList\",\n    itemListElement: [\n      {\n        \"@type\": \"ListItem\",\n        position: 1,\n        name: \"Home\",\n        item: \"https://www.misinc.com/\",\n      },\n      {\n        \"@type\": \"ListItem\",\n        position: 2,\n        name: \"Case Studies\",\n        item: \"https://www.misinc.com/case-studies\",\n      },\n    ],\n  };\n\n  return (\n    <SiteShell>\n      <CaseStudiesMetadata />\n      <script type=\"application/ld+json\">{JSON.stringify(breadcrumbSchema)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <HeroSection\n          sectionId=\"case-studies-hero\"\n          eyebrow=\"Client Case Studies\"\n          title={\n            <>\n              Real Results from\n              <br />\n              Strategic Client Partnerships\n            </>\n          }\n          description=\"See how focused strategy, better systems, and disciplined execution have helped clients improve visibility, increase conversion, and build more durable growth.\"\n          primaryAction={{\n            label: \"Schedule a Strategy Call\",\n            to: \"/contact\",\n            variant: \"primary\",\n          }}\n          secondaryAction={{\n            label: \"View Featured Case Studies\",\n            scrollToId: \"case-studies-showcase\",\n            variant: \"secondary\",\n          }}\n        />\n\n        <CaseStudiesSection\n          sectionId=\"case-studies-showcase\"\n          backgroundColor=\"#f6efe3\"\n        />\n\n        <AuthorityOrbitSection sectionId=\"case-studies-authority\" />\n\n        <FinalCTASection\n          sectionId=\"case-studies-cta\"\n          eyebrow=\"Next Step\"\n          title=\"Ready to Create the Next Success Story?\"\n          description=\"If you''re planning a redesign, new system, or AI-enabled growth initiative, we can help map the right path and execution plan.\"\n          actionLabel=\"Schedule a Strategy Call\"\n          actionTo=\"/contact\"\n          footnote=\"No-pressure consult. Clear next steps.\"\n          backgroundColor=\"#eadcc6\"\n        />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/CaseStudyDetailPage.tsx","content":"import { useEffect, useMemo, useState } from \"react\";\nimport { Link, useParams } from \"react-router\";\nimport { ArrowRight } from \"lucide-react\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { Section, Container } from \"@/app/components/ui/layout\";\nimport { Button } from \"@/app/components/ui/button\";\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardFooter,\n  CardHeader,\n  CardTitle,\n} from \"@/app/components/ui/card\";\nimport {\n  fetchCaseStudyBySlug,\n  fetchCaseStudies,\n  type CaseStudyRecord,\n} from \"@/app/lib/contentApi\";\n\nfunction CaseStudyMetadata({\n  title,\n  description,\n  canonicalUrl,\n}: {\n  title: string;\n  description: string;\n  canonicalUrl: string;\n}) {\n  useEffect(() => {\n    document.title = title;\n\n    const upsertMetaByName = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\"${name}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    const upsertMetaByProperty = (property: string, content: string) => {\n      let meta = document.querySelector(`meta[property=\"${property}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"property\", property);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMetaByName(\"description\", description);\n    upsertMetaByProperty(\"og:title\", title);\n    upsertMetaByProperty(\"og:description\", description);\n    upsertMetaByProperty(\"og:type\", \"article\");\n    upsertMetaByProperty(\"og:url\", canonicalUrl);\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", canonicalUrl);\n  }, [canonicalUrl, description, title]);\n\n  return null;\n}\n\nexport default function CaseStudyDetailPage() {\n  const { slug } = useParams();\n  const [caseStudy, setCaseStudy] = useState<CaseStudyRecord | null>(null);\n  const [allCaseStudies, setAllCaseStudies] = useState<CaseStudyRecord[]>([]);\n\n  useEffect(() => {\n    const activeSlug = slug ?? \"\";\n    if (!activeSlug) {\n      return;\n    }\n\n    let isActive = true;\n\n    const loadData = async () => {\n      const [single, list] = await Promise.all([\n        fetchCaseStudyBySlug(activeSlug),\n        fetchCaseStudies(),\n      ]);\n\n      if (!isActive) {\n        return;\n      }\n\n      setCaseStudy(single);\n      setAllCaseStudies(list ?? []);\n    };\n\n    void loadData();\n    return () => {\n      isActive = false;\n    };\n  }, [slug]);\n\n  const relatedCaseStudies = useMemo(() => {\n    if (!caseStudy) {\n      return [];\n    }\n\n    return allCaseStudies\n      .filter((entry) => entry.slug !== caseStudy.slug)\n      .slice(0, 3);\n  }, [allCaseStudies, caseStudy]);\n\n  if (!caseStudy) {\n    return (\n      <SiteShell>\n        <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n          <SiteHeader>\n            <MainNavbar />\n          </SiteHeader>\n        </div>\n        <main className=\"flex-1\">\n          <Section variant=\"hero\">\n            <Container size=\"medium\">\n              <div className=\"text-center\">\n                <h1 className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\">\n                  Case Study Not Found\n                </h1>\n                <p className=\"mt-4 text-base leading-loose text-muted-foreground\">\n                  This case study is unavailable. Explore our full success stories.\n                </p>\n                <div className=\"mt-8 flex flex-col items-center justify-center gap-3 sm:flex-row\">\n                  <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                    <Link to=\"/case-studies\">View Case Studies</Link>\n                  </Button>\n                </div>\n              </div>\n            </Container>\n          </Section>\n        </main>\n        <SiteFooter />\n      </SiteShell>\n    );\n  }\n\n  const canonicalPath = caseStudy.detail && typeof caseStudy.detail === \"object\" && \"canonicalPath\" in caseStudy.detail\n    ? String((caseStudy.detail as { canonicalPath?: string }).canonicalPath ?? `/case-studies/${caseStudy.slug}`)\n    : `/case-studies/${caseStudy.slug}`;\n  const canonicalUrl = `https://www.misinc.com${canonicalPath}`;\n  const description = caseStudy.outcome ?? caseStudy.problem ?? \"Case study results\";\n\n  const breadcrumbSchema = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"BreadcrumbList\",\n    itemListElement: [\n      { \"@type\": \"ListItem\", position: 1, name: \"Home\", item: \"https://www.misinc.com/\" },\n      {\n        \"@type\": \"ListItem\",\n        position: 2,\n        name: \"Case Studies\",\n        item: \"https://www.misinc.com/case-studies\",\n      },\n      { \"@type\": \"ListItem\", position: 3, name: caseStudy.title, item: canonicalUrl },\n    ],\n  };\n\n  return (\n    <SiteShell>\n      <CaseStudyMetadata\n        title={caseStudy.title}\n        description={description}\n        canonicalUrl={canonicalUrl}\n      />\n      <script type=\"application/ld+json\">{JSON.stringify(breadcrumbSchema)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <Section variant=\"hero\">\n          <Container size=\"standard\">\n            <div className=\"grid grid-cols-1 items-center gap-8 lg:grid-cols-2\">\n              <div className=\"space-y-5\">\n                <p className=\"text-xs font-normal uppercase tracking-wide text-primary\">Case Study</p>\n                <h1 className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\">\n                  {caseStudy.title}\n                </h1>\n                <p className=\"text-base leading-loose text-muted-foreground md:text-lg\">\n                  {caseStudy.industry} | {caseStudy.metric}\n                </p>\n                <div className=\"flex flex-col gap-3 sm:flex-row\">\n                  <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                    <Link to=\"/services\">Schedule a Strategy Call</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to=\"/case-studies\">View All Case Studies</Link>\n                  </Button>\n                </div>\n              </div>\n              {caseStudy.imageUrl && (\n                <Card className=\"overflow-hidden border-border bg-card\">\n                  <img\n                    src={caseStudy.imageUrl}\n                    alt={caseStudy.imageAlt ?? caseStudy.title}\n                    className=\"h-full w-full object-cover\"\n                    loading=\"lazy\"\n                  />\n                </Card>\n              )}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"grid grid-cols-1 gap-6 lg:grid-cols-3\">\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-xl leading-snug text-foreground\">Challenge</CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    {caseStudy.problem}\n                  </CardDescription>\n                </CardContent>\n              </Card>\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-xl leading-snug text-foreground\">Strategy</CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    {caseStudy.strategy}\n                  </CardDescription>\n                </CardContent>\n              </Card>\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-xl leading-snug text-foreground\">Outcome</CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    {caseStudy.outcome}\n                  </CardDescription>\n                </CardContent>\n              </Card>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-8 max-w-3xl\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Related Success Stories\n              </h2>\n            </div>\n            <div className=\"grid grid-cols-1 gap-4 md:grid-cols-3\">\n              {relatedCaseStudies.map((related) => (\n                <Card key={related.slug} className=\"border-border bg-card\">\n                  <CardHeader>\n                    <CardTitle className=\"text-xl leading-snug text-foreground\">{related.title}</CardTitle>\n                  </CardHeader>\n                  <CardContent>\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {related.outcome}\n                    </CardDescription>\n                  </CardContent>\n                  <CardFooter>\n                    <Link\n                      to={`/case-studies/${related.slug}`}\n                      className=\"inline-flex items-center gap-2 text-sm font-medium tracking-wide text-primary transition-colors hover:text-primary/80\"\n                    >\n                      View this case study <ArrowRight className=\"size-4\" />\n                    </Link>\n                  </CardFooter>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ContactPage.tsx","content":"import { FormEvent, useEffect, useMemo, useRef, useState } from \"react\";\nimport { Link, useLocation, useNavigate } from \"react-router\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { Section, Container } from \"@/app/components/ui/layout\";\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardFooter,\n  CardHeader,\n  CardTitle,\n} from \"@/app/components/ui/card\";\nimport { Button } from \"@/app/components/ui/button\";\nimport { Input } from \"@/app/components/ui/input\";\nimport { Textarea } from \"@/app/components/ui/textarea\";\nimport { Label } from \"@/app/components/ui/label\";\nimport { Checkbox } from \"@/app/components/ui/checkbox\";\nimport {\n  Select,\n  SelectContent,\n  SelectItem,\n  SelectTrigger,\n  SelectValue,\n} from \"@/app/components/ui/select\";\n\ntype FormType = \"strategy\" | \"proposal\" | \"inquiry\";\n\nconst hashToForm: Record<string, FormType> = {\n  \"#strategy\": \"strategy\",\n  \"#proposal\": \"proposal\",\n  \"#inquiry\": \"inquiry\",\n};\n\ntype StrategyFormState = {\n  fullName: string;\n  email: string;\n  companyName: string;\n  websiteUrl: string;\n  projectType: string;\n  briefDescription: string;\n};\n\ntype ProposalFormState = {\n  fullName: string;\n  email: string;\n  phone: string;\n  companyName: string;\n  websiteUrl: string;\n  projectTypes: string[];\n  serviceInterests: string[];\n  budgetRange: string;\n  timeline: string;\n  projectGoals: string;\n};\n\ntype InquiryFormState = {\n  fullName: string;\n  email: string;\n  subject: string;\n  message: string;\n};\n\nconst strategyProjectOptions = [\n  \"New website\",\n  \"Redesign\",\n  \"Webflow development\",\n  \"AI consulting\",\n  \"SEO / AEO\",\n  \"Not sure yet\",\n];\n\nconst proposalServiceOptions = [\n  \"Web Design & Redesign\",\n  \"Webflow Development\",\n  \"Custom Applications\",\n  \"AI Consulting\",\n  \"SEO / AEO\",\n  \"Ongoing Optimization\",\n];\n\nconst proposalProjectTypeOptions = [\n  \"New build\",\n  \"Redesign\",\n  \"Migration\",\n  \"Optimization\",\n  \"Ongoing support\",\n];\n\nconst proposalBudgetOptions = [\n  \"Under $10,000\",\n  \"$10,000 - $25,000\",\n  \"$25,000 - $50,000\",\n  \"$50,000 - $100,000\",\n  \"$100,000+\",\n  \"Not sure yet\",\n];\n\nconst proposalTimelineOptions = [\n  \"ASAP (within 30 days)\",\n  \"1-2 months\",\n  \"3-4 months\",\n  \"5+ months\",\n  \"Flexible timeline\",\n];\n\nfunction isValidEmail(email: string) {\n  return /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(email);\n}\n\nfunction isValidUrl(url: string) {\n  if (!url.trim()) return true;\n  try {\n    const normalized = url.startsWith(\"http\") ? url : `https://${url}`;\n    new URL(normalized);\n    return true;\n  } catch {\n    return false;\n  }\n}\n\nasync function submitContactPayload(payload: Record<string, unknown>) {\n  const response = await fetch(\"/api/contact\", {\n    method: \"POST\",\n    headers: {\n      \"Content-Type\": \"application/json\",\n    },\n    body: JSON.stringify(payload),\n  });\n\n  if (!response.ok) {\n    throw new Error(\"Unable to submit form\");\n  }\n}\n\nfunction ContactPageMetadata() {\n  useEffect(() => {\n    document.title = \"Contact MIS, Inc. — Strategy Calls, Proposal Requests & Inquiries\";\n\n    const description =\n      \"Contact MIS, Inc. to book a free strategy call, request a custom proposal, or send an inquiry for web design, AI, SEO, and digital growth support.\";\n\n    const upsertMeta = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\\\"${name}\\\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMeta(\"description\", description);\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", \"https://www.misinc.com/contact\");\n  }, []);\n\n  return null;\n}\n\nexport default function ContactPage() {\n  const navigate = useNavigate();\n  const location = useLocation();\n  const [activeForm, setActiveForm] = useState<FormType | null>(null);\n  const [isSubmitting, setIsSubmitting] = useState(false);\n\n  const [strategyForm, setStrategyForm] = useState<StrategyFormState>({\n    fullName: \"\",\n    email: \"\",\n    companyName: \"\",\n    websiteUrl: \"\",\n    projectType: \"\",\n    briefDescription: \"\",\n  });\n  const [strategyErrors, setStrategyErrors] = useState<Record<string, string>>({});\n  const [strategySuccess, setStrategySuccess] = useState(false);\n\n  const [proposalForm, setProposalForm] = useState<ProposalFormState>({\n    fullName: \"\",\n    email: \"\",\n    phone: \"\",\n    companyName: \"\",\n    websiteUrl: \"\",\n    projectTypes: [],\n    serviceInterests: [],\n    budgetRange: \"\",\n    timeline: \"\",\n    projectGoals: \"\",\n  });\n  const [proposalErrors, setProposalErrors] = useState<Record<string, string>>({});\n  const [proposalSuccess, setProposalSuccess] = useState(false);\n\n  const [inquiryForm, setInquiryForm] = useState<InquiryFormState>({\n    fullName: \"\",\n    email: \"\",\n    subject: \"\",\n    message: \"\",\n  });\n  const [inquiryErrors, setInquiryErrors] = useState<Record<string, string>>({});\n  const [inquirySuccess, setInquirySuccess] = useState(false);\n\n  const [submitError, setSubmitError] = useState(\"\");\n  const revealSectionRef = useRef<HTMLElement | null>(null);\n\n  useEffect(() => {\n    const mapped = hashToForm[location.hash];\n    setActiveForm(mapped ?? null);\n  }, [location.hash]);\n\n  useEffect(() => {\n    if (activeForm && revealSectionRef.current) {\n      revealSectionRef.current.scrollIntoView({ behavior: \"smooth\", block: \"start\" });\n    }\n  }, [activeForm]);\n\n  const contactPageStructuredData = useMemo(\n    () => ({\n      \"@context\": \"https://schema.org\",\n      \"@type\": \"ContactPage\",\n      name: \"Contact MIS, Inc.\",\n      url: \"https://www.misinc.com/contact\",\n      mainEntity: {\n        \"@type\": \"Organization\",\n        name: \"MIS, Inc.\",\n        url: \"https://www.misinc.com\",\n        contactPoint: {\n          \"@type\": \"ContactPoint\",\n          contactType: \"customer support\",\n          email: \"karim@misinc.com\",\n          telephone: \"+1-505-555-1234\",\n        },\n      },\n    }),\n    [],\n  );\n\n  const revealForm = (formType: FormType) => {\n    setActiveForm(formType);\n    navigate({ pathname: \"/contact\", hash: `#${formType}` }, { replace: false });\n    window.setTimeout(() => {\n      revealSectionRef.current?.scrollIntoView({ behavior: \"smooth\", block: \"start\" });\n    }, 0);\n  };\n\n  const validateStrategy = () => {\n    const errors: Record<string, string> = {};\n    if (!strategyForm.fullName.trim()) errors.fullName = \"Full name is required.\";\n    if (!strategyForm.email.trim()) {\n      errors.email = \"Email is required.\";\n    } else if (!isValidEmail(strategyForm.email)) {\n      errors.email = \"Enter a valid email address.\";\n    }\n\n    if (!isValidUrl(strategyForm.websiteUrl)) {\n      errors.websiteUrl = \"Enter a valid website URL.\";\n    }\n\n    setStrategyErrors(errors);\n    return Object.keys(errors).length === 0;\n  };\n\n  const validateProposal = () => {\n    const errors: Record<string, string> = {};\n\n    if (!proposalForm.fullName.trim()) errors.fullName = \"Full name is required.\";\n    if (!proposalForm.email.trim()) {\n      errors.email = \"Email is required.\";\n    } else if (!isValidEmail(proposalForm.email)) {\n      errors.email = \"Enter a valid email address.\";\n    }\n    if (!isValidUrl(proposalForm.websiteUrl)) {\n      errors.websiteUrl = \"Enter a valid website URL.\";\n    }\n    if (!proposalForm.projectGoals.trim()) {\n      errors.projectGoals = \"Project goals are required.\";\n    }\n\n    setProposalErrors(errors);\n    return Object.keys(errors).length === 0;\n  };\n\n  const validateInquiry = () => {\n    const errors: Record<string, string> = {};\n\n    if (!inquiryForm.fullName.trim()) errors.fullName = \"Full name is required.\";\n    if (!inquiryForm.email.trim()) {\n      errors.email = \"Email is required.\";\n    } else if (!isValidEmail(inquiryForm.email)) {\n      errors.email = \"Enter a valid email address.\";\n    }\n    if (!inquiryForm.subject.trim()) errors.subject = \"Subject is required.\";\n    if (!inquiryForm.message.trim()) errors.message = \"Message is required.\";\n\n    setInquiryErrors(errors);\n    return Object.keys(errors).length === 0;\n  };\n\n  const handleStrategySubmit = async (event: FormEvent<HTMLFormElement>) => {\n    event.preventDefault();\n    setSubmitError(\"\");\n\n    if (!validateStrategy()) return;\n\n    try {\n      setIsSubmitting(true);\n      await submitContactPayload({ formType: \"strategy\", ...strategyForm });\n      setStrategySuccess(true);\n      setStrategyErrors({});\n    } catch {\n      setSubmitError(\n        \"We couldn''t submit your request right now. Please try again or email karim@misinc.com.\",\n      );\n    } finally {\n      setIsSubmitting(false);\n    }\n  };\n\n  const handleProposalSubmit = async (event: FormEvent<HTMLFormElement>) => {\n    event.preventDefault();\n    setSubmitError(\"\");\n\n    if (!validateProposal()) return;\n\n    try {\n      setIsSubmitting(true);\n      await submitContactPayload({ formType: \"proposal\", ...proposalForm });\n      setProposalSuccess(true);\n      setProposalErrors({});\n    } catch {\n      setSubmitError(\n        \"We couldn''t submit your request right now. Please try again or email karim@misinc.com.\",\n      );\n    } finally {\n      setIsSubmitting(false);\n    }\n  };\n\n  const handleInquirySubmit = async (event: FormEvent<HTMLFormElement>) => {\n    event.preventDefault();\n    setSubmitError(\"\");\n\n    if (!validateInquiry()) return;\n\n    try {\n      setIsSubmitting(true);\n      await submitContactPayload({ formType: \"inquiry\", ...inquiryForm });\n      setInquirySuccess(true);\n      setInquiryErrors({});\n    } catch {\n      setSubmitError(\n        \"We couldn''t submit your request right now. Please try again or email karim@misinc.com.\",\n      );\n    } finally {\n      setIsSubmitting(false);\n    }\n  };\n\n  return (\n    <SiteShell>\n      <ContactPageMetadata />\n      <script type=\"application/ld+json\">{JSON.stringify(contactPageStructuredData)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\" aria-labelledby=\"contact-page-heading\">\n        <Section variant=\"hero\">\n          <Container size=\"standard\">\n            <div className=\"mx-auto flex max-w-4xl flex-col gap-6 text-center\">\n              <p className=\"text-xs font-medium uppercase tracking-wide text-primary\">\n                Contact MIS, Inc.\n              </p>\n              <h1\n                id=\"contact-page-heading\"\n                className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\"\n              >\n                Get in Touch - We''re Ready to Help\n              </h1>\n              <p className=\"mx-auto max-w-3xl text-base leading-loose text-muted-foreground md:text-lg\">\n                Choose the path that fits your goal: book a free strategy call, request a\n                custom proposal, or send a general inquiry. Each option opens a focused\n                form so you can share only what matters and get a faster response.\n              </p>\n              <div className=\"mx-auto flex w-full max-w-3xl flex-col gap-3 sm:flex-row sm:justify-center\">\n                <Button\n                  className=\"rounded-full px-6 py-6 text-sm tracking-wide\"\n                  onClick={() => revealForm(\"strategy\")}\n                >\n                  Schedule a Strategy Call\n                </Button>\n                <Button\n                  className=\"rounded-full px-6 py-6 text-sm tracking-wide\"\n                  onClick={() => revealForm(\"proposal\")}\n                >\n                  Request a Proposal\n                </Button>\n                <Button\n                  className=\"rounded-full px-6 py-6 text-sm tracking-wide\"\n                  onClick={() => revealForm(\"inquiry\")}\n                >\n                  Send a Message\n                </Button>\n              </div>\n              <p className=\"text-sm text-muted-foreground\">We respond within one business day.</p>\n            </div>\n          </Container>\n        </Section>\n\n        {activeForm && (\n          <Section\n            id=\"revealable-forms\"\n            variant=\"standard\"\n            aria-live=\"polite\"\n            aria-labelledby=\"forms-heading\"\n          >\n            <Container size=\"narrow\">\n              <div ref={revealSectionRef} className=\"mb-8 flex flex-col gap-4\">\n                <h2\n                  id=\"forms-heading\"\n                  className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\"\n                >\n                  Tell Us What You Need\n                </h2>\n                <p className=\"text-base leading-loose text-muted-foreground\">\n                  Use the form below to share just the essentials. We respond within one\n                  business day.\n                </p>\n              </div>\n\n              {submitError && (\n                <p className=\"mb-4 rounded-md border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive\">\n                  {submitError}\n                </p>\n              )}\n\n              {activeForm === \"strategy\" && (\n              <Card id=\"strategy\" className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Free Strategy Call\n                  </CardTitle>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    Share a few details and we''ll send next-step options for your strategy\n                    call.\n                  </CardDescription>\n                </CardHeader>\n                <CardContent>\n                  {strategySuccess ? (\n                    <div className=\"rounded-md border border-primary/20 bg-primary/5 p-4 text-sm leading-relaxed text-foreground\">\n                      Request received. Our team will contact you within one business day to\n                      confirm details and schedule your strategy call.\n                    </div>\n                  ) : (\n                    <form className=\"space-y-5\" onSubmit={handleStrategySubmit} noValidate>\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-full-name\">Full Name *</Label>\n                        <Input\n                          id=\"strategy-full-name\"\n                          value={strategyForm.fullName}\n                          onChange={(event) =>\n                            setStrategyForm((prev) => ({ ...prev, fullName: event.target.value }))\n                          }\n                          aria-invalid={Boolean(strategyErrors.fullName)}\n                          aria-describedby={strategyErrors.fullName ? \"strategy-full-name-error\" : undefined}\n                        />\n                        {strategyErrors.fullName && (\n                          <p id=\"strategy-full-name-error\" className=\"text-sm text-destructive\">\n                            {strategyErrors.fullName}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-email\">Email *</Label>\n                        <Input\n                          id=\"strategy-email\"\n                          type=\"email\"\n                          value={strategyForm.email}\n                          onChange={(event) =>\n                            setStrategyForm((prev) => ({ ...prev, email: event.target.value }))\n                          }\n                          aria-invalid={Boolean(strategyErrors.email)}\n                          aria-describedby={strategyErrors.email ? \"strategy-email-error\" : undefined}\n                        />\n                        {strategyErrors.email && (\n                          <p id=\"strategy-email-error\" className=\"text-sm text-destructive\">\n                            {strategyErrors.email}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-company\">Company Name</Label>\n                        <Input\n                          id=\"strategy-company\"\n                          value={strategyForm.companyName}\n                          onChange={(event) =>\n                            setStrategyForm((prev) => ({ ...prev, companyName: event.target.value }))\n                          }\n                        />\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-website\">Website URL</Label>\n                        <Input\n                          id=\"strategy-website\"\n                          type=\"url\"\n                          value={strategyForm.websiteUrl}\n                          onChange={(event) =>\n                            setStrategyForm((prev) => ({ ...prev, websiteUrl: event.target.value }))\n                          }\n                          aria-invalid={Boolean(strategyErrors.websiteUrl)}\n                          aria-describedby={strategyErrors.websiteUrl ? \"strategy-website-error\" : undefined}\n                        />\n                        {strategyErrors.websiteUrl && (\n                          <p id=\"strategy-website-error\" className=\"text-sm text-destructive\">\n                            {strategyErrors.websiteUrl}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-project-type\">What best describes your project?</Label>\n                        <Select\n                          value={strategyForm.projectType}\n                          onValueChange={(value) =>\n                            setStrategyForm((prev) => ({ ...prev, projectType: value }))\n                          }\n                        >\n                          <SelectTrigger id=\"strategy-project-type\">\n                            <SelectValue placeholder=\"Select one\" />\n                          </SelectTrigger>\n                          <SelectContent>\n                            {strategyProjectOptions.map((option) => (\n                              <SelectItem key={option} value={option}>\n                                {option}\n                              </SelectItem>\n                            ))}\n                          </SelectContent>\n                        </Select>\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"strategy-description\">Brief description</Label>\n                        <Textarea\n                          id=\"strategy-description\"\n                          value={strategyForm.briefDescription}\n                          onChange={(event) =>\n                            setStrategyForm((prev) => ({\n                              ...prev,\n                              briefDescription: event.target.value,\n                            }))\n                          }\n                          className=\"min-h-[140px]\"\n                        />\n                      </div>\n\n                      <p className=\"text-sm text-muted-foreground\">We respond within one business day.</p>\n\n                      <Button\n                        type=\"submit\"\n                        className=\"w-full rounded-full px-6 py-6 text-sm tracking-wide\"\n                        disabled={isSubmitting}\n                      >\n                        {isSubmitting ? \"Submitting...\" : \"Schedule My Call\"}\n                      </Button>\n                    </form>\n                  )}\n                </CardContent>\n              </Card>\n              )}\n\n              {activeForm === \"proposal\" && (\n              <Card id=\"proposal\" className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Request a Proposal\n                  </CardTitle>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    Share your scope and priorities. We''ll prepare a proposal timeline and\n                    estimate.\n                  </CardDescription>\n                </CardHeader>\n                <CardContent>\n                  {proposalSuccess ? (\n                    <div className=\"rounded-md border border-primary/20 bg-primary/5 p-4 text-sm leading-relaxed text-foreground\">\n                      Proposal request received. We''ll review your project details and\n                      respond with next steps and timeline expectations within one business\n                      day.\n                    </div>\n                  ) : (\n                    <form className=\"space-y-6\" onSubmit={handleProposalSubmit} noValidate>\n                      <div className=\"space-y-4\">\n                        <h3 className=\"text-base font-medium text-foreground\">Section A - Contact Info</h3>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-full-name\">Full Name *</Label>\n                          <Input\n                            id=\"proposal-full-name\"\n                            value={proposalForm.fullName}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, fullName: event.target.value }))\n                            }\n                            aria-invalid={Boolean(proposalErrors.fullName)}\n                            aria-describedby={proposalErrors.fullName ? \"proposal-full-name-error\" : undefined}\n                          />\n                          {proposalErrors.fullName && (\n                            <p id=\"proposal-full-name-error\" className=\"text-sm text-destructive\">\n                              {proposalErrors.fullName}\n                            </p>\n                          )}\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-email\">Email *</Label>\n                          <Input\n                            id=\"proposal-email\"\n                            type=\"email\"\n                            value={proposalForm.email}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, email: event.target.value }))\n                            }\n                            aria-invalid={Boolean(proposalErrors.email)}\n                            aria-describedby={proposalErrors.email ? \"proposal-email-error\" : undefined}\n                          />\n                          {proposalErrors.email && (\n                            <p id=\"proposal-email-error\" className=\"text-sm text-destructive\">\n                              {proposalErrors.email}\n                            </p>\n                          )}\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-phone\">Phone</Label>\n                          <Input\n                            id=\"proposal-phone\"\n                            type=\"tel\"\n                            value={proposalForm.phone}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, phone: event.target.value }))\n                            }\n                          />\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-company\">Company Name</Label>\n                          <Input\n                            id=\"proposal-company\"\n                            value={proposalForm.companyName}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, companyName: event.target.value }))\n                            }\n                          />\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-website\">Website URL</Label>\n                          <Input\n                            id=\"proposal-website\"\n                            type=\"url\"\n                            value={proposalForm.websiteUrl}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, websiteUrl: event.target.value }))\n                            }\n                            aria-invalid={Boolean(proposalErrors.websiteUrl)}\n                            aria-describedby={proposalErrors.websiteUrl ? \"proposal-website-error\" : undefined}\n                          />\n                          {proposalErrors.websiteUrl && (\n                            <p id=\"proposal-website-error\" className=\"text-sm text-destructive\">\n                              {proposalErrors.websiteUrl}\n                            </p>\n                          )}\n                        </div>\n                      </div>\n\n                      <div className=\"space-y-4\">\n                        <h3 className=\"text-base font-medium text-foreground\">Section B - Project Details</h3>\n\n                        <fieldset className=\"space-y-2\">\n                          <legend className=\"text-sm font-medium text-foreground\">\n                            What service are you interested in?\n                          </legend>\n                          <div className=\"grid grid-cols-1 gap-3\">\n                            {proposalServiceOptions.map((option) => {\n                              const checked = proposalForm.serviceInterests.includes(option);\n                              return (\n                                <label key={option} className=\"flex items-center gap-2 text-sm text-foreground\">\n                                  <Checkbox\n                                    checked={checked}\n                                    onCheckedChange={(value) => {\n                                      setProposalForm((prev) => ({\n                                        ...prev,\n                                        serviceInterests: value\n                                          ? [...prev.serviceInterests, option]\n                                          : prev.serviceInterests.filter((item) => item !== option),\n                                      }));\n                                    }}\n                                  />\n                                  <span>{option}</span>\n                                </label>\n                              );\n                            })}\n                          </div>\n                        </fieldset>\n\n                        <fieldset className=\"space-y-2\">\n                          <legend className=\"text-sm font-medium text-foreground\">Project Type</legend>\n                          <div className=\"grid grid-cols-1 gap-3 sm:grid-cols-2\">\n                            {proposalProjectTypeOptions.map((option) => {\n                              const checked = proposalForm.projectTypes.includes(option);\n                              return (\n                                <label key={option} className=\"flex items-center gap-2 text-sm text-foreground\">\n                                  <Checkbox\n                                    checked={checked}\n                                    onCheckedChange={(value) => {\n                                      setProposalForm((prev) => ({\n                                        ...prev,\n                                        projectTypes: value\n                                          ? [...prev.projectTypes, option]\n                                          : prev.projectTypes.filter((item) => item !== option),\n                                      }));\n                                    }}\n                                  />\n                                  <span>{option}</span>\n                                </label>\n                              );\n                            })}\n                          </div>\n                        </fieldset>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-budget\">Estimated Budget Range</Label>\n                          <Select\n                            value={proposalForm.budgetRange}\n                            onValueChange={(value) =>\n                              setProposalForm((prev) => ({ ...prev, budgetRange: value }))\n                            }\n                          >\n                            <SelectTrigger id=\"proposal-budget\">\n                              <SelectValue placeholder=\"Select budget range\" />\n                            </SelectTrigger>\n                            <SelectContent>\n                              {proposalBudgetOptions.map((option) => (\n                                <SelectItem key={option} value={option}>\n                                  {option}\n                                </SelectItem>\n                              ))}\n                            </SelectContent>\n                          </Select>\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-timeline\">Desired Timeline</Label>\n                          <Select\n                            value={proposalForm.timeline}\n                            onValueChange={(value) =>\n                              setProposalForm((prev) => ({ ...prev, timeline: value }))\n                            }\n                          >\n                            <SelectTrigger id=\"proposal-timeline\">\n                              <SelectValue placeholder=\"Select timeline\" />\n                            </SelectTrigger>\n                            <SelectContent>\n                              {proposalTimelineOptions.map((option) => (\n                                <SelectItem key={option} value={option}>\n                                  {option}\n                                </SelectItem>\n                              ))}\n                            </SelectContent>\n                          </Select>\n                        </div>\n\n                        <div className=\"space-y-2\">\n                          <Label htmlFor=\"proposal-goals\">Project Goals *</Label>\n                          <Textarea\n                            id=\"proposal-goals\"\n                            value={proposalForm.projectGoals}\n                            onChange={(event) =>\n                              setProposalForm((prev) => ({ ...prev, projectGoals: event.target.value }))\n                            }\n                            className=\"min-h-[160px]\"\n                            aria-invalid={Boolean(proposalErrors.projectGoals)}\n                            aria-describedby={proposalErrors.projectGoals ? \"proposal-goals-error\" : undefined}\n                          />\n                          {proposalErrors.projectGoals && (\n                            <p id=\"proposal-goals-error\" className=\"text-sm text-destructive\">\n                              {proposalErrors.projectGoals}\n                            </p>\n                          )}\n                        </div>\n                      </div>\n\n                      <p className=\"text-sm text-muted-foreground\">We respond within one business day.</p>\n\n                      <Button\n                        type=\"submit\"\n                        className=\"w-full rounded-full px-6 py-6 text-sm tracking-wide\"\n                        disabled={isSubmitting}\n                      >\n                        {isSubmitting ? \"Submitting...\" : \"Request My Proposal\"}\n                      </Button>\n                    </form>\n                  )}\n                </CardContent>\n              </Card>\n              )}\n\n              {activeForm === \"inquiry\" && (\n              <Card id=\"inquiry\" className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    General Inquiry\n                  </CardTitle>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    Send your question and our team will follow up with a direct answer.\n                  </CardDescription>\n                </CardHeader>\n                <CardContent>\n                  {inquirySuccess ? (\n                    <div className=\"rounded-md border border-primary/20 bg-primary/5 p-4 text-sm leading-relaxed text-foreground\">\n                      Message received. Thanks for contacting MIS, Inc. We''ll follow up\n                      shortly.\n                    </div>\n                  ) : (\n                    <form className=\"space-y-5\" onSubmit={handleInquirySubmit} noValidate>\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"inquiry-full-name\">Full Name *</Label>\n                        <Input\n                          id=\"inquiry-full-name\"\n                          value={inquiryForm.fullName}\n                          onChange={(event) =>\n                            setInquiryForm((prev) => ({ ...prev, fullName: event.target.value }))\n                          }\n                          aria-invalid={Boolean(inquiryErrors.fullName)}\n                          aria-describedby={inquiryErrors.fullName ? \"inquiry-full-name-error\" : undefined}\n                        />\n                        {inquiryErrors.fullName && (\n                          <p id=\"inquiry-full-name-error\" className=\"text-sm text-destructive\">\n                            {inquiryErrors.fullName}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"inquiry-email\">Email *</Label>\n                        <Input\n                          id=\"inquiry-email\"\n                          type=\"email\"\n                          value={inquiryForm.email}\n                          onChange={(event) =>\n                            setInquiryForm((prev) => ({ ...prev, email: event.target.value }))\n                          }\n                          aria-invalid={Boolean(inquiryErrors.email)}\n                          aria-describedby={inquiryErrors.email ? \"inquiry-email-error\" : undefined}\n                        />\n                        {inquiryErrors.email && (\n                          <p id=\"inquiry-email-error\" className=\"text-sm text-destructive\">\n                            {inquiryErrors.email}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"inquiry-subject\">Subject *</Label>\n                        <Input\n                          id=\"inquiry-subject\"\n                          value={inquiryForm.subject}\n                          onChange={(event) =>\n                            setInquiryForm((prev) => ({ ...prev, subject: event.target.value }))\n                          }\n                          aria-invalid={Boolean(inquiryErrors.subject)}\n                          aria-describedby={inquiryErrors.subject ? \"inquiry-subject-error\" : undefined}\n                        />\n                        {inquiryErrors.subject && (\n                          <p id=\"inquiry-subject-error\" className=\"text-sm text-destructive\">\n                            {inquiryErrors.subject}\n                          </p>\n                        )}\n                      </div>\n\n                      <div className=\"space-y-2\">\n                        <Label htmlFor=\"inquiry-message\">Message *</Label>\n                        <Textarea\n                          id=\"inquiry-message\"\n                          value={inquiryForm.message}\n                          onChange={(event) =>\n                            setInquiryForm((prev) => ({ ...prev, message: event.target.value }))\n                          }\n                          className=\"min-h-[160px]\"\n                          aria-invalid={Boolean(inquiryErrors.message)}\n                          aria-describedby={inquiryErrors.message ? \"inquiry-message-error\" : undefined}\n                        />\n                        {inquiryErrors.message && (\n                          <p id=\"inquiry-message-error\" className=\"text-sm text-destructive\">\n                            {inquiryErrors.message}\n                          </p>\n                        )}\n                      </div>\n\n                      <p className=\"text-sm text-muted-foreground\">We respond within one business day.</p>\n\n                      <Button\n                        type=\"submit\"\n                        className=\"w-full rounded-full px-6 py-6 text-sm tracking-wide\"\n                        disabled={isSubmitting}\n                      >\n                        {isSubmitting ? \"Submitting...\" : \"Send My Message\"}\n                      </Button>\n                    </form>\n                  )}\n                </CardContent>\n              </Card>\n              )}\n            </Container>\n          </Section>\n        )}\n\n        {activeForm && (\n          <Section variant=\"flush\" tone=\"muted\" aria-labelledby=\"related-links-heading\">\n            <Container size=\"standard\">\n              <div className=\"flex flex-col gap-3 py-10 text-sm leading-relaxed text-muted-foreground md:flex-row md:items-center md:justify-between\">\n                <p id=\"related-links-heading\" className=\"font-medium text-foreground\">\n                  Explore related pages before you reach out:\n                </p>\n                <div className=\"flex flex-wrap gap-4\">\n                  <Link to=\"/services\" className=\"underline-offset-4 hover:underline\">\n                    View our services\n                  </Link>\n                  <Link to=\"/solutions\" className=\"underline-offset-4 hover:underline\">\n                    Explore solutions\n                  </Link>\n                  <Link to=\"/case-studies\" className=\"underline-offset-4 hover:underline\">\n                    Review case studies\n                  </Link>\n                </div>\n              </div>\n            </Container>\n          </Section>\n        )}\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/FaqSectionVariantsPage.tsx","content":"import { ArrowLeft, ArrowRight, Bot, ChevronRight, Clock3, Globe2, Search, Sparkles } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport {\n  Accordion,\n  AccordionContent,\n  AccordionItem,\n  AccordionTrigger,\n} from \"@/app/components/ui/accordion\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/faq-section-variants.css\";\n\ntype FaqItem = {\n  question: string;\n  answer: string;\n  tag: string;\n  icon: typeof Clock3;\n  accent: string;\n};\n\nconst faqs: FaqItem[] = [\n  {\n    question: \"How much does a professional website cost?\",\n    answer:\n      \"Project cost depends on scope, content complexity, integrations, and timeline. Most engagements are scoped after strategy discovery so the investment aligns with your business goals.\",\n    tag: \"Pricing\",\n    icon: Clock3,\n    accent: \"#A62025\",\n  },\n  {\n    question: \"How long does a typical project take?\",\n    answer:\n      \"Most website projects run between six and twelve weeks depending on complexity and feedback cadence. Larger builds involving custom applications or automation can extend beyond that range.\",\n    tag: \"Timeline\",\n    icon: Clock3,\n    accent: \"#C9923D\",\n  },\n  {\n    question: \"What is the difference between SEO and AEO?\",\n    answer:\n      \"SEO focuses on rankings and qualified organic traffic. AEO focuses on helping content appear in direct answers, AI summaries, and conversational search results. They work best together.\",\n    tag: \"Search Strategy\",\n    icon: Search,\n    accent: \"#FF9902\",\n  },\n  {\n    question: \"Is Webflow better than WordPress?\",\n    answer:\n      \"Webflow is often better for teams that need visual control, speed, and easier ongoing content management with fewer plugin dependencies. WordPress can still fit certain legacy ecosystems.\",\n    tag: \"Platform\",\n    icon: Globe2,\n    accent: \"#8D6A2A\",\n  },\n  {\n    question: \"How can AI consulting help my business?\",\n    answer:\n      \"AI consulting helps identify high-impact workflows where automation can save time, reduce errors, and improve responsiveness. We focus on practical use cases tied to measurable outcomes.\",\n    tag: \"AI Strategy\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n  },\n  {\n    question: \"Do you work with companies outside New Mexico?\",\n    answer:\n      \"Yes. MIS, Inc. is based in Albuquerque, New Mexico, and works with organizations across the United States through a remote-friendly, milestone-driven process.\",\n    tag: \"Geography\",\n    icon: Sparkles,\n    accent: \"#A62025\",\n  },\n  {\n    question: \"Do I need all services at once?\",\n    answer:\n      \"No. Most clients start with one priority outcome and phase additional services over time. We help define the right sequence so you can move forward without unnecessary complexity or spend.\",\n    tag: \"Scope\",\n    icon: ChevronRight,\n    accent: \"#C9923D\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"fsv-header\">\n      <p className=\"fsv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"fsv-section\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Refined Editorial Accordion\"\n        body=\"A cleaner, sharper version of the current FAQ with stronger type, spacing, and a more intentional frame.\"\n      />\n      <div className=\"fsv-accordion-shell\">\n        <Accordion type=\"single\" collapsible className=\"fsv-accordion\">\n          {faqs.map((faq, index) => (\n            <AccordionItem key={faq.question} value={`editorial-${index}`}>\n              <AccordionTrigger className=\"fsv-trigger\">\n                <span>{faq.question}</span>\n              </AccordionTrigger>\n              <AccordionContent className=\"fsv-content\">\n                {faq.answer}\n              </AccordionContent>\n            </AccordionItem>\n          ))}\n        </Accordion>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"fsv-section fsv-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Narrative Split FAQ\"\n        body=\"A left-side story panel gives the FAQ a stronger reason to exist, while the right side stays compact and scannable.\"\n      />\n      <div className=\"fsv-split-shell\">\n        <aside className=\"fsv-story\">\n          <p className=\"fsv-mini-label\">Buyer friction</p>\n          <h3>Answer the high-intent objections before they slow the decision.</h3>\n          <p>\n            This direction turns the FAQ from a utility list into a strategic confidence section. It works better when\n            the page needs more persuasion and less repetition.\n          </p>\n          <div className=\"fsv-story-note\">\n            <span>Pricing</span>\n            <ArrowRight size={16} />\n            <span>Timeline</span>\n            <ArrowRight size={16} />\n            <span>Platform fit</span>\n          </div>\n        </aside>\n        <div className=\"fsv-split-list\">\n          {faqs.map((faq, index) => (\n            <Accordion key={faq.question} type=\"single\" collapsible defaultValue={index === 0 ? `split-${index}` : undefined}>\n              <AccordionItem className=\"fsv-split-item\" value={`split-${index}`}>\n                <AccordionTrigger className=\"fsv-split-trigger\">\n                  <span className=\"fsv-pill\">{faq.tag}</span>\n                  <strong>{faq.question}</strong>\n                </AccordionTrigger>\n                <AccordionContent className=\"fsv-split-content\">{faq.answer}</AccordionContent>\n              </AccordionItem>\n            </Accordion>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  const featured = faqs[2];\n  const FeaturedIcon = featured.icon;\n\n  return (\n    <section className=\"fsv-section fsv-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Mosaic Answer Board\"\n        body=\"One featured FAQ and a supporting card grid create better pacing and a clearer focal point than a single uninterrupted accordion.\"\n      />\n      <div className=\"fsv-mosaic-grid\">\n        <article className=\"fsv-mosaic-hero\" style={{ [\"--accent\" as string]: featured.accent }}>\n          <div className=\"fsv-mosaic-top\">\n            <span className=\"fsv-pill\">{featured.tag}</span>\n            <FeaturedIcon />\n          </div>\n          <h3>{featured.question}</h3>\n          <p>{featured.answer}</p>\n        </article>\n        {faqs.filter((faq) => faq !== featured).map((faq) => {\n          const Icon = faq.icon;\n\n          return (\n            <article key={faq.question} className=\"fsv-mosaic-card\" style={{ [\"--accent\" as string]: faq.accent }}>\n              <div className=\"fsv-mosaic-top\">\n                <Icon />\n                <span className=\"fsv-pill\">{faq.tag}</span>\n              </div>\n              <h3>{faq.question}</h3>\n              <p>{faq.answer}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"fsv-section fsv-section--rail\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Horizontal FAQ Rail\"\n        body=\"A numbered rail makes the content feel more guided and gives each answer a stronger individual presence.\"\n      />\n      <div className=\"fsv-rail-shell\">\n        <div className=\"fsv-rail-line\" />\n        {faqs.map((faq, index) => {\n          const Icon = faq.icon;\n\n          return (\n            <article key={faq.question} className=\"fsv-rail-card\" style={{ [\"--accent\" as string]: faq.accent }}>\n              <div className=\"fsv-rail-top\">\n                <span className=\"fsv-card-index\">0{index + 1}</span>\n                <div className=\"fsv-icon-wrap\">\n                  <Icon />\n                </div>\n              </div>\n              <span className=\"fsv-pill\">{faq.tag}</span>\n              <h3>{faq.question}</h3>\n              <p>{faq.answer}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"fsv-section fsv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight FAQ Console\"\n        body=\"A darker premium direction that turns the FAQ into a stronger confidence and objection-handling section.\"\n      />\n      <div className=\"fsv-midnight-shell\">\n        <aside className=\"fsv-midnight-aside\">\n          <span className=\"fsv-chip fsv-chip--light\">Objection handling</span>\n          <h3>Use the FAQ as a closing tool, not just a content dump.</h3>\n          <p>\n            This version breaks the page rhythm hard and makes the section feel more curated. It works well when the\n            rest of the page needs a stronger credibility shift near the bottom.\n          </p>\n        </aside>\n        <div className=\"fsv-midnight-grid\">\n          {faqs.map((faq, index) => (\n            <Accordion key={faq.question} type=\"single\" collapsible defaultValue={index === 0 ? `midnight-${index}` : undefined}>\n              <AccordionItem className=\"fsv-midnight-item\" value={`midnight-${index}`}>\n                <AccordionTrigger className=\"fsv-midnight-trigger\">\n                  <div>\n                    <span className=\"fsv-chip fsv-chip--light\">{faq.tag}</span>\n                    <strong>{faq.question}</strong>\n                  </div>\n                </AccordionTrigger>\n                <AccordionContent className=\"fsv-midnight-content\">{faq.answer}</AccordionContent>\n              </AccordionItem>\n            </Accordion>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function FaqSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"faq-section-lab\">\n        <section className=\"fsv-hero\">\n          <div className=\"fsv-hero-inner\">\n            <Link to=\"/services\" className=\"fsv-back-link\">\n              <ArrowLeft />\n              Back to Services\n            </Link>\n            <p className=\"fsv-eyebrow\">FAQ Section Explorations</p>\n            <h1>Five stronger directions for the Services page FAQ section.</h1>\n            <p>\n              These variations keep the same question set, but push the hierarchy, pacing, and sense of confidence much\n              harder than the current default accordion.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/GuidesSectionVariantsPage.tsx","content":"import type { ComponentType, SVGProps } from \"react\";\nimport {\n  ArrowLeft,\n  ArrowRight,\n  BookOpenText,\n  Bot,\n  Compass,\n  LayoutGrid,\n  LibraryBig,\n  ScrollText,\n} from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport {\n  GuidesEditorialSection,\n  type GuidesEditorialItem,\n} from \"@/app/components/sections\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/guides-section-variants.css\";\n\ntype IconComponent = ComponentType<SVGProps<SVGSVGElement>>;\n\ntype GuideCard = {\n  title: string;\n  description: string;\n  href: string;\n  eyebrow: string;\n  readTime: string;\n  icon: IconComponent;\n  accent: string;\n};\n\nconst guides: GuideCard[] = [\n  {\n    title: \"Webflow vs WordPress Guide\",\n    description:\n      \"Compare platform tradeoffs, governance, publishing speed, and long-term maintenance costs before committing.\",\n    href: \"/guides/webflow-vs-wordpress\",\n    eyebrow: \"Platform Strategy\",\n    readTime: \"8 min read\",\n    icon: LayoutGrid,\n    accent: \"#a62025\",\n  },\n  {\n    title: \"Website Redesign Checklist\",\n    description:\n      \"Use a practical step-by-step checklist to reduce redesign risk and align UX, SEO, and conversion goals.\",\n    href: \"/guides/website-redesign-checklist\",\n    eyebrow: \"Planning Framework\",\n    readTime: \"6 min read\",\n    icon: ScrollText,\n    accent: \"#c9923d\",\n  },\n  {\n    title: \"Cost of Web Design in Albuquerque\",\n    description:\n      \"Understand pricing ranges, delivery scope, and budget planning for business websites in the New Mexico market.\",\n    href: \"/guides/web-design-cost-albuquerque\",\n    eyebrow: \"Budget Clarity\",\n    readTime: \"7 min read\",\n    icon: Compass,\n    accent: \"#c76438\",\n  },\n  {\n    title: \"AI for Small Businesses Guide\",\n    description:\n      \"Identify realistic AI opportunities that improve team output, reduce manual work, and support measurable growth.\",\n    href: \"/guides/ai-for-small-businesses\",\n    eyebrow: \"AI Adoption\",\n    readTime: \"9 min read\",\n    icon: Bot,\n    accent: \"#6b4a1e\",\n  },\n];\n\nconst editorialGuides: GuidesEditorialItem[] = guides.map((guide) => ({\n  title: guide.title,\n  description: guide.description,\n  href: guide.href,\n  eyebrow: guide.eyebrow,\n  accent: guide.accent,\n}));\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"gsv-header\">\n      <p className=\"gsv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction GuideLink({ href }: { href: string }) {\n  return (\n    <Link to={href} className=\"gsv-link\">\n      Open guide\n      <ArrowRight />\n    </Link>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <GuidesEditorialSection\n      eyebrow=\"Variant 1\"\n      title=\"Editorial Card Grid\"\n      description=\"Closest to the current structure, but with stronger spacing, metadata, and more visual lift so it feels designed instead of default.\"\n      guides={editorialGuides}\n    />\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"gsv-section gsv-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Narrative Split Layout\"\n        body=\"A stronger left-hand story frame with more vertical pressure on the right, so the guides feel like a curated library instead of a neutral resource list.\"\n      />\n      <div className=\"gsv-split-shell\">\n        <aside className=\"gsv-split-aside\">\n          <span className=\"gsv-chip gsv-chip--soft\">Evergreen library</span>\n          <h3>Built for high-intent questions that need durable answers.</h3>\n          <p>\n            This direction gives the section a strategic narrative first, then lets each guide operate as a clear next click.\n          </p>\n        </aside>\n        <div className=\"gsv-split-list\">\n          {guides.map((guide, index) => {\n            const Icon = guide.icon;\n\n            return (\n              <article key={guide.title} className=\"gsv-card gsv-card--row\">\n                <div className=\"gsv-row-index\">0{index + 1}</div>\n                <div className=\"gsv-row-copy\">\n                  <div className=\"gsv-card-top\">\n                    <span className=\"gsv-chip\" style={{ color: guide.accent }}>\n                      {guide.eyebrow}\n                    </span>\n                    <span className=\"gsv-meta\">\n                      <Icon />\n                      {guide.readTime}\n                    </span>\n                  </div>\n                  <h3>{guide.title}</h3>\n                  <p>{guide.description}</p>\n                </div>\n                <GuideLink href={guide.href} />\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"gsv-section gsv-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Featured Mosaic\"\n        body=\"One lead guide gets more surface area, while the rest support it in a staggered composition that feels more custom and homepage-worthy.\"\n      />\n      <div className=\"gsv-mosaic\">\n        <article className=\"gsv-card gsv-card--feature\">\n          <div className=\"gsv-feature-mark\">\n            <BookOpenText />\n            <span>Featured guide</span>\n          </div>\n          <h3>{guides[0].title}</h3>\n          <p>{guides[0].description}</p>\n          <div className=\"gsv-feature-notes\">\n            <span>Platform comparison</span>\n            <span>Publishing governance</span>\n            <span>Total cost perspective</span>\n          </div>\n          <GuideLink href={guides[0].href} />\n        </article>\n\n        <div className=\"gsv-mosaic-stack\">\n          {guides.slice(1).map((guide) => {\n            const Icon = guide.icon;\n\n            return (\n              <article key={guide.title} className=\"gsv-card gsv-card--compact\">\n                <div className=\"gsv-card-top\">\n                  <span className=\"gsv-chip\" style={{ color: guide.accent }}>\n                    {guide.eyebrow}\n                  </span>\n                  <Icon className=\"gsv-compact-icon\" />\n                </div>\n                <h3>{guide.title}</h3>\n                <p>{guide.description}</p>\n                <GuideLink href={guide.href} />\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"gsv-section gsv-section--shelves\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Library Shelves\"\n        body=\"A more literal library metaphor with horizontal bands, stronger labels, and cleaner grouping so the section feels curated and ownable.\"\n      />\n      <div className=\"gsv-shelves\">\n        {guides.map((guide) => {\n          const Icon = guide.icon;\n\n          return (\n            <article key={guide.title} className=\"gsv-shelf-card\">\n              <div className=\"gsv-shelf-spine\" style={{ background: guide.accent }} />\n              <div className=\"gsv-shelf-body\">\n                <div className=\"gsv-card-top\">\n                  <span className=\"gsv-chip\">{guide.eyebrow}</span>\n                  <span className=\"gsv-meta\">\n                    <Icon />\n                    {guide.readTime}\n                  </span>\n                </div>\n                <h3>{guide.title}</h3>\n                <p>{guide.description}</p>\n              </div>\n              <GuideLink href={guide.href} />\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"gsv-section gsv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Knowledge Board\"\n        body=\"A darker, premium direction that turns the guides block into a stronger brand moment and gives the resources page more visual pacing.\"\n      />\n      <div className=\"gsv-midnight-shell\">\n        <aside className=\"gsv-midnight-lead\">\n          <div className=\"gsv-midnight-badge\">\n            <LibraryBig />\n            Resource library\n          </div>\n          <h3>Give evergreen content more authority and presence.</h3>\n          <p>\n            This treatment creates a real section break and makes the guide collection feel more deliberate, premium, and worth exploring.\n          </p>\n        </aside>\n        <div className=\"gsv-midnight-grid\">\n          {guides.map((guide) => {\n            const Icon = guide.icon;\n\n            return (\n              <article key={guide.title} className=\"gsv-midnight-card\">\n                <div className=\"gsv-card-top\">\n                  <span className=\"gsv-chip gsv-chip--light\">{guide.eyebrow}</span>\n                  <span className=\"gsv-meta gsv-meta--light\">\n                    <Icon />\n                    {guide.readTime}\n                  </span>\n                </div>\n                <h3>{guide.title}</h3>\n                <p>{guide.description}</p>\n                <GuideLink href={guide.href} />\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function GuidesSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"guides-section-lab\">\n        <section className=\"gsv-hero\">\n          <div className=\"gsv-hero-inner\">\n            <Link to=\"/resources\" className=\"gsv-back-link\">\n              <ArrowLeft />\n              Back to Resources\n            </Link>\n            <p className=\"gsv-eyebrow\">Guides Section Explorations</p>\n            <h1>Five stronger directions for the Resources page guides section.</h1>\n            <p>\n              These concepts keep the same four guides and overall tone, but push hierarchy, rhythm, and layout harder so the section feels more intentional.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/HomeGradientVariants.tsx","content":"import HomePage from \"@/app/pages/HomePage\";\nimport \"@/styles/home-gradient-variants.css\";\n\ntype HomeGradientVariantProps = {\n  variantClassName: string;\n};\n\nfunction HomeGradientVariant({ variantClassName }: HomeGradientVariantProps) {\n  return (\n    <div className={`home-gradient-variant ${variantClassName}`}>\n      <HomePage />\n    </div>\n  );\n}\n\nexport function MainHomePageApricotLight() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-apricot-light\" />;\n}\n\nexport function NewHomePageV5AdobeDusk() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--adobe-dusk\" />;\n}\n\nexport function NewHomePageV6RioGrande() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--rio-grande\" />;\n}\n\nexport function NewHomePageV7SageHorizon() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--sage-horizon\" />;\n}\n\nexport function NewHomePageV8TurquoiseClay() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--turquoise-clay\" />;\n}\n\nexport function NewHomePageV9SandstoneDawn() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--sandstone-dawn\" />;\n}\n\nexport function NewHomePageV10LogoEmber() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-ember\" />;\n}\n\nexport function NewHomePageV11LogoSignal() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-signal\" />;\n}\n\nexport function NewHomePageV12LogoHorizon() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-horizon\" />;\n}\n\nexport function NewHomePageV13LogoSolar() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-solar\" />;\n}\n\nexport function NewHomePageV14LogoMarigold() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-marigold\" />;\n}\n\nexport function NewHomePageV15LogoSunburst() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-sunburst\" />;\n}\n\nexport function NewHomePageV16LogoMesaGold() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-mesa-gold\" />;\n}\n\nexport function NewHomePageV17LogoApricotLight() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-apricot-light\" />;\n}\n\nexport function NewHomePageV18LogoCreamsicleLight() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-creamsicle-light\" />;\n}\n\nexport function NewHomePageV19LogoHoneyLight() {\n  return <HomeGradientVariant variantClassName=\"home-gradient-variant--logo-honey-light\" />;\n}\n"},{"path":"src/app/pages/HomePage.tsx","content":"import { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport {\n  AuthoritySection,\n  CaseStudiesSection,\n  FinalCTASection,\n  HeroSection,\n  SolutionsSection,\n  StrategicServicesSection,\n} from \"@/app/components/sections\";\n\nexport default function HomePage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <HeroSection />\n        <StrategicServicesSection />\n        <SolutionsSection />\n        <CaseStudiesSection />\n        <AuthoritySection />\n        <FinalCTASection />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/NewHomePage.tsx","content":"import HomePage from \"@/app/pages/HomePage\";\nimport \"@/styles/new-home.css\";\n\nexport default function NewHomePage() {\n  return <div className=\"new-home-redesign\"><HomePage /></div>;\n}\n"},{"path":"src/app/pages/NewHomePageV2.tsx","content":"import HomePage from \"@/app/pages/HomePage\";\nimport \"@/styles/new-home-v2.css\";\n\nexport default function NewHomePageV2() {\n  return (\n    <div className=\"new-home-v2\">\n      <HomePage />\n    </div>\n  );\n}\n"},{"path":"src/app/pages/NewHomePageV3.tsx","content":"import { useState } from \"react\";\nimport { motion } from \"motion/react\";\nimport { ChevronDown, Menu, X } from \"lucide-react\";\nimport logo from \"figma:asset/7345e90366d343ada99455fe5e0c1de849dd5f34.png\";\nimport vintageLogo from \"@/assets/1995-logo.png\";\nimport { ImageWithFallback } from \"@/app/components/figma/ImageWithFallback\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport \"@/styles/new-home-v3.css\";\n\ntype NavbarDropdownGroup = {\n  label: string;\n  sectionId: string;\n  items: string[];\n};\n\nconst navbarDropdowns: NavbarDropdownGroup[] = [\n  {\n    label: \"Solutions\",\n    sectionId: \"solutions\",\n    items: [\"Small Businesses\", \"Real Estate\", \"Nonprofits\", \"Professional Services\", \"Startups & SaaS\"],\n  },\n  {\n    label: \"Services\",\n    sectionId: \"services\",\n    items: [\n      \"Website Design\",\n      \"Website Redesign\",\n      \"Ecommerce Websites\",\n      \"Conversion Optimization (CRO)\",\n      \"Webflow Website Development\",\n      \"Webflow Migrations (WordPress -> Webflow)\",\n      \"Webflow Performance Optimization\",\n      \"Square Online Website Design\",\n      \"Square Ecommerce Setup\",\n      \"Shopify -> Square Migrations\",\n      \"Web Applications\",\n      \"SaaS MVP Development\",\n      \"Internal Tools & Dashboards\",\n      \"API & System Integrations\",\n      \"AI Strategy for Small Businesses\",\n      \"AI Chat Implementation\",\n      \"Workflow Automation\",\n      \"Internal AI Systems\",\n      \"AI Search Optimization\",\n      \"Structured Content Strategy\",\n      \"Schema & Structured Data Implementation\",\n      \"AI Visibility Audits\",\n    ],\n  },\n  {\n    label: \"Resources\",\n    sectionId: \"ai-aeo\",\n    items: [\n      \"Blog Listing\",\n      \"Blog Post (Dynamic Template)\",\n      \"Webflow vs WordPress Guide\",\n      \"Website Redesign Checklist\",\n      \"Cost of Web Design in Albuquerque\",\n      \"AI for Small Businesses Guide\",\n      \"Web Design FAQ\",\n      \"Webflow FAQ\",\n      \"AI & AEO FAQ\",\n    ],\n  },\n];\n\nfunction scrollToSection(id: string) {\n  const el = document.getElementById(id);\n  if (el) el.scrollIntoView({ behavior: \"smooth\" });\n}\n\nfunction NewHomeHeader({\n  vintageMode,\n  onToggleVintage,\n}: {\n  vintageMode: boolean;\n  onToggleVintage: () => void;\n}) {\n  const [open, setOpen] = useState(false);\n  const [mobileExpanded, setMobileExpanded] = useState<string | null>(null);\n\n  return (\n    <header className=\"nh3-header-wrap\">\n      <div className=\"nh3-topbar\">30 Years of Web Design (Since 1995) • Now with AI &amp; Custom App Development</div>\n      <div className=\"nh3-header\">\n        <button className=\"nh3-logo\" onClick={() => scrollToSection(\"hero\")}>\n          {vintageMode ? (\n            <img src={vintageLogo} alt=\"MIS vintage logo\" className=\"nh3-vintage-logo\" />\n          ) : (\n            <img src={logo} alt=\"MIS, Inc.\" />\n          )}\n          <span>MIS, Inc.</span>\n        </button>\n\n        <nav className=\"nh3-nav desktop\">\n          <button onClick={() => scrollToSection(\"hero\")}>Home</button>\n          {navbarDropdowns.map((group) => (\n            <div className=\"nh3-dd\" key={group.label}>\n              <button onClick={() => scrollToSection(group.sectionId)}>\n                {group.label}\n                <ChevronDown size={14} />\n              </button>\n              <div className=\"nh3-dd-menu\">\n                {group.items.map((item) => (\n                  <button key={`${group.label}-${item}`} onClick={() => scrollToSection(group.sectionId)}>\n                    {item}\n                  </button>\n                ))}\n              </div>\n            </div>\n          ))}\n          <button onClick={() => scrollToSection(\"case-studies\")}>Case Studies</button>\n          <button onClick={() => scrollToSection(\"authority\")}>About</button>\n          <button onClick={() => scrollToSection(\"contact\")}>Contact</button>\n        </nav>\n\n        <button className=\"nh3-cta desktop\" onClick={() => scrollToSection(\"contact\")}>\n          Book a Free Strategy Call\n        </button>\n        <button className=\"nh3-vintage-toggle desktop\" onClick={onToggleVintage}>\n          {vintageMode ? \"Back to 2026\" : \"Enter 1995 Mode\"}\n        </button>\n\n        <button className=\"nh3-mobile-toggle\" onClick={() => setOpen((v) => !v)} aria-label=\"Toggle menu\">\n          {open ? <X size={22} /> : <Menu size={22} />}\n        </button>\n      </div>\n\n      {open && (\n        <nav className=\"nh3-nav-mobile\">\n          <button onClick={() => { scrollToSection(\"hero\"); setOpen(false); }}>Home</button>\n          {navbarDropdowns.map((group) => (\n            <div key={`mobile-${group.label}`}>\n              <button onClick={() => setMobileExpanded((v) => (v === group.label ? null : group.label))}>\n                {group.label}\n                <ChevronDown size={14} className={mobileExpanded === group.label ? \"rot\" : \"\"} />\n              </button>\n              {mobileExpanded === group.label && (\n                <div className=\"nh3-mobile-submenu\">\n                  {group.items.map((item) => (\n                    <button key={`${group.label}-${item}`} onClick={() => { scrollToSection(group.sectionId); setOpen(false); }}>\n                      {item}\n                    </button>\n                  ))}\n                </div>\n              )}\n            </div>\n          ))}\n          <button onClick={() => { scrollToSection(\"case-studies\"); setOpen(false); }}>Case Studies</button>\n          <button onClick={() => { scrollToSection(\"authority\"); setOpen(false); }}>About</button>\n          <button onClick={() => { scrollToSection(\"contact\"); setOpen(false); }}>Contact</button>\n          <button onClick={onToggleVintage}>{vintageMode ? \"Back to 2026\" : \"Enter 1995 Mode\"}</button>\n        </nav>\n      )}\n    </header>\n  );\n}\n\nexport default function NewHomePageV3() {\n  const [vintageMode, setVintageMode] = useState(false);\n\n  return (\n    <div className={`new-home-v3 ${vintageMode ? \"nh3-vintage\" : \"\"}`}>\n      <NewHomeHeader\n        vintageMode={vintageMode}\n        onToggleVintage={() => setVintageMode((v) => !v)}\n      />\n      <main>\n        <section id=\"hero\" className=\"nh3-hero\">\n          <div className=\"nh3-hero-noise\" />\n          <motion.h1 initial={{ opacity: 0, y: 28 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.68, ease: [0.22, 1, 0.36, 1] }}>\n            Albuquerque Web Design & AI Consulting That Drives Real Business Growth\n          </motion.h1>\n          <motion.p initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.08, duration: 0.65, ease: [0.22, 1, 0.36, 1] }}>\n            Strategic web design using Webflow and Square, custom application development, and cutting-edge AI & AEO optimization services for growing businesses.\n          </motion.p>\n          <motion.div className=\"nh3-hero-cta\" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.18, duration: 0.62, ease: [0.22, 1, 0.36, 1] }}>\n            <button className=\"nh3-cta\" onClick={() => scrollToSection(\"contact\")}>Book a Free Strategy Call</button>\n            <button className=\"nh3-ghost\" onClick={() => scrollToSection(\"case-studies\")}>View Case Studies</button>\n          </motion.div>\n        </section>\n\n        <section id=\"services\" className=\"nh3-section\">\n          <h2>Strategic Technology for Growing Businesses</h2>\n          <div className=\"nh3-cards-3\">\n            {[\n              [\"Web Design That Converts\", \"Modern, conversion-optimized websites built on Webflow and Square Online that grow with your business and adapt to changing needs.\"],\n              [\"Custom Applications\", \"Tailored web applications and integrations designed to solve your specific business challenges and streamline operations.\"],\n              [\"AI & AEO Optimization\", \"Forward-thinking AI integration and Answer Engine Optimization to ensure your business is found by both search engines and AI assistants.\"],\n            ].map(([title, body], i) => (\n              <motion.article key={title} initial={{ opacity: 0, y: 26 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: \"-80px\" }} transition={{ delay: i * 0.08, duration: 0.48, ease: [0.22, 1, 0.36, 1] }}>\n                <h3>{title}</h3>\n                <p>{body}</p>\n              </motion.article>\n            ))}\n          </div>\n        </section>\n\n        <section id=\"authority\" className=\"nh3-section nh3-authority\">\n          <div>\n            <h2>30 Years of Innovation. Built for What''s Next.</h2>\n            <p>Since 1995, we''ve helped businesses navigate every major shift in web technology — from the early web to mobile-first design to AI-powered optimization.</p>\n          </div>\n          <div className=\"nh3-metrics\">\n            {[\n              [\"1995\", \"Founded\"],\n              [\"30+\", \"Years Experience\"],\n              [\"500+\", \"Projects Delivered\"],\n              [\"2024\", \"AI Integration\"],\n            ].map(([value, label], i) => (\n              <motion.div key={label} initial={{ opacity: 0, scale: 0.94 }} whileInView={{ opacity: 1, scale: 1 }} viewport={{ once: true, margin: \"-60px\" }} transition={{ delay: i * 0.07, duration: 0.45, ease: [0.22, 1, 0.36, 1] }}>\n                <p>{value}</p><span>{label}</span>\n              </motion.div>\n            ))}\n          </div>\n        </section>\n\n        <section id=\"local\" className=\"nh3-section nh3-split\">\n          <div>\n            <h2>Proudly Serving Albuquerque & New Mexico</h2>\n            <p>Based in Albuquerque since 1995, we understand the unique needs of New Mexico businesses. From local startups to established nonprofits and professional organizations, we''re your neighbors and your partners in growth.</p>\n            <p>We combine the personal touch of a local agency with the technical expertise and forward-thinking approach needed to compete on a national stage.</p>\n          </div>\n          <motion.div className=\"nh3-image-wrap\" whileInView={{ opacity: 1, y: 0 }} initial={{ opacity: 0, y: 26 }} viewport={{ once: true, margin: \"-80px\" }} transition={{ duration: 0.52, ease: [0.22, 1, 0.36, 1] }}>\n            <ImageWithFallback\n              src=\"https://images.unsplash.com/photo-1563302111-eab3c9c51f6e?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxhbGJ1cXVlcnF1ZSUyMG5ldyUyMG1leGljbyUyMHNreWxpbmV8ZW58MXx8fHwxNzY5Mjc5NjQwfDA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\"\n              alt=\"Albuquerque New Mexico\"\n            />\n          </motion.div>\n        </section>\n\n        <section id=\"case-studies\" className=\"nh3-section\">\n          <h2>Recent Client Success Stories</h2>\n          <div className=\"nh3-cards-3\">\n            {[\n              [\"Healthcare\", \"Regional Medical Practice\", \"300% increase in online appointment bookings within 6 months\", \"https://images.unsplash.com/photo-1460925895917-afdab827c52f?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxidXNpbmVzcyUyMGRhc2hib2FyZCUyMGFuYWx5dGljc3xlbnwxfHx8fDE3NjkyNzk2NDB8MA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\"],\n              [\"Nonprofit\", \"Community Foundation\", \"Streamlined donation process increased contributions by 85%\", \"https://images.unsplash.com/photo-1553877522-43269d4ea984?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxub25wcm9maXQlMjBjb21tdW5pdHklMjBzZXJ2aWNlfGVufDF8fHx8MTc2OTI3OTY0MXww&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\"],\n              [\"Professional Services\", \"Legal Association\", \"Custom member portal reduced admin time by 60%\", \"https://images.unsplash.com/photo-1556761175-b413da4baf72?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxwcm9mZXNzaW9uYWwlMjBzZXJ2aWNlcyUyMG9mZmljZXxlbnwxfHx8fDE3NjkyNzk2NDF8MA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\"],\n            ].map(([industry, title, outcome, src], i) => (\n              <motion.article key={title} initial={{ opacity: 0, y: 24 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: \"-80px\" }} transition={{ delay: i * 0.08, duration: 0.5, ease: [0.22, 1, 0.36, 1] }}>\n                <div className=\"nh3-image-wrap\"><ImageWithFallback src={src} alt={title} /></div>\n                <span>{industry}</span>\n                <h3>{title}</h3>\n                <p>{outcome}</p>\n              </motion.article>\n            ))}\n          </div>\n        </section>\n\n        <section id=\"solutions\" className=\"nh3-section\">\n          <h2>Solutions Tailored to Your Industry</h2>\n          <div className=\"nh3-cards-2\">\n            {[\n              [\"Healthcare\", \"HIPAA-compliant websites, patient portals, and appointment systems designed for medical practices and health organizations.\"],\n              [\"Nonprofits\", \"Mission-driven websites with integrated donation systems, volunteer management, and storytelling features.\"],\n              [\"Professional Services\", \"Sophisticated web presence for legal, consulting, and financial services with client portals and custom tools.\"],\n              [\"Small Business\", \"E-commerce solutions, local SEO optimization, and conversion-focused websites that drive growth.\"],\n            ].map(([title, body], i) => (\n              <motion.article key={title} initial={{ opacity: 0, x: i % 2 ? 20 : -20 }} whileInView={{ opacity: 1, x: 0 }} viewport={{ once: true, margin: \"-80px\" }} transition={{ duration: 0.46, ease: [0.22, 1, 0.36, 1] }}>\n                <h3>{title}</h3>\n                <p>{body}</p>\n              </motion.article>\n            ))}\n          </div>\n        </section>\n\n        <section id=\"ai-aeo\" className=\"nh3-section nh3-split reverse\">\n          <motion.div className=\"nh3-image-wrap\" whileInView={{ opacity: 1, y: 0 }} initial={{ opacity: 0, y: 26 }} viewport={{ once: true, margin: \"-80px\" }} transition={{ duration: 0.52, ease: [0.22, 1, 0.36, 1] }}>\n            <ImageWithFallback\n              src=\"https://images.unsplash.com/photo-1677442136019-21780ecad995?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxhaSUyMGFydGlmaWNpYWwlMjBpbnRlbGxpZ2VuY2UlMjB0ZWNobm9sb2d5fGVufDF8fHx8MTc2OTI3OTY0MXww&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral\"\n              alt=\"AI and AEO Technology\"\n            />\n          </motion.div>\n          <div>\n            <h2>Optimized for Search — and AI</h2>\n            <p>The future of search is changing. AI assistants like ChatGPT, Perplexity, and Google''s AI Overviews are reshaping how people find information online.</p>\n            <p>Our Answer Engine Optimization (AEO) services ensure your business is discoverable not just in traditional search results, but in AI-generated answers. We combine proven SEO practices with forward-thinking AI optimization to future-proof your online presence.</p>\n            <div className=\"nh3-mini-metrics\">\n              <div><strong>AEO</strong><span>Answer Engine Optimization</span></div>\n              <div><strong>AI-Ready</strong><span>Future-Proof Strategy</span></div>\n            </div>\n          </div>\n        </section>\n\n        <section id=\"contact\" className=\"nh3-section nh3-final\">\n          <h2>Ready to Build What''s Next?</h2>\n          <p>Let''s discuss how strategic web design, custom development, and AI optimization can help your business grow. Schedule a free consultation — no pressure, just solutions.</p>\n          <button className=\"nh3-cta\">Book a Free Strategy Call</button>\n          <div className=\"nh3-contact-row\">\n            <a href=\"mailto:contact@mis-inc.com\">contact@mis-inc.com</a>\n            <a href=\"tel:+15055551234\">(505) 555-1234</a>\n            <span>Albuquerque, NM</span>\n          </div>\n        </section>\n      </main>\n      <SiteFooter />\n      {vintageMode && (\n        <div className=\"nh3-vintage-dock\" aria-label=\"1995 quick links\">\n          <button onClick={() => scrollToSection(\"hero\")}>HOME</button>\n          <button onClick={() => scrollToSection(\"case-studies\")}>RECENT WORK</button>\n          <button onClick={() => scrollToSection(\"services\")}>RATES &amp; SERVICES</button>\n          <button onClick={() => scrollToSection(\"contact\")}>QUOTE REQUEST</button>\n          <button onClick={() => scrollToSection(\"ai-aeo\")}>LINKS</button>\n        </div>\n      )}\n    </div>\n  );\n}\n"},{"path":"src/app/pages/NewHomePageV4.tsx","content":"import { useEffect, useState } from \"react\";\nimport { createPortal } from \"react-dom\";\nimport HomePage from \"@/app/pages/HomePage\";\nimport \"@/styles/new-home-v4.css\";\n\nconst heroImages = [\n  \"https://images.unsplash.com/photo-1552664730-d307ca884978?auto=format&fit=crop&w=1800&q=80\",\n  \"https://images.unsplash.com/photo-1521737711867-e3b97375f902?auto=format&fit=crop&w=1800&q=80\",\n  \"https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&fit=crop&w=1800&q=80\",\n  \"https://images.unsplash.com/photo-1557804506-669a67965ba0?auto=format&fit=crop&w=1800&q=80\",\n  \"https://images.unsplash.com/photo-1556740749-887f6717d7e4?auto=format&fit=crop&w=1800&q=80\",\n];\n\nfunction HeroBackgroundRotator() {\n  const [heroElement, setHeroElement] = useState<HTMLElement | null>(null);\n  const [activeIndex, setActiveIndex] = useState(0);\n\n  useEffect(() => {\n    setHeroElement(document.getElementById(\"hero\"));\n  }, []);\n\n  useEffect(() => {\n    const interval = window.setInterval(() => {\n      setActiveIndex((current) => (current + 1) % heroImages.length);\n    }, 3800);\n\n    return () => window.clearInterval(interval);\n  }, []);\n\n  if (!heroElement) return null;\n\n  return createPortal(\n    <div className=\"nh4-hero-rotator\" aria-hidden=\"true\">\n      {heroImages.map((image, index) => (\n        <div\n          key={image}\n          className={`nh4-hero-image ${index === activeIndex ? \"is-active\" : \"\"}`}\n          style={{ backgroundImage: `url(\"${image}\")` }}\n        />\n      ))}\n      <div className=\"nh4-hero-overlay\" />\n    </div>,\n    heroElement,\n  );\n}\n\nexport default function NewHomePageV4() {\n  return (\n    <div className=\"new-home-v4\">\n      <HomePage />\n      <HeroBackgroundRotator />\n    </div>\n  );\n}\n"},{"path":"src/app/pages/OurApproachSectionVariantsPage.tsx","content":"import type { ComponentType, SVGProps } from \"react\";\nimport {\n  ArrowLeft,\n  ArrowRight,\n  BarChart3,\n  Compass,\n  DraftingCompass,\n  Sparkles,\n  Wrench,\n} from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { OurApproachSection } from \"@/app/components/sections\";\nimport \"@/styles/approach-section-variants.css\";\n\ntype IconComponent = ComponentType<SVGProps<SVGSVGElement>>;\n\ntype ApproachStep = {\n  title: string;\n  description: string;\n  outcome: string;\n  icon: IconComponent;\n  accent: string;\n};\n\nconst steps: ApproachStep[] = [\n  {\n    title: \"Discover\",\n    description:\n      \"We align business goals, audience needs, and operating constraints before design or development starts.\",\n    outcome: \"Sharper scope and fewer expensive assumptions.\",\n    icon: Compass,\n    accent: \"#A62025\",\n  },\n  {\n    title: \"Design\",\n    description:\n      \"We shape clear user journeys, messaging hierarchy, and interface systems built for trust and conversion.\",\n    outcome: \"Stronger clarity for buyers and internal teams.\",\n    icon: DraftingCompass,\n    accent: \"#C9923D\",\n  },\n  {\n    title: \"Build\",\n    description:\n      \"We implement with performance, maintainability, CMS governance, and real operational use in mind.\",\n    outcome: \"A system your team can actually run and extend.\",\n    icon: Wrench,\n    accent: \"#FF9902\",\n  },\n  {\n    title: \"Optimize\",\n    description:\n      \"We improve continuously through analytics, testing, search visibility, and iterative UX refinement.\",\n    outcome: \"Compounding gains after launch instead of drift.\",\n    icon: BarChart3,\n    accent: \"#6B4A1E\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"asv-header\">\n      <p className=\"asv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"asv-section asv-section--pathway\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Momentum Pathway\"\n        body=\"A connected sequence with more visual movement, so the process feels like a guided progression instead of four equal cards.\"\n      />\n      <div className=\"asv-pathway\">\n        <div className=\"asv-pathway__line\" />\n        {steps.map((step, index) => {\n          const Icon = step.icon;\n\n          return (\n            <article\n              key={step.title}\n              className={`asv-path-card asv-path-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: step.accent }}\n            >\n              <div className=\"asv-path-card__top\">\n                <span className=\"asv-step-index\">0{index + 1}</span>\n                <div className=\"asv-icon-wrap\">\n                  <Icon />\n                </div>\n              </div>\n              <h3>{step.title}</h3>\n              <p>{step.description}</p>\n              <div className=\"asv-outcome-chip\">{step.outcome}</div>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"asv-section asv-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Strategy Narrative Split\"\n        body=\"A stronger editorial composition with a left-side story panel and a right-side stack of process cards.\"\n      />\n      <div className=\"asv-split-shell\">\n        <aside className=\"asv-split-story\">\n          <p className=\"asv-mini-label\">Why it lands</p>\n          <h3>The process reads like a point of view, not just a checklist.</h3>\n          <p>\n            This direction gives the section a persuasive frame first, then lets the steps act as evidence. It feels\n            more premium and more homepage-worthy.\n          </p>\n          <div className=\"asv-story-note\">\n            <span>Strategy first</span>\n            <ArrowRight size={16} />\n            <span>Execution with measurable follow-through</span>\n          </div>\n        </aside>\n        <div className=\"asv-split-list\">\n          {steps.map((step, index) => {\n            const Icon = step.icon;\n\n            return (\n              <article key={step.title} className=\"asv-split-card\" style={{ [\"--accent\" as string]: step.accent }}>\n                <div className=\"asv-split-card__top\">\n                  <span className=\"asv-mini-label\">Step 0{index + 1}</span>\n                  <Icon />\n                </div>\n                <h3>{step.title}</h3>\n                <p>{step.description}</p>\n                <strong>{step.outcome}</strong>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"asv-section\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Editorial Ladder\"\n        body=\"One featured opening panel and a staggered step ladder give the process a stronger focal point and better pacing.\"\n      />\n      <OurApproachSection\n        sectionId=\"approach-variant-three\"\n        eyebrow=\"Our Approach\"\n        title=\"A process designed to create momentum, not just deliverables.\"\n        description=\"Good outcomes come from disciplined sequencing. Each phase sharpens the next, so strategy, execution, and optimization work as one continuous system.\"\n        featureEyebrow=\"Flagship message\"\n        featureTitle=\"Good outcomes come from disciplined sequencing.\"\n        featureDescription=\"Instead of treating every phase as equal visual weight, this version emphasizes the overall promise and lets the steps cascade beside it.\"\n        steps={steps}\n        backgroundColor=\"transparent\"\n      />\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"asv-section asv-section--radial\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Orbit Framework\"\n        body=\"A central strategy hub with steps orbiting around it. More expressive and distinct, while still keeping the process readable.\"\n      />\n      <div className=\"asv-radial-grid\">\n        <article className=\"asv-radial-core\">\n          <div className=\"asv-radial-core__inner\">\n            <Sparkles />\n            <h3>Strategy with a feedback loop</h3>\n            <p>Each phase informs the next, and optimization feeds back into better discovery.</p>\n          </div>\n        </article>\n        {steps.map((step, index) => {\n          const Icon = step.icon;\n\n          return (\n            <article\n              key={step.title}\n              className={`asv-radial-card asv-radial-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: step.accent }}\n            >\n              <Icon />\n              <h3>{step.title}</h3>\n              <p>{step.description}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"asv-section asv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Command Board\"\n        body=\"A darker premium option that gives the process more contrast and makes the section feel like a strategic control panel.\"\n      />\n      <div className=\"asv-midnight-shell\">\n        <aside className=\"asv-midnight-aside\">\n          <span className=\"asv-chip asv-chip--light\">Operating model</span>\n          <h3>A process that reduces risk while increasing momentum.</h3>\n          <p>\n            This direction breaks the page rhythm more aggressively, which helps the section feel more intentional and\n            more persuasive.\n          </p>\n        </aside>\n        <div className=\"asv-midnight-grid\">\n          {steps.map((step, index) => {\n            const Icon = step.icon;\n\n            return (\n              <article key={step.title} className=\"asv-midnight-card\" style={{ [\"--accent\" as string]: step.accent }}>\n                <div className=\"asv-midnight-card__top\">\n                  <span className=\"asv-chip asv-chip--light\">0{index + 1}</span>\n                  <Icon />\n                </div>\n                <h3>{step.title}</h3>\n                <p>{step.description}</p>\n                <strong>{step.outcome}</strong>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function OurApproachSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"approach-section-lab\">\n        <section className=\"asv-hero\">\n          <div className=\"asv-hero-inner\">\n            <Link to=\"/solutions\" className=\"asv-back-link\">\n              <ArrowLeft />\n              Back to Solutions\n            </Link>\n            <p className=\"asv-eyebrow\">Our Approach Explorations</p>\n            <h1>Five stronger directions for the Solutions page process section.</h1>\n            <p>\n              These variations keep the same four-step process, but push the visual hierarchy, pacing, and emotional\n              pull much harder than a standard card row.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ResourcesFaqVariantsPage.tsx","content":"import { ArrowLeft, ArrowRight, BookMarked, Compass, Library, MessagesSquare, Sparkles } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport {\n  ResourcesFaqCollectionsSection,\n  type ResourcesFaqCollectionItem,\n} from \"@/app/components/sections\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/resources-faq-variants.css\";\n\nconst collections: ResourcesFaqCollectionItem[] = [\n  {\n    title: \"Web Design FAQ\",\n    href: \"/faqs/web-design\",\n    preview: [\n      \"What should a modern business website include?\",\n      \"How long does a redesign usually take?\",\n      \"How do we measure conversion improvements?\",\n    ],\n    eyebrow: \"Planning\",\n    accent: \"#a62025\",\n  },\n  {\n    title: \"Webflow FAQ\",\n    href: \"/faqs/webflow\",\n    preview: [\n      \"Is Webflow suitable for marketing teams?\",\n      \"How does Webflow compare to WordPress maintenance?\",\n      \"Can Webflow support multi-page service sites?\",\n    ],\n    eyebrow: \"Platform\",\n    accent: \"#c9923d\",\n  },\n  {\n    title: \"AI & AEO FAQ\",\n    href: \"/faqs/ai-aeo\",\n    preview: [\n      \"What is the difference between SEO and AEO?\",\n      \"How do answer engines evaluate content quality?\",\n      \"Where should businesses start with AI implementation?\",\n    ],\n    eyebrow: \"AI Search\",\n    accent: \"#6b4a1e\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"rfv-header\">\n      <p className=\"rfv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction FaqLink({ href, label = \"View full FAQ\" }: { href: string; label?: string }) {\n  return (\n    <Link to={href} className=\"rfv-link\">\n      {label}\n      <ArrowRight />\n    </Link>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <ResourcesFaqCollectionsSection\n      eyebrow=\"Variant 1\"\n      title=\"Refined FAQ Collection Cards\"\n      description=\"A sharper version of the current section with stronger spacing, cleaner hierarchy, and more intentional card polish.\"\n      collections={collections}\n    />\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"rfv-section rfv-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Guided Answer Paths\"\n        body=\"A left-side narrative frame helps explain why the FAQs matter, while the collection cards on the right stay easy to browse.\"\n      />\n      <div className=\"rfv-split-shell\">\n        <aside className=\"rfv-story\">\n          <div className=\"rfv-flag\">\n            <MessagesSquare />\n            Common objections\n          </div>\n          <h3>Answer the questions people ask before they reach out.</h3>\n          <p>\n            This direction gives the section a clearer strategic role and turns the FAQ collections into decision-support content instead of a generic utility block.\n          </p>\n        </aside>\n        <div className=\"rfv-split-list\">\n          {collections.map((collection) => (\n            <article key={collection.title} className=\"rfv-card rfv-card--row\">\n              <div>\n                <span className=\"rfv-chip\" style={{ color: collection.accent }}>\n                  {collection.eyebrow}\n                </span>\n                <h3>{collection.title}</h3>\n                <ul>\n                  {collection.preview.map((item) => (\n                    <li key={item}>{item}</li>\n                  ))}\n                </ul>\n              </div>\n              <FaqLink href={collection.href} />\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"rfv-section rfv-section--shelves\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Knowledge Shelves\"\n        body=\"A more literal library metaphor that frames the FAQs as a collection of practical references instead of another card grid.\"\n      />\n      <div className=\"rfv-shelves\">\n        {collections.map((collection) => (\n          <article key={collection.title} className=\"rfv-shelf\">\n            <div className=\"rfv-shelf-spine\" style={{ backgroundColor: collection.accent }} />\n            <div className=\"rfv-shelf-body\">\n              <span className=\"rfv-chip\">{collection.eyebrow}</span>\n              <h3>{collection.title}</h3>\n              <ul>\n                {collection.preview.map((item) => (\n                  <li key={item}>{item}</li>\n                ))}\n              </ul>\n            </div>\n            <FaqLink href={collection.href} />\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"rfv-section rfv-section--atlas\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Answer Atlas\"\n        body=\"A more expressive layout that treats the FAQ collections as territories on a map, giving the section a distinct visual identity while keeping the content straightforward.\"\n      />\n      <div className=\"rfv-atlas\">\n        <article className=\"rfv-atlas-core\">\n          <div className=\"rfv-flag\">\n            <Compass />\n            Answer map\n          </div>\n          <h3>Give visitors a clearer path to the answers they need.</h3>\n          <p>\n            This concept is more exploratory, but it still works as a clean list of FAQ collections with clear next clicks.\n          </p>\n        </article>\n        {collections.map((collection, index) => (\n          <article\n            key={collection.title}\n            className={`rfv-atlas-card rfv-atlas-card--${index + 1}`}\n            style={{ [\"--accent\" as string]: collection.accent }}\n          >\n            <span className=\"rfv-chip\">{collection.eyebrow}</span>\n            <h3>{collection.title}</h3>\n            <ul>\n              {collection.preview.map((item) => (\n                <li key={item}>{item}</li>\n              ))}\n            </ul>\n            <FaqLink href={collection.href} />\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"rfv-section rfv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Answer Console\"\n        body=\"A darker, premium treatment that makes the FAQ collections feel more curated and gives the page a stronger confidence shift near the bottom.\"\n      />\n      <div className=\"rfv-midnight-shell\">\n        <aside className=\"rfv-midnight-aside\">\n          <div className=\"rfv-flag rfv-flag--light\">\n            <Sparkles />\n            Confidence layer\n          </div>\n          <h3>Make the FAQ collections feel like a strategic tool, not leftover content.</h3>\n          <p>\n            This direction creates a stronger visual break and gives the section more presence, while still presenting the same three collection paths.\n          </p>\n        </aside>\n        <div className=\"rfv-midnight-grid\">\n          {collections.map((collection) => (\n            <article key={collection.title} className=\"rfv-midnight-card\">\n              <div className=\"rfv-midnight-top\">\n                <Library />\n                <span className=\"rfv-chip rfv-chip--light\">{collection.eyebrow}</span>\n              </div>\n              <h3>{collection.title}</h3>\n              <ul>\n                {collection.preview.map((item) => (\n                  <li key={item}>{item}</li>\n                ))}\n              </ul>\n              <FaqLink href={collection.href} />\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function ResourcesFaqVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"resources-faq-lab\">\n        <section className=\"rfv-hero\">\n          <div className=\"rfv-hero-inner\">\n            <Link to=\"/resources\" className=\"rfv-back-link\">\n              <ArrowLeft />\n              Back to Resources\n            </Link>\n            <p className=\"rfv-eyebrow\">Resources FAQ Explorations</p>\n            <h1>Five directions for the Resources page FAQ collections section.</h1>\n            <p>\n              These concepts are built specifically for showcasing FAQ collections, not individual accordion questions. They keep the same MIS tone and palette while exploring stronger ways to organize and frame the content.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ResourcesPage.tsx","content":"import { useEffect, useState } from \"react\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport {\n  BlogLatestGridSection,\n  FinalCTASection,\n  GuidesEditorialSection,\n  HeroSection,\n  type BlogLatestGridItem,\n  type GuidesEditorialItem,\n  ResourcesFaqCollectionsSection,\n  type ResourcesFaqCollectionItem,\n} from \"@/app/components/sections\";\nimport { Section, Container } from \"@/app/components/ui/layout\";\nimport blogImageOne from \"@/assets/24a40fea387d6d870b36715ebf5f41ccc1196a04.png\";\nimport blogImageTwo from \"@/assets/53cf0a9d13b54d45ba6d8faaf8dde556b80e4b8f.png\";\nimport blogImageThree from \"@/assets/7345e90366d343ada99455fe5e0c1de849dd5f34.png\";\nimport blogImageFour from \"@/assets/8ed6481142f4588cada7b6b9a2dbaffa2a6b4855.png\";\nimport { fetchBlogPosts, type BlogPostRecord } from \"@/app/lib/contentApi\";\n\nconst guides: GuidesEditorialItem[] = [\n  {\n    title: \"Webflow vs WordPress Guide\",\n    description:\n      \"Compare platform tradeoffs, governance, publishing speed, and long-term maintenance costs before committing.\",\n    href: \"/guides/webflow-vs-wordpress\",\n    eyebrow: \"Platform Strategy\",\n    accent: \"#a62025\",\n  },\n  {\n    title: \"Website Redesign Checklist\",\n    description:\n      \"Use a practical step-by-step checklist to reduce redesign risk and align UX, SEO, and conversion goals.\",\n    href: \"/guides/website-redesign-checklist\",\n    eyebrow: \"Planning Framework\",\n    accent: \"#c9923d\",\n  },\n  {\n    title: \"Cost of Web Design in Albuquerque\",\n    description:\n      \"Understand pricing ranges, delivery scope, and budget planning for business websites in the New Mexico market.\",\n    href: \"/guides/web-design-cost-albuquerque\",\n    eyebrow: \"Budget Clarity\",\n    accent: \"#c76438\",\n  },\n  {\n    title: \"AI for Small Businesses Guide\",\n    description:\n      \"Identify realistic AI opportunities that improve team output, reduce manual work, and support measurable growth.\",\n    href: \"/guides/ai-for-small-businesses\",\n    eyebrow: \"AI Adoption\",\n    accent: \"#6b4a1e\",\n  },\n];\n\nconst blogPosts: BlogLatestGridItem[] = [\n  {\n    title: \"How To Improve Local Search Visibility for Service Businesses\",\n    excerpt:\n      \"A practical framework for increasing qualified local traffic with stronger intent alignment and trust cues.\",\n    href: \"/blog/improve-local-search-visibility\",\n    image: blogImageOne,\n    category: \"Local SEO\",\n    published: \"March 18, 2026\",\n  },\n  {\n    title: \"AEO Basics: Structuring Pages for AI-Powered Answers\",\n    excerpt:\n      \"Learn the page architecture and schema fundamentals that help content surface in answer-first experiences.\",\n    href: \"/blog/aeo-basics-structured-content\",\n    image: blogImageTwo,\n    category: \"AEO\",\n    published: \"March 10, 2026\",\n  },\n  {\n    title: \"When a Website Redesign Is Strategic, Not Cosmetic\",\n    excerpt:\n      \"Signals that your current site is holding back growth and how to scope redesign work around outcomes.\",\n    href: \"/blog/strategic-website-redesign-signals\",\n    image: blogImageThree,\n    category: \"Website Strategy\",\n    published: \"February 25, 2026\",\n  },\n  {\n    title: \"Using AI To Reduce Operational Bottlenecks\",\n    excerpt:\n      \"A measured approach to workflow automation that improves reliability without adding technical complexity.\",\n    href: \"/blog/ai-for-operations-workflows\",\n    image: blogImageFour,\n    category: \"Operations AI\",\n    published: \"February 11, 2026\",\n  },\n];\n\nconst fallbackBlogImageBySlug: Record<string, string> = {\n  \"improve-local-search-visibility\": blogImageOne,\n  \"aeo-basics-structured-content\": blogImageTwo,\n  \"strategic-website-redesign-signals\": blogImageThree,\n  \"ai-for-operations-workflows\": blogImageFour,\n};\n\nconst fallbackBlogMetaBySlug: Record<string, Pick<BlogLatestGridItem, \"category\" | \"published\">> = {\n  \"improve-local-search-visibility\": {\n    category: \"Local SEO\",\n    published: \"March 18, 2026\",\n  },\n  \"aeo-basics-structured-content\": {\n    category: \"AEO\",\n    published: \"March 10, 2026\",\n  },\n  \"strategic-website-redesign-signals\": {\n    category: \"Website Strategy\",\n    published: \"February 25, 2026\",\n  },\n  \"ai-for-operations-workflows\": {\n    category: \"Operations AI\",\n    published: \"February 11, 2026\",\n  },\n};\n\nconst faqCollections: ResourcesFaqCollectionItem[] = [\n  {\n    title: \"Web Design FAQ\",\n    href: \"/faqs/web-design\",\n    preview: [\n      \"What should a modern business website include?\",\n      \"How long does a redesign usually take?\",\n      \"How do we measure conversion improvements?\",\n    ],\n    eyebrow: \"Planning\",\n    accent: \"#a62025\",\n  },\n  {\n    title: \"Webflow FAQ\",\n    href: \"/faqs/webflow\",\n    preview: [\n      \"Is Webflow suitable for marketing teams?\",\n      \"How does Webflow compare to WordPress maintenance?\",\n      \"Can Webflow support multi-page service sites?\",\n    ],\n    eyebrow: \"Platform\",\n    accent: \"#c9923d\",\n  },\n  {\n    title: \"AI & AEO FAQ\",\n    href: \"/faqs/ai-aeo\",\n    preview: [\n      \"What is the difference between SEO and AEO?\",\n      \"How do answer engines evaluate content quality?\",\n      \"Where should businesses start with AI implementation?\",\n    ],\n    eyebrow: \"AI Search\",\n    accent: \"#6b4a1e\",\n  },\n];\n\nfunction ResourcesPageMetadata() {\n  useEffect(() => {\n    document.title =\n      \"Resources — Guides, FAQs & Blog for Web Design, AI, SEO | MIS, Inc\";\n\n    const description =\n      \"Explore guides, FAQs, and blog insights on web design, AI, SEO, and AEO to support smarter digital decisions and growth.\";\n\n    const upsertMetaByName = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\"${name}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    const upsertMetaByProperty = (property: string, content: string) => {\n      let meta = document.querySelector(`meta[property=\"${property}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"property\", property);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMetaByName(\"description\", description);\n    upsertMetaByProperty(\"og:title\", document.title);\n    upsertMetaByProperty(\"og:description\", description);\n    upsertMetaByProperty(\"og:type\", \"website\");\n    upsertMetaByProperty(\"og:url\", \"https://www.misinc.com/resources\");\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", \"https://www.misinc.com/resources\");\n\n    let preload = document.querySelector(\"link[data-resources-preload=''hero-blog'']\");\n    if (!preload) {\n      preload = document.createElement(\"link\");\n      preload.setAttribute(\"data-resources-preload\", \"hero-blog\");\n      preload.setAttribute(\"rel\", \"preload\");\n      preload.setAttribute(\"as\", \"image\");\n      preload.setAttribute(\"href\", blogImageOne);\n      document.head.appendChild(preload);\n    }\n  }, []);\n\n  return null;\n}\n\nexport default function ResourcesPage() {\n  const [dbBlogPosts, setDbBlogPosts] = useState<BlogLatestGridItem[]>(blogPosts);\n\n  useEffect(() => {\n    let isActive = true;\n    const loadBlogPosts = async () => {\n      const rows = await fetchBlogPosts();\n      if (!rows || !isActive || rows.length === 0) {\n        return;\n      }\n\n      const mapped = rows.map((post: BlogPostRecord) => ({\n        title: post.title,\n        excerpt: post.excerpt,\n        href: `/blog/${post.slug}`,\n        image: post.imageUrl || fallbackBlogImageBySlug[post.slug] || blogImageOne,\n        category: fallbackBlogMetaBySlug[post.slug]?.category || \"Insights\",\n        published: fallbackBlogMetaBySlug[post.slug]?.published || \"Recent article\",\n      }));\n\n      setDbBlogPosts(mapped);\n    };\n\n    void loadBlogPosts();\n    return () => {\n      isActive = false;\n    };\n  }, []);\n\n  const guidesItemListSchema = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"ItemList\",\n    name: \"MIS Guides and Evergreen Resources\",\n    itemListElement: guides.map((guide, index) => ({\n      \"@type\": \"ListItem\",\n      position: index + 1,\n      name: guide.title,\n      url: `https://www.misinc.com${guide.href}`,\n    })),\n  };\n\n  const blogItemListSchema = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"ItemList\",\n    name: \"MIS Recent Blog Posts\",\n    itemListElement: dbBlogPosts.map((post, index) => ({\n      \"@type\": \"ListItem\",\n      position: index + 1,\n      name: post.title,\n      url: `https://www.misinc.com${post.href}`,\n    })),\n  };\n\n  return (\n    <SiteShell>\n      <ResourcesPageMetadata />\n      <script type=\"application/ld+json\">{JSON.stringify(guidesItemListSchema)}</script>\n      <script type=\"application/ld+json\">{JSON.stringify(blogItemListSchema)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <HeroSection\n          sectionId=\"resources-hero\"\n          eyebrow=\"Resources Hub\"\n          title=\"Resources to Learn, Decide, and Grow Your Business\"\n          description=\"This resource hub helps business teams find clear answers, practical frameworks, and strategic guidance for digital growth. Use it to compare options, understand best practices, and make confident decisions about web design, SEO, and AI-enabled operations.\"\n          primaryAction={{\n            label: \"Explore Guides\",\n            scrollToId: \"guides\",\n            variant: \"primary\",\n          }}\n          secondaryAction={{\n            label: \"Browse Blog Posts\",\n            scrollToId: \"blog\",\n            variant: \"secondary\",\n          }}\n          supplemental={\n            <p className=\"text-sm text-[#4A3F37] md:text-base\">\n              Trusted insights from 30+ years of building digital systems.\n            </p>\n          }\n        />\n\n        <Section variant=\"flush\">\n          <Container size=\"standard\">\n            <nav\n              aria-label=\"Resources section navigation\"\n              className=\"flex flex-wrap items-center justify-center gap-3 border-y border-border py-6 text-sm\"\n            >\n              <a className=\"text-muted-foreground transition-colors hover:text-foreground\" href=\"#guides\">\n                Guides\n              </a>\n              <a className=\"text-muted-foreground transition-colors hover:text-foreground\" href=\"#blog\">\n                Blog\n              </a>\n              <a className=\"text-muted-foreground transition-colors hover:text-foreground\" href=\"#resources-cta\">\n                Next Step\n              </a>\n            </nav>\n          </Container>\n        </Section>\n\n        <GuidesEditorialSection\n          sectionId=\"guides\"\n          title=\"Practical Guides for Growing Businesses\"\n          description=\"Explore clear, practical guides that help you compare options, plan smarter, and make more confident decisions about your website, marketing, and growth strategy.\"\n          guides={guides}\n          backgroundColor=\"#f6efe3\"\n        />\n\n        <BlogLatestGridSection\n          sectionId=\"blog\"\n          title=\"From the Blog\"\n          description=\"Explore timely insights, implementation notes, and strategic updates from our team.\"\n          posts={dbBlogPosts}\n          viewAllHref=\"/blog\"\n          viewAllLabel=\"View All Blog Posts\"\n          backgroundColor=\"#fffaf2\"\n        />\n\n        <ResourcesFaqCollectionsSection\n          sectionId=\"faqs\"\n          title=\"Frequently Asked Questions\"\n          description=\"Review dedicated FAQ collections that answer common business questions across digital strategy, web platforms, and AI-led visibility.\"\n          collections={faqCollections}\n          backgroundColor=\"#f0e2cf\"\n        />\n\n        <FinalCTASection\n          sectionId=\"resources-cta\"\n          eyebrow=\"Next Step\"\n          title=\"Need a Clear Next Move?\"\n          description=\"If you''re sorting through options for your website, growth strategy, or AI implementation, we can help you turn that research into a practical plan.\"\n          actionLabel=\"Schedule a Strategy Call\"\n          actionTo=\"/contact\"\n          footnote=\"No-pressure consult. Clear recommendations and a practical next step.\"\n          backgroundColor=\"#eadcc6\"\n        />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ServiceDetailTemplatePage.tsx","content":"import { useEffect, useState } from \"react\";\nimport { Link, useParams } from \"react-router\";\nimport { ArrowRight } from \"lucide-react\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { Section, Container } from \"@/app/components/ui/layout\";\nimport { Button } from \"@/app/components/ui/button\";\nimport { Badge } from \"@/app/components/ui/badge\";\nimport {\n  Card,\n  CardHeader,\n  CardTitle,\n  CardContent,\n  CardDescription,\n  CardFooter,\n} from \"@/app/components/ui/card\";\nimport {\n  Accordion,\n  AccordionContent,\n  AccordionItem,\n  AccordionTrigger,\n} from \"@/app/components/ui/accordion\";\nimport {\n  getServiceDetailBySlug,\n  SERVICE_PROCESS,\n} from \"@/app/data/serviceDetails\";\nimport { fetchServiceBySlug, type ServiceDetailRecord } from \"@/app/lib/contentApi\";\n\nfunction ServiceDetailMetadata({\n  title,\n  description,\n  canonicalUrl,\n  ogTitle,\n  ogDescription,\n  ogType = \"website\",\n}: {\n  title: string;\n  description: string;\n  canonicalUrl: string;\n  ogTitle: string;\n  ogDescription: string;\n  ogType?: string;\n}) {\n  useEffect(() => {\n    document.title = title;\n\n    const upsertMetaByName = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\"${name}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    const upsertMetaByProperty = (property: string, content: string) => {\n      let meta = document.querySelector(`meta[property=\"${property}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"property\", property);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMetaByName(\"description\", description);\n    upsertMetaByProperty(\"og:title\", ogTitle);\n    upsertMetaByProperty(\"og:description\", ogDescription);\n    upsertMetaByProperty(\"og:type\", ogType);\n    upsertMetaByProperty(\"og:url\", canonicalUrl);\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", canonicalUrl);\n  }, [canonicalUrl, description, ogDescription, ogTitle, ogType, title]);\n\n  return null;\n}\n\nexport default function ServiceDetailTemplatePage() {\n  const { slug } = useParams();\n  const fallbackService = getServiceDetailBySlug(slug ?? \"\");\n  const [service, setService] = useState(fallbackService);\n\n  useEffect(() => {\n    const requestedSlug = slug ?? \"\";\n    if (!requestedSlug) {\n      return;\n    }\n\n    let isActive = true;\n    const loadService = async () => {\n      const remoteService = await fetchServiceBySlug(requestedSlug);\n      if (!remoteService || !isActive) {\n        return;\n      }\n\n      const mappedService = {\n        slug: remoteService.slug,\n        serviceName: remoteService.serviceName,\n        heroTitle: remoteService.heroTitle,\n        heroDescription: remoteService.heroDescription,\n        quickAnswer: remoteService.quickAnswer,\n        challenges: (remoteService.challenges ?? []) as string[],\n        outcomes: (remoteService.outcomes ?? []) as string[],\n        deliverables: (remoteService.deliverables ?? []) as ServiceDetailRecord[\"deliverables\"],\n        idealFor: (remoteService.idealFor ?? []) as string[],\n        proofQuote: remoteService.proofQuote,\n        proofAttribution: remoteService.proofAttribution,\n        proofMetrics: (remoteService.proofMetrics ?? []) as string[],\n        caseStudyHref: remoteService.caseStudyHref,\n        solutionHref: remoteService.solutionHref,\n        relatedServiceSlugs: (remoteService.relatedServiceSlugs ?? []) as string[],\n        faqs: (remoteService.faqs ?? []) as ServiceDetailRecord[\"faqs\"],\n        seoTitle: remoteService.seoTitle,\n        seoDescription: remoteService.seoDescription,\n        canonicalPath: remoteService.canonicalPath,\n      };\n\n      setService(mappedService);\n    };\n\n    void loadService();\n    return () => {\n      isActive = false;\n    };\n  }, [slug]);\n\n  if (!service) {\n    return (\n      <SiteShell>\n        <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n          <SiteHeader>\n            <MainNavbar />\n          </SiteHeader>\n        </div>\n        <main className=\"flex-1\">\n          <Section variant=\"hero\">\n            <Container size=\"medium\">\n              <div className=\"text-center\">\n                <h1 className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\">\n                  Service Not Found\n                </h1>\n                <p className=\"mt-4 text-base leading-loose text-muted-foreground\">\n                  The requested service page is not available. Explore all available\n                  services or review solution pages.\n                </p>\n                <div className=\"mt-8 flex flex-col items-center justify-center gap-3 sm:flex-row\">\n                  <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                    <Link to=\"/services\">Explore All Services</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to=\"/solutions\">View Solutions</Link>\n                  </Button>\n                </div>\n              </div>\n            </Container>\n          </Section>\n        </main>\n        <SiteFooter />\n      </SiteShell>\n    );\n  }\n\n  const canonicalUrl = `https://www.misinc.com${service.canonicalPath}`;\n  const trustSignals = [\n    \"30 Years of Experience\",\n    \"Albuquerque, New Mexico\",\n    \"Strategic + Technical Execution\",\n  ];\n\n  const relatedServices = service.relatedServiceSlugs\n    .map((relatedSlug) => getServiceDetailBySlug(relatedSlug))\n    .filter((entry): entry is NonNullable<typeof entry> => Boolean(entry))\n    .slice(0, 4);\n\n  const faqStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"FAQPage\",\n    mainEntity: service.faqs.map((faq) => ({\n      \"@type\": \"Question\",\n      name: faq.question,\n      acceptedAnswer: {\n        \"@type\": \"Answer\",\n        text: faq.answer,\n      },\n    })),\n  };\n\n  const professionalServiceStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"ProfessionalService\",\n    name: \"MIS, Inc.\",\n    serviceType: service.serviceName,\n    areaServed: [\"New Mexico\", \"United States\"],\n    provider: {\n      \"@type\": \"Organization\",\n      name: \"MIS, Inc.\",\n    },\n    url: canonicalUrl,\n  };\n\n  return (\n    <SiteShell>\n      <ServiceDetailMetadata\n        title={service.seoTitle}\n        description={service.seoDescription}\n        canonicalUrl={canonicalUrl}\n        ogTitle={service.seoTitle}\n        ogDescription={service.seoDescription}\n      />\n      <script type=\"application/ld+json\">\n        {JSON.stringify(professionalServiceStructuredData)}\n      </script>\n      <script type=\"application/ld+json\">{JSON.stringify(faqStructuredData)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <Section variant=\"hero\">\n          <Container size=\"standard\">\n            <div className=\"mx-auto max-w-4xl text-center\">\n              <Badge variant=\"secondary\" className=\"mb-4\">\n                {service.serviceName}\n              </Badge>\n              <h1 className=\"text-4xl font-medium leading-tight text-foreground md:text-5xl\">\n                {service.heroTitle}\n              </h1>\n              <p className=\"mt-5 text-base leading-loose text-muted-foreground md:text-lg\">\n                {service.heroDescription}\n              </p>\n              <div className=\"mt-8 flex flex-col items-center justify-center gap-3 sm:flex-row\">\n                <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                  <Link to=\"/#contact\">Schedule a Strategy Call</Link>\n                </Button>\n                <Button\n                  variant=\"outline\"\n                  className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                  asChild\n                >\n                  <Link to=\"/case-studies\">View Case Studies</Link>\n                </Button>\n              </div>\n              <ul className=\"mt-6 flex flex-col items-center justify-center gap-2 text-sm text-muted-foreground sm:flex-row sm:gap-6\">\n                {trustSignals.map((signal) => (\n                  <li key={signal} className=\"flex items-center gap-2\">\n                    <span aria-hidden=\"true\" className=\"size-1.5 rounded-full bg-primary\" />\n                    <span>{signal}</span>\n                  </li>\n                ))}\n              </ul>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"medium\">\n            <div className=\"mx-auto max-w-4xl\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                What Is {service.serviceName}?\n              </h2>\n              <p className=\"mt-4 text-base leading-loose text-muted-foreground\">\n                {service.quickAnswer}\n              </p>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-10\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Challenges This Service Solves\n              </h2>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 lg:grid-cols-2\">\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Common pain points\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <ul className=\"space-y-3 text-base leading-relaxed text-muted-foreground\">\n                    {service.challenges.map((challenge) => (\n                      <li key={challenge} className=\"flex items-start gap-2\">\n                        <span className=\"mt-2 size-1.5 rounded-full bg-primary\" />\n                        <span>{challenge}</span>\n                      </li>\n                    ))}\n                  </ul>\n                </CardContent>\n              </Card>\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Outcome-focused results\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <ul className=\"space-y-3 text-base leading-relaxed text-muted-foreground\">\n                    {service.outcomes.map((outcome) => (\n                      <li key={outcome} className=\"flex items-start gap-2\">\n                        <span className=\"mt-2 size-1.5 rounded-full bg-primary\" />\n                        <span>{outcome}</span>\n                      </li>\n                    ))}\n                  </ul>\n                </CardContent>\n              </Card>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mb-10\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                What&apos;s Included\n              </h2>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2\">\n              {service.deliverables.map((deliverable) => (\n                <Card key={deliverable.title} className=\"border-border bg-card\">\n                  <CardHeader>\n                    <CardTitle className=\"text-xl leading-snug text-foreground md:text-2xl\">\n                      {deliverable.title}\n                    </CardTitle>\n                  </CardHeader>\n                  <CardContent>\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {deliverable.description}\n                    </CardDescription>\n                  </CardContent>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"grid grid-cols-1 gap-6 lg:grid-cols-2\">\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                    Who This Service Is Best For\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <ul className=\"space-y-3 text-base leading-relaxed text-muted-foreground\">\n                    {service.idealFor.map((entry) => (\n                      <li key={entry} className=\"flex items-start gap-2\">\n                        <span className=\"mt-2 size-1.5 rounded-full bg-primary\" />\n                        <span>{entry}</span>\n                      </li>\n                    ))}\n                  </ul>\n                </CardContent>\n              </Card>\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Need a broader strategy context?\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                    This service is part of a complete growth system. Explore the\n                    matching solution path and related case studies to evaluate fit.\n                  </CardDescription>\n                </CardContent>\n                <CardFooter className=\"flex flex-col items-start gap-3 sm:flex-row\">\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to={service.solutionHref}>View Related Solution</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to=\"/services\">Explore All Services</Link>\n                  </Button>\n                </CardFooter>\n              </Card>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mb-10\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Our Approach\n              </h2>\n            </div>\n            <ol className=\"grid grid-cols-1 gap-4 md:grid-cols-2 xl:grid-cols-4\">\n              {SERVICE_PROCESS.map((step, index) => (\n                <li key={step.title}>\n                  <Card className=\"h-full border-border bg-card\">\n                    <CardHeader>\n                      <p className=\"text-sm font-medium uppercase tracking-wide text-primary\">\n                        Step {index + 1}\n                      </p>\n                      <CardTitle className=\"text-xl leading-snug text-foreground\">\n                        {step.title}\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent>\n                      <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                        {step.description}\n                      </CardDescription>\n                    </CardContent>\n                  </Card>\n                </li>\n              ))}\n            </ol>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-10\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Proven Results\n              </h2>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 lg:grid-cols-3\">\n              <Card className=\"border-border bg-card lg:col-span-2\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Client perspective\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <blockquote className=\"border-l-2 border-primary pl-4 text-base leading-loose text-muted-foreground\">\n                    “{service.proofQuote}”\n                  </blockquote>\n                  <p className=\"mt-4 text-sm text-foreground/80\">{service.proofAttribution}</p>\n                </CardContent>\n              </Card>\n              <Card className=\"border-border bg-card\">\n                <CardHeader>\n                  <CardTitle className=\"text-2xl leading-snug text-foreground\">\n                    Measurable outcomes\n                  </CardTitle>\n                </CardHeader>\n                <CardContent>\n                  <ul className=\"space-y-3 text-base leading-relaxed text-muted-foreground\">\n                    {service.proofMetrics.map((metric) => (\n                      <li key={metric} className=\"flex items-start gap-2\">\n                        <span className=\"mt-2 size-1.5 rounded-full bg-primary\" />\n                        <span>{metric}</span>\n                      </li>\n                    ))}\n                  </ul>\n                </CardContent>\n                <CardFooter>\n                  <Link\n                    to={service.caseStudyHref}\n                    className=\"inline-flex items-center gap-2 text-sm font-medium tracking-wide text-primary transition-opacity hover:opacity-70\"\n                  >\n                    View related case study\n                    <ArrowRight className=\"size-4\" />\n                  </Link>\n                </CardFooter>\n              </Card>\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mb-10\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Related Services\n              </h2>\n            </div>\n            <div className=\"grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4\">\n              {relatedServices.map((relatedService) => (\n                <Card key={relatedService.slug} className=\"border-border bg-card\">\n                  <CardHeader>\n                    <CardTitle className=\"text-xl leading-snug text-foreground\">\n                      {relatedService.serviceName}\n                    </CardTitle>\n                  </CardHeader>\n                  <CardContent>\n                    <CardDescription className=\"text-base leading-loose text-muted-foreground\">\n                      {relatedService.heroDescription}\n                    </CardDescription>\n                  </CardContent>\n                  <CardFooter>\n                    <Link\n                      to={`/services/${relatedService.slug}`}\n                      className=\"inline-flex items-center gap-2 text-sm font-medium tracking-wide text-primary transition-opacity hover:opacity-70\"\n                    >\n                      View service\n                      <ArrowRight className=\"size-4\" />\n                    </Link>\n                  </CardFooter>\n                </Card>\n              ))}\n            </div>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\">\n          <Container size=\"standard\">\n            <div className=\"mb-8\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Frequently Asked Questions\n              </h2>\n            </div>\n            <Accordion\n              type=\"single\"\n              collapsible\n              className=\"w-full rounded-lg border border-border bg-card px-6 md:px-8\"\n            >\n              {service.faqs.map((faq, index) => (\n                <AccordionItem key={faq.question} value={`faq-${index + 1}`}>\n                  <AccordionTrigger className=\"text-base leading-relaxed text-foreground hover:no-underline\">\n                    {faq.question}\n                  </AccordionTrigger>\n                  <AccordionContent className=\"text-base leading-loose text-muted-foreground\">\n                    {faq.answer}\n                  </AccordionContent>\n                </AccordionItem>\n              ))}\n            </Accordion>\n          </Container>\n        </Section>\n\n        <Section variant=\"cta\" tone=\"warm\">\n          <Container size=\"medium\">\n            <Card className=\"border-border bg-card text-center\">\n              <CardHeader>\n                <CardTitle className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                  Let&apos;s Plan Your {service.serviceName}\n                </CardTitle>\n              </CardHeader>\n              <CardContent>\n                <CardDescription className=\"mx-auto max-w-3xl text-base leading-loose text-muted-foreground\">\n                  Clear scope. Transparent process. No pressure.\n                </CardDescription>\n                <div className=\"mt-8 flex flex-col items-center justify-center gap-3 sm:flex-row\">\n                  <Button className=\"rounded-full px-6 py-6 text-sm tracking-wide\" asChild>\n                    <Link to=\"/#contact\">Schedule a Strategy Call</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-primary/60 px-6 py-6 text-sm tracking-wide text-primary\"\n                    asChild\n                  >\n                    <Link to=\"/services\">Explore All Services</Link>\n                  </Button>\n                </div>\n              </CardContent>\n            </Card>\n          </Container>\n        </Section>\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <nav aria-label=\"Service navigation links\" className=\"flex flex-wrap gap-3 text-sm\">\n              <Link to=\"/services\" className=\"text-primary hover:underline\">\n                All services\n              </Link>\n              <Link to={service.solutionHref} className=\"text-primary hover:underline\">\n                Related solution\n              </Link>\n              <Link to=\"/case-studies\" className=\"text-primary hover:underline\">\n                Case studies\n              </Link>\n            </nav>\n          </Container>\n        </Section>\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ServicesOutcomesVariantsPage.tsx","content":"import { ArrowLeft, ArrowRight } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/services-outcomes-variants.css\";\n\ntype GoalCard = {\n  title: string;\n  problem: string;\n  serviceLinks: { label: string; href: string }[];\n  eyebrow: string;\n  accent: string;\n};\n\nconst goals: GoalCard[] = [\n  {\n    title: \"Generate More Qualified Leads\",\n    problem:\n      \"Traffic is reaching your site, but the right prospects are not converting into booked conversations.\",\n    serviceLinks: [\n      { label: \"Web Design & Redesign\", href: \"/services/web-design\" },\n      { label: \"SEO Strategy\", href: \"/services/seo-strategy\" },\n      { label: \"AEO Services\", href: \"/services/aeo-services\" },\n    ],\n    eyebrow: \"Demand Quality\",\n    accent: \"#A62025\",\n  },\n  {\n    title: \"Increase Conversion Rates\",\n    problem:\n      \"Your site looks credible but fails to turn interest into inquiries, consultations, or revenue opportunities.\",\n    serviceLinks: [\n      { label: \"Webflow Development\", href: \"/services/webflow-development\" },\n      { label: \"Web Design & Redesign\", href: \"/services/web-design\" },\n    ],\n    eyebrow: \"Revenue Efficiency\",\n    accent: \"#C9923D\",\n  },\n  {\n    title: \"Streamline Internal Workflows\",\n    problem:\n      \"Teams spend too much time on repetitive tasks, manual updates, and disconnected operational systems.\",\n    serviceLinks: [\n      { label: \"Custom Applications\", href: \"/services/custom-applications\" },\n      { label: \"AI Consulting & Automation\", href: \"/services/ai-consulting\" },\n    ],\n    eyebrow: \"Operational Flow\",\n    accent: \"#FF9902\",\n  },\n  {\n    title: \"Improve Google Rankings\",\n    problem:\n      \"Important service pages are difficult to find in search and underperform against local or regional competitors.\",\n    serviceLinks: [\n      { label: \"SEO Strategy\", href: \"/services/seo-strategy\" },\n      { label: \"Webflow Development\", href: \"/services/webflow-development\" },\n      { label: \"Web Design & Redesign\", href: \"/services/web-design\" },\n    ],\n    eyebrow: \"Search Visibility\",\n    accent: \"#8D6A2A\",\n  },\n  {\n    title: \"Improve AI Search Visibility\",\n    problem:\n      \"Prospects are using AI tools for discovery, but your brand rarely appears in direct-answer responses.\",\n    serviceLinks: [\n      { label: \"AEO Services\", href: \"/services/aeo-services\" },\n      { label: \"AI Consulting & Automation\", href: \"/services/ai-consulting\" },\n    ],\n    eyebrow: \"Answer Engines\",\n    accent: \"#6B4A1E\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"sov-header\">\n      <p className=\"sov-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction ServicePills({\n  serviceLinks,\n  light = false,\n}: {\n  serviceLinks: GoalCard[\"serviceLinks\"];\n  light?: boolean;\n}) {\n  return (\n    <div className={`sov-pill-row ${light ? \"is-light\" : \"\"}`}>\n      {serviceLinks.map((link, index) => (\n        <span key={link.label} className=\"sov-pill-item\">\n          <Link to={link.href} className=\"sov-pill\">\n            {link.label}\n          </Link>\n          {index < serviceLinks.length - 1 ? <span className=\"sov-pill-separator\">/</span> : null}\n        </span>\n      ))}\n    </div>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"sov-section sov-section--editorial\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Editorial Decision Grid\"\n        body=\"A stronger version of the current section with more rhythm, bolder card framing, and clearer visual entry points.\"\n      />\n      <div className=\"sov-editorial-grid\">\n        {goals.map((goal, index) => {\n          return (\n            <article\n              key={goal.title}\n              className={`sov-editorial-card sov-editorial-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: goal.accent }}\n            >\n              <div className=\"sov-editorial-top\">\n                <span className=\"sov-card-index\">0{index + 1}</span>\n                <span className=\"sov-card-chip\">{goal.eyebrow}</span>\n              </div>\n              <h3>{goal.title}</h3>\n              <p>{goal.problem}</p>\n              <ServicePills serviceLinks={goal.serviceLinks} />\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"sov-section sov-section--split\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Narrative Split\"\n        body=\"A left-side decision frame and right-side outcome cards make the section feel more strategic and less like a neutral utility grid.\"\n      />\n      <div className=\"sov-split-shell\">\n        <aside className=\"sov-story\">\n          <p className=\"sov-mini-label\">Decision model</p>\n          <h3>Pick the business result first. Let the services follow that priority.</h3>\n          <p>\n            This direction makes the section feel like a guided diagnostic instead of a list of options. It creates a\n            stronger reason to keep scrolling and click with intent.\n          </p>\n          <div className=\"sov-story-note\">\n            <span>5 outcome paths</span>\n            <ArrowRight size={16} />\n            <span>Focused service recommendations</span>\n          </div>\n        </aside>\n        <div className=\"sov-split-list\">\n          {goals.map((goal, index) => (\n            <article key={goal.title} className=\"sov-split-card\" style={{ [\"--accent\" as string]: goal.accent }}>\n              <div className=\"sov-split-card__lead\">\n                <span className=\"sov-card-index\">0{index + 1}</span>\n                <span className=\"sov-card-chip\">{goal.eyebrow}</span>\n              </div>\n              <div className=\"sov-split-card__body\">\n                <h3>{goal.title}</h3>\n                <p>{goal.problem}</p>\n                <ServicePills serviceLinks={goal.serviceLinks} />\n              </div>\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  const featured = goals[0];\n\n  return (\n    <section className=\"sov-section sov-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Mosaic Priority Board\"\n        body=\"One featured flagship outcome with supporting cards around it creates a clearer focal point and better pacing than five equal blocks.\"\n      />\n      <div className=\"sov-mosaic-grid\">\n        <article className=\"sov-mosaic-hero\" style={{ [\"--accent\" as string]: featured.accent }}>\n          <div className=\"sov-mosaic-hero__top\">\n            <span className=\"sov-card-chip\">{featured.eyebrow}</span>\n            <span className=\"sov-card-index\">01</span>\n          </div>\n          <h3>{featured.title}</h3>\n          <p>{featured.problem}</p>\n          <ServicePills serviceLinks={featured.serviceLinks} />\n        </article>\n\n        {goals.slice(1).map((goal, index) => (\n          <article key={goal.title} className=\"sov-mosaic-card\" style={{ [\"--accent\" as string]: goal.accent }}>\n            <div className=\"sov-mosaic-card__top\">\n              <span className=\"sov-card-chip\">{goal.eyebrow}</span>\n              <span className=\"sov-card-index\">0{index + 2}</span>\n            </div>\n            <h3>{goal.title}</h3>\n            <p>{goal.problem}</p>\n            <ServicePills serviceLinks={goal.serviceLinks} />\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"sov-section sov-section--rail\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Outcome Rail\"\n        body=\"A horizontal-feeling rail with numbered steps makes the options feel more guided and more systematized.\"\n      />\n      <div className=\"sov-rail-shell\">\n        <article className=\"sov-rail-intro\">\n          <p className=\"sov-mini-label\">Guided selection</p>\n          <h3>Move from the business problem to the right service cluster.</h3>\n          <p>\n            This version gives the section an actual path to follow instead of compressing five cards into a shallow\n            row. The rail feels more editorial and much less cramped.\n          </p>\n        </article>\n        <div className=\"sov-rail-track\">\n          <div className=\"sov-rail-line\" />\n          {goals.map((goal, index) => (\n            <article\n              key={goal.title}\n              className={`sov-rail-card sov-rail-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: goal.accent }}\n            >\n              <div className=\"sov-rail-card__top\">\n                <span className=\"sov-card-index\">0{index + 1}</span>\n                <span className=\"sov-card-chip\">{goal.eyebrow}</span>\n              </div>\n              <h3>{goal.title}</h3>\n              <p>{goal.problem}</p>\n              <ServicePills serviceLinks={goal.serviceLinks} />\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"sov-section sov-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Midnight Outcome Console\"\n        body=\"A darker premium direction that gives the section more contrast and makes the decision paths feel more intentional.\"\n      />\n      <div className=\"sov-midnight-shell\">\n        <aside className=\"sov-midnight-aside\">\n          <span className=\"sov-chip sov-chip--light\">Outcome selector</span>\n          <h3>Frame the services around buyer intent, not internal categories.</h3>\n          <p>\n            This breaks the page rhythm more aggressively and makes the section feel like a strategic control panel\n            instead of another warm card block.\n          </p>\n        </aside>\n        <div className=\"sov-midnight-grid\">\n          {goals.map((goal, index) => (\n            <article key={goal.title} className=\"sov-midnight-card\" style={{ [\"--accent\" as string]: goal.accent }}>\n              <div className=\"sov-midnight-card__top\">\n                <span className=\"sov-chip sov-chip--light\">{goal.eyebrow}</span>\n                <span className=\"sov-card-index\">0{index + 1}</span>\n              </div>\n              <h3>{goal.title}</h3>\n              <p>{goal.problem}</p>\n              <ServicePills serviceLinks={goal.serviceLinks} light />\n            </article>\n          ))}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function ServicesOutcomesVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"services-outcomes-lab\">\n        <section className=\"sov-hero\">\n          <div className=\"sov-hero-inner\">\n            <Link to=\"/services\" className=\"sov-back-link\">\n              <ArrowLeft />\n              Back to Services\n            </Link>\n            <p className=\"sov-eyebrow\">Outcome Section Explorations</p>\n            <h1>Five stronger directions for the Services page outcome selector.</h1>\n            <p>\n              These variations keep the same five buyer outcomes and linked services, but push the hierarchy,\n              composition, and visual pressure much harder than the current soft card grid.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ServicesPage.tsx","content":"import { useEffect } from \"react\";\nimport { Link } from \"react-router\";\nimport { ArrowRight, Bot, Globe, Layers3 } from \"lucide-react\";\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardHeader,\n  CardTitle,\n} from \"@/app/components/ui/card\";\nimport {\n  Accordion,\n  AccordionContent,\n  AccordionItem,\n  AccordionTrigger,\n} from \"@/app/components/ui/accordion\";\nimport { Container, Section } from \"@/app/components/ui/layout\";\nimport {\n  CapabilitiesBridgeSection,\n  FinalCTASection,\n  HeroSection,\n  OurApproachSection,\n} from \"@/app/components/sections\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport servicesHeroVideo from \"@/assets/bg-hero-video.mp4\";\nimport \"@/styles/services-page.css\";\n\ntype FaqItem = {\n  question: string;\n  answer: string;\n};\n\nconst coreCapabilities = [\n  {\n    title: \"Web Design & Development\",\n    description:\n      \"Websites built to clarify your offer, earn trust quickly, and support long-term growth.\",\n    href: \"/services/web-design\",\n    icon: Globe,\n    accent: \"#A62025\",\n    eyebrow: \"Digital Foundation\",\n    ctaLabel: \"View service\",\n  },\n  {\n    title: \"Custom Applications\",\n    description:\n      \"Purpose-built tools and integrations that reduce manual work and fit the way your team actually operates.\",\n    href: \"/services/custom-applications\",\n    icon: Layers3,\n    accent: \"#FF9902\",\n    eyebrow: \"Operational Systems\",\n    ctaLabel: \"View service\",\n  },\n  {\n    title: \"AI Solutions\",\n    description:\n      \"Practical AI strategy and automation that create leverage, improve execution speed, and support smarter workflows.\",\n    href: \"/services/ai-consulting\",\n    icon: Bot,\n    accent: \"#6B4A1E\",\n    eyebrow: \"Efficiency Multiplier\",\n    ctaLabel: \"View service\",\n  },\n];\n\nconst faqs: FaqItem[] = [\n  {\n    question: \"How much does a professional website cost?\",\n    answer:\n      \"Project cost depends on scope, content complexity, integrations, and timeline. Most engagements are scoped after strategy discovery so the investment aligns with your business goals. We provide clear deliverables and pricing before work begins.\",\n  },\n  {\n    question: \"How long does a typical project take?\",\n    answer:\n      \"Most website projects run between six and twelve weeks depending on complexity and feedback cadence. Larger builds involving custom applications or automation can extend beyond that range. We provide a phased timeline with milestones at kickoff.\",\n  },\n  {\n    question: \"What is the difference between SEO and AEO?\",\n    answer:\n      \"SEO focuses on improving rankings in search engine result pages and driving qualified organic traffic. AEO services focus on helping your content appear in direct answers, AI summaries, and conversational search results. Together they improve visibility across both traditional and AI search behavior.\",\n  },\n  {\n    question: \"Is Webflow better than WordPress?\",\n    answer:\n      \"Webflow is often better for teams that need visual control, speed, and easier ongoing content management with fewer plugin dependencies. WordPress can still be a fit for certain legacy ecosystems. We recommend based on your operational needs, not a one-size-fits-all preference.\",\n  },\n  {\n    question: \"How can AI consulting help my business?\",\n    answer:\n      \"AI consulting helps identify high-impact workflows where automation can save time, reduce errors, and improve responsiveness. We prioritize practical use cases tied to measurable outcomes instead of novelty. Typical wins include streamlined operations and faster internal execution.\",\n  },\n  {\n    question: \"Do you work with companies outside New Mexico?\",\n    answer:\n      \"Yes. MIS, Inc. is based in Albuquerque, New Mexico, and we work with organizations across the United States. Remote collaboration is built into our process with structured communication and milestone reviews.\",\n  },\n  {\n    question: \"Do I need all services at once?\",\n    answer:\n      \"No. Most clients start with one priority outcome and phase additional services over time. We help define the right sequence so you can move forward without unnecessary complexity or spend.\",\n  },\n];\n\nconst trustSignals = [\n  \"30 Years of Experience\",\n  \"Albuquerque, New Mexico\",\n  \"Strategic + Technical Execution\",\n];\n\nfunction ServicesPageMetadata() {\n  useEffect(() => {\n    document.title = \"Web Design & AI Services in Albuquerque | MIS, Inc.\";\n\n    const description =\n      \"Explore web design, webflow development, SEO, AEO, and AI consulting services in Albuquerque for lead growth, visibility, and scalable execution.\";\n\n    const upsertMeta = (name: string, content: string) => {\n      let meta = document.querySelector(`meta[name=\"${name}\"]`);\n      if (!meta) {\n        meta = document.createElement(\"meta\");\n        meta.setAttribute(\"name\", name);\n        document.head.appendChild(meta);\n      }\n      meta.setAttribute(\"content\", content);\n    };\n\n    upsertMeta(\"description\", description);\n\n    let canonical = document.querySelector(\"link[rel=''canonical'']\");\n    if (!canonical) {\n      canonical = document.createElement(\"link\");\n      canonical.setAttribute(\"rel\", \"canonical\");\n      document.head.appendChild(canonical);\n    }\n    canonical.setAttribute(\"href\", \"https://www.misinc.com/services\");\n  }, []);\n\n  return null;\n}\n\nexport default function ServicesPage() {\n  const faqStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"FAQPage\",\n    mainEntity: faqs.map((faq) => ({\n      \"@type\": \"Question\",\n      name: faq.question,\n      acceptedAnswer: {\n        \"@type\": \"Answer\",\n        text: faq.answer,\n      },\n    })),\n  };\n\n  const professionalServiceStructuredData = {\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"ProfessionalService\",\n    name: \"MIS, Inc.\",\n    areaServed: \"New Mexico\",\n    serviceType: [\n      \"Web Design\",\n      \"Webflow Development\",\n      \"AI Consulting\",\n      \"AEO Services\",\n    ],\n    url: \"https://www.misinc.com/services\",\n  };\n\n  return (\n    <SiteShell>\n      <ServicesPageMetadata />\n      <script type=\"application/ld+json\">\n        {JSON.stringify(professionalServiceStructuredData)}\n      </script>\n      <script type=\"application/ld+json\">{JSON.stringify(faqStructuredData)}</script>\n\n      <div className=\"content-stretch relative flex w-full shrink-0 flex-col items-center\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <HeroSection\n          sectionId=\"services-hero\"\n          className=\"services-page-hero\"\n          eyebrow=\"Services Overview\"\n          title={\n            <>\n              Web Design, Development, and AI Services for Growth-Focused Businesses\n            </>\n          }\n          description=\"We help businesses generate better leads, improve visibility, automate high-friction workflows, and build scalable digital systems that support long-term growth.\"\n          backgroundVideoSrc={servicesHeroVideo}\n          primaryAction={{\n            label: \"Schedule a Strategy Call\",\n            to: \"/contact\",\n            variant: \"primary\",\n          }}\n          secondaryAction={{\n            label: \"Explore Services\",\n            scrollToId: \"services-core-capabilities\",\n            variant: \"secondary\",\n          }}\n          supplemental={\n            <ul className=\"services-hero-trust\">\n              {trustSignals.map((signal) => (\n                <li key={signal}>\n                  <span aria-hidden=\"true\" className=\"services-hero-trust-dot\" />\n                  <span>{signal}</span>\n                </li>\n              ))}\n            </ul>\n          }\n        />\n\n        <CapabilitiesBridgeSection\n          sectionId=\"services-core-capabilities\"\n          eyebrow=\"Core Capabilities\"\n          title=\"Three service areas that power every solution we deliver.\"\n          description=\"From high-performing websites to custom operational tools to practical AI systems, these are the core capabilities behind our solution work.\"\n          capabilities={coreCapabilities}\n          backgroundColor=\"#fafafa\"\n        />\n\n        <OurApproachSection\n          sectionId=\"our-approach\"\n          eyebrow=\"Our Approach\"\n          title=\"A process designed to create momentum, not just deliverables.\"\n          description=\"Good outcomes come from disciplined sequencing. Each phase sharpens the next, so strategy, execution, and optimization work as one continuous system.\"\n          featureEyebrow=\"Flagship message\"\n          featureTitle=\"Good outcomes come from disciplined sequencing.\"\n          featureDescription=\"Instead of treating every phase as equal visual weight, this version emphasizes the overall promise and lets the steps cascade beside it.\"\n          backgroundColor=\"var(--mis-bg-soft)\"\n        />\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <div className=\"mb-8 flex flex-col gap-4\">\n              <h2 className=\"text-3xl font-medium leading-snug text-foreground md:text-4xl\">\n                Frequently Asked Questions\n              </h2>\n              <p className=\"max-w-3xl text-base leading-loose text-muted-foreground\">\n                Direct answers to high-intent buyer questions about webflow\n                development, AI consulting, SEO, and AEO services.\n              </p>\n            </div>\n\n            <div className=\"services-page-faq-shell\">\n              <Accordion type=\"single\" collapsible className=\"services-page-faq\">\n                {faqs.map((faq, index) => (\n                  <AccordionItem key={faq.question} value={`faq-${index + 1}`}>\n                    <AccordionTrigger className=\"services-page-faq-trigger\">\n                      <span>{faq.question}</span>\n                    </AccordionTrigger>\n                    <AccordionContent className=\"services-page-faq-content\">\n                      {faq.answer}\n                    </AccordionContent>\n                  </AccordionItem>\n                ))}\n              </Accordion>\n            </div>\n          </Container>\n        </Section>\n\n        <FinalCTASection\n          sectionId=\"services-cta\"\n          eyebrow=\"Next Step\"\n          title=\"Ready to Plan the Right Service Mix?\"\n          description=\"Tell us what you need to improve next and we’ll help map the service path that makes the most sense for your goals, constraints, and timeline.\"\n          actionLabel=\"Schedule a Strategy Call\"\n          actionTo=\"/contact\"\n          footnote=\"No-pressure consult. Clear next steps.\"\n        />\n\n        <Section variant=\"standard\" tone=\"muted\">\n          <Container size=\"standard\">\n            <nav aria-label=\"Related pages\" className=\"flex flex-wrap items-center gap-3 text-sm\">\n              <span className=\"font-medium text-foreground\">Explore more:</span>\n              <Link to=\"/solutions\" className=\"text-primary hover:underline\">\n                Solutions overview\n              </Link>\n              <Link to=\"/solutions/small-businesses\" className=\"text-primary hover:underline\">\n                Small business solution\n              </Link>\n              <Link to=\"/resources\" className=\"text-primary hover:underline\">\n                Resources\n              </Link>\n            </nav>\n          </Container>\n        </Section>\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/ServicesSectionVariantsPage.tsx","content":"import type { ComponentType, SVGProps } from \"react\";\nimport { ArrowLeft, ArrowRight, Bot, Globe, Layers3, ShoppingBag, Stethoscope } from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport \"@/styles/services-section-variants.css\";\n\ntype IconComponent = ComponentType<SVGProps<SVGSVGElement>>;\n\ntype ServiceCard = {\n  title: string;\n  description: string;\n  eyebrow: string;\n  icon: IconComponent;\n  accent: string;\n};\n\nconst services: ServiceCard[] = [\n  {\n    title: \"Web Design That Converts\",\n    description:\n      \"Modern, conversion-optimized websites built on Webflow and Square Online that grow with your business and adapt to changing needs.\",\n    eyebrow: \"Growth Foundation\",\n    icon: Globe,\n    accent: \"var(--mis-primary)\",\n  },\n  {\n    title: \"Custom Applications\",\n    description:\n      \"Tailored web applications and integrations designed to solve your specific business challenges and streamline operations.\",\n    eyebrow: \"Operational Systems\",\n    icon: Layers3,\n    accent: \"var(--mis-brand-red)\",\n  },\n  {\n    title: \"AI & Automation\",\n    description:\n      \"Forward-thinking AI integration, workflow automation, and implementation strategy that create leverage across your business.\",\n    eyebrow: \"Efficiency Multiplier\",\n    icon: Bot,\n    accent: \"#c9923d\",\n  },\n];\n\nconst industrySignals = [\n  { label: \"Healthcare\", icon: Stethoscope },\n  { label: \"Retail / Ecommerce\", icon: ShoppingBag },\n  { label: \"Professional Services\", icon: ArrowRight },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <div className=\"ssv-header\">\n      <p className=\"ssv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </div>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"ssv-section ssv-section--editorial\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Editorial Stripe\"\n        body=\"A staggered, magazine-like layout that gives each service its own moment and a stronger sense of motion.\"\n      />\n      <div className=\"ssv-editorial-grid\">\n        {services.map((service, index) => {\n          const Icon = service.icon;\n\n          return (\n            <article key={service.title} className={`ssv-editorial-card ssv-editorial-card--${index + 1}`}>\n              <div className=\"ssv-editorial-bar\" style={{ backgroundColor: service.accent }} />\n              <span className=\"ssv-editorial-index\">0{index + 1}</span>\n              <div className=\"ssv-icon-wrap\" style={{ color: service.accent }}>\n                <Icon />\n              </div>\n              <p className=\"ssv-card-eyebrow\">{service.eyebrow}</p>\n              <h3>{service.title}</h3>\n              <p>{service.description}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"ssv-section ssv-section--spotlight\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Spotlight Band\"\n        body=\"A darker, higher-contrast section that lets the services feel more premium and creates a stronger break in the homepage flow.\"\n      />\n      <div className=\"ssv-spotlight-shell\">\n        <div className=\"ssv-spotlight-copy\">\n          <p className=\"ssv-card-eyebrow\">Strategic Technology for Growing Businesses</p>\n          <h3>Clear offers. Clear outcomes. A stronger visual story.</h3>\n          <p>\n            This direction makes the Services section feel like a flagship moment instead of a neutral card row.\n          </p>\n        </div>\n        <div className=\"ssv-spotlight-grid\">\n          {services.map((service) => {\n            const Icon = service.icon;\n\n            return (\n              <article key={service.title} className=\"ssv-spotlight-card\">\n                <div className=\"ssv-icon-wrap\" style={{ color: service.accent }}>\n                  <Icon />\n                </div>\n                <h3>{service.title}</h3>\n                <p>{service.description}</p>\n                <span className=\"ssv-pill\" style={{ borderColor: service.accent, color: service.accent }}>\n                  {service.eyebrow}\n                </span>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"ssv-section ssv-section--rail\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Center-Weighted Rail\"\n        body=\"A horizontal composition with one featured middle card, giving the section a stronger focal point and more deliberate pacing.\"\n      />\n      <div className=\"ssv-rail-grid\">\n        {services.map((service, index) => {\n          const Icon = service.icon;\n          const featured = index === 1;\n\n          return (\n            <article key={service.title} className={`ssv-rail-card ${featured ? \"is-featured\" : \"\"}`}>\n              <div className=\"ssv-rail-top\">\n                <p className=\"ssv-card-eyebrow\">{service.eyebrow}</p>\n                <div className=\"ssv-icon-wrap\" style={{ color: service.accent }}>\n                  <Icon />\n                </div>\n              </div>\n              <h3>{service.title}</h3>\n              <p>{service.description}</p>\n              <div className=\"ssv-rail-line\" style={{ backgroundColor: service.accent }} />\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"ssv-section ssv-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Mosaic Storyboard\"\n        body=\"A more sculpted, mixed-scale layout that feels more custom and less template-like while still being easy to scan.\"\n      />\n      <div className=\"ssv-mosaic-grid\">\n        <article className=\"ssv-mosaic-hero\">\n          <p className=\"ssv-card-eyebrow\">Flagship Offer</p>\n          <h3>{services[0].title}</h3>\n          <p>{services[0].description}</p>\n          <div className=\"ssv-signal-row\">\n            {industrySignals.map((signal) => {\n              const Icon = signal.icon;\n\n              return (\n                <span key={signal.label} className=\"ssv-signal\">\n                  <Icon />\n                  {signal.label}\n                </span>\n              );\n            })}\n          </div>\n        </article>\n        <article className=\"ssv-mosaic-card\">\n          <p className=\"ssv-card-eyebrow\">{services[1].eyebrow}</p>\n          <h3>{services[1].title}</h3>\n          <p>{services[1].description}</p>\n        </article>\n        <article className=\"ssv-mosaic-card ssv-mosaic-card--accent\">\n          <p className=\"ssv-card-eyebrow\">{services[2].eyebrow}</p>\n          <h3>{services[2].title}</h3>\n          <p>{services[2].description}</p>\n        </article>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"ssv-section ssv-section--stacked\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Stacked Cards With Side Narrative\"\n        body=\"A split layout that gives the section a stronger narrative frame on the left and more expressive service cards on the right.\"\n      />\n      <div className=\"ssv-stacked-shell\">\n        <aside className=\"ssv-stacked-aside\">\n          <p className=\"ssv-card-eyebrow\">Why this works</p>\n          <h3>More visual pressure, less generic repetition.</h3>\n          <p>\n            The current homepage section communicates well, but it does not claim enough attention. This variation uses hierarchy and contrast to earn the scroll stop.\n          </p>\n          <Link to=\"/\" className=\"ssv-inline-link\">\n            Back to homepage\n            <ArrowLeft />\n          </Link>\n        </aside>\n        <div className=\"ssv-stacked-list\">\n          {services.map((service) => {\n            const Icon = service.icon;\n\n            return (\n              <article key={service.title} className=\"ssv-stacked-card\">\n                <div className=\"ssv-icon-wrap\" style={{ color: service.accent }}>\n                  <Icon />\n                </div>\n                <div>\n                  <p className=\"ssv-card-eyebrow\">{service.eyebrow}</p>\n                  <h3>{service.title}</h3>\n                  <p>{service.description}</p>\n                </div>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function ServicesSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"services-section-lab\">\n        <section className=\"ssv-hero\">\n          <div className=\"ssv-hero-inner\">\n            <Link to=\"/\" className=\"ssv-back-link\">\n              <ArrowLeft />\n              Back to Home\n            </Link>\n            <p className=\"ssv-eyebrow\">Services Section Explorations</p>\n            <h1>Five stronger directions for the homepage Services section.</h1>\n            <p>\n              These variations keep the same offer structure and brand palette, but push the layout, rhythm, and emphasis much harder than the current white-card grid.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/SolutionDetailPage.tsx","content":"import { Link, useParams } from \"react-router\";\nimport { ArrowRight, CheckCircle2 } from \"lucide-react\";\nimport { Button } from \"@/app/components/ui/button\";\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardHeader,\n  CardTitle,\n} from \"@/app/components/ui/card\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\n\ntype Capability = {\n  title: string;\n  description: string;\n  href: string;\n};\n\ntype SolutionContent = {\n  audience: string;\n  heroTitle: string;\n  heroDescription: string;\n  painTitle: string;\n  pains: string[];\n  outcomes: string[];\n  capabilities: Capability[];\n  testimonialQuote: string;\n  testimonialName: string;\n  testimonialRole: string;\n  metricLabel: string;\n  metricValue: string;\n};\n\nconst solutionContentMap: Record<string, SolutionContent> = {\n  \"small-businesses\": {\n    audience: \"Small Businesses\",\n    heroTitle: \"Web & Digital Growth Solutions for Small Businesses\",\n    heroDescription:\n      \"Turn your website into a dependable growth engine with better lead flow, clearer messaging, and systems that reduce day-to-day operational friction.\",\n    painTitle: \"Common Growth Challenges Small Businesses Face\",\n    pains: [\n      \"Inconsistent lead quality from outdated websites\",\n      \"Limited internal bandwidth to manage digital systems\",\n      \"Disconnected tools causing manual, repetitive work\",\n      \"Low visibility in search and AI-powered discovery\",\n    ],\n    outcomes: [\n      \"Higher-quality inbound inquiries from ideal customers\",\n      \"Faster response workflows with integrated automations\",\n      \"Stronger local and regional digital visibility\",\n      \"A scalable website foundation aligned to growth goals\",\n    ],\n    capabilities: [\n      {\n        title: \"Albuquerque Web Design\",\n        description:\n          \"Conversion-focused website design that reflects your brand and improves action rates.\",\n        href: \"/services/albuquerque-web-design\",\n      },\n      {\n        title: \"Webflow Development\",\n        description:\n          \"Fast, maintainable implementation with CMS control for your team.\",\n        href: \"/services/webflow-development\",\n      },\n      {\n        title: \"AI Consulting\",\n        description:\n          \"Practical AI opportunities that save time and improve customer experience.\",\n        href: \"/services/ai-consulting\",\n      },\n      {\n        title: \"AEO Services\",\n        description:\n          \"Optimization for both traditional search and AI answer engines.\",\n        href: \"/services/aeo-services\",\n      },\n    ],\n    testimonialQuote:\n      \"MIS helped us simplify our digital stack and improve qualified leads without adding complexity.\",\n    testimonialName: \"Operations Director\",\n    testimonialRole: \"Local Services Company\",\n    metricLabel: \"Qualified Lead Growth\",\n    metricValue: \"+42%\",\n  },\n  \"real-estate\": {\n    audience: \"Real Estate\",\n    heroTitle: \"Web & Digital Growth Solutions for Real Estate Teams\",\n    heroDescription:\n      \"Build a high-trust digital presence that captures, nurtures, and converts property interest into measurable pipeline growth.\",\n    painTitle: \"Common Real Estate Digital Challenges\",\n    pains: [\n      \"High traffic but low lead-to-appointment conversion\",\n      \"Fragmented listing, CRM, and follow-up systems\",\n      \"Difficulty standing out in competitive local markets\",\n      \"Slow content updates across active property pages\",\n    ],\n    outcomes: [\n      \"Improved conversion from listings to consultations\",\n      \"Faster handoff between website and sales workflows\",\n      \"More authority in local search and AI visibility\",\n      \"Streamlined content operations for active inventory\",\n    ],\n    capabilities: [\n      {\n        title: \"Web Design & Redesign\",\n        description: \"Trust-oriented layouts for high-consideration buying journeys.\",\n        href: \"/services/albuquerque-web-design\",\n      },\n      {\n        title: \"Custom Applications\",\n        description: \"Custom listing and inquiry flows integrated with your systems.\",\n        href: \"/services/custom-applications\",\n      },\n      {\n        title: \"Square Website Design\",\n        description: \"Commerce-capable experiences for brokerages and service upsells.\",\n        href: \"/services/square-website-design\",\n      },\n      {\n        title: \"AEO Services\",\n        description: \"Content strategy optimized for modern AI-driven discovery.\",\n        href: \"/services/aeo-services\",\n      },\n    ],\n    testimonialQuote:\n      \"The new experience made our team look more premium and improved inquiry quality almost immediately.\",\n    testimonialName: \"Managing Broker\",\n    testimonialRole: \"Regional Real Estate Group\",\n    metricLabel: \"Inquiry-to-Meeting Rate\",\n    metricValue: \"+33%\",\n  },\n  nonprofits: {\n    audience: \"Nonprofits\",\n    heroTitle: \"Web & Digital Growth Solutions for Nonprofits\",\n    heroDescription:\n      \"Strengthen donor trust, increase program visibility, and improve supporter engagement with a mission-centered digital foundation.\",\n    painTitle: \"Common Nonprofit Challenges\",\n    pains: [\n      \"Mission impact is hard to communicate online\",\n      \"Donation and volunteer paths are difficult to navigate\",\n      \"Limited capacity for content and technical updates\",\n      \"Disconnected tools for campaigns and reporting\",\n    ],\n    outcomes: [\n      \"Improved donation and volunteer conversion paths\",\n      \"Clearer storytelling tied to measurable impact\",\n      \"Operational efficiency through integrated workflows\",\n      \"A scalable platform for campaigns and long-term growth\",\n    ],\n    capabilities: [\n      {\n        title: \"Webflow Development\",\n        description: \"Flexible CMS architecture for campaigns, programs, and stories.\",\n        href: \"/services/webflow-development\",\n      },\n      {\n        title: \"AI Consulting\",\n        description: \"Automated supporter communications and internal workflow support.\",\n        href: \"/services/ai-consulting\",\n      },\n      {\n        title: \"AEO Services\",\n        description: \"Increase discoverability for mission topics in search and AI.\",\n        href: \"/services/aeo-services\",\n      },\n      {\n        title: \"Custom Applications\",\n        description: \"Program and donor workflow tools built around your operations.\",\n        href: \"/services/custom-applications\",\n      },\n    ],\n    testimonialQuote:\n      \"MIS translated our mission into a clearer digital experience that improved supporter action.\",\n    testimonialName: \"Executive Director\",\n    testimonialRole: \"Community Nonprofit\",\n    metricLabel: \"Donation Conversion Lift\",\n    metricValue: \"+28%\",\n  },\n  \"professional-services\": {\n    audience: \"Professional Services\",\n    heroTitle: \"Web & Digital Growth Solutions for Professional Services\",\n    heroDescription:\n      \"Position your firm as the clear strategic choice with a website that supports credibility, trust, and complex buying decisions.\",\n    painTitle: \"Common Professional Services Challenges\",\n    pains: [\n      \"Generic web presence that fails to communicate expertise\",\n      \"Long sales cycles with weak digital nurture touchpoints\",\n      \"Difficult content governance across practice areas\",\n      \"Low differentiation in crowded competitive markets\",\n    ],\n    outcomes: [\n      \"Stronger authority and buyer confidence online\",\n      \"Better lead qualification through clear positioning\",\n      \"Structured content systems for scalable thought leadership\",\n      \"Improved digital performance across target service lines\",\n    ],\n    capabilities: [\n      {\n        title: \"Albuquerque Web Design\",\n        description: \"Premium positioning and conversion strategy for high-trust buyers.\",\n        href: \"/services/albuquerque-web-design\",\n      },\n      {\n        title: \"Webflow Development\",\n        description: \"Maintainable multi-practice content architecture and governance.\",\n        href: \"/services/webflow-development\",\n      },\n      {\n        title: \"AEO Services\",\n        description: \"Authority-building content for search and AI response visibility.\",\n        href: \"/services/aeo-services\",\n      },\n      {\n        title: \"AI Consulting\",\n        description: \"Internal process and client-experience workflow automation.\",\n        href: \"/services/ai-consulting\",\n      },\n    ],\n    testimonialQuote:\n      \"Our new digital experience finally reflects the level of strategy and quality we deliver to clients.\",\n    testimonialName: \"Partner\",\n    testimonialRole: \"Advisory Firm\",\n    metricLabel: \"Qualified Consultation Requests\",\n    metricValue: \"+37%\",\n  },\n  \"startups-saas\": {\n    audience: \"Startups & SaaS\",\n    heroTitle: \"Web & Digital Growth Solutions for Startups & SaaS\",\n    heroDescription:\n      \"Accelerate traction with conversion-focused positioning, faster experimentation, and scalable growth systems aligned to your go-to-market strategy.\",\n    painTitle: \"Common Startup & SaaS Growth Challenges\",\n    pains: [\n      \"Messaging that does not clearly communicate product value\",\n      \"Low trial or demo conversion from website traffic\",\n      \"Limited resources for rapid web and funnel iteration\",\n      \"Weak visibility in high-intent category searches\",\n    ],\n    outcomes: [\n      \"Clearer product positioning and conversion pathways\",\n      \"Higher activation rates from demo and trial funnels\",\n      \"Faster campaign and content iteration cycles\",\n      \"Improved demand capture across search and AI channels\",\n    ],\n    capabilities: [\n      {\n        title: \"Webflow Development\",\n        description: \"High-velocity landing and product marketing page operations.\",\n        href: \"/services/webflow-development\",\n      },\n      {\n        title: \"Custom Applications\",\n        description: \"Workflow and product-adjacent tools tailored to your GTM motion.\",\n        href: \"/services/custom-applications\",\n      },\n      {\n        title: \"AI Consulting\",\n        description: \"Automation for onboarding, support, and growth experiments.\",\n        href: \"/services/ai-consulting\",\n      },\n      {\n        title: \"AEO Services\",\n        description: \"Visibility strategy for AI-assisted discovery and category queries.\",\n        href: \"/services/aeo-services\",\n      },\n    ],\n    testimonialQuote:\n      \"MIS gave us a clearer growth system that helped us move from traffic to consistent activation.\",\n    testimonialName: \"Head of Growth\",\n    testimonialRole: \"B2B SaaS Startup\",\n    metricLabel: \"Demo Conversion Increase\",\n    metricValue: \"+46%\",\n  },\n  \"retail-ecommerce\": {\n    audience: \"Retail / Ecommerce\",\n    heroTitle: \"Web & Digital Growth Solutions for Retail & Ecommerce Brands\",\n    heroDescription:\n      \"Increase revenue with storefront experiences built around product discovery, merchandising clarity, and lower-friction purchase paths.\",\n    painTitle: \"Common Retail & Ecommerce Growth Challenges\",\n    pains: [\n      \"Traffic reaches product pages but does not convert consistently\",\n      \"Storefront messaging does not clearly differentiate offers\",\n      \"Promotions, inventory, and campaign content are difficult to update quickly\",\n      \"Purchase, fulfillment, and retention systems are fragmented across tools\",\n    ],\n    outcomes: [\n      \"Higher conversion rates across key product and category pages\",\n      \"Stronger average order value through better merchandising structure\",\n      \"Faster campaign launches and seasonal content updates\",\n      \"Improved customer retention through smoother post-purchase workflows\",\n    ],\n    capabilities: [\n      {\n        title: \"Square Website Design\",\n        description:\n          \"Commerce-ready storefronts for product sales, local pickup, and service add-ons.\",\n        href: \"/services/square-website-design\",\n      },\n      {\n        title: \"Webflow Development\",\n        description:\n          \"Flexible landing pages, category experiences, and campaign infrastructure for growth teams.\",\n        href: \"/services/webflow-development\",\n      },\n      {\n        title: \"SEO Strategy\",\n        description:\n          \"Category and product discovery strategies that improve qualified organic traffic.\",\n        href: \"/services/seo-strategy\",\n      },\n      {\n        title: \"AI Consulting\",\n        description:\n          \"Operational automations for merchandising, service workflows, and customer support systems.\",\n        href: \"/services/ai-consulting\",\n      },\n    ],\n    testimonialQuote:\n      \"MIS helped us turn a fragmented storefront into a clearer buying journey that directly improved online sales.\",\n    testimonialName: \"Ecommerce Director\",\n    testimonialRole: \"Regional Retail Brand\",\n    metricLabel: \"Online Revenue Growth\",\n    metricValue: \"+34%\",\n  },\n};\n\nfunction NotFoundState() {\n  return (\n    <section className=\"flex w-full justify-center py-[120px]\">\n      <div className=\"w-full max-w-[900px] px-5 text-center md:px-8 lg:px-12\">\n        <h1 className=\"font-[''Manrope:Light'',sans-serif] text-[40px] leading-[1.1] text-[#151515] md:text-[56px]\">\n          Solution Not Found\n        </h1>\n        <p className=\"mx-auto mt-[16px] max-w-[680px] text-[16px] leading-[1.6] text-[#777] md:text-[20px]\">\n          The requested solution page is not available yet. Explore the solutions\n          overview to choose an audience track.\n        </p>\n        <div className=\"mt-[28px]\">\n          <Button className=\"rounded-full px-8 py-6 text-[14px] tracking-[1px]\" asChild>\n            <Link to=\"/solutions\">Back to Solutions</Link>\n          </Button>\n        </div>\n      </div>\n    </section>\n  );\n}\n\nexport default function SolutionDetailPage() {\n  const { slug } = useParams();\n  const solution = slug ? solutionContentMap[slug] : undefined;\n\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        {!solution ? (\n          <NotFoundState />\n        ) : (\n          <>\n            <section className=\"flex w-full justify-center pb-[80px] pt-[64px] md:pb-[120px] md:pt-[100px]\">\n              <div className=\"w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n                <div className=\"mx-auto flex w-full max-w-[920px] flex-col items-center gap-[24px] text-center\">\n                  <p className=\"text-[12px] font-normal uppercase tracking-[1px] text-[#9B3139]\">\n                    {solution.audience}\n                  </p>\n                  <h1 className=\"font-[''Manrope:Light'',sans-serif] text-[36px] leading-[1.1] text-[#151515] md:text-[56px] lg:text-[64px]\">\n                    {solution.heroTitle}\n                  </h1>\n                  <p className=\"max-w-[760px] text-[16px] leading-[1.6] text-[#4A3F37] md:text-[20px]\">\n                    {solution.heroDescription}\n                  </p>\n                  <div className=\"flex flex-col gap-[12px] pt-[8px] sm:flex-row\">\n                    <Button className=\"rounded-full px-6 py-6 text-[14px] tracking-[1px]\" asChild>\n                      <Link to=\"/#contact\">Schedule a Strategy Call</Link>\n                    </Button>\n                    <Button\n                      variant=\"outline\"\n                      className=\"rounded-full border-[#9B3139]/60 px-6 py-6 text-[14px] tracking-[1px] text-[#9B3139] hover:bg-black/5\"\n                      asChild\n                    >\n                      <Link to=\"/#services\">View Related Services</Link>\n                    </Button>\n                  </div>\n                </div>\n              </div>\n            </section>\n\n            <section className=\"flex w-full justify-center bg-[#fafafa] py-[80px] md:py-[120px]\">\n              <div className=\"w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n                <div className=\"mb-[36px] flex flex-col gap-[14px]\">\n                  <h2 className=\"font-[''Manrope:Light'',sans-serif] text-[32px] leading-[1.2] text-[#151515] md:text-[48px]\">\n                    {solution.painTitle}\n                  </h2>\n                  <p className=\"max-w-[700px] text-[16px] leading-[1.6] text-[#777] md:text-[18px]\">\n                    We focus on removing friction and building measurable outcomes\n                    for {solution.audience.toLowerCase()}.\n                  </p>\n                </div>\n                <div className=\"grid grid-cols-1 gap-[20px] lg:grid-cols-2\">\n                  <Card className=\"border-[#f0e6db] bg-white p-6 md:p-8\">\n                    <CardHeader className=\"p-0\">\n                      <CardTitle className=\"text-[22px] leading-[1.3] text-[#151515]\">\n                        Typical Pain Points\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent className=\"p-0 pt-[14px]\">\n                      <ul className=\"space-y-[10px] text-[15px] leading-[1.6] text-[#4A3F37]\">\n                        {solution.pains.map((pain) => (\n                          <li key={pain} className=\"flex gap-[10px]\">\n                            <span aria-hidden=\"true\" className=\"mt-[8px] h-[6px] w-[6px] shrink-0 rounded-full bg-[#9B3139]\" />\n                            <span>{pain}</span>\n                          </li>\n                        ))}\n                      </ul>\n                    </CardContent>\n                  </Card>\n                  <Card className=\"border-[#f0e6db] bg-white p-6 md:p-8\">\n                    <CardHeader className=\"p-0\">\n                      <CardTitle className=\"text-[22px] leading-[1.3] text-[#151515]\">\n                        Key Outcomes\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent className=\"p-0 pt-[14px]\">\n                      <ul className=\"space-y-[10px] text-[15px] leading-[1.6] text-[#4A3F37]\">\n                        {solution.outcomes.map((outcome) => (\n                          <li key={outcome} className=\"flex gap-[10px]\">\n                            <CheckCircle2 aria-hidden=\"true\" className=\"mt-[2px] h-5 w-5 shrink-0 text-[#9B3139]\" />\n                            <span>{outcome}</span>\n                          </li>\n                        ))}\n                      </ul>\n                    </CardContent>\n                  </Card>\n                </div>\n              </div>\n            </section>\n\n            <section className=\"flex w-full justify-center py-[80px] md:py-[120px]\">\n              <div className=\"w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n                <div className=\"mb-[36px] flex flex-col gap-[14px]\">\n                  <h2 className=\"font-[''Manrope:Light'',sans-serif] text-[32px] leading-[1.2] text-[#151515] md:text-[48px]\">\n                    How We Help\n                  </h2>\n                  <p className=\"max-w-[740px] text-[16px] leading-[1.6] text-[#777] md:text-[18px]\">\n                    A focused stack of strategy, design, engineering, and optimization\n                    capabilities designed for {solution.audience.toLowerCase()}.\n                  </p>\n                </div>\n                <div className=\"grid grid-cols-1 gap-[20px] md:grid-cols-2\">\n                  {solution.capabilities.map((capability) => (\n                    <Card\n                      key={capability.title}\n                      className=\"group border-transparent bg-[#fafafa] p-6 transition-all duration-300 hover:-translate-y-1 hover:border-[#eadfda] hover:bg-white hover:shadow-lg\"\n                    >\n                      <CardHeader className=\"p-0\">\n                        <CardTitle className=\"text-[22px] leading-[1.3] text-[#151515]\">\n                          {capability.title}\n                        </CardTitle>\n                      </CardHeader>\n                      <CardContent className=\"p-0 pt-[10px]\">\n                        <CardDescription className=\"text-[15px] leading-[1.6] text-[#777]\">\n                          {capability.description}\n                        </CardDescription>\n                        <Link\n                          to={capability.href}\n                          className=\"mt-[16px] inline-flex items-center gap-[8px] text-[14px] font-medium tracking-[1px] text-[#9B3139] transition-opacity hover:opacity-70\"\n                        >\n                          View Service\n                          <ArrowRight className=\"size-4\" />\n                        </Link>\n                      </CardContent>\n                    </Card>\n                  ))}\n                </div>\n              </div>\n            </section>\n\n            <section className=\"flex w-full justify-center bg-[#fafafa] py-[80px] md:py-[120px]\">\n              <div className=\"w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n                <div className=\"mb-[36px] flex flex-col gap-[14px]\">\n                  <h2 className=\"font-[''Manrope:Light'',sans-serif] text-[32px] leading-[1.2] text-[#151515] md:text-[48px]\">\n                    Trusted by Clients Like You\n                  </h2>\n                </div>\n                <div className=\"grid grid-cols-1 gap-[20px] lg:grid-cols-[1.2fr_1fr]\">\n                  <Card className=\"border-[#eadfda] bg-white p-6 md:p-8\">\n                    <CardContent className=\"p-0\">\n                      <blockquote className=\"text-[20px] leading-[1.5] text-[#2A2420] md:text-[24px]\">\n                        “{solution.testimonialQuote}”\n                      </blockquote>\n                      <p className=\"mt-[16px] text-[14px] text-[#777]\">\n                        {solution.testimonialName} • {solution.testimonialRole}\n                      </p>\n                    </CardContent>\n                  </Card>\n                  <Card className=\"border-[#eadfda] bg-[#fff8f0] p-6 md:p-8\">\n                    <CardHeader className=\"p-0\">\n                      <CardTitle className=\"text-[18px] leading-[1.3] text-[#151515]\">\n                        Mini Case Outcome\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent className=\"p-0 pt-[10px]\">\n                      <p className=\"text-[42px] leading-[1.1] text-[#9B3139] md:text-[52px]\">\n                        {solution.metricValue}\n                      </p>\n                      <p className=\"mt-[8px] text-[15px] leading-[1.5] text-[#4A3F37]\">\n                        {solution.metricLabel}\n                      </p>\n                      <p className=\"mt-[14px] text-[14px] leading-[1.6] text-[#777]\">\n                        Add audience-relevant client logo here.\n                      </p>\n                      <img\n                        src=\"https://via.placeholder.com/320x120\"\n                        alt={`${solution.audience} client logo placeholder`}\n                        className=\"mt-[10px] h-[70px] w-auto rounded-sm border border-[#eadfda]\"\n                      />\n                    </CardContent>\n                  </Card>\n                </div>\n              </div>\n            </section>\n\n            <section className=\"flex w-full justify-center py-[80px] md:py-[120px]\">\n              <div className=\"w-full max-w-[1200px] px-5 md:px-8 lg:px-12\">\n                <div className=\"grid grid-cols-1 gap-[20px] lg:grid-cols-[1.2fr_1fr]\">\n                  <Card className=\"border-[#eadfda] bg-white p-6 md:p-8\">\n                    <CardHeader className=\"p-0\">\n                      <CardTitle className=\"font-[''Manrope:Light'',sans-serif] text-[32px] leading-[1.2] text-[#151515] md:text-[44px]\">\n                        Why MIS Is the Right Partner\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent className=\"p-0 pt-[12px]\">\n                      <p className=\"text-[16px] leading-[1.7] text-[#4A3F37] md:text-[18px]\">\n                        With 30 years of experience and deep New Mexico market knowledge,\n                        MIS, Inc. combines strategic planning with technical execution to\n                        help organizations build digital systems that compound value over time.\n                      </p>\n                    </CardContent>\n                  </Card>\n                  <Card className=\"border-[#eadfda] bg-[#fafafa] p-6 md:p-8\">\n                    <CardHeader className=\"p-0\">\n                      <CardTitle className=\"text-[18px] leading-[1.3] text-[#151515]\">\n                        Key Differentiators\n                      </CardTitle>\n                    </CardHeader>\n                    <CardContent className=\"p-0 pt-[12px]\">\n                      <ul className=\"space-y-[10px] text-[15px] leading-[1.6] text-[#4A3F37]\">\n                        <li className=\"flex gap-[10px]\">\n                          <span aria-hidden=\"true\" className=\"mt-[8px] h-[6px] w-[6px] shrink-0 rounded-full bg-[#9B3139]\" />\n                          <span>Webflow and Square implementation expertise</span>\n                        </li>\n                        <li className=\"flex gap-[10px]\">\n                          <span aria-hidden=\"true\" className=\"mt-[8px] h-[6px] w-[6px] shrink-0 rounded-full bg-[#9B3139]\" />\n                          <span>AI workflow design for real operational efficiency</span>\n                        </li>\n                        <li className=\"flex gap-[10px]\">\n                          <span aria-hidden=\"true\" className=\"mt-[8px] h-[6px] w-[6px] shrink-0 rounded-full bg-[#9B3139]\" />\n                          <span>AEO-first content strategy and technical SEO depth</span>\n                        </li>\n                      </ul>\n                    </CardContent>\n                  </Card>\n                </div>\n              </div>\n            </section>\n\n            <section className=\"flex w-full justify-center bg-[#fafafa] py-[100px] md:py-[140px]\">\n              <div className=\"w-full max-w-[900px] px-5 text-center md:px-8 lg:px-12\">\n                <h2 className=\"font-[''Manrope:Light'',sans-serif] text-[36px] leading-[1.1] text-[#151515] md:text-[52px]\">\n                  Ready to Transform Your Digital Strategy?\n                </h2>\n                <p className=\"mx-auto mt-[16px] max-w-[700px] text-[16px] leading-[1.6] text-[#777] md:text-[20px]\">\n                  Get a focused roadmap for your audience, goals, and growth stage\n                  with clear next steps and execution priorities.\n                </p>\n                <div className=\"mt-[30px] flex flex-col justify-center gap-[12px] sm:flex-row\">\n                  <Button className=\"rounded-full px-8 py-6 text-[14px] tracking-[1px]\" asChild>\n                    <Link to=\"/#contact\">Schedule a Call</Link>\n                  </Button>\n                  <Button\n                    variant=\"outline\"\n                    className=\"rounded-full border-[#9B3139]/60 px-8 py-6 text-[14px] tracking-[1px] text-[#9B3139] hover:bg-black/5\"\n                    asChild\n                  >\n                    <Link to=\"/#case-studies\">View Related Case Studies</Link>\n                  </Button>\n                </div>\n              </div>\n            </section>\n          </>\n        )}\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/SolutionsPage.tsx","content":"import { Bot, Globe, Layers3 } from \"lucide-react\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport {\n  AuthorityOrbitSection,\n  CapabilitiesBridgeSection,\n  FinalCTASection,\n  HeroSection,\n  OurApproachSection,\n  SolutionsSection,\n} from \"@/app/components/sections\";\nimport solutionsHeroVideo from \"@/assets/bg-hero-video.mp4\";\n\nexport default function SolutionsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"flex-1\">\n        <HeroSection\n          eyebrow=\"Solutions\"\n          title={\n            <>\n              Solutions Built Around <br />\n              Your Business\n            </>\n          }\n          description=\"We design and build digital systems tailored to your operating model, audience, and growth stage so your website works as a real business asset.\"\n          backgroundVideoSrc={solutionsHeroVideo}\n          primaryAction={{\n            label: \"Book a Strategy Call\",\n            href: \"/contact\",\n            variant: \"primary\",\n          }}\n          secondaryAction={{\n            label: \"Explore Audiences\",\n            scrollToId: \"solutions-audience\",\n            variant: \"secondary\",\n          }}\n        />\n\n        <SolutionsSection\n          sectionId=\"solutions-audience\"\n          title=\"Solutions by Audience\"\n          leadTitle=\"Choose the audience track that matches how your organization operates.\"\n          leadDescription=\"Each solution page is organized around the needs, buying patterns, and delivery realities of a specific type of business or team.\"\n          backgroundColor=\"var(--mis-surface)\"\n        />\n\n        <OurApproachSection\n          sectionId=\"our-approach\"\n          eyebrow=\"Our Approach\"\n          title=\"A process designed to create momentum, not just deliverables.\"\n          description=\"Good outcomes come from disciplined sequencing. Each phase sharpens the next, so strategy, execution, and optimization work as one continuous system.\"\n          featureEyebrow=\"Flagship message\"\n          featureTitle=\"Good outcomes come from disciplined sequencing.\"\n          featureDescription=\"Instead of treating every phase as equal visual weight, this version emphasizes the overall promise and lets the steps cascade beside it.\"\n          backgroundColor=\"var(--mis-bg-soft)\"\n        />\n\n        <CapabilitiesBridgeSection\n          sectionId=\"capabilities-bridge\"\n          eyebrow=\"Core Capabilities\"\n          title=\"Three service areas that power every solution we deliver.\"\n          description=\"From high-performing websites to custom operational tools to practical AI systems, these are the core capabilities behind our solution work.\"\n          capabilities={[\n            {\n              title: \"Web Design & Development\",\n              description:\n                \"Websites built to clarify your offer, earn trust quickly, and support long-term growth.\",\n              href: \"/services/web-design\",\n              icon: Globe,\n              accent: \"#A62025\",\n              eyebrow: \"Digital Foundation\",\n              ctaLabel: \"View service\",\n            },\n            {\n              title: \"Custom Applications\",\n              description:\n                \"Purpose-built tools and integrations that reduce manual work and fit the way your team actually operates.\",\n              href: \"/services/custom-applications\",\n              icon: Layers3,\n              accent: \"#FF9902\",\n              eyebrow: \"Operational Systems\",\n              ctaLabel: \"View service\",\n            },\n            {\n              title: \"AI Solutions\",\n              description:\n                \"Practical AI strategy and automation that create leverage, improve execution speed, and support smarter workflows.\",\n              href: \"/services/ai-consulting\",\n              icon: Bot,\n              accent: \"#6B4A1E\",\n              eyebrow: \"Efficiency Multiplier\",\n              ctaLabel: \"View service\",\n            },\n          ]}\n          backgroundColor=\"#fafafa\"\n        />\n\n        <AuthorityOrbitSection\n          sectionId=\"trusted-innovation\"\n          eyebrow=\"Founded in 1995\"\n          title={\n            <>\n              30 Years of Innovation.\n              <br />\n              Built for What&apos;s Next.\n            </>\n          }\n          description=\"Since 1995, we’ve helped businesses navigate every major shift in web technology — from the early web to mobile-first design to AI-powered optimization.\"\n          orbitValue=\"30\"\n          orbitLabel=\"Years of innovation\"\n        />\n\n        <FinalCTASection\n          sectionId=\"solutions-cta\"\n          eyebrow=\"Next Step\"\n          title=\"Build the Right Solution Next\"\n          description=\"Tell us your goals, constraints, and timeline. We’ll map the right solution path and delivery plan for your team.\"\n          actionLabel=\"Start Your Project\"\n          actionTo=\"/contact\"\n          footnote=\"No pressure. Clear recommendations and a practical delivery path.\"\n        />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/SolutionsSectionVariantsPage.tsx","content":"import type { ComponentType, SVGProps } from \"react\";\nimport {\n  ArrowLeft,\n  BriefcaseBusiness,\n  Building2,\n  HandHeart,\n  Rocket,\n  ShoppingBag,\n  Stethoscope,\n  Store,\n} from \"lucide-react\";\nimport { Link } from \"react-router\";\nimport { MainNavbar } from \"@/app/components/layout/MainNavbar\";\nimport { SiteFooter } from \"@/app/components/layout/SiteFooter\";\nimport { SiteHeader } from \"@/app/components/layout/SiteHeader\";\nimport { SiteShell } from \"@/app/components/layout/SiteShell\";\nimport \"@/styles/solutions-section-variants.css\";\n\ntype IconComponent = ComponentType<SVGProps<SVGSVGElement>>;\n\ntype IndustryCard = {\n  title: string;\n  description: string;\n  eyebrow: string;\n  icon: IconComponent;\n  accent: string;\n};\n\nconst industries: IndustryCard[] = [\n  {\n    title: \"Healthcare\",\n    description:\n      \"HIPAA-compliant websites, patient portals, and appointment systems designed for medical practices and health organizations.\",\n    eyebrow: \"Regulated Trust\",\n    icon: Stethoscope,\n    accent: \"#A62025\",\n  },\n  {\n    title: \"Nonprofits\",\n    description:\n      \"Mission-driven websites with integrated donation systems, volunteer management, and storytelling features.\",\n    eyebrow: \"Mission Momentum\",\n    icon: HandHeart,\n    accent: \"#C9923D\",\n  },\n  {\n    title: \"Professional Services\",\n    description:\n      \"Sophisticated web presence for legal, consulting, and financial services with client portals and custom tools.\",\n    eyebrow: \"Credibility Systems\",\n    icon: BriefcaseBusiness,\n    accent: \"#6B4A1E\",\n  },\n  {\n    title: \"Small Business\",\n    description:\n      \"E-commerce solutions, local SEO optimization, and conversion-focused websites that drive growth.\",\n    eyebrow: \"Growth Engine\",\n    icon: Store,\n    accent: \"#FF9902\",\n  },\n  {\n    title: \"Startups\",\n    description:\n      \"Launch-ready websites, MVP experiences, and flexible digital systems built to help emerging companies move quickly and scale with confidence.\",\n    eyebrow: \"Scale Fast\",\n    icon: Rocket,\n    accent: \"#C76438\",\n  },\n  {\n    title: \"Retail / Ecommerce\",\n    description:\n      \"Online storefronts, product-focused user journeys, and conversion-driven ecommerce experiences designed to increase sales and repeat customers.\",\n    eyebrow: \"Revenue Pathways\",\n    icon: ShoppingBag,\n    accent: \"#7C3D33\",\n  },\n];\n\nfunction SectionHeader({\n  eyebrow,\n  title,\n  body,\n}: {\n  eyebrow: string;\n  title: string;\n  body: string;\n}) {\n  return (\n    <header className=\"solv-header\">\n      <p className=\"solv-eyebrow\">{eyebrow}</p>\n      <h2>{title}</h2>\n      <p>{body}</p>\n    </header>\n  );\n}\n\nfunction VariantOne() {\n  return (\n    <section className=\"solv-section solv-section--mosaic\">\n      <SectionHeader\n        eyebrow=\"Variant 1\"\n        title=\"Sector Mosaic\"\n        body=\"A mixed-scale layout with one featured vertical panel and tighter supporting cards, so the section feels designed rather than repeated.\"\n      />\n      <div className=\"solv-mosaic-grid\">\n        <article className=\"solv-mosaic-lead\">\n          <h3>Solutions designed around how each industry actually operates.</h3>\n          <p>\n            Instead of presenting every audience at the same weight, this version creates a stronger entry point and a more editorial scan path.\n          </p>\n          <div className=\"solv-mini-stack\">\n            {industries.map((industry) => {\n              const Icon = industry.icon;\n\n              return (\n                <div key={industry.title} className=\"solv-mini-pill\">\n                  <Icon />\n                  <span>{industry.title}</span>\n                </div>\n              );\n            })}\n          </div>\n        </article>\n\n        <div className=\"solv-mosaic-cards\">\n          {industries.map((industry, index) => {\n            const Icon = industry.icon;\n\n            return (\n            <article\n              key={industry.title}\n              className={`solv-card solv-mosaic-card solv-mosaic-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: industry.accent }}\n            >\n              <div className=\"solv-mosaic-card__title\">\n                <Icon />\n                <h3>{industry.title}</h3>\n              </div>\n              <p>{industry.description}</p>\n            </article>\n          );\n        })}\n      </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantTwo() {\n  return (\n    <section className=\"solv-section solv-section--columns\">\n      <SectionHeader\n        eyebrow=\"Variant 2\"\n        title=\"Industry Columns\"\n        body=\"Three vertical bands create more rhythm and let each audience feel like a lane, rather than another card in a flat matrix.\"\n      />\n      <div className=\"solv-columns-grid\">\n        {[industries.slice(0, 2), industries.slice(2, 4), industries.slice(4, 6)].map((column, columnIndex) => (\n          <div key={`column-${columnIndex + 1}`} className=\"solv-column\">\n            <div className=\"solv-column-marker\">0{columnIndex + 1}</div>\n            {column.map((industry) => {\n              const Icon = industry.icon;\n\n              return (\n                <article key={industry.title} className=\"solv-card solv-column-card\" style={{ [\"--accent\" as string]: industry.accent }}>\n                  <div className=\"solv-card-top\">\n                    <span className=\"solv-chip\">{industry.eyebrow}</span>\n                    <Icon />\n                  </div>\n                  <h3>{industry.title}</h3>\n                  <p>{industry.description}</p>\n                </article>\n              );\n            })}\n          </div>\n        ))}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantThree() {\n  return (\n    <section className=\"solv-section solv-section--radial\">\n      <SectionHeader\n        eyebrow=\"Variant 3\"\n        title=\"Radial Hub\"\n        body=\"A central strategy core with sectors orbiting around it. More expressive, more homepage-worthy, and still easy to collapse responsively.\"\n      />\n      <div className=\"solv-radial-grid\">\n        <article className=\"solv-radial-core\">\n          <div className=\"solv-radial-core__inner\">\n            <Building2 />\n            <h3>Industry-fit strategy</h3>\n            <p>Each sector needs a different trust signal, buying journey, and content architecture.</p>\n          </div>\n        </article>\n\n        {industries.map((industry, index) => {\n          const Icon = industry.icon;\n\n          return (\n            <article\n              key={industry.title}\n              className={`solv-card solv-radial-card solv-radial-card--${index + 1}`}\n              style={{ [\"--accent\" as string]: industry.accent }}\n            >\n              <Icon />\n              <h3>{industry.title}</h3>\n              <p>{industry.description}</p>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFour() {\n  return (\n    <section className=\"solv-section solv-section--midnight\">\n      <SectionHeader\n        eyebrow=\"Variant 4\"\n        title=\"Midnight Sector Board\"\n        body=\"A darker, premium treatment that gives the Solutions section more contrast and creates a stronger transition in the homepage flow.\"\n      />\n      <div className=\"solv-midnight-shell\">\n        <aside className=\"solv-midnight-aside\">\n          <span className=\"solv-chip solv-chip--light\">Audience map</span>\n          <h3>Six sectors. One system. Different growth constraints.</h3>\n          <p>\n            This direction turns the section into more of a strategic control panel, which helps it stand apart from lighter content blocks above and below.\n          </p>\n        </aside>\n        <div className=\"solv-midnight-grid\">\n          {industries.map((industry) => {\n            const Icon = industry.icon;\n\n            return (\n              <article key={industry.title} className=\"solv-midnight-card\" style={{ [\"--accent\" as string]: industry.accent }}>\n                <div className=\"solv-card-top\">\n                  <span className=\"solv-chip solv-chip--light\">{industry.eyebrow}</span>\n                  <Icon />\n                </div>\n                <h3>{industry.title}</h3>\n                <p>{industry.description}</p>\n              </article>\n            );\n          })}\n        </div>\n      </div>\n    </section>\n  );\n}\n\nfunction VariantFive() {\n  return (\n    <section className=\"solv-section solv-section--rail\">\n      <SectionHeader\n        eyebrow=\"Variant 5\"\n        title=\"Progressive Solution Rail\"\n        body=\"A stacked sequence with large indices and long cards, useful if the section should feel more directional and premium than a simple grid.\"\n      />\n      <div className=\"solv-rail-list\">\n        {industries.map((industry, index) => {\n          const Icon = industry.icon;\n\n          return (\n            <article key={industry.title} className=\"solv-rail-card\" style={{ [\"--accent\" as string]: industry.accent }}>\n              <div className=\"solv-rail-index\">0{index + 1}</div>\n              <div className=\"solv-rail-main\">\n                <div className=\"solv-card-top\">\n                  <span className=\"solv-chip\">{industry.eyebrow}</span>\n                  <Icon />\n                </div>\n                <h3>{industry.title}</h3>\n                <p>{industry.description}</p>\n              </div>\n            </article>\n          );\n        })}\n      </div>\n    </section>\n  );\n}\n\nexport default function SolutionsSectionVariantsPage() {\n  return (\n    <SiteShell>\n      <div className=\"content-stretch flex flex-col items-center relative shrink-0 w-full\">\n        <SiteHeader>\n          <MainNavbar />\n        </SiteHeader>\n      </div>\n\n      <main className=\"solutions-section-lab\">\n        <section className=\"solv-hero\">\n          <div className=\"solv-hero-inner\">\n            <Link to=\"/\" className=\"solv-back-link\">\n              <ArrowLeft />\n              Back to Home\n            </Link>\n            <p className=\"solv-eyebrow\">Solutions Section Explorations</p>\n            <h1>Five stronger directions for the homepage Solutions section.</h1>\n            <p>\n              These options keep the same six audiences, but move past the plain two-column card grid into layouts with more character, hierarchy, and pacing.\n            </p>\n          </div>\n        </section>\n\n        <VariantOne />\n        <VariantTwo />\n        <VariantThree />\n        <VariantFour />\n        <VariantFive />\n      </main>\n\n      <SiteFooter />\n    </SiteShell>\n  );\n}\n"},{"path":"src/app/pages/UIKitPage.tsx","content":"import { Link } from \"react-router\";\nimport { ArrowLeft } from \"lucide-react\";\n\nexport default function UIKitPage() {\n  return (\n    <div className=\"min-h-screen bg-[#FFF8F0] p-8 md:p-12 font-[''Manrope'',sans-serif]\">\n      <div className=\"max-w-7xl mx-auto\">\n        {/* Header */}\n        <div className=\"mb-12\">\n          <Link to=\"/\" className=\"inline-flex items-center gap-2 text-[#9B3139] hover:text-[#7A2730] transition-colors mb-6\">\n            <ArrowLeft className=\"w-4 h-4\" />\n            <span className=\"font-medium\">Back to Home</span>\n          </Link>\n          <h1 className=\"text-6xl font-light text-[#2A2420] mb-4\">MIS, Inc. UI Kit</h1>\n          <p className=\"text-xl text-[#4A3F37] font-light\">Santa Fe-inspired design system featuring warm earth tones and clean typography</p>\n        </div>\n\n        {/* Color Palette */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Color Palette</h2>\n          \n          <div className=\"mb-8\">\n            <h3 className=\"text-xl font-medium text-[#4A3F37] mb-4\">Primary Colors</h3>\n            <div className=\"grid grid-cols-2 md:grid-cols-3 gap-4\">\n              <div className=\"space-y-2\">\n                <div className=\"h-24 bg-[#9B3139] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Brick Red</p>\n                <p className=\"text-xs text-[#6B564A]\">#9B3139</p>\n                <p className=\"text-xs text-[#A89080]\">Primary brand color</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-24 bg-[#7A2730] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Brick Red Dark</p>\n                <p className=\"text-xs text-[#6B564A]\">#7A2730</p>\n                <p className=\"text-xs text-[#A89080]\">Hover states</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-24 bg-[#D64F2A] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Terracotta</p>\n                <p className=\"text-xs text-[#6B564A]\">#D64F2A</p>\n                <p className=\"text-xs text-[#A89080]\">Secondary accents</p>\n              </div>\n            </div>\n          </div>\n\n          <div className=\"mb-8\">\n            <h3 className=\"text-xl font-medium text-[#4A3F37] mb-4\">Accent Colors</h3>\n            <div className=\"grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4\">\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#FFAA1D] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Gold</p>\n                <p className=\"text-xs text-[#6B564A]\">#FFAA1D</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#4FA5AE] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Turquoise</p>\n                <p className=\"text-xs text-[#6B564A]\">#4FA5AE</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#E8B89A] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Adobe</p>\n                <p className=\"text-xs text-[#6B564A]\">#E8B89A</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#F4E8D8] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Sand</p>\n                <p className=\"text-xs text-[#6B564A]\">#F4E8D8</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#D4A574] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Clay</p>\n                <p className=\"text-xs text-[#6B564A]\">#D4A574</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#9CAF88] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Sage</p>\n                <p className=\"text-xs text-[#6B564A]\">#9CAF88</p>\n              </div>\n            </div>\n          </div>\n\n          <div className=\"mb-8\">\n            <h3 className=\"text-xl font-medium text-[#4A3F37] mb-4\">Warm Neutrals</h3>\n            <div className=\"grid grid-cols-2 md:grid-cols-4 gap-4\">\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#FFF8F0] rounded-lg shadow-md border border-[#E8D9C8]\"></div>\n                <p className=\"font-medium text-sm\">Warm Cream</p>\n                <p className=\"text-xs text-[#6B564A]\">#FFF8F0</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#F5EFE7] rounded-lg shadow-md border border-[#E8D9C8]\"></div>\n                <p className=\"font-medium text-sm\">Warm Beige</p>\n                <p className=\"text-xs text-[#6B564A]\">#F5EFE7</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#E8DCC8] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Warm Tan</p>\n                <p className=\"text-xs text-[#6B564A]\">#E8DCC8</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#A89080] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm\">Neutral 300</p>\n                <p className=\"text-xs text-[#FDFAF7]\">#A89080</p>\n              </div>\n            </div>\n          </div>\n\n          <div>\n            <h3 className=\"text-xl font-medium text-[#4A3F37] mb-4\">Dark Neutrals</h3>\n            <div className=\"grid grid-cols-2 md:grid-cols-3 gap-4\">\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#6B564A] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm text-white\">Neutral 400</p>\n                <p className=\"text-xs text-[#A89080]\">#6B564A</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#4A3F37] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm text-white\">Neutral 500</p>\n                <p className=\"text-xs text-[#A89080]\">#4A3F37</p>\n              </div>\n              <div className=\"space-y-2\">\n                <div className=\"h-20 bg-[#2A2420] rounded-lg shadow-md\"></div>\n                <p className=\"font-medium text-sm text-white\">Neutral 900</p>\n                <p className=\"text-xs text-[#A89080]\">#2A2420</p>\n              </div>\n            </div>\n          </div>\n        </section>\n\n        {/* Typography */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Typography</h2>\n          <div className=\"space-y-6 bg-white p-8 rounded-lg shadow-md\">\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">Display / 96px Light</p>\n              <h1 className=\"text-8xl font-light text-[#2A2420]\">Websites built to last</h1>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">H1 / 64px Light</p>\n              <h1 className=\"text-6xl font-light text-[#2A2420]\">Modern, strategic websites</h1>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">H2 / 48px Light</p>\n              <h2 className=\"text-5xl font-light text-[#2A2420]\">Featured Projects</h2>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">H3 / 32px Light</p>\n              <h3 className=\"text-3xl font-light text-[#2A2420]\">30 Years of Expertise</h3>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">H4 / 24px Light</p>\n              <h4 className=\"text-2xl font-light text-[#2A2420]\">Web Design & Webflow</h4>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">Body / 16px Light</p>\n              <p className=\"text-base font-light text-[#4A3F37] leading-relaxed\">\n                At MIS, we believe great websites aren''t just beautiful — they''re strategic tools that help your organization grow. Since 1995, we''ve helped small businesses, nonprofits, and professional organizations build websites that reflect their mission.\n              </p>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">Label / 14px Medium</p>\n              <p className=\"text-sm font-medium text-[#9B3139] tracking-wide\">OUR SERVICES</p>\n            </div>\n            <div>\n              <p className=\"text-xs text-[#A89080] mb-2\">Caption / 12px Medium</p>\n              <p className=\"text-xs font-medium text-[#A89080] tracking-wider uppercase\">Founded 1995</p>\n            </div>\n          </div>\n        </section>\n\n        {/* Buttons */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Buttons</h2>\n          <div className=\"space-y-8 bg-white p-8 rounded-lg shadow-md\">\n            <div>\n              <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Primary Buttons</h3>\n              <div className=\"flex flex-wrap gap-4\">\n                <button className=\"bg-[#9B3139] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#7A2730] transition-all hover:scale-105\">\n                  Our Services\n                </button>\n                <button className=\"bg-[#9B3139] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#7A2730] transition-all\">\n                  Schedule Consultation\n                </button>\n                <button className=\"bg-[#9B3139] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide opacity-50 cursor-not-allowed\">\n                  Disabled State\n                </button>\n              </div>\n            </div>\n\n            <div>\n              <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Turquoise CTA Buttons</h3>\n              <div className=\"flex flex-wrap gap-4\">\n                <button className=\"bg-[#4FA5AE] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#3D8A92] transition-all hover:scale-105\">\n                  Schedule a Free Consultation\n                </button>\n                <button className=\"bg-[#4FA5AE] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#3D8A92] transition-all\">\n                  Get Started\n                </button>\n                <button className=\"bg-[#4FA5AE] text-white px-6 py-3 rounded-full font-medium text-sm tracking-wide opacity-50 cursor-not-allowed\">\n                  Disabled State\n                </button>\n              </div>\n            </div>\n\n            <div>\n              <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Secondary Buttons</h3>\n              <div className=\"flex flex-wrap gap-4\">\n                <button className=\"bg-white border border-[#9B3139] text-[#9B3139] px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#9B3139] hover:text-white transition-all\">\n                  Learn More\n                </button>\n                <button className=\"bg-white border border-[#4FA5AE] text-[#4FA5AE] px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#4FA5AE] hover:text-white transition-all\">\n                  View Process\n                </button>\n                <button className=\"bg-white border border-[#6B564A] text-[#2A2420] px-6 py-3 rounded-full font-medium text-sm tracking-wide hover:bg-[#F5EFE7] transition-all\">\n                  View Portfolio\n                </button>\n              </div>\n            </div>\n\n            <div>\n              <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Text Buttons</h3>\n              <div className=\"flex flex-wrap gap-6\">\n                <button className=\"text-[#9B3139] font-medium text-sm tracking-wide hover:opacity-60 transition-opacity underline underline-offset-4\">\n                  Learn More →\n                </button>\n                <button className=\"text-[#4FA5AE] font-medium text-sm tracking-wide hover:opacity-60 transition-opacity underline underline-offset-4\">\n                  View Process →\n                </button>\n              </div>\n            </div>\n          </div>\n        </section>\n\n        {/* Badges & Labels */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Badges & Labels</h2>\n          <div className=\"bg-white p-8 rounded-lg shadow-md\">\n            <div className=\"flex flex-wrap gap-4\">\n              <div className=\"bg-[#FFAA1D] px-4 py-2 rounded-full\">\n                <span className=\"text-[#9B3139] font-medium text-xs tracking-wide\">30 years of experience</span>\n              </div>\n              <div className=\"bg-[#F4E8D8] px-4 py-2 rounded-full\">\n                <span className=\"text-[#4A3F37] font-medium text-xs tracking-wide\">Webflow Partner</span>\n              </div>\n              <div className=\"bg-[#9CAF88] px-4 py-2 rounded-full\">\n                <span className=\"text-white font-medium text-xs tracking-wide\">AI-Powered</span>\n              </div>\n              <div className=\"border border-[#9B3139] px-4 py-2 rounded-full\">\n                <span className=\"text-[#9B3139] font-medium text-xs tracking-wide\">Webflow</span>\n              </div>\n              <div className=\"border border-[#6B564A] px-4 py-2 rounded-full\">\n                <span className=\"text-[#4A3F37] font-medium text-xs tracking-wide\">E-commerce</span>\n              </div>\n            </div>\n          </div>\n        </section>\n\n        {/* Cards */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Cards</h2>\n          \n          <div className=\"mb-8\">\n            <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Service Cards</h3>\n            <div className=\"grid md:grid-cols-2 gap-6\">\n              <div className=\"bg-[#f9f9f9] p-12 transition-all hover:bg-[#f0f0f0] hover:shadow-lg cursor-pointer group\">\n                <h4 className=\"text-2xl font-light text-[#2A2420] mb-3\">Web Design & Webflow</h4>\n                <p className=\"text-base font-light text-[#6B564A] leading-relaxed mb-6\">\n                  Modern, user-focused designs built on Webflow for fast, scalable, and easy-to-update websites.\n                </p>\n                <div className=\"inline-flex flex-col\">\n                  <span className=\"font-medium text-sm text-[#2A2420] group-hover:translate-x-1 transition-transform\">Learn More</span>\n                  <div className=\"h-px bg-[#2A2420] w-full\"></div>\n                </div>\n              </div>\n\n              <div className=\"bg-[#f8ede3] p-12 transition-all hover:shadow-lg cursor-pointer group\">\n                <h4 className=\"text-2xl font-light text-[#2A2420] mb-3\">AI Integration</h4>\n                <p className=\"text-base font-light text-[#6B564A] leading-relaxed mb-6\">\n                  Practical AI that improves search visibility, engagement, and long-term site performance.\n                </p>\n                <div className=\"inline-flex flex-col\">\n                  <span className=\"font-medium text-sm text-[#2A2420] group-hover:translate-x-1 transition-transform\">Discover AI</span>\n                  <div className=\"h-px bg-[#2A2420] w-full\"></div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <div>\n            <h3 className=\"text-lg font-medium text-[#4A3F37] mb-4\">Value Cards</h3>\n            <div className=\"grid md:grid-cols-3 gap-6\">\n              <div className=\"bg-[#f1f6f5] p-12 flex flex-col justify-between min-h-[280px]\">\n                <p className=\"text-xs font-normal text-[#2A2420] tracking-wider uppercase mb-auto\">Deep Technical Background</p>\n                <p className=\"text-2xl font-light text-[#2A2420] leading-relaxed\">We speak both business and tech.</p>\n              </div>\n\n              <div className=\"bg-[#f8ede3] p-12 flex flex-col justify-between min-h-[280px]\">\n                <p className=\"text-xs font-normal text-[#2A2420] tracking-wider uppercase mb-auto\">Clear Communication</p>\n                <p className=\"text-2xl font-light text-[#2A2420] leading-relaxed\">No jargon. Just clarity.</p>\n              </div>\n\n              <div className=\"bg-[#fffae7] p-12 flex flex-col justify-between min-h-[280px]\">\n                <p className=\"text-xs font-normal text-[#2A2420] tracking-wider uppercase mb-auto\">Calm, Confident Approach</p>\n                <p className=\"text-2xl font-light text-[#2A2420] leading-relaxed\">Built to last. Not built to churn.</p>\n              </div>\n            </div>\n          </div>\n        </section>\n\n        {/* Spacing */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Spacing System</h2>\n          <div className=\"bg-white p-8 rounded-lg shadow-md space-y-4\">\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">8px</div>\n              <div className=\"h-8 w-2 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">Micro spacing (gaps, padding)</span>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">16px</div>\n              <div className=\"h-8 w-4 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">Small spacing (card padding)</span>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">32px</div>\n              <div className=\"h-8 w-8 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">Medium spacing (section gaps)</span>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">48px</div>\n              <div className=\"h-8 w-12 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">Large spacing (component padding)</span>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">96px</div>\n              <div className=\"h-8 w-24 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">XL spacing (hero top padding)</span>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              <div className=\"w-16 text-sm text-[#6B564A]\">160px</div>\n              <div className=\"h-8 w-40 bg-[#9B3139]\"></div>\n              <span className=\"text-sm text-[#A89080]\">Section spacing (vertical gaps)</span>\n            </div>\n          </div>\n        </section>\n\n        {/* Shadows */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Shadows</h2>\n          <div className=\"grid md:grid-cols-3 gap-6\">\n            <div className=\"bg-white p-8 rounded-lg shadow-sm\">\n              <p className=\"text-sm font-medium text-[#4A3F37] mb-2\">Subtle Shadow</p>\n              <p className=\"text-xs text-[#A89080]\">shadow-sm</p>\n              <p className=\"text-xs text-[#A89080] mt-2\">Cards, buttons</p>\n            </div>\n            <div className=\"bg-white p-8 rounded-lg shadow-md\">\n              <p className=\"text-sm font-medium text-[#4A3F37] mb-2\">Medium Shadow</p>\n              <p className=\"text-xs text-[#A89080]\">shadow-md</p>\n              <p className=\"text-xs text-[#A89080] mt-2\">Hover states</p>\n            </div>\n            <div className=\"bg-white p-8 rounded-lg shadow-lg\">\n              <p className=\"text-sm font-medium text-[#4A3F37] mb-2\">Large Shadow</p>\n              <p className=\"text-xs text-[#A89080]\">shadow-lg</p>\n              <p className=\"text-xs text-[#A89080] mt-2\">Modal, dropdowns</p>\n            </div>\n          </div>\n        </section>\n\n        {/* Design Principles */}\n        <section className=\"mb-16\">\n          <h2 className=\"text-3xl font-light text-[#2A2420] mb-6\">Design Principles</h2>\n          <div className=\"bg-white p-8 rounded-lg shadow-md space-y-6\">\n            <div>\n              <h3 className=\"text-lg font-medium text-[#9B3139] mb-2\">Santa Fe Warmth</h3>\n              <p className=\"text-base font-light text-[#4A3F37] leading-relaxed\">\n                Inspired by Southwestern adobe and desert landscapes, our color palette features warm brick reds, terracotta, golden yellows, and soft earth tones.\n              </p>\n            </div>\n            <div>\n              <h3 className=\"text-lg font-medium text-[#9B3139] mb-2\">Generous White Space</h3>\n              <p className=\"text-base font-light text-[#4A3F37] leading-relaxed\">\n                Premium feel through breathable layouts. Major sections use 160px+ spacing, cards use 48px padding for a luxurious, uncluttered aesthetic.\n              </p>\n            </div>\n            <div>\n              <h3 className=\"text-lg font-medium text-[#9B3139] mb-2\">Clean Typography</h3>\n              <p className=\"text-base font-light text-[#4A3F37] leading-relaxed\">\n                Manrope Light for body and headings creates a modern, approachable feel. Medium weight for emphasis and interactive elements.\n              </p>\n            </div>\n            <div>\n              <h3 className=\"text-lg font-medium text-[#9B3139] mb-2\">Subtle Motion</h3>\n              <p className=\"text-base font-light text-[#4A3F37] leading-relaxed\">\n                Smooth transitions (300ms), gentle scale transforms (hover:scale-105), and opacity changes create refined interactivity without distraction.\n              </p>\n            </div>\n          </div>\n        </section>\n\n        {/* Footer */}\n        <div className=\"text-center pt-12 border-t border-[#E8D9C8]\">\n          <p className=\"text-sm text-[#A89080]\">MIS, Inc. Design System • Santa Fe Theme • v1.0.0</p>\n          <Link to=\"/\" className=\"text-sm text-[#9B3139] hover:text-[#7A2730] mt-2 inline-block\">\n            Return to Homepage\n          </Link>\n        </div>\n      </div>\n    </div>\n  );\n}"},{"path":"src/styles/approach-section-variants.css","content":".approach-section-lab {\n  background:\n    radial-gradient(circle at top, rgba(255, 153, 2, 0.16), transparent 28%),\n    linear-gradient(180deg, var(--mis-bg-soft) 0%, #fffdf8 100%);\n}\n\n.asv-hero,\n.asv-section {\n  padding: 88px 20px;\n}\n\n.asv-hero-inner,\n.asv-section > * {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.asv-hero-inner,\n.asv-header,\n.asv-path-card,\n.asv-split-story,\n.asv-split-card,\n.asv-editorial-feature,\n.asv-ladder-card,\n.asv-radial-core,\n.asv-radial-card,\n.asv-midnight-aside,\n.asv-midnight-card {\n  display: grid;\n  gap: 16px;\n}\n\n.asv-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 10px;\n  text-decoration: none;\n  transition: opacity 160ms ease;\n}\n\n.asv-back-link:hover {\n  opacity: 0.72;\n}\n\n.asv-eyebrow,\n.asv-mini-label,\n.asv-chip {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.asv-hero h1,\n.asv-header h2,\n.asv-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.asv-hero h1 {\n  font-size: clamp(3rem, 6vw, 5.2rem);\n  line-height: 0.96;\n  max-width: 12ch;\n}\n\n.asv-hero p:last-child,\n.asv-header p:last-child,\n.asv-section p {\n  color: var(--mis-muted);\n  line-height: 1.7;\n  margin: 0;\n}\n\n.asv-header {\n  margin-bottom: 36px;\n  max-width: 780px;\n}\n\n.asv-header h2 {\n  font-size: clamp(2.2rem, 4vw, 4rem);\n  line-height: 0.98;\n}\n\n.asv-pathway {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  position: relative;\n}\n\n.asv-pathway__line {\n  background: linear-gradient(90deg, rgba(166, 32, 37, 0.14), rgba(255, 153, 2, 0.18), rgba(107, 74, 30, 0.12));\n  border-radius: 999px;\n  height: 2px;\n  left: 8%;\n  position: absolute;\n  right: 8%;\n  top: 52px;\n}\n\n.asv-path-card,\n.asv-split-card,\n.asv-ladder-card,\n.asv-radial-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 28px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  padding: 24px;\n  position: relative;\n}\n\n.asv-path-card {\n  min-height: 280px;\n  padding-top: 28px;\n}\n\n.asv-path-card__top,\n.asv-split-card__top,\n.asv-midnight-card__top {\n  align-items: center;\n  display: flex;\n  justify-content: space-between;\n}\n\n.asv-step-index {\n  color: color-mix(in srgb, var(--accent) 72%, white);\n  font-family: \"Manrope\", sans-serif;\n  font-size: 0.88rem;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n}\n\n.asv-icon-wrap,\n.asv-radial-card svg,\n.asv-midnight-card svg {\n  color: var(--accent);\n}\n\n.asv-icon-wrap {\n  align-items: center;\n  background: color-mix(in srgb, var(--accent) 10%, white);\n  border-radius: 999px;\n  display: inline-flex;\n  height: 44px;\n  justify-content: center;\n  width: 44px;\n}\n\n.asv-outcome-chip,\n.asv-chip {\n  align-self: start;\n  border: 1px solid color-mix(in srgb, var(--accent, var(--mis-brand-red)) 20%, white);\n  border-radius: 999px;\n  color: var(--accent, var(--mis-brand-red));\n  padding: 8px 12px;\n}\n\n.asv-split-shell {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.88fr) minmax(0, 1.12fr);\n}\n\n.asv-split-story {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.2), transparent 28%),\n    linear-gradient(160deg, #fff8ef 0%, #ffefcf 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 34px;\n  box-shadow: 0 22px 46px rgba(107, 74, 30, 0.09);\n  padding: 34px;\n}\n\n.asv-split-story h3,\n.asv-editorial-feature h3,\n.asv-radial-core h3,\n.asv-midnight-aside h3 {\n  font-size: clamp(2.2rem, 3.8vw, 3.8rem);\n  line-height: 0.96;\n}\n\n.asv-story-note {\n  align-items: center;\n  display: inline-flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 8px;\n}\n\n.asv-story-note span {\n  color: var(--mis-text);\n  font-size: 0.92rem;\n}\n\n.asv-split-list {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.asv-split-card strong,\n.asv-midnight-card strong {\n  color: var(--mis-text);\n  font-size: 0.98rem;\n  font-weight: 600;\n}\n\n.asv-editorial-shell {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.98fr) minmax(0, 1.02fr);\n}\n\n.asv-editorial-feature {\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.74), rgba(255, 250, 243, 0.96)),\n    radial-gradient(circle at top left, rgba(166, 32, 37, 0.08), transparent 28%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 36px;\n  box-shadow: 0 22px 52px rgba(107, 74, 30, 0.09);\n  padding: 34px;\n}\n\n.asv-feature-metrics {\n  display: grid;\n  gap: 12px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.asv-feature-metrics div {\n  background: rgba(255, 255, 255, 0.62);\n  border: 1px solid rgba(166, 32, 37, 0.1);\n  border-radius: 22px;\n  padding: 18px;\n}\n\n.asv-feature-metrics span {\n  color: var(--mis-text);\n  display: block;\n  font-family: \"Manrope\", sans-serif;\n  font-size: 2.4rem;\n  font-weight: 300;\n  line-height: 1;\n  margin-bottom: 8px;\n}\n\n.asv-editorial-ladder {\n  display: grid;\n  gap: 18px;\n}\n\n.asv-ladder-card {\n  grid-template-columns: 1fr;\n}\n\n.asv-ladder-card--2 {\n  margin-left: 36px;\n}\n\n.asv-ladder-card--3 {\n  margin-left: 72px;\n}\n\n.asv-ladder-card--4 {\n  margin-left: 108px;\n}\n\n.asv-ladder-card__title {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n}\n\n.asv-ladder-card__rail {\n  background: linear-gradient(90deg, color-mix(in srgb, var(--accent) 36%, white), transparent);\n  border-radius: 999px;\n  height: 2px;\n  margin-top: 8px;\n  width: 100%;\n}\n\n.asv-radial-grid {\n  align-items: center;\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.asv-radial-core {\n  align-items: center;\n  display: flex;\n  grid-column: 2;\n  grid-row: 2;\n  justify-content: center;\n  min-height: 280px;\n}\n\n.asv-radial-core__inner {\n  align-items: center;\n  aspect-ratio: 1;\n  background:\n    radial-gradient(circle at 30% 30%, rgba(255, 153, 2, 0.18), transparent 44%),\n    linear-gradient(145deg, #fff8ed, #ffefcf);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 999px;\n  box-shadow: 0 22px 52px rgba(107, 74, 30, 0.1);\n  display: grid;\n  gap: 14px;\n  max-width: 280px;\n  padding: 34px;\n  place-items: center;\n  text-align: center;\n}\n\n.asv-radial-core__inner svg {\n  color: var(--mis-brand-red);\n}\n\n.asv-radial-card {\n  min-height: 220px;\n}\n\n.asv-radial-card--1 {\n  grid-column: 2;\n  grid-row: 1;\n}\n\n.asv-radial-card--2 {\n  grid-column: 3;\n  grid-row: 2;\n}\n\n.asv-radial-card--3 {\n  grid-column: 2;\n  grid-row: 3;\n}\n\n.asv-radial-card--4 {\n  grid-column: 1;\n  grid-row: 2;\n}\n\n.asv-midnight-shell {\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.12), transparent 24%),\n    radial-gradient(circle at bottom right, rgba(166, 32, 37, 0.16), transparent 24%),\n    linear-gradient(160deg, #3f2b17 0%, #24160b 100%);\n  border: 1px solid rgba(255, 244, 227, 0.12);\n  border-radius: 38px;\n  box-shadow: 0 28px 58px rgba(36, 22, 11, 0.3);\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.86fr) minmax(0, 1.14fr);\n  padding: 26px;\n}\n\n.asv-midnight-aside,\n.asv-midnight-card {\n  background: rgba(255, 255, 255, 0.04);\n  border: 1px solid rgba(255, 244, 227, 0.08);\n  border-radius: 30px;\n  padding: 28px;\n}\n\n.asv-midnight-aside h3,\n.asv-midnight-aside p,\n.asv-midnight-card h3,\n.asv-midnight-card p,\n.asv-midnight-card strong,\n.asv-chip--light {\n  color: #fff4e3;\n}\n\n.asv-chip--light {\n  border-color: rgba(255, 244, 227, 0.18);\n}\n\n.asv-midnight-grid {\n  display: grid;\n  gap: 16px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.asv-path-card:hover,\n.asv-split-card:hover,\n.asv-ladder-card:hover,\n.asv-radial-card:hover,\n.asv-midnight-card:hover {\n  box-shadow: 0 24px 56px rgba(107, 74, 30, 0.16);\n  transform: translateY(-8px);\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n@media (max-width: 1100px) {\n  .asv-pathway,\n  .asv-split-shell,\n  .asv-editorial-shell,\n  .asv-midnight-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .asv-radial-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .asv-radial-core,\n  .asv-radial-card--1,\n  .asv-radial-card--2,\n  .asv-radial-card--3,\n  .asv-radial-card--4 {\n    grid-column: auto;\n    grid-row: auto;\n  }\n\n  .asv-ladder-card--2,\n  .asv-ladder-card--3,\n  .asv-ladder-card--4 {\n    margin-left: 0;\n  }\n}\n\n@media (max-width: 760px) {\n  .asv-hero,\n  .asv-section {\n    padding: 72px 16px;\n  }\n\n  .asv-pathway,\n  .asv-split-list,\n  .asv-feature-metrics,\n  .asv-midnight-grid,\n  .asv-radial-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .asv-pathway__line {\n    display: none;\n  }\n\n  .asv-split-story,\n  .asv-editorial-feature,\n  .asv-midnight-aside,\n  .asv-midnight-card,\n  .asv-path-card,\n  .asv-split-card,\n  .asv-ladder-card,\n  .asv-radial-card {\n    border-radius: 24px;\n    padding: 22px;\n  }\n\n  .asv-split-story h3,\n  .asv-editorial-feature h3,\n  .asv-radial-core h3,\n  .asv-midnight-aside h3 {\n    font-size: 2rem;\n  }\n}\n"},{"path":"src/styles/authority-orbit-section.css","content":".aos-section {\n  padding: 88px 20px;\n}\n\n.aos-shell {\n  align-items: center;\n  display: grid;\n  gap: 32px;\n  grid-template-columns: minmax(0, 1.05fr) minmax(320px, 0.95fr);\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.aos-copy {\n  display: grid;\n  gap: 16px;\n}\n\n.aos-eyebrow {\n  color: #fff4e3;\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.aos-copy h2 {\n  color: #fff4e3;\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(2.6rem, 4.8vw, 4.8rem);\n  font-weight: 300;\n  letter-spacing: -0.05em;\n  line-height: 0.96;\n  margin: 0;\n  max-width: 10ch;\n}\n\n@media (min-width: 981px) {\n  .aos-copy h2 {\n    max-width: none;\n    white-space: nowrap;\n  }\n}\n\n.aos-description {\n  color: #fff4e3;\n  font-size: clamp(1rem, 1.6vw, 1.15rem);\n  line-height: 1.7;\n  margin: 0;\n  max-width: 36rem;\n}\n\n.aos-orbit {\n  align-items: center;\n  aspect-ratio: 1;\n  background:\n    radial-gradient(circle, rgba(255, 170, 29, 0.14), transparent 58%),\n    radial-gradient(circle, rgba(255, 255, 255, 0.05), transparent 68%);\n  border: 1px solid rgba(255, 244, 227, 0.12);\n  border-radius: 999px;\n  display: grid;\n  justify-self: center;\n  max-width: 460px;\n  padding: 24px;\n  place-items: center;\n  position: relative;\n  width: 100%;\n}\n\n.aos-orbit::before,\n.aos-orbit::after {\n  animation: aos-orbit-pulse 4.6s ease-out infinite;\n  border: 1px solid rgba(255, 244, 227, 0.2);\n  border-radius: 999px;\n  content: \"\";\n  inset: 7%;\n  position: absolute;\n  transform-origin: center;\n}\n\n.aos-orbit::after {\n  inset: 18%;\n}\n\n.aos-orbit__ripple {\n  animation: aos-orbit-pulse 4.6s ease-out infinite;\n  border: 1px solid rgba(255, 244, 227, 0.2);\n  border-radius: 999px;\n  opacity: 0;\n  pointer-events: none;\n  position: absolute;\n  transform-origin: center;\n}\n\n.aos-orbit__ripple--1 {\n  inset: 4%;\n}\n\n.aos-orbit__ripple--2 {\n  inset: 12%;\n}\n\n.aos-orbit__ripple--3 {\n  inset: 22%;\n}\n\n.aos-orbit__core {\n  align-items: center;\n  background: rgba(255, 248, 237, 0.06);\n  border: 1px solid rgba(255, 244, 227, 0.14);\n  border-radius: 999px;\n  display: grid;\n  gap: 6px;\n  height: 210px;\n  justify-items: center;\n  width: 210px;\n}\n\n.aos-orbit__core span {\n  color: #ffb34a;\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(3.6rem, 6vw, 5.2rem);\n  font-weight: 300;\n  letter-spacing: -0.05em;\n  line-height: 0.9;\n}\n\n.aos-orbit__core p {\n  color: #fff4e3;\n  font-size: 0.88rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n@keyframes aos-orbit-pulse {\n  0% {\n    opacity: 0.42;\n    transform: scale(0.96);\n  }\n\n  70% {\n    opacity: 0.2;\n  }\n\n  100% {\n    opacity: 0.06;\n    transform: scale(1.16);\n  }\n}\n\n@media (max-width: 980px) {\n  .aos-shell {\n    grid-template-columns: 1fr;\n    text-align: center;\n  }\n\n  .aos-copy {\n    justify-items: center;\n  }\n\n  .aos-copy h2 {\n    max-width: 12ch;\n  }\n}\n\n@media (max-width: 720px) {\n  .aos-section {\n    padding: 72px 16px;\n  }\n\n  .aos-orbit {\n    max-width: 360px;\n  }\n\n  .aos-orbit__core {\n    height: 170px;\n    width: 170px;\n  }\n}\n"},{"path":"src/styles/authority-section-variants.css","content":".authority-section-lab {\n  background:\n    radial-gradient(circle at top, rgba(255, 170, 29, 0.12), transparent 24%),\n    linear-gradient(180deg, #fffdf9 0%, #fff8ed 100%);\n}\n\n.authority-lab-hero,\n.authority-variant {\n  padding: 88px 20px;\n}\n\n.authority-lab-hero__inner,\n.authority-variant > * {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.authority-lab-hero__inner,\n.authority-variant-header,\n.split-story,\n.editorial-feature,\n.midnight-card,\n.timeline-card,\n.split-card,\n.runway-card {\n  display: grid;\n  gap: 16px;\n}\n\n.authority-lab-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 10px;\n  text-decoration: none;\n  transition: opacity 160ms ease;\n}\n\n.authority-lab-back-link:hover {\n  opacity: 0.72;\n}\n\n.authority-lab-eyebrow,\n.authority-mini-label {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  text-transform: uppercase;\n}\n\n.authority-lab-hero h1,\n.authority-variant-header h2,\n.split-story h3,\n.timeline-card__value,\n.split-card__value,\n.editorial-stack-card__value,\n.runway-card__value,\n.midnight-card__value {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.authority-lab-hero h1 {\n  font-size: clamp(3rem, 6vw, 5.6rem);\n  line-height: 0.96;\n  max-width: 11ch;\n}\n\n.authority-lab-hero-copy,\n.authority-variant-header p,\n.split-story p,\n.timeline-card__detail,\n.split-card__detail,\n.editorial-feature__copy,\n.editorial-stack-card__detail,\n.runway-card__detail,\n.midnight-card__detail {\n  color: var(--mis-muted);\n  font-size: 1rem;\n  line-height: 1.7;\n  margin: 0;\n}\n\n.authority-lab-hero-copy {\n  max-width: 50rem;\n}\n\n.authority-variant-header {\n  margin-bottom: 36px;\n  max-width: 760px;\n}\n\n.authority-variant-header h2 {\n  font-size: clamp(2.2rem, 4.1vw, 4rem);\n  line-height: 0.98;\n}\n\n.timeline-rail {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  position: relative;\n}\n\n.timeline-rail__line {\n  background: linear-gradient(90deg, rgba(166, 32, 37, 0.2), rgba(255, 153, 2, 0.25), rgba(107, 74, 30, 0.2));\n  height: 2px;\n  left: 8%;\n  position: absolute;\n  right: 8%;\n  top: 90px;\n}\n\n.timeline-card {\n  --accent: var(--mis-primary);\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.98), rgba(255, 247, 234, 0.96));\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 30px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  min-height: 280px;\n  padding: 34px 26px 28px;\n  position: relative;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.timeline-card:hover,\n.split-card:hover,\n.editorial-stack-card:hover,\n.runway-card:hover,\n.midnight-card:hover {\n  box-shadow: 0 30px 62px rgba(107, 74, 30, 0.2);\n  transform: translateY(-10px) scale(1.02);\n}\n\n.timeline-card--2,\n.timeline-card--4 {\n  transform: translateY(42px);\n}\n\n.timeline-card:hover.timeline-card--2,\n.timeline-card:hover.timeline-card--4 {\n  transform: translateY(36px);\n}\n\n.timeline-card__dot {\n  background: var(--accent);\n  border: 6px solid #fff6ea;\n  border-radius: 999px;\n  box-shadow: 0 0 0 1px rgba(166, 32, 37, 0.1);\n  height: 20px;\n  left: 28px;\n  position: absolute;\n  top: 79px;\n  width: 20px;\n}\n\n.timeline-card__icon,\n.split-card__topline svg,\n.editorial-stack-card__eyebrow svg,\n.midnight-card__header svg {\n  color: var(--accent);\n}\n\n.timeline-card__icon {\n  align-items: center;\n  background: rgba(255, 255, 255, 0.92);\n  border: 1px solid color-mix(in srgb, var(--accent) 28%, white);\n  border-radius: 999px;\n  display: inline-flex;\n  height: 48px;\n  justify-content: center;\n  width: 48px;\n}\n\n.timeline-card__value,\n.split-card__value,\n.editorial-stack-card__value,\n.runway-card__value,\n.midnight-card__value {\n  font-size: clamp(2.8rem, 4vw, 4rem);\n  line-height: 0.92;\n}\n\n.timeline-card__label,\n.split-card__label,\n.runway-card__label,\n.midnight-card__label {\n  color: var(--mis-text);\n  font-size: 0.95rem;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.split-shell {\n  align-items: stretch;\n  display: grid;\n  gap: 24px;\n  grid-template-columns: 0.92fr 1.08fr;\n}\n\n.split-story {\n  background:\n    radial-gradient(circle at top right, rgba(255, 170, 29, 0.18), transparent 28%),\n    linear-gradient(145deg, #fff5e1 0%, #fffdfa 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 34px;\n  box-shadow: 0 18px 42px rgba(107, 74, 30, 0.08);\n  padding: 34px;\n}\n\n.split-story h3 {\n  font-size: clamp(2.1rem, 3.3vw, 3.6rem);\n  line-height: 0.98;\n  max-width: 10ch;\n}\n\n.split-story__note {\n  align-items: center;\n  border-top: 1px solid rgba(166, 32, 37, 0.12);\n  color: var(--mis-text);\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: auto;\n  padding-top: 18px;\n}\n\n.split-grid {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.split-card {\n  --accent: var(--mis-primary);\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 28px;\n  box-shadow: 0 16px 34px rgba(107, 74, 30, 0.07);\n  min-height: 240px;\n  overflow: hidden;\n  padding: 24px;\n  position: relative;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.split-card::before {\n  background: linear-gradient(180deg, color-mix(in srgb, var(--accent) 12%, white), transparent);\n  content: \"\";\n  height: 120px;\n  left: 0;\n  position: absolute;\n  right: 0;\n  top: 0;\n}\n\n.split-card--1,\n.split-card--4 {\n  transform: translateY(18px);\n}\n\n.split-card:hover.split-card--1,\n.split-card:hover.split-card--4 {\n  transform: translateY(12px);\n}\n\n.split-card__topline,\n.editorial-stack-card__eyebrow,\n.midnight-card__header {\n  align-items: center;\n  display: flex;\n  justify-content: space-between;\n  position: relative;\n}\n\n.editorial-shell {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: 1.14fr 0.86fr;\n}\n\n.editorial-feature {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.2), transparent 22%),\n    linear-gradient(145deg, #fff7e8 0%, #ffefcf 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 34px;\n  box-shadow: 0 22px 46px rgba(107, 74, 30, 0.1);\n  overflow: hidden;\n  padding: 36px;\n  position: relative;\n}\n\n.editorial-feature::after {\n  background: radial-gradient(circle, rgba(166, 32, 37, 0.08), transparent 68%);\n  content: \"\";\n  height: 260px;\n  pointer-events: none;\n  position: absolute;\n  right: -60px;\n  top: -80px;\n  width: 260px;\n}\n\n.editorial-feature__headline {\n  color: var(--mis-text);\n  display: grid;\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(2.4rem, 4vw, 4.6rem);\n  font-weight: 300;\n  letter-spacing: -0.05em;\n  line-height: 0.93;\n}\n\n.editorial-feature__copy {\n  max-width: 42rem;\n}\n\n.editorial-feature__metrics {\n  display: grid;\n  gap: 14px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  margin-top: 14px;\n}\n\n.editorial-feature__metric {\n  background: rgba(255, 255, 255, 0.6);\n  border: 1px solid rgba(166, 32, 37, 0.1);\n  border-radius: 22px;\n  display: grid;\n  gap: 8px;\n  padding: 18px 20px;\n}\n\n.editorial-feature__metric span {\n  color: var(--mis-brand-red);\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(2.1rem, 3vw, 3.2rem);\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  line-height: 0.95;\n}\n\n.editorial-feature__metric p {\n  color: var(--mis-text);\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.editorial-stack {\n  display: grid;\n  gap: 18px;\n}\n\n.editorial-stack-card {\n  --accent: var(--mis-primary);\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-left: 8px solid var(--accent);\n  border-radius: 28px;\n  box-shadow: 0 16px 34px rgba(107, 74, 30, 0.07);\n  padding: 26px 24px;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.editorial-stack-card__eyebrow span {\n  color: var(--mis-text);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n}\n\n.runway-shell {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  position: relative;\n}\n\n.runway-shell__beam {\n  background:\n    linear-gradient(90deg, rgba(255, 153, 2, 0.1), rgba(166, 32, 37, 0.18), rgba(107, 74, 30, 0.14));\n  border-radius: 999px;\n  bottom: 28px;\n  content: \"\";\n  height: 18px;\n  left: 5%;\n  position: absolute;\n  right: 5%;\n}\n\n.runway-card {\n  --accent: var(--mis-primary);\n  background: linear-gradient(180deg, #fffdfa 0%, #fff4df 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 28px;\n  box-shadow: 0 18px 38px rgba(107, 74, 30, 0.08);\n  min-height: 320px;\n  padding: 24px;\n  position: relative;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.runway-card::before {\n  background: linear-gradient(180deg, color-mix(in srgb, var(--accent) 72%, white), transparent);\n  border-radius: 999px;\n  content: \"\";\n  height: 88px;\n  opacity: 0.4;\n  position: absolute;\n  right: 22px;\n  top: 18px;\n  width: 88px;\n}\n\n.runway-card--2 {\n  transform: translateY(24px);\n}\n\n.runway-card--3 {\n  transform: translateY(48px);\n}\n\n.runway-card--4 {\n  transform: translateY(18px);\n}\n\n.runway-card:hover.runway-card--2 {\n  transform: translateY(18px);\n}\n\n.runway-card:hover.runway-card--3 {\n  transform: translateY(42px);\n}\n\n.runway-card:hover.runway-card--4 {\n  transform: translateY(12px);\n}\n\n.runway-card__step {\n  color: color-mix(in srgb, var(--accent) 72%, white);\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  text-transform: uppercase;\n}\n\n.authority-variant--midnight {\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%),\n    linear-gradient(180deg, #451b17 0%, #261614 100%);\n}\n\n.authority-variant--midnight .authority-lab-eyebrow,\n.authority-variant--midnight .authority-variant-header h2,\n.authority-variant--midnight .authority-variant-header p,\n.authority-variant--midnight .authority-mini-label,\n.authority-variant--midnight .midnight-card__label,\n.authority-variant--midnight .midnight-card__detail {\n  color: #fff4e3;\n}\n\n.midnight-shell {\n  align-items: center;\n  display: grid;\n  gap: 30px;\n  grid-template-columns: 0.85fr 1.15fr;\n}\n\n.midnight-orbit {\n  align-items: center;\n  aspect-ratio: 1;\n  background:\n    radial-gradient(circle, rgba(255, 170, 29, 0.14), transparent 58%),\n    radial-gradient(circle, rgba(255, 255, 255, 0.05), transparent 68%);\n  border: 1px solid rgba(255, 244, 227, 0.12);\n  border-radius: 999px;\n  display: grid;\n  padding: 24px;\n  place-items: center;\n  position: relative;\n}\n\n.midnight-orbit::before,\n.midnight-orbit::after {\n  animation: midnight-orbit-pulse 4.6s ease-out infinite;\n  border: 1px solid rgba(255, 244, 227, 0.2);\n  border-radius: 999px;\n  content: \"\";\n  inset: 7%;\n  position: absolute;\n  transform-origin: center;\n}\n\n.midnight-orbit::after {\n  inset: 18%;\n}\n\n.midnight-orbit__ripple {\n  animation: midnight-orbit-pulse 4.6s ease-out infinite;\n  border: 1px solid rgba(255, 244, 227, 0.2);\n  border-radius: 999px;\n  opacity: 0;\n  pointer-events: none;\n  position: absolute;\n  transform-origin: center;\n}\n\n.midnight-orbit__ripple--1 {\n  inset: 4%;\n}\n\n.midnight-orbit__ripple--2 {\n  inset: 12%;\n}\n\n.midnight-orbit__ripple--3 {\n  inset: 22%;\n}\n\n.midnight-orbit__core {\n  align-items: center;\n  background: rgba(255, 248, 237, 0.06);\n  border: 1px solid rgba(255, 244, 227, 0.14);\n  border-radius: 999px;\n  display: grid;\n  gap: 6px;\n  height: 210px;\n  justify-items: center;\n  width: 210px;\n}\n\n.midnight-orbit__core span {\n  color: #ffb34a;\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(3.6rem, 6vw, 5.2rem);\n  font-weight: 300;\n  letter-spacing: -0.05em;\n  line-height: 0.9;\n}\n\n.midnight-orbit__core p {\n  color: #fff4e3;\n  font-size: 0.88rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.midnight-grid {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.midnight-card {\n  --accent: var(--mis-primary);\n  backdrop-filter: blur(10px);\n  background: linear-gradient(180deg, rgba(255, 248, 237, 0.1), rgba(255, 248, 237, 0.05));\n  border: 1px solid rgba(255, 244, 227, 0.14);\n  border-radius: 28px;\n  box-shadow: 0 22px 44px rgba(0, 0, 0, 0.2);\n  min-height: 240px;\n  padding: 24px;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.midnight-card__value {\n  color: #ffffff;\n}\n\n@keyframes midnight-orbit-ripple {\n  0% {\n    inset: 22%;\n    opacity: 0;\n    transform: scale(0.82);\n  }\n\n  12% {\n    opacity: 0.42;\n  }\n\n  70% {\n    opacity: 0.12;\n  }\n\n  100% {\n    inset: -4%;\n    opacity: 0;\n    transform: scale(1.2);\n  }\n}\n\n@keyframes midnight-orbit-pulse {\n  0% {\n    opacity: 0.42;\n    transform: scale(0.96);\n  }\n\n  70% {\n    opacity: 0.2;\n  }\n\n  100% {\n    opacity: 0.06;\n    transform: scale(1.16);\n  }\n}\n\n@media (max-width: 1100px) {\n  .timeline-rail,\n  .runway-shell {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .timeline-rail__line,\n  .runway-shell__beam {\n    display: none;\n  }\n\n  .timeline-card--2,\n  .timeline-card--4,\n  .split-card--1,\n  .split-card--4,\n  .runway-card--2,\n  .runway-card--3,\n  .runway-card--4 {\n    transform: none;\n  }\n\n  .editorial-shell,\n  .midnight-shell {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 920px) {\n  .split-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .split-grid,\n  .midnight-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 720px) {\n  .authority-lab-hero,\n  .authority-variant {\n    padding: 68px 16px;\n  }\n\n  .timeline-rail,\n  .runway-shell,\n  .editorial-feature__metrics {\n    grid-template-columns: 1fr;\n  }\n\n  .split-story,\n  .timeline-card,\n  .split-card,\n  .editorial-feature,\n  .editorial-stack-card,\n  .runway-card,\n  .midnight-card {\n    border-radius: 24px;\n    padding: 24px 20px;\n  }\n\n  .midnight-orbit__core {\n    height: 180px;\n    width: 180px;\n  }\n}\n"},{"path":"src/styles/blog-section-variants.css","content":".blog-section-lab {\n  background:\n    radial-gradient(circle at top center, rgba(255, 187, 84, 0.16), transparent 22%),\n    linear-gradient(180deg, #f7f1e7 0%, #eee0cd 100%);\n  color: #2c231d;\n}\n\n.bsv-hero {\n  padding: 5.5rem 1.5rem 3rem;\n}\n\n.bsv-hero-inner,\n.bsv-section {\n  width: min(1200px, 100%);\n  margin: 0 auto;\n}\n\n.bsv-hero-inner {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.bsv-back-link,\n.bsv-link {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.5rem;\n  font-weight: 600;\n  letter-spacing: 0.02em;\n  transition: opacity 180ms ease, transform 180ms ease;\n}\n\n.bsv-back-link {\n  color: #7a4f1d;\n}\n\n.bsv-back-link:hover,\n.bsv-link:hover {\n  opacity: 0.84;\n  transform: translateX(2px);\n}\n\n.bsv-hero h1 {\n  margin: 0;\n  max-width: 11ch;\n  font-size: clamp(2.6rem, 5vw, 4.8rem);\n  line-height: 0.98;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4c261f;\n}\n\n.bsv-hero p:not(.bsv-eyebrow) {\n  margin: 0;\n  max-width: 54rem;\n  font-size: 1.08rem;\n  line-height: 1.7;\n  color: #6e5849;\n}\n\n.bsv-section {\n  padding: 2rem 1.5rem 4.5rem;\n}\n\n.bsv-header {\n  display: flex;\n  flex-direction: column;\n  gap: 0.85rem;\n  max-width: 50rem;\n  margin-bottom: 2.25rem;\n}\n\n.bsv-eyebrow {\n  margin: 0;\n  font-size: 0.78rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.22em;\n  color: #9b3139;\n}\n\n.bsv-header h2 {\n  margin: 0;\n  font-size: clamp(2rem, 3vw, 3.3rem);\n  line-height: 1.05;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4b2d22;\n}\n\n.bsv-header p {\n  margin: 0;\n  font-size: 1rem;\n  line-height: 1.75;\n  color: #735d4d;\n}\n\n.bsv-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 1.5rem;\n}\n\n.bsv-card,\n.bsv-list-item,\n.bsv-journal-card {\n  border-radius: 1.8rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.9);\n  box-shadow: 0 20px 40px rgba(90, 55, 33, 0.06);\n}\n\n.bsv-card--article,\n.bsv-timeline-card,\n.bsv-board-card,\n.bsv-journal-card {\n  overflow: hidden;\n  transition:\n    transform 220ms ease,\n    box-shadow 220ms ease,\n    border-color 220ms ease;\n}\n\n.bsv-card--article:hover,\n.bsv-timeline-card:hover,\n.bsv-board-card:hover,\n.bsv-journal-card:hover {\n  transform: translateY(-8px);\n  border-color: rgba(255, 153, 2, 0.24);\n  box-shadow: 0 28px 52px rgba(90, 55, 33, 0.12);\n}\n\n.bsv-media,\n.bsv-feed-thumb,\n.bsv-list-thumb,\n.bsv-journal-thumb {\n  background: #efe6d7;\n}\n\n.bsv-media img,\n.bsv-feed-thumb img,\n.bsv-list-thumb img,\n.bsv-journal-thumb img {\n  display: block;\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n}\n\n.bsv-media img {\n  aspect-ratio: 16 / 9;\n}\n\n.bsv-card-body,\n.bsv-feed-copy,\n.bsv-list-copy {\n  display: flex;\n  flex-direction: column;\n  gap: 0.95rem;\n  padding: 1.35rem 1.4rem 1.5rem;\n}\n\n.bsv-meta-row {\n  display: flex;\n  align-items: center;\n  gap: 0.8rem;\n  flex-wrap: wrap;\n}\n\n.bsv-chip {\n  display: inline-flex;\n  align-items: center;\n  width: fit-content;\n  border-radius: 999px;\n  background: rgba(255, 170, 29, 0.12);\n  padding: 0.38rem 0.7rem;\n  font-size: 0.78rem;\n  font-weight: 700;\n  letter-spacing: 0.06em;\n  text-transform: uppercase;\n  color: #8b541f;\n}\n\n.bsv-chip--light {\n  background: rgba(255, 255, 255, 0.08);\n  color: #f7ecdf;\n}\n\n.bsv-meta-item {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.38rem;\n  font-size: 0.84rem;\n  color: #8a6e59;\n}\n\n.bsv-meta-item svg,\n.bsv-flag svg,\n.bsv-flag--light svg,\n.bsv-back-link svg,\n.bsv-link svg {\n  width: 1rem;\n  height: 1rem;\n  flex: 0 0 auto;\n}\n\n.bsv-card h3,\n.bsv-timeline-card h3,\n.bsv-board-card h3,\n.bsv-journal-card h3 {\n  margin: 0;\n  font-size: clamp(1.55rem, 2vw, 2rem);\n  line-height: 1.12;\n  font-weight: 500;\n  letter-spacing: -0.03em;\n  color: #6a4d2b;\n}\n\n.bsv-card p,\n.bsv-timeline-card p,\n.bsv-board-card p,\n.bsv-journal-card p,\n.bsv-journal-aside p,\n.bsv-digest-note p {\n  margin: 0;\n  font-size: 1rem;\n  line-height: 1.8;\n  color: #8d714d;\n}\n\n.bsv-link {\n  margin-top: auto;\n  color: #ff9902;\n}\n\n.bsv-section-footer {\n  margin-top: 2rem;\n}\n\n.bsv-flag,\n.bsv-flag--light {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.55rem;\n  width: fit-content;\n  font-size: 0.82rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.bsv-flag {\n  color: #9b3139;\n}\n\n.bsv-feature-feed {\n  display: grid;\n  grid-template-columns: minmax(0, 1.08fr) minmax(0, 0.92fr);\n  gap: 1.5rem;\n}\n\n.bsv-card--feature-post {\n  overflow: hidden;\n}\n\n.bsv-media--feature img {\n  aspect-ratio: 16 / 10;\n}\n\n.bsv-recent-feed {\n  display: grid;\n  gap: 1rem;\n}\n\n.bsv-card--feed-item {\n  display: grid;\n  grid-template-columns: 12rem minmax(0, 1fr);\n  overflow: hidden;\n}\n\n.bsv-feed-copy {\n  padding: 1.1rem 1.2rem;\n}\n\n.bsv-columns {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 1.5rem;\n}\n\n.bsv-list-thumb img {\n  aspect-ratio: 4 / 3;\n}\n\n.bsv-timeline {\n  position: relative;\n  display: grid;\n  gap: 1rem;\n}\n\n.bsv-timeline::before {\n  content: \"\";\n  position: absolute;\n  top: 0;\n  bottom: 0;\n  left: 50%;\n  width: 1px;\n  transform: translateX(-50%);\n  background: linear-gradient(180deg, rgba(198, 100, 56, 0.1) 0%, rgba(155, 49, 57, 0.24) 50%, rgba(198, 100, 56, 0.1) 100%);\n}\n\n.bsv-timeline-item {\n  position: relative;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 3rem minmax(0, 1fr);\n  gap: 1rem;\n  align-items: center;\n}\n\n.bsv-timeline-item.is-left .bsv-timeline-date,\n.bsv-timeline-item.is-left .bsv-timeline-card {\n  grid-column: 1;\n}\n\n.bsv-timeline-item.is-right .bsv-timeline-date,\n.bsv-timeline-item.is-right .bsv-timeline-card {\n  grid-column: 3;\n}\n\n.bsv-timeline-date {\n  margin-bottom: 0.7rem;\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n  color: rgba(106, 77, 43, 0.64);\n}\n\n.bsv-timeline-node {\n  grid-column: 2;\n  justify-self: center;\n  width: 1rem;\n  height: 1rem;\n  border-radius: 999px;\n  border: 4px solid #f7f1e7;\n  background: #c76438;\n  box-shadow: 0 0 0 1px rgba(199, 100, 56, 0.18);\n}\n\n.bsv-timeline-card {\n  border-radius: 1.8rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.92);\n  box-shadow: 0 20px 40px rgba(90, 55, 33, 0.06);\n}\n\n.bsv-timeline-item.is-left .bsv-timeline-card {\n  transform-origin: right center;\n}\n\n.bsv-timeline-item.is-right .bsv-timeline-card {\n  transform-origin: left center;\n}\n\n.bsv-board-intro {\n  display: grid;\n  gap: 1rem;\n  margin-bottom: 1.5rem;\n}\n\n.bsv-digest-note {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.4rem 1.5rem;\n  border-radius: 1.8rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background:\n    radial-gradient(circle at top left, rgba(255, 187, 84, 0.18), transparent 28%),\n    rgba(255, 252, 247, 0.92);\n}\n\n.bsv-digest-note h3,\n.bsv-journal-aside h3 {\n  margin: 0;\n  font-size: clamp(2rem, 3vw, 3rem);\n  line-height: 1;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4c261f;\n}\n\n.bsv-topic-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.bsv-topic-pill {\n  display: inline-flex;\n  border-radius: 999px;\n  border: 1px solid rgba(155, 49, 57, 0.12);\n  background: rgba(255, 252, 247, 0.9);\n  padding: 0.55rem 0.9rem;\n  font-size: 0.88rem;\n  color: #7a5d45;\n}\n\n.bsv-board {\n  position: relative;\n  min-height: 44rem;\n  border-radius: 2rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background:\n    radial-gradient(circle at top left, rgba(255, 187, 84, 0.16), transparent 24%),\n    linear-gradient(180deg, rgba(255, 252, 247, 0.76) 0%, rgba(244, 233, 215, 0.88) 100%);\n  overflow: hidden;\n}\n\n.bsv-board::before {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  background-image:\n    linear-gradient(rgba(155, 49, 57, 0.04) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(155, 49, 57, 0.04) 1px, transparent 1px);\n  background-size: 36px 36px;\n  pointer-events: none;\n}\n\n.bsv-board-card {\n  position: absolute;\n  width: 29rem;\n  border-radius: 1.8rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.96);\n  box-shadow: 0 20px 40px rgba(90, 55, 33, 0.08);\n}\n\n.bsv-board-card--1 {\n  top: 2rem;\n  left: 2rem;\n  transform: rotate(-2deg);\n}\n\n.bsv-board-card--2 {\n  top: 3rem;\n  right: 2.4rem;\n  transform: rotate(1.6deg);\n}\n\n.bsv-board-card--3 {\n  bottom: 2.6rem;\n  left: 4rem;\n  transform: rotate(1.8deg);\n}\n\n.bsv-board-card--4 {\n  bottom: 2rem;\n  right: 3rem;\n  transform: rotate(-1.4deg);\n}\n\n.bsv-media--board img {\n  aspect-ratio: 16 / 8;\n}\n\n.bsv-journal-board {\n  display: grid;\n  grid-template-columns: minmax(0, 0.82fr) minmax(0, 1.38fr);\n  gap: 1.5rem;\n  padding: 1.6rem;\n  border-radius: 2.25rem;\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%),\n    linear-gradient(180deg, #52261f 0%, #261614 100%);\n  box-shadow: 0 34px 78px rgba(40, 19, 16, 0.26);\n}\n\n.bsv-journal-aside {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.2rem;\n}\n\n.bsv-flag--light {\n  color: #ffcb86;\n}\n\n.bsv-journal-aside h3 {\n  color: #fff2e6;\n}\n\n.bsv-journal-aside p {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.bsv-journal-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 1rem;\n}\n\n.bsv-journal-card {\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.09);\n  box-shadow: none;\n}\n\n.bsv-journal-thumb img {\n  aspect-ratio: 16 / 9;\n}\n\n.bsv-journal-card h3 {\n  color: #fff2e6;\n}\n\n.bsv-journal-card p,\n.bsv-journal-card .bsv-meta-item {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.bsv-journal-card .bsv-link {\n  color: #ffb24a;\n}\n\n.bsv-journal-card .bsv-chip {\n  background: rgba(255, 255, 255, 0.08);\n  color: #f7ecdf;\n}\n\n@media (max-width: 960px) {\n  .bsv-grid,\n  .bsv-columns,\n  .bsv-feature-feed,\n  .bsv-journal-board,\n  .bsv-journal-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .bsv-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .bsv-card--feed-item,\n  .bsv-timeline-item {\n    grid-template-columns: 1fr;\n  }\n\n  .bsv-timeline::before,\n  .bsv-timeline-node {\n    display: none;\n  }\n\n  .bsv-timeline-item.is-left .bsv-timeline-date,\n  .bsv-timeline-item.is-left .bsv-timeline-card,\n  .bsv-timeline-item.is-right .bsv-timeline-date,\n  .bsv-timeline-item.is-right .bsv-timeline-card {\n    grid-column: auto;\n  }\n\n  .bsv-board {\n    min-height: auto;\n    display: grid;\n    gap: 1rem;\n    padding: 1rem;\n  }\n\n  .bsv-board-card {\n    position: static;\n    width: auto;\n    transform: none;\n  }\n}\n\n@media (max-width: 640px) {\n  .bsv-hero {\n    padding-top: 4.5rem;\n  }\n\n  .bsv-section {\n    padding-bottom: 3.5rem;\n  }\n\n  .bsv-grid {\n    grid-template-columns: 1fr;\n  }\n}\n"},{"path":"src/styles/capabilities-bridge-section.css","content":".cbs-section {\n  padding: 88px 20px;\n}\n\n.cbs-shell {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.cbs-header,\n.cbs-editorial-card {\n  display: grid;\n  gap: 16px;\n}\n\n.cbs-eyebrow,\n.cbs-chip {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.cbs-header {\n  margin-bottom: 36px;\n  max-width: 780px;\n}\n\n.cbs-header h2,\n.cbs-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.cbs-header h2 {\n  font-size: clamp(2.2rem, 4vw, 4rem);\n  line-height: 0.98;\n}\n\n.cbs-header p,\n.cbs-editorial-card p {\n  color: var(--mis-muted);\n  line-height: 1.7;\n  margin: 0;\n}\n\n.cbs-editorial-grid {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.cbs-editorial-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 30px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  padding: 26px;\n  text-decoration: none;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.cbs-editorial-card:hover {\n  box-shadow: 0 24px 56px rgba(107, 74, 30, 0.16);\n  transform: translateY(-8px);\n}\n\n.cbs-chip {\n  align-self: start;\n  border: 1px solid color-mix(in srgb, var(--accent, var(--mis-brand-red)) 20%, white);\n  border-radius: 999px;\n  color: var(--accent, var(--mis-brand-red));\n  padding: 8px 12px;\n}\n\n.cbs-icon-wrap {\n  align-items: center;\n  background: color-mix(in srgb, var(--accent) 10%, white);\n  border-radius: 999px;\n  color: var(--accent);\n  display: inline-flex;\n  height: 46px;\n  justify-content: center;\n  width: 46px;\n}\n\n.cbs-inline-link {\n  align-items: center;\n  color: var(--accent);\n  display: inline-flex;\n  font-weight: 600;\n  gap: 10px;\n}\n\n@media (max-width: 1100px) {\n  .cbs-editorial-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 760px) {\n  .cbs-section {\n    padding: 72px 16px;\n  }\n\n  .cbs-editorial-card {\n    border-radius: 24px;\n    padding: 22px;\n  }\n}\n"},{"path":"src/styles/capabilities-bridge-variants.css","content":".capabilities-bridge-lab {\n  background:\n    radial-gradient(circle at top, rgba(255, 153, 2, 0.14), transparent 28%),\n    linear-gradient(180deg, var(--mis-bg-soft) 0%, #fffdf8 100%);\n}\n\n.cbv-hero,\n.cbv-section {\n  padding: 88px 20px;\n}\n\n.cbv-hero-inner,\n.cbv-section > * {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.cbv-hero-inner,\n.cbv-header,\n.cbv-editorial-card,\n.cbv-story,\n.cbv-split-card,\n.cbv-rail-intro,\n.cbv-rail-card,\n.cbv-mosaic-hero,\n.cbv-mosaic-card,\n.cbv-midnight-aside,\n.cbv-midnight-card {\n  display: grid;\n  gap: 16px;\n}\n\n.cbv-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 10px;\n  text-decoration: none;\n  transition: opacity 160ms ease;\n}\n\n.cbv-back-link:hover {\n  opacity: 0.72;\n}\n\n.cbv-eyebrow,\n.cbv-mini-label,\n.cbv-chip {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.cbv-hero h1,\n.cbv-header h2,\n.cbv-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.cbv-hero h1 {\n  font-size: clamp(3rem, 6vw, 5.2rem);\n  line-height: 0.96;\n  max-width: 12ch;\n}\n\n.cbv-hero p:last-child,\n.cbv-header p:last-child,\n.cbv-section p {\n  color: var(--mis-muted);\n  line-height: 1.7;\n  margin: 0;\n}\n\n.cbv-header {\n  margin-bottom: 36px;\n  max-width: 780px;\n}\n\n.cbv-header h2 {\n  font-size: clamp(2.2rem, 4vw, 4rem);\n  line-height: 0.98;\n}\n\n.cbv-chip {\n  align-self: start;\n  border: 1px solid color-mix(in srgb, var(--accent, var(--mis-brand-red)) 20%, white);\n  border-radius: 999px;\n  color: var(--accent, var(--mis-brand-red));\n  padding: 8px 12px;\n}\n\n.cbv-chip--light {\n  border-color: rgba(255, 244, 227, 0.18);\n  color: #fff4e3;\n}\n\n.cbv-icon-wrap {\n  align-items: center;\n  background: color-mix(in srgb, var(--accent) 10%, white);\n  border-radius: 999px;\n  color: var(--accent);\n  display: inline-flex;\n  height: 46px;\n  justify-content: center;\n  width: 46px;\n}\n\n.cbv-editorial-grid {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.cbv-editorial-card,\n.cbv-split-card,\n.cbv-rail-card,\n.cbv-mosaic-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 30px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  padding: 26px;\n  text-decoration: none;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.cbv-editorial-card:hover,\n.cbv-split-card:hover,\n.cbv-rail-card:hover,\n.cbv-mosaic-hero:hover,\n.cbv-mosaic-card:hover,\n.cbv-midnight-card:hover {\n  box-shadow: 0 24px 56px rgba(107, 74, 30, 0.16);\n  transform: translateY(-8px);\n}\n\n.cbv-inline-link,\n.cbv-story-note {\n  align-items: center;\n  display: inline-flex;\n  gap: 10px;\n}\n\n.cbv-inline-link {\n  color: var(--accent);\n  font-weight: 600;\n}\n\n.cbv-split-shell {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.9fr) minmax(0, 1.1fr);\n}\n\n.cbv-story,\n.cbv-rail-intro,\n.cbv-mosaic-hero {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.2), transparent 28%),\n    linear-gradient(160deg, #fff8ef 0%, #ffefcf 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 34px;\n  box-shadow: 0 22px 46px rgba(107, 74, 30, 0.09);\n  padding: 34px;\n}\n\n.cbv-story h3,\n.cbv-rail-intro h3,\n.cbv-mosaic-hero h3,\n.cbv-midnight-aside h3 {\n  font-size: clamp(2.2rem, 3.8vw, 3.8rem);\n  line-height: 0.96;\n}\n\n.cbv-split-list {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.cbv-split-card__top,\n.cbv-midnight-card__top {\n  align-items: center;\n  color: var(--accent);\n  display: flex;\n  justify-content: space-between;\n}\n\n.cbv-split-card strong {\n  color: var(--mis-text);\n  font-size: 0.98rem;\n  font-weight: 600;\n}\n\n.cbv-rail-shell {\n  position: relative;\n}\n\n.cbv-rail-line {\n  background: linear-gradient(90deg, rgba(166, 32, 37, 0.14), rgba(255, 153, 2, 0.18), rgba(107, 74, 30, 0.12));\n  border-radius: 999px;\n  height: 2px;\n  left: 24%;\n  position: absolute;\n  right: 4%;\n  top: 194px;\n}\n\n.cbv-rail-list {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  margin-top: 24px;\n}\n\n.cbv-rail-card {\n  min-height: 260px;\n}\n\n.cbv-rail-card__step {\n  color: color-mix(in srgb, var(--accent) 72%, white);\n  font-family: \"Manrope\", sans-serif;\n  font-size: 0.88rem;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n}\n\n.cbv-mosaic-grid {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: minmax(0, 1.08fr) minmax(0, 0.92fr);\n}\n\n.cbv-mosaic-hero,\n.cbv-mosaic-card {\n  overflow: hidden;\n  position: relative;\n}\n\n.cbv-mosaic-card__title {\n  align-items: center;\n  color: var(--accent);\n  display: flex;\n  gap: 12px;\n}\n\n.cbv-midnight-shell {\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.12), transparent 24%),\n    radial-gradient(circle at bottom right, rgba(166, 32, 37, 0.16), transparent 24%),\n    linear-gradient(160deg, #3f2b17 0%, #24160b 100%);\n  border: 1px solid rgba(255, 244, 227, 0.12);\n  border-radius: 38px;\n  box-shadow: 0 28px 58px rgba(36, 22, 11, 0.3);\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.86fr) minmax(0, 1.14fr);\n  padding: 26px;\n}\n\n.cbv-midnight-aside,\n.cbv-midnight-card {\n  background: rgba(255, 255, 255, 0.04);\n  border: 1px solid rgba(255, 244, 227, 0.08);\n  border-radius: 30px;\n  padding: 28px;\n}\n\n.cbv-midnight-aside h3,\n.cbv-midnight-aside p,\n.cbv-midnight-card h3,\n.cbv-midnight-card p,\n.cbv-chip--light,\n.cbv-midnight-card svg {\n  color: #fff4e3;\n}\n\n.cbv-midnight-grid {\n  display: grid;\n  gap: 16px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n@media (max-width: 1100px) {\n  .cbv-editorial-grid,\n  .cbv-split-list,\n  .cbv-rail-list,\n  .cbv-midnight-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .cbv-split-shell,\n  .cbv-mosaic-grid,\n  .cbv-midnight-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .cbv-rail-line {\n    display: none;\n  }\n}\n\n@media (max-width: 760px) {\n  .cbv-hero,\n  .cbv-section {\n    padding: 72px 16px;\n  }\n\n  .cbv-editorial-card,\n  .cbv-split-card,\n  .cbv-rail-card,\n  .cbv-mosaic-hero,\n  .cbv-mosaic-card,\n  .cbv-story,\n  .cbv-rail-intro,\n  .cbv-midnight-aside,\n  .cbv-midnight-card {\n    border-radius: 24px;\n    padding: 22px;\n  }\n\n  .cbv-story h3,\n  .cbv-rail-intro h3,\n  .cbv-mosaic-hero h3,\n  .cbv-midnight-aside h3 {\n    font-size: 2rem;\n  }\n}\n"},{"path":"src/styles/faq-section-variants.css","content":".faq-section-lab {\n  background:\n    radial-gradient(circle at top right, rgba(255, 170, 29, 0.14), transparent 28%),\n    linear-gradient(180deg, #fffdf9 0%, #fff7ea 100%);\n  color: var(--mis-text);\n}\n\n.faq-section-lab *,\n.faq-section-lab *::before,\n.faq-section-lab *::after {\n  box-sizing: border-box;\n}\n\n.fsv-hero,\n.fsv-section {\n  padding: clamp(3.5rem, 6vw, 5.5rem) clamp(1.25rem, 4vw, 3rem);\n}\n\n.fsv-hero-inner,\n.fsv-header,\n.fsv-accordion-shell,\n.fsv-split-shell,\n.fsv-mosaic-grid,\n.fsv-rail-shell,\n.fsv-midnight-shell {\n  margin: 0 auto;\n  max-width: 1180px;\n}\n\n.fsv-hero-inner,\n.fsv-header {\n  display: grid;\n  gap: 1rem;\n}\n\n.fsv-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 0.5rem;\n  text-decoration: none;\n}\n\n.fsv-back-link:hover {\n  opacity: 0.72;\n}\n\n.fsv-eyebrow,\n.fsv-mini-label {\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n}\n\n.fsv-eyebrow {\n  color: #9b3139;\n}\n\n.fsv-mini-label {\n  color: #8d6a2a;\n}\n\n.fsv-hero h1,\n.fsv-header h2,\n.fsv-story h3,\n.fsv-midnight-aside h3 {\n  color: #6b4a1e;\n  font-size: clamp(2.2rem, 5vw, 4rem);\n  letter-spacing: -0.04em;\n  line-height: 0.98;\n  margin: 0;\n}\n\n.fsv-header h2 {\n  font-size: clamp(1.8rem, 3vw, 2.8rem);\n  line-height: 1.02;\n}\n\n.fsv-hero p:last-child,\n.fsv-header > p:last-child,\n.fsv-story p,\n.fsv-midnight-aside p {\n  color: rgba(107, 74, 30, 0.8);\n  font-size: 1.08rem;\n  line-height: 1.7;\n  margin: 0;\n  max-width: 56rem;\n}\n\n.fsv-section {\n  border-top: 1px solid rgba(201, 146, 61, 0.12);\n}\n\n.fsv-accordion-shell {\n  background: rgba(255, 253, 249, 0.92);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  border-radius: 2rem;\n  box-shadow: 0 24px 50px rgba(107, 74, 30, 0.07);\n  padding: 1.5rem 2rem;\n}\n\n.fsv-trigger,\n.fsv-split-trigger,\n.fsv-midnight-trigger {\n  color: #6b4a1e;\n  font-size: 1.25rem;\n  font-weight: 600;\n  line-height: 1.45;\n  text-decoration: none;\n}\n\n.fsv-trigger:hover,\n.fsv-split-trigger:hover,\n.fsv-midnight-trigger:hover {\n  text-decoration: none;\n}\n\n.fsv-content,\n.fsv-split-content {\n  color: rgba(107, 74, 30, 0.82);\n  font-size: 1rem;\n  line-height: 1.8;\n}\n\n.fsv-section--split {\n  background: linear-gradient(180deg, rgba(255, 249, 239, 0.72), rgba(255, 244, 226, 0.88));\n}\n\n.fsv-split-shell {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: 0.92fr 1.4fr;\n}\n\n.fsv-story {\n  background: linear-gradient(155deg, #fff4df 0%, #ffe7c1 100%);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  border-radius: 2rem;\n  display: grid;\n  gap: 1rem;\n  padding: 2rem;\n}\n\n.fsv-story h3,\n.fsv-midnight-aside h3 {\n  font-size: clamp(1.8rem, 3vw, 3rem);\n}\n\n.fsv-story-note {\n  align-items: center;\n  color: #8d6a2a;\n  display: inline-flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.fsv-split-list,\n.fsv-midnight-grid {\n  display: grid;\n  gap: 1rem;\n}\n\n.fsv-split-item {\n  background: rgba(255, 253, 249, 0.92);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  border-radius: 1.4rem;\n  overflow: hidden;\n  padding: 0 1.2rem;\n}\n\n.fsv-pill,\n.fsv-chip {\n  border: 1px solid rgba(201, 146, 61, 0.22);\n  border-radius: 999px;\n  color: #8d6a2a;\n  display: inline-flex;\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  padding: 0.42rem 0.78rem;\n  text-transform: uppercase;\n}\n\n.fsv-split-trigger {\n  align-items: center;\n  display: flex;\n  gap: 0.8rem;\n}\n\n.fsv-split-trigger strong,\n.fsv-midnight-trigger strong {\n  display: block;\n  font-size: 1.1rem;\n  line-height: 1.5;\n  margin-top: 0.6rem;\n}\n\n.fsv-section--mosaic {\n  background: linear-gradient(180deg, rgba(255, 253, 249, 0.56), rgba(255, 247, 234, 0.94));\n}\n\n.fsv-mosaic-grid {\n  display: grid;\n  gap: 1.25rem;\n  grid-template-columns: 1.2fr 1fr 1fr;\n}\n\n.fsv-mosaic-hero,\n.fsv-mosaic-card,\n.fsv-rail-card,\n.fsv-midnight-aside,\n.fsv-midnight-item {\n  border-radius: 2rem;\n}\n\n.fsv-mosaic-hero {\n  background:\n    radial-gradient(circle at top right, color-mix(in srgb, var(--accent) 18%, transparent), transparent 34%),\n    rgba(255, 253, 249, 0.96);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  box-shadow: 0 30px 55px rgba(107, 74, 30, 0.09);\n  display: grid;\n  gap: 1rem;\n  grid-column: span 2;\n  min-height: 20rem;\n  padding: 2rem;\n}\n\n.fsv-mosaic-card {\n  background: rgba(255, 251, 244, 0.94);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  display: grid;\n  gap: 0.85rem;\n  min-height: 15rem;\n  padding: 1.4rem;\n}\n\n.fsv-mosaic-top,\n.fsv-rail-top {\n  align-items: center;\n  color: var(--accent);\n  display: flex;\n  justify-content: space-between;\n}\n\n.fsv-mosaic-hero h3,\n.fsv-mosaic-card h3,\n.fsv-rail-card h3 {\n  color: #6b4a1e;\n  font-size: clamp(1.35rem, 2.2vw, 2.2rem);\n  line-height: 1.08;\n  margin: 0;\n}\n\n.fsv-mosaic-hero p,\n.fsv-mosaic-card p,\n.fsv-rail-card p {\n  color: rgba(107, 74, 30, 0.82);\n  font-size: 1rem;\n  line-height: 1.75;\n  margin: 0;\n}\n\n.fsv-section--rail {\n  background: linear-gradient(180deg, rgba(255, 244, 226, 0.46), rgba(255, 253, 249, 0.92));\n}\n\n.fsv-rail-shell {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  position: relative;\n}\n\n.fsv-rail-line {\n  background: linear-gradient(90deg, rgba(201, 146, 61, 0.35), rgba(166, 32, 37, 0.18));\n  height: 1px;\n  left: 0;\n  position: absolute;\n  right: 0;\n  top: 3rem;\n}\n\n.fsv-rail-card {\n  background: rgba(255, 253, 249, 0.94);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  display: grid;\n  gap: 0.9rem;\n  min-height: 18rem;\n  padding: 1.35rem;\n  position: relative;\n  z-index: 1;\n}\n\n.fsv-rail-card:nth-child(2n) {\n  transform: translateY(1.1rem);\n}\n\n.fsv-card-index {\n  color: var(--accent);\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n}\n\n.fsv-icon-wrap {\n  align-items: center;\n  background: color-mix(in srgb, var(--accent) 10%, white);\n  border-radius: 999px;\n  color: var(--accent);\n  display: inline-flex;\n  height: 3rem;\n  justify-content: center;\n  width: 3rem;\n}\n\n.fsv-section--midnight {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.12), transparent 28%),\n    linear-gradient(180deg, #2b1b10 0%, #120c08 100%);\n}\n\n.fsv-section--midnight .fsv-header h2,\n.fsv-section--midnight .fsv-header > p:last-child,\n.fsv-section--midnight .fsv-eyebrow {\n  color: #fff7ea;\n}\n\n.fsv-midnight-shell {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: 0.9fr 1.35fr;\n}\n\n.fsv-midnight-aside {\n  background: rgba(255, 255, 255, 0.04);\n  border: 1px solid rgba(255, 231, 193, 0.1);\n  display: grid;\n  gap: 1rem;\n  padding: 2rem;\n}\n\n.fsv-chip--light {\n  background: rgba(255, 255, 255, 0.06);\n  border-color: rgba(255, 231, 193, 0.18);\n  color: #ffe7c1;\n}\n\n.fsv-midnight-item {\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 231, 193, 0.1);\n  overflow: hidden;\n  padding: 0 1.2rem;\n}\n\n.fsv-midnight-trigger,\n.fsv-midnight-content,\n.fsv-midnight-aside h3,\n.fsv-midnight-aside p {\n  color: #fff7ea;\n}\n\n.fsv-midnight-content {\n  font-size: 1rem;\n  line-height: 1.8;\n}\n\n@media (max-width: 1100px) {\n  .fsv-split-shell,\n  .fsv-midnight-shell,\n  .fsv-mosaic-grid,\n  .fsv-rail-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .fsv-mosaic-hero {\n    grid-column: auto;\n  }\n\n  .fsv-rail-line {\n    display: none;\n  }\n\n  .fsv-rail-card:nth-child(2n) {\n    transform: none;\n  }\n}\n\n@media (max-width: 720px) {\n  .fsv-hero,\n  .fsv-section {\n    padding-inline: 1rem;\n  }\n\n  .fsv-accordion-shell {\n    padding: 1rem 1.25rem;\n  }\n\n  .fsv-trigger,\n  .fsv-split-trigger,\n  .fsv-midnight-trigger {\n    font-size: 1.08rem;\n  }\n}\n"},{"path":"src/styles/fonts.css","content":"@import url(\"https://fonts.googleapis.com/css2?family=Manrope:wght@300;400;500&display=swap\");\n"},{"path":"src/styles/guides-section-variants.css","content":".guides-section-lab {\n  background:\n    radial-gradient(circle at top center, rgba(255, 187, 84, 0.16), transparent 24%),\n    linear-gradient(180deg, #f7f1e7 0%, #efe4d2 100%);\n  color: #2b211d;\n}\n\n.gsv-hero {\n  padding: 5.5rem 1.5rem 3rem;\n}\n\n.gsv-hero-inner,\n.gsv-section {\n  width: min(1200px, 100%);\n  margin: 0 auto;\n}\n\n.gsv-hero-inner {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.gsv-back-link,\n.gsv-link {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.5rem;\n  font-weight: 600;\n  letter-spacing: 0.02em;\n  transition: opacity 180ms ease, transform 180ms ease;\n}\n\n.gsv-back-link {\n  color: #7a4f1d;\n}\n\n.gsv-back-link:hover,\n.gsv-link:hover {\n  opacity: 0.8;\n  transform: translateX(2px);\n}\n\n.gsv-hero h1 {\n  font-size: clamp(2.6rem, 5vw, 4.8rem);\n  line-height: 0.98;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  max-width: 11ch;\n  color: #4c261f;\n}\n\n.gsv-hero p:not(.gsv-eyebrow) {\n  max-width: 52rem;\n  font-size: 1.08rem;\n  line-height: 1.7;\n  color: #6e5849;\n}\n\n.gsv-section {\n  padding: 2rem 1.5rem 4.5rem;\n}\n\n.gsv-header {\n  display: flex;\n  flex-direction: column;\n  gap: 0.85rem;\n  max-width: 48rem;\n  margin-bottom: 2.25rem;\n}\n\n.gsv-eyebrow {\n  margin: 0;\n  font-size: 0.78rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.22em;\n  color: #9b3139;\n}\n\n.gsv-header h2 {\n  margin: 0;\n  font-size: clamp(2rem, 3vw, 3.3rem);\n  line-height: 1.05;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4b2d22;\n}\n\n.gsv-header p {\n  margin: 0;\n  font-size: 1rem;\n  line-height: 1.75;\n  color: #735d4d;\n}\n\n.gsv-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 1.5rem;\n}\n\n.gsv-card {\n  border-radius: 1.75rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.9);\n  box-shadow: 0 20px 40px rgba(90, 55, 33, 0.06);\n}\n\n.gsv-card--editorial {\n  transition:\n    transform 220ms ease,\n    box-shadow 220ms ease,\n    border-color 220ms ease;\n}\n\n.gsv-card--editorial:hover {\n  transform: translateY(-8px);\n  border-color: rgba(255, 153, 2, 0.28);\n  box-shadow: 0 28px 52px rgba(90, 55, 33, 0.12);\n}\n\n.gsv-card--editorial,\n.gsv-card--compact,\n.gsv-card--feature,\n.gsv-midnight-card {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.5rem;\n}\n\n.gsv-card-top {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 1rem;\n  flex-wrap: wrap;\n}\n\n.gsv-chip {\n  display: inline-flex;\n  align-items: center;\n  border-radius: 999px;\n  background: rgba(255, 170, 29, 0.12);\n  padding: 0.38rem 0.7rem;\n  font-size: 0.78rem;\n  font-weight: 700;\n  letter-spacing: 0.06em;\n  text-transform: uppercase;\n  color: #8b541f;\n}\n\n.gsv-chip--soft {\n  background: rgba(155, 49, 57, 0.1);\n  color: #9b3139;\n}\n\n.gsv-chip--light {\n  background: rgba(255, 255, 255, 0.08);\n  color: #f7ecdf;\n}\n\n.gsv-meta,\n.gsv-meta--light {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.45rem;\n  font-size: 0.84rem;\n  color: #8a6e59;\n}\n\n.gsv-meta svg,\n.gsv-meta--light svg,\n.gsv-link svg,\n.gsv-back-link svg,\n.gsv-compact-icon,\n.gsv-feature-mark svg,\n.gsv-midnight-badge svg {\n  width: 1rem;\n  height: 1rem;\n  flex: 0 0 auto;\n}\n\n.gsv-card h3,\n.gsv-shelf-card h3 {\n  margin: 0;\n  font-size: clamp(1.6rem, 2vw, 2.15rem);\n  line-height: 1.08;\n  font-weight: 500;\n  letter-spacing: -0.03em;\n  color: #6a4d2b;\n}\n\n.gsv-card p,\n.gsv-shelf-card p,\n.gsv-split-aside p,\n.gsv-midnight-lead p {\n  margin: 0;\n  font-size: 1rem;\n  line-height: 1.8;\n  color: #8d714d;\n}\n\n.gsv-link {\n  color: #ff9902;\n  margin-top: auto;\n}\n\n.gsv-split-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 0.9fr) minmax(0, 1.4fr);\n  gap: 1.5rem;\n  align-items: start;\n}\n\n.gsv-split-aside {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 2rem;\n  min-height: 100%;\n  border-radius: 2rem;\n  background: linear-gradient(180deg, #6a2f24 0%, #3d231f 100%);\n  color: #f7ecdf;\n  box-shadow: 0 24px 52px rgba(58, 29, 23, 0.22);\n}\n\n.gsv-split-aside h3,\n.gsv-midnight-lead h3 {\n  margin: 0;\n  font-size: clamp(2rem, 3vw, 3.2rem);\n  line-height: 1;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n}\n\n.gsv-split-aside p {\n  color: rgba(247, 236, 223, 0.78);\n}\n\n.gsv-split-list {\n  display: grid;\n  gap: 1rem;\n}\n\n.gsv-card--row {\n  display: grid;\n  grid-template-columns: auto minmax(0, 1fr) auto;\n  gap: 1.25rem;\n  align-items: center;\n  padding: 1.25rem 1.5rem;\n}\n\n.gsv-row-index {\n  font-size: 1.4rem;\n  font-weight: 600;\n  letter-spacing: -0.04em;\n  color: rgba(106, 77, 43, 0.45);\n}\n\n.gsv-row-copy {\n  display: flex;\n  flex-direction: column;\n  gap: 0.8rem;\n}\n\n.gsv-mosaic {\n  display: grid;\n  grid-template-columns: minmax(0, 1.15fr) minmax(0, 0.95fr);\n  gap: 1.5rem;\n}\n\n.gsv-card--feature {\n  min-height: 30rem;\n  justify-content: space-between;\n  background:\n    radial-gradient(circle at top right, rgba(255, 170, 29, 0.16), transparent 28%),\n    linear-gradient(180deg, #fff6ea 0%, #f7ead6 100%);\n}\n\n.gsv-feature-mark,\n.gsv-midnight-badge {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.6rem;\n  font-size: 0.85rem;\n  font-weight: 700;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.gsv-feature-mark {\n  color: #9b3139;\n}\n\n.gsv-feature-notes {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.65rem;\n}\n\n.gsv-feature-notes span {\n  border-radius: 999px;\n  background: rgba(155, 49, 57, 0.08);\n  padding: 0.45rem 0.8rem;\n  font-size: 0.82rem;\n  color: #7b5a40;\n}\n\n.gsv-mosaic-stack {\n  display: grid;\n  gap: 1rem;\n}\n\n.gsv-card--compact {\n  min-height: 13rem;\n}\n\n.gsv-shelves {\n  display: grid;\n  gap: 1rem;\n}\n\n.gsv-shelf-card {\n  display: grid;\n  grid-template-columns: 0.5rem minmax(0, 1fr) auto;\n  gap: 1.25rem;\n  align-items: center;\n  padding: 1.25rem 1.4rem;\n  border-radius: 1.75rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.78);\n  transition:\n    transform 220ms ease,\n    box-shadow 220ms ease,\n    border-color 220ms ease;\n}\n\n.gsv-shelf-card:hover {\n  transform: translateY(-8px);\n  border-color: rgba(198, 100, 56, 0.28);\n  box-shadow: 0 28px 52px rgba(90, 55, 33, 0.12);\n}\n\n.gsv-shelf-spine {\n  align-self: stretch;\n  border-radius: 999px;\n}\n\n.gsv-shelf-body {\n  display: flex;\n  flex-direction: column;\n  gap: 0.8rem;\n}\n\n.gsv-section--midnight .gsv-header h2,\n.gsv-section--midnight .gsv-header p {\n  color: #f3e8da;\n}\n\n.gsv-section--midnight .gsv-eyebrow {\n  color: #ffb24a;\n}\n\n.gsv-midnight-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 0.8fr) minmax(0, 1.35fr);\n  gap: 1.5rem;\n  padding: 1.6rem;\n  border-radius: 2.25rem;\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%),\n    linear-gradient(180deg, #52261f 0%, #261614 100%);\n  box-shadow: 0 34px 78px rgba(40, 19, 16, 0.26);\n}\n\n.gsv-midnight-lead {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.2rem;\n}\n\n.gsv-midnight-badge {\n  color: #ffcb86;\n}\n\n.gsv-midnight-lead p {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.gsv-midnight-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 1rem;\n}\n\n.gsv-midnight-card {\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.09);\n  box-shadow: none;\n}\n\n.gsv-midnight-card h3 {\n  color: #fff2e6;\n}\n\n.gsv-midnight-card p {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.gsv-meta--light {\n  color: rgba(255, 242, 230, 0.7);\n}\n\n.gsv-midnight-card .gsv-link {\n  color: #ffb24a;\n}\n\n@media (max-width: 900px) {\n  .gsv-grid,\n  .gsv-mosaic,\n  .gsv-split-shell,\n  .gsv-midnight-shell,\n  .gsv-midnight-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .gsv-card--row,\n  .gsv-shelf-card {\n    grid-template-columns: 1fr;\n  }\n\n  .gsv-card--row {\n    align-items: start;\n  }\n\n  .gsv-row-index {\n    order: -1;\n  }\n}\n\n@media (max-width: 640px) {\n  .gsv-hero {\n    padding-top: 4.5rem;\n  }\n\n  .gsv-section {\n    padding-bottom: 3.5rem;\n  }\n\n  .gsv-grid {\n    grid-template-columns: 1fr;\n  }\n}\n"},{"path":"src/styles/home-gradient-variants.css","content":".home-gradient-variant {\n  --home-variant-shell-bg:\n    radial-gradient(1300px 760px at 90% -14%, rgba(222, 132, 68, 0.34), transparent 60%),\n    radial-gradient(1100px 820px at -10% 18%, rgba(128, 43, 50, 0.5), transparent 58%),\n    linear-gradient(142deg, #5d252b 0%, #8d3e32 36%, #c67938 72%, #edd0a6 100%);\n  --home-variant-frame-bg: #fffaf3;\n  --home-variant-frame-border: rgba(126, 69, 44, 0.18);\n  --home-variant-shadow-rgb: 74 38 23;\n}\n\n.home-gradient-variant > div {\n  background: var(--home-variant-shell-bg) !important;\n}\n\n.home-gradient-variant > div > div {\n  background: var(--home-variant-frame-bg) !important;\n  border-color: var(--home-variant-frame-border) !important;\n  box-shadow:\n    0 2px 0 rgba(255, 255, 255, 0.76) inset,\n    0 1px 0 rgb(var(--home-variant-shadow-rgb) / 0.08),\n    0 24px 32px rgb(var(--home-variant-shadow-rgb) / 0.16),\n    0 48px 90px rgb(var(--home-variant-shadow-rgb) / 0.28) !important;\n}\n\n.home-gradient-variant--adobe-dusk {\n  --home-variant-shell-bg:\n    radial-gradient(1300px 760px at 90% -14%, rgba(222, 132, 68, 0.34), transparent 60%),\n    radial-gradient(1100px 820px at -10% 18%, rgba(128, 43, 50, 0.5), transparent 58%),\n    linear-gradient(142deg, #5d252b 0%, #8d3e32 36%, #c67938 72%, #edd0a6 100%);\n  --home-variant-frame-bg: #fff9f3;\n  --home-variant-frame-border: rgba(132, 73, 45, 0.18);\n  --home-variant-shadow-rgb: 76 36 22;\n}\n\n.home-gradient-variant--rio-grande {\n  --home-variant-shell-bg:\n    radial-gradient(1280px 760px at 88% -16%, rgba(105, 165, 161, 0.34), transparent 60%),\n    radial-gradient(1100px 780px at -8% 22%, rgba(155, 49, 57, 0.46), transparent 56%),\n    linear-gradient(146deg, #2e5360 0%, #4a7b87 32%, #b96f43 68%, #efddc0 100%);\n  --home-variant-frame-bg: #fffdf9;\n  --home-variant-frame-border: rgba(80, 109, 112, 0.2);\n  --home-variant-shadow-rgb: 38 67 72;\n}\n\n.home-gradient-variant--sage-horizon {\n  --home-variant-shell-bg:\n    radial-gradient(1220px 720px at 92% -16%, rgba(195, 162, 96, 0.28), transparent 58%),\n    radial-gradient(1100px 860px at -8% 16%, rgba(92, 108, 97, 0.44), transparent 56%),\n    linear-gradient(144deg, #4b5750 0%, #728076 34%, #b59b76 70%, #ebdcc1 100%);\n  --home-variant-frame-bg: #fffdf8;\n  --home-variant-frame-border: rgba(102, 112, 97, 0.18);\n  --home-variant-shadow-rgb: 55 63 58;\n}\n\n.home-gradient-variant--turquoise-clay {\n  --home-variant-shell-bg:\n    radial-gradient(1260px 760px at 90% -12%, rgba(56, 147, 152, 0.36), transparent 60%),\n    radial-gradient(1020px 760px at -10% 24%, rgba(164, 88, 63, 0.42), transparent 56%),\n    linear-gradient(145deg, #214d5a 0%, #3c727a 30%, #b6684b 68%, #efe1cb 100%);\n  --home-variant-frame-bg: #fffdfa;\n  --home-variant-frame-border: rgba(71, 110, 114, 0.19);\n  --home-variant-shadow-rgb: 32 74 81;\n}\n\n.home-gradient-variant--sandstone-dawn {\n  --home-variant-shell-bg:\n    radial-gradient(1220px 720px at 88% -14%, rgba(214, 171, 105, 0.3), transparent 58%),\n    radial-gradient(1080px 820px at -10% 18%, rgba(150, 78, 66, 0.38), transparent 54%),\n    linear-gradient(144deg, #6a3937 0%, #a5664d 34%, #c8a06d 70%, #f0e0c5 100%);\n  --home-variant-frame-bg: #fffbf6;\n  --home-variant-frame-border: rgba(139, 98, 71, 0.18);\n  --home-variant-shadow-rgb: 74 47 39;\n}\n\n.home-gradient-variant--logo-ember {\n  --home-variant-shell-bg:\n    radial-gradient(1240px 760px at 92% -16%, rgba(255, 170, 29, 0.34), transparent 58%),\n    radial-gradient(1080px 820px at -10% 18%, rgba(219, 67, 10, 0.4), transparent 56%),\n    linear-gradient(145deg, #8f1d29 0%, #b02129 28%, #db430a 62%, #ffaa1d 100%);\n  --home-variant-frame-bg: #fffaf2;\n  --home-variant-frame-border: rgba(176, 53, 31, 0.18);\n  --home-variant-shadow-rgb: 89 24 24;\n}\n\n.home-gradient-variant--logo-signal {\n  --home-variant-shell-bg:\n    radial-gradient(1280px 760px at 90% -14%, rgba(255, 170, 29, 0.28), transparent 56%),\n    radial-gradient(1120px 860px at -8% 20%, rgba(155, 49, 57, 0.52), transparent 58%),\n    linear-gradient(144deg, #7d1722 0%, #9b3139 34%, #c84a14 70%, #f5a11d 100%);\n  --home-variant-frame-bg: #fffcf7;\n  --home-variant-frame-border: rgba(134, 50, 47, 0.18);\n  --home-variant-shadow-rgb: 77 25 28;\n}\n\n.home-gradient-variant--logo-horizon {\n  --home-variant-shell-bg:\n    radial-gradient(1260px 720px at 88% -16%, rgba(255, 170, 29, 0.32), transparent 58%),\n    radial-gradient(960px 760px at -10% 24%, rgba(224, 72, 0, 0.32), transparent 54%),\n    linear-gradient(146deg, #6f121c 0%, #942530 30%, #cd4d10 62%, #ff9f0f 84%, #ffd089 100%);\n  --home-variant-frame-bg: #fffbf6;\n  --home-variant-frame-border: rgba(150, 73, 35, 0.18);\n  --home-variant-shadow-rgb: 82 31 20;\n}\n\n.home-gradient-variant--logo-solar {\n  --home-variant-shell-bg:\n    radial-gradient(1300px 760px at 92% -16%, rgba(255, 153, 2, 0.38), transparent 56%),\n    radial-gradient(1040px 760px at -10% 18%, rgba(255, 196, 92, 0.34), transparent 58%),\n    linear-gradient(144deg, #b34d00 0%, #df7300 34%, #ff9902 72%, #ffd88c 100%);\n  --home-variant-frame-bg: #fffbf3;\n  --home-variant-frame-border: rgba(181, 112, 24, 0.18);\n  --home-variant-shadow-rgb: 100 57 10;\n}\n\n.home-gradient-variant--logo-marigold {\n  --home-variant-shell-bg:\n    radial-gradient(1240px 740px at 88% -14%, rgba(255, 153, 2, 0.34), transparent 56%),\n    radial-gradient(1100px 860px at -8% 22%, rgba(255, 175, 44, 0.3), transparent 58%),\n    linear-gradient(145deg, #8f4500 0%, #c96a00 30%, #ff9902 68%, #ffe1a5 100%);\n  --home-variant-frame-bg: #fffcf6;\n  --home-variant-frame-border: rgba(173, 114, 25, 0.17);\n  --home-variant-shadow-rgb: 93 57 11;\n}\n\n.home-gradient-variant--logo-sunburst {\n  --home-variant-shell-bg:\n    radial-gradient(1320px 780px at 90% -18%, rgba(255, 153, 2, 0.4), transparent 54%),\n    radial-gradient(980px 720px at -10% 26%, rgba(255, 214, 120, 0.26), transparent 56%),\n    linear-gradient(146deg, #a54800 0%, #ea7c00 32%, #ff9902 62%, #ffbf3f 82%, #ffe8b8 100%);\n  --home-variant-frame-bg: #fffdf7;\n  --home-variant-frame-border: rgba(186, 119, 20, 0.17);\n  --home-variant-shadow-rgb: 103 60 8;\n}\n\n.home-gradient-variant--logo-mesa-gold {\n  --home-variant-shell-bg:\n    radial-gradient(1260px 720px at 92% -16%, rgba(255, 153, 2, 0.32), transparent 56%),\n    radial-gradient(1080px 820px at -8% 18%, rgba(247, 188, 73, 0.28), transparent 58%),\n    linear-gradient(144deg, #7e4200 0%, #ba6900 28%, #f59400 62%, #ff9902 78%, #ffdca0 100%);\n  --home-variant-frame-bg: #fffcf8;\n  --home-variant-frame-border: rgba(170, 113, 29, 0.16);\n  --home-variant-shadow-rgb: 88 55 14;\n}\n\n.home-gradient-variant--logo-apricot-light {\n  --home-variant-shell-bg:\n    radial-gradient(1320px 760px at 92% -18%, rgba(255, 153, 2, 0.2), transparent 54%),\n    radial-gradient(1120px 820px at -8% 20%, rgba(255, 207, 138, 0.34), transparent 56%),\n    linear-gradient(146deg, #fff7ea 0%, #ffefcf 38%, #ffd99e 72%, #ff9902 100%);\n  --home-variant-frame-bg: #fffdf9;\n  --home-variant-frame-border: rgba(201, 146, 61, 0.16);\n  --home-variant-shadow-rgb: 119 82 28;\n}\n\n.home-gradient-variant--logo-apricot-light {\n  --home-section-base: #fffdf9;\n  --home-section-soft: #fff7ea;\n  --home-section-warm: #ffefcf;\n  --home-section-orange: #fff1d8;\n  --home-section-red: #f8eaea;\n}\n\n.home-gradient-variant--logo-apricot-light header > div:first-child {\n  background: var(--mis-brand-red) !important;\n}\n\n.home-gradient-variant--logo-apricot-light [data-name=\"Section Hero\"] {\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.58), rgba(255, 247, 234, 0.84)),\n    radial-gradient(circle at 85% 12%, rgba(255, 153, 2, 0.14), transparent 34%) !important;\n}\n\n.home-gradient-variant--logo-apricot-light .hero-video-layer {\n  opacity: 1;\n}\n\n.home-gradient-variant--logo-apricot-light .hero-video-layer video {\n  filter: saturate(0.9) sepia(0.1) brightness(0.82);\n}\n\n.home-gradient-variant--logo-apricot-light .hero-video-scrim {\n  opacity: 1;\n  background:\n    linear-gradient(90deg, rgba(255, 253, 249, 0.9) 0%, rgba(255, 247, 234, 0.72) 34%, rgba(255, 239, 207, 0.42) 64%, rgba(255, 247, 234, 0.84) 100%),\n    linear-gradient(180deg, rgba(255, 255, 255, 0.18) 0%, rgba(255, 247, 234, 0.3) 100%);\n}\n\n.home-gradient-variant--logo-apricot-light [data-name=\"Section Hero\"]::after {\n  background: radial-gradient(circle at center, rgba(255, 153, 2, 0.18) 0%, rgba(255, 153, 2, 0) 70%);\n}\n\n.home-gradient-variant--logo-apricot-light [style*=\"#9B3139 1px\"] {\n  background-image:\n    linear-gradient(rgba(166, 32, 37, 0.12) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(255, 153, 2, 0.12) 1px, transparent 1px) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero h1,\n.home-gradient-variant--logo-apricot-light #services h2,\n.home-gradient-variant--logo-apricot-light #authority h2,\n.home-gradient-variant--logo-apricot-light #local h2,\n.home-gradient-variant--logo-apricot-light #case-studies h2,\n.home-gradient-variant--logo-apricot-light #solutions h2,\n.home-gradient-variant--logo-apricot-light #ai-aeo h2,\n.home-gradient-variant--logo-apricot-light #contact h2,\n.home-gradient-variant--logo-apricot-light #services h3,\n.home-gradient-variant--logo-apricot-light #case-studies h3,\n.home-gradient-variant--logo-apricot-light #solutions h3 {\n  color: var(--mis-text) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero p,\n.home-gradient-variant--logo-apricot-light #services p,\n.home-gradient-variant--logo-apricot-light #authority p,\n.home-gradient-variant--logo-apricot-light #local p,\n.home-gradient-variant--logo-apricot-light #case-studies p,\n.home-gradient-variant--logo-apricot-light #solutions p,\n.home-gradient-variant--logo-apricot-light #ai-aeo p,\n.home-gradient-variant--logo-apricot-light #contact p {\n  color: var(--mis-muted) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #services {\n  background: var(--home-section-warm) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority {\n  background: var(--home-section-base) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight {\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.18), transparent 18%),\n    linear-gradient(180deg, #451b17 0%, #261614 100%) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight h2,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight p,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .authority-lab-eyebrow,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .authority-mini-label,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-card__label,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-card__detail {\n  color: #fff4e3 !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-card {\n  backdrop-filter: blur(10px);\n  background: linear-gradient(180deg, rgba(255, 248, 237, 0.1), rgba(255, 248, 237, 0.05)) !important;\n  border: 1px solid rgba(255, 244, 227, 0.14) !important;\n  box-shadow: 0 22px 44px rgba(0, 0, 0, 0.2) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-card__value {\n  color: #ffffff !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-orbit {\n  background:\n    radial-gradient(circle, rgba(255, 170, 29, 0.14), transparent 58%),\n    radial-gradient(circle, rgba(255, 255, 255, 0.05), transparent 68%) !important;\n  border: 1px solid rgba(255, 244, 227, 0.12) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-orbit::before,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-orbit::after,\n.home-gradient-variant--logo-apricot-light #authority.authority-variant--midnight .midnight-orbit__core {\n  border-color: rgba(255, 244, 227, 0.14) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #local {\n  background: linear-gradient(180deg, var(--home-section-orange) 0%, rgba(255, 255, 255, 0) 100%) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #case-studies {\n  background: var(--home-section-soft) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #solutions {\n  background: var(--home-section-base) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #ai-aeo {\n  background: linear-gradient(180deg, var(--home-section-red) 0%, rgba(255, 255, 255, 0) 100%) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #contact {\n  background:\n    radial-gradient(circle at 50% 0%, rgba(255, 153, 2, 0.14), transparent 38%),\n    linear-gradient(180deg, #fff4d7 0%, var(--home-section-warm) 58%, #fff8ea 100%) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #authority .bg-\\[\\#f9f9f9\\],\n.home-gradient-variant--logo-apricot-light #local .bg-\\[\\#f9f9f9\\],\n.home-gradient-variant--logo-apricot-light #ai-aeo .bg-\\[\\#f9f9f9\\],\n.home-gradient-variant--logo-apricot-light #services .bg-white,\n.home-gradient-variant--logo-apricot-light #case-studies .bg-white,\n.home-gradient-variant--logo-apricot-light #solutions .bg-\\[\\#f9f9f9\\] {\n  background: var(--home-section-base) !important;\n  border: 1px solid var(--mis-border) !important;\n  box-shadow: 0 14px 28px rgba(107, 74, 30, 0.08) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #services .group:hover,\n.home-gradient-variant--logo-apricot-light #case-studies .group:hover,\n.home-gradient-variant--logo-apricot-light #solutions .group:hover {\n  box-shadow: 0 20px 36px rgba(107, 74, 30, 0.12) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero button:first-of-type,\n.home-gradient-variant--logo-apricot-light #contact button {\n  background: var(--mis-primary) !important;\n  box-shadow: 0 18px 34px rgba(255, 153, 2, 0.28);\n}\n\n.home-gradient-variant--logo-apricot-light #hero button:first-of-type p,\n.home-gradient-variant--logo-apricot-light #contact button p {\n  color: #ffffff !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero button:last-of-type {\n  background: rgba(255, 255, 255, 0.66) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero button:last-of-type div {\n  border-color: rgba(107, 74, 30, 0.3) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #hero button:last-of-type p {\n  color: var(--mis-text) !important;\n}\n\n.home-gradient-variant--logo-apricot-light .bg-\\[\\#9B3139\\],\n.home-gradient-variant--logo-apricot-light .absolute.bg-\\[\\#9B3139\\],\n.home-gradient-variant--logo-apricot-light .h-\\[2px\\].bg-\\[\\#9B3139\\],\n.home-gradient-variant--logo-apricot-light .h-\\[6px\\].w-\\[6px\\].shrink-0.rounded-full.bg-\\[\\#9B3139\\] {\n  background-color: var(--mis-brand-red) !important;\n}\n\n.home-gradient-variant--logo-apricot-light .text-\\[\\#9B3139\\] {\n  color: var(--mis-brand-red) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #case-studies .bg-\\[\\#FFAA1D\\]\\/10 {\n  background: rgba(255, 153, 2, 0.14) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #case-studies .bg-\\[\\#FFAA1D\\]\\/10 p,\n.home-gradient-variant--logo-apricot-light #authority .text-\\[\\#9B3139\\],\n.home-gradient-variant--logo-apricot-light #ai-aeo .text-\\[\\#9B3139\\],\n.home-gradient-variant--logo-apricot-light footer .text-\\[\\#9B3139\\] {\n  color: var(--mis-brand-red) !important;\n}\n\n.home-gradient-variant--logo-apricot-light #ai-aeo .text-\\[\\#4FA5AE\\] {\n  color: var(--mis-primary-hover) !important;\n}\n\n.home-gradient-variant--logo-creamsicle-light {\n  --home-variant-shell-bg:\n    radial-gradient(1280px 740px at 90% -16%, rgba(255, 153, 2, 0.18), transparent 56%),\n    radial-gradient(1040px 760px at -10% 18%, rgba(255, 226, 179, 0.34), transparent 58%),\n    linear-gradient(144deg, #fffaf1 0%, #fff1d8 34%, #ffe2b2 70%, #ffb84d 100%);\n  --home-variant-frame-bg: #fffefa;\n  --home-variant-frame-border: rgba(204, 154, 78, 0.15);\n  --home-variant-shadow-rgb: 122 87 36;\n}\n\n.home-gradient-variant--logo-honey-light {\n  --home-variant-shell-bg:\n    radial-gradient(1260px 720px at 88% -16%, rgba(255, 153, 2, 0.16), transparent 58%),\n    radial-gradient(1100px 820px at -8% 22%, rgba(255, 221, 161, 0.3), transparent 60%),\n    linear-gradient(145deg, #fffaf3 0%, #fff3de 36%, #ffe8bf 70%, #ffc76a 100%);\n  --home-variant-frame-bg: #fffefb;\n  --home-variant-frame-border: rgba(205, 159, 88, 0.14);\n  --home-variant-shadow-rgb: 124 91 43;\n}\n\n@media (max-width: 640px) {\n  .home-gradient-variant > div {\n    background-position: center top, center top, center !important;\n  }\n}\n"},{"path":"src/styles/index.css","content":"@import ''./fonts.css'';\n@import ''./tailwind.css'';\n@import ''./theme.css'';\n"},{"path":"src/styles/new-home-v2.css","content":".new-home-v2 {\n  --v2-bg: #f7f1e8;\n  --v2-ink: #21160f;\n  --v2-muted: #6c5a50;\n  --v2-cream: #fffaf1;\n  --v2-panel: #efe3d3;\n  --v2-line: rgba(90, 67, 51, 0.24);\n  --v2-accent: #b0412b;\n  --v2-accent-2: #0e6a73;\n}\n\n.new-home-v2 > div {\n  background:\n    radial-gradient(1200px 580px at 90% -15%, rgba(14, 106, 115, 0.2), transparent 65%),\n    radial-gradient(900px 500px at -10% 15%, rgba(176, 65, 43, 0.2), transparent 65%),\n    linear-gradient(170deg, #f8f4ed 0%, #f5eada 48%, #f7f1e8 100%) !important;\n}\n\n.new-home-v2 > div > div {\n  background: color-mix(in srgb, var(--v2-cream) 86%, #fff) !important;\n  border-color: rgba(117, 92, 70, 0.2) !important;\n  border-radius: 8px !important;\n  box-shadow:\n    0 1px 0 rgba(255, 255, 255, 0.8) inset,\n    0 20px 32px rgba(48, 32, 22, 0.14),\n    0 46px 90px rgba(43, 28, 19, 0.2) !important;\n}\n\n.new-home-v2 [data-name=\"Section Hero\"] {\n  padding-top: 92px !important;\n  position: relative;\n}\n\n.new-home-v2 [data-name=\"Section Hero\"]::before {\n  animation: v2-stripes 22s linear infinite;\n  background:\n    repeating-linear-gradient(\n      -45deg,\n      transparent 0 14px,\n      rgba(176, 65, 43, 0.06) 14px 16px,\n      transparent 16px 30px\n    );\n  content: \"\";\n  inset: 0;\n  pointer-events: none;\n  position: absolute;\n}\n\n.new-home-v2 #hero h1,\n.new-home-v2 #services h2,\n.new-home-v2 #authority h2,\n.new-home-v2 #local h2,\n.new-home-v2 #case-studies h2,\n.new-home-v2 #solutions h2,\n.new-home-v2 #ai-aeo h2,\n.new-home-v2 #contact h2 {\n  color: var(--v2-ink) !important;\n  font-family: var(--font-family-sans) !important;\n  font-weight: 300 !important;\n  letter-spacing: -0.01em;\n}\n\n.new-home-v2 #hero h1 {\n  font-size: clamp(2.2rem, 6vw, 5.25rem) !important;\n  max-width: 14ch !important;\n  text-wrap: balance;\n}\n\n.new-home-v2 p,\n.new-home-v2 #services p,\n.new-home-v2 #authority p,\n.new-home-v2 #local p,\n.new-home-v2 #case-studies p,\n.new-home-v2 #solutions p,\n.new-home-v2 #ai-aeo p,\n.new-home-v2 #contact p,\n.new-home-v2 footer p,\n.new-home-v2 footer a {\n  color: var(--v2-muted) !important;\n}\n\n.new-home-v2 #hero button:first-of-type,\n.new-home-v2 #contact button {\n  background: linear-gradient(95deg, #a73b28, #cb6444) !important;\n  box-shadow: 0 14px 28px rgba(167, 59, 40, 0.24);\n}\n\n.new-home-v2 #hero button:first-of-type p,\n.new-home-v2 #contact button p {\n  color: #fff6f1 !important;\n}\n\n.new-home-v2 #hero button:last-of-type {\n  background: color-mix(in srgb, #fff8ee 80%, #fff) !important;\n}\n\n.new-home-v2 #hero button:last-of-type div {\n  border-color: rgba(68, 45, 30, 0.5) !important;\n}\n\n.new-home-v2 #hero button:last-of-type p {\n  color: #352317 !important;\n}\n\n.new-home-v2 #services,\n.new-home-v2 #case-studies,\n.new-home-v2 #contact {\n  background: linear-gradient(180deg, #f9f2e8 0%, #f4e8d9 100%) !important;\n}\n\n.new-home-v2 #local,\n.new-home-v2 #ai-aeo {\n  background: linear-gradient(180deg, rgba(14, 106, 115, 0.08) 0%, transparent 75%) !important;\n}\n\n.new-home-v2 #services .bg-white,\n.new-home-v2 #case-studies .bg-white,\n.new-home-v2 #authority .bg-\\[\\#f9f9f9\\],\n.new-home-v2 #solutions .bg-\\[\\#f9f9f9\\],\n.new-home-v2 #local .bg-\\[\\#f9f9f9\\],\n.new-home-v2 #ai-aeo .bg-\\[\\#f9f9f9\\] {\n  background: linear-gradient(160deg, #f6ecde, var(--v2-panel)) !important;\n  border: 1px solid var(--v2-line) !important;\n  box-shadow: 0 12px 24px rgba(76, 53, 37, 0.1);\n}\n\n.new-home-v2 #services .group,\n.new-home-v2 #case-studies .group,\n.new-home-v2 #solutions .group {\n  transition: transform 280ms ease, box-shadow 280ms ease, border-color 280ms ease !important;\n}\n\n.new-home-v2 #services .group:hover,\n.new-home-v2 #case-studies .group:hover,\n.new-home-v2 #solutions .group:hover {\n  border-color: rgba(176, 65, 43, 0.5) !important;\n  box-shadow: 0 24px 34px rgba(71, 50, 36, 0.18) !important;\n  transform: translateY(-8px) !important;\n}\n\n.new-home-v2 #authority .text-\\[\\#9B3139\\],\n.new-home-v2 #ai-aeo .text-\\[\\#9B3139\\] {\n  color: var(--v2-accent) !important;\n}\n\n.new-home-v2 #ai-aeo .text-\\[\\#4FA5AE\\] {\n  color: var(--v2-accent-2) !important;\n}\n\n.new-home-v2 #case-studies .bg-\\[\\#FFAA1D\\]\\/10 {\n  background: rgba(176, 65, 43, 0.12) !important;\n}\n\n.new-home-v2 #case-studies .bg-\\[\\#FFAA1D\\]\\/10 p {\n  color: var(--v2-accent) !important;\n}\n\n.new-home-v2 header > div:first-child {\n  background: linear-gradient(90deg, #8d3323, #b74e37) !important;\n}\n\n.new-home-v2 header p {\n  color: #ffe8dd !important;\n}\n\n/* Accessibility fix: keep message-bar and navbar CTA text legible */\n.new-home-v2 .w-full.bg-\\[\\#9B3139\\] > p {\n  color: #fff4ea !important;\n  text-shadow: 0 1px 0 rgba(0, 0, 0, 0.18);\n}\n\n.new-home-v2 .bg-\\[\\#9B3139\\].content-stretch p {\n  color: #fff4ea !important;\n  text-shadow: 0 1px 0 rgba(0, 0, 0, 0.18);\n}\n\n.new-home-v2 nav p,\n.new-home-v2 nav svg {\n  color: #51362a !important;\n}\n\n.new-home-v2 nav button:hover p {\n  color: #1f130d !important;\n}\n\n.new-home-v2 footer {\n  background: #f7ede1 !important;\n}\n\n.new-home-v2 footer h3 {\n  color: #2a1b11 !important;\n}\n\n.new-home-v2 footer .text-\\[\\#9B3139\\] {\n  color: var(--v2-accent-2) !important;\n}\n\n@keyframes v2-stripes {\n  from {\n    background-position: 0 0;\n  }\n  to {\n    background-position: 90px 0;\n  }\n}\n\n@media (max-width: 920px) {\n  .new-home-v2 #hero h1 {\n    max-width: 18ch !important;\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .new-home-v2 *,\n  .new-home-v2 *::before,\n  .new-home-v2 *::after {\n    animation: none !important;\n    transition: none !important;\n  }\n}\n"},{"path":"src/styles/new-home-v3.css","content":".new-home-v3 {\n  --bg: #071424;\n  --panel: #10253f;\n  --panel-2: #153355;\n  --text: #eef5ff;\n  --muted: #a9bfd8;\n  --line: rgba(182, 212, 245, 0.24);\n  --accent: #ffa84c;\n  --accent-2: #4bd1be;\n  background: radial-gradient(1200px 700px at 90% -20%, rgba(75, 209, 190, 0.2), transparent 60%), linear-gradient(155deg, #071321 8%, #081a2d 45%, #10253f 100%);\n  color: var(--text);\n  min-height: 100vh;\n}\n\n.nh3-header-wrap {\n  position: sticky;\n  top: 0;\n  z-index: 30;\n  backdrop-filter: blur(12px);\n  background: color-mix(in srgb, #081a2d 78%, transparent);\n  border-bottom: 1px solid var(--line);\n}\n\n.nh3-topbar {\n  background: linear-gradient(90deg, #123f64, #1e577e);\n  color: #d9ecff;\n  font-size: 12px;\n  letter-spacing: 0.12em;\n  padding: 8px 14px;\n  text-align: center;\n  text-transform: uppercase;\n}\n\n.nh3-header {\n  align-items: center;\n  display: flex;\n  gap: 20px;\n  justify-content: space-between;\n  padding: 14px 20px;\n}\n\n.nh3-logo {\n  align-items: center;\n  color: var(--text);\n  display: flex;\n  gap: 10px;\n}\n\n.nh3-logo img { height: 36px; width: 36px; }\n.nh3-logo span { font-size: 13px; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; }\n.nh3-vintage-logo { border-radius: 999px; }\n\n.nh3-nav.desktop {\n  align-items: center;\n  display: none;\n  gap: 8px;\n}\n\n.nh3-nav button,\n.nh3-dd > button {\n  align-items: center;\n  color: var(--muted);\n  display: inline-flex;\n  font-size: 13px;\n  gap: 6px;\n  letter-spacing: 0.08em;\n  padding: 8px 10px;\n  text-transform: uppercase;\n}\n\n.nh3-nav button:hover,\n.nh3-dd > button:hover { color: var(--text); }\n\n.nh3-dd { position: relative; }\n.nh3-dd-menu {\n  background: #102944;\n  border: 1px solid var(--line);\n  border-radius: 12px;\n  box-shadow: 0 18px 36px rgba(3, 10, 20, 0.45);\n  display: none;\n  left: 50%;\n  max-height: 260px;\n  overflow-y: auto;\n  padding: 8px;\n  position: absolute;\n  top: 34px;\n  transform: translateX(-50%);\n  width: 300px;\n}\n.nh3-dd:hover .nh3-dd-menu { display: block; }\n.nh3-dd-menu button {\n  border-radius: 8px;\n  color: var(--muted);\n  display: block;\n  font-size: 13px;\n  padding: 9px 10px;\n  text-align: left;\n  text-transform: none;\n  width: 100%;\n}\n.nh3-dd-menu button:hover { background: rgba(255, 255, 255, 0.06); color: var(--text); }\n\n.nh3-mobile-toggle { color: var(--text); }\n.nh3-nav-mobile {\n  border-top: 1px solid var(--line);\n  display: grid;\n  gap: 4px;\n  padding: 14px;\n}\n.nh3-nav-mobile > button,\n.nh3-nav-mobile > div > button {\n  align-items: center;\n  color: var(--muted);\n  display: flex;\n  justify-content: space-between;\n  padding: 10px;\n}\n.nh3-mobile-submenu { display: grid; gap: 2px; padding-left: 12px; }\n.nh3-mobile-submenu button { color: var(--muted); font-size: 13px; padding: 8px 10px; text-align: left; }\n.rot { transform: rotate(180deg); }\n.nh3-vintage-toggle {\n  border: 1px dashed rgba(255, 168, 76, 0.7);\n  border-radius: 999px;\n  color: var(--accent);\n  font-size: 12px;\n  letter-spacing: 0.08em;\n  padding: 10px 14px;\n  text-transform: uppercase;\n}\n\n.nh3-cta,\n.nh3-ghost {\n  border-radius: 999px;\n  font-size: 13px;\n  font-weight: 700;\n  letter-spacing: 0.08em;\n  padding: 12px 18px;\n  text-transform: uppercase;\n  transition: transform 220ms ease, box-shadow 220ms ease;\n}\n.nh3-cta { background: linear-gradient(92deg, var(--accent), #ffc17b); color: #21170f; box-shadow: 0 16px 30px rgba(255, 168, 76, 0.25); }\n.nh3-ghost { border: 1px solid rgba(190, 216, 245, 0.45); color: var(--text); }\n.nh3-cta:hover, .nh3-ghost:hover { transform: translateY(-2px); }\n\n.nh3-section,\n.nh3-hero {\n  margin: 0 auto;\n  max-width: 1220px;\n  padding: 88px 20px;\n}\n\n.nh3-hero {\n  padding-top: 96px;\n  position: relative;\n}\n.nh3-hero-noise {\n  animation: nh3-pan 28s linear infinite;\n  background: repeating-linear-gradient(-45deg, transparent 0 16px, rgba(255, 255, 255, 0.04) 16px 18px);\n  border: 1px solid var(--line);\n  border-radius: 22px;\n  inset: 34px 20px 0;\n  position: absolute;\n  z-index: 0;\n}\n.nh3-hero h1,\n.nh3-hero p,\n.nh3-hero-cta { position: relative; z-index: 1; }\n.nh3-hero h1 { font-family: var(--font-family-sans); font-size: clamp(2.2rem, 6.2vw, 5.45rem); line-height: 1.02; max-width: 13.5ch; letter-spacing: -0.02em; }\n.nh3-hero p { color: var(--muted); font-size: clamp(1rem, 1.55vw, 1.2rem); line-height: 1.72; margin-top: 22px; max-width: 62ch; }\n.nh3-hero-cta { display: flex; flex-wrap: wrap; gap: 12px; margin-top: 32px; }\n\n.nh3-section h2 { font-family: var(--font-family-sans); font-size: clamp(1.82rem, 3.4vw, 3.08rem); line-height: 1.1; margin-bottom: 26px; max-width: 20ch; letter-spacing: -0.01em; }\n.nh3-section h3 { font-size: 1.22rem; line-height: 1.35; margin-bottom: 10px; }\n.nh3-section p { color: var(--muted); line-height: 1.74; }\n\n.nh3-cards-3 { display: grid; gap: 18px; grid-template-columns: repeat(3, minmax(0, 1fr)); }\n.nh3-cards-2 { display: grid; gap: 18px; grid-template-columns: repeat(2, minmax(0, 1fr)); }\n\n.nh3-cards-3 article,\n.nh3-cards-2 article,\n.nh3-metrics > div {\n  background: linear-gradient(160deg, var(--panel), var(--panel-2));\n  border: 1px solid var(--line);\n  border-radius: 16px;\n  box-shadow: 0 16px 28px rgba(2, 9, 18, 0.22);\n  padding: 24px;\n  transition: transform 260ms ease, border-color 260ms ease, box-shadow 260ms ease;\n}\n.nh3-cards-3 article:hover,\n.nh3-cards-2 article:hover { border-color: rgba(255, 168, 76, 0.58); box-shadow: 0 22px 36px rgba(2, 9, 18, 0.28); transform: translateY(-7px); }\n\n.nh3-authority { display: grid; gap: 22px; grid-template-columns: 1.1fr 1fr; }\n.nh3-metrics { display: grid; gap: 16px; grid-template-columns: repeat(2, minmax(0, 1fr)); }\n.nh3-metrics p { color: var(--accent); font-size: clamp(1.8rem, 3.8vw, 2.7rem); font-weight: 700; line-height: 1; margin: 0; }\n.nh3-metrics span { color: var(--muted); font-size: 12px; letter-spacing: 0.11em; text-transform: uppercase; }\n\n.nh3-split { align-items: center; display: grid; gap: 22px; grid-template-columns: 1fr 1fr; }\n.nh3-split.reverse { grid-template-columns: 1fr 1fr; }\n.nh3-image-wrap { border-radius: 18px; overflow: hidden; min-height: 360px; }\n.nh3-image-wrap img { height: 100%; object-fit: cover; width: 100%; }\n\n.nh3-cards-3 article span {\n  background: rgba(255, 168, 76, 0.16);\n  border-radius: 999px;\n  color: var(--accent);\n  display: inline-block;\n  font-size: 11px;\n  letter-spacing: 0.08em;\n  margin-top: 14px;\n  padding: 5px 10px;\n  text-transform: uppercase;\n}\n\n.nh3-mini-metrics { display: grid; gap: 12px; grid-template-columns: repeat(2, minmax(0, 1fr)); margin-top: 16px; }\n.nh3-mini-metrics > div { background: rgba(255, 255, 255, 0.04); border: 1px solid var(--line); border-radius: 12px; padding: 12px; }\n.nh3-mini-metrics strong { color: var(--accent-2); display: block; font-size: 1.4rem; }\n.nh3-mini-metrics span { color: var(--muted); font-size: 13px; }\n\n.nh3-final { text-align: center; }\n.nh3-final p { margin: 0 auto 20px; max-width: 62ch; }\n.nh3-final .nh3-cta { margin-bottom: 18px; }\n.nh3-contact-row { display: flex; flex-wrap: wrap; gap: 14px; justify-content: center; }\n.nh3-contact-row a, .nh3-contact-row span { color: var(--muted); font-size: 14px; }\n\n/* Footer redesign scoped to v3 only */\n.new-home-v3 footer {\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0)),\n    linear-gradient(160deg, #0a1d33, #102945) !important;\n  border-top: 1px solid var(--line) !important;\n  position: relative;\n}\n\n.new-home-v3 footer::before {\n  background: linear-gradient(90deg, transparent, rgba(255, 168, 76, 0.32), transparent);\n  content: \"\";\n  height: 1px;\n  left: 0;\n  position: absolute;\n  right: 0;\n  top: 0;\n}\n\n.new-home-v3 footer h3 {\n  color: var(--text) !important;\n  font-size: 13px !important;\n  letter-spacing: 0.1em;\n  text-transform: uppercase;\n}\n\n.new-home-v3 footer p,\n.new-home-v3 footer li,\n.new-home-v3 footer a {\n  color: var(--muted) !important;\n}\n\n.new-home-v3 footer a:hover {\n  color: #ffffff !important;\n}\n\n.new-home-v3 footer img {\n  filter: drop-shadow(0 10px 22px rgba(0, 0, 0, 0.35));\n}\n\n.new-home-v3 footer .text-\\[\\#9B3139\\] {\n  color: var(--accent-2) !important;\n}\n\n.new-home-v3 footer .border-t,\n.new-home-v3 footer .border-\\[\\#f3f3f3\\] {\n  border-color: var(--line) !important;\n}\n\n@media (max-width: 1080px) {\n  .new-home-v3 footer {\n    border-radius: 0 0 14px 14px;\n  }\n}\n\n/* 1995 mode */\n.new-home-v3.nh3-vintage {\n  background: #e8ee93 !important;\n  color: #000 !important;\n  font-family: \"Times New Roman\", Times, serif !important;\n}\n\n.new-home-v3.nh3-vintage * {\n  border-radius: 0 !important;\n  box-shadow: none !important;\n  text-shadow: none !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-header-wrap,\n.new-home-v3.nh3-vintage .nh3-topbar,\n.new-home-v3.nh3-vintage footer,\n.new-home-v3.nh3-vintage .nh3-cards-3 article,\n.new-home-v3.nh3-vintage .nh3-cards-2 article,\n.new-home-v3.nh3-vintage .nh3-metrics > div,\n.new-home-v3.nh3-vintage .nh3-mini-metrics > div {\n  background: transparent !important;\n  border: 0 !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-hero-noise,\n.new-home-v3.nh3-vintage .nh3-image-wrap::before,\n.new-home-v3.nh3-vintage footer::before {\n  display: none !important;\n}\n\n.new-home-v3.nh3-vintage h1,\n.new-home-v3.nh3-vintage h2,\n.new-home-v3.nh3-vintage h3,\n.new-home-v3.nh3-vintage p,\n.new-home-v3.nh3-vintage a,\n.new-home-v3.nh3-vintage span,\n.new-home-v3.nh3-vintage button,\n.new-home-v3.nh3-vintage strong {\n  color: #000 !important;\n  font-family: \"Times New Roman\", Times, serif !important;\n  letter-spacing: 0 !important;\n  text-transform: none !important;\n}\n\n.new-home-v3.nh3-vintage h1,\n.new-home-v3.nh3-vintage h2,\n.new-home-v3.nh3-vintage h3,\n.new-home-v3.nh3-vintage strong {\n  color: #4b0018 !important;\n}\n\n.new-home-v3.nh3-vintage a {\n  color: #0000ee !important;\n  text-decoration: underline !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-cta,\n.new-home-v3.nh3-vintage .nh3-ghost,\n.new-home-v3.nh3-vintage .nh3-vintage-toggle {\n  background: #d23f2f !important;\n  border: 2px outset #f3a153 !important;\n  color: #ffe8b5 !important;\n  font-weight: 400 !important;\n  padding: 10px 12px !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-cta:active,\n.new-home-v3.nh3-vintage .nh3-ghost:active,\n.new-home-v3.nh3-vintage .nh3-vintage-toggle:active {\n  border: 2px inset #fff !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-nav.desktop {\n  border-top: 1px solid rgba(106, 85, 51, 0.35);\n  border-bottom: 1px solid rgba(106, 85, 51, 0.35);\n  padding: 6px 0;\n}\n\n.new-home-v3.nh3-vintage .nh3-dd-menu {\n  background: #e8ee93 !important;\n  border: 1px solid rgba(106, 85, 51, 0.35) !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-section,\n.new-home-v3.nh3-vintage .nh3-hero {\n  max-width: 1100px;\n  padding: 32px 18px;\n  text-align: center;\n}\n\n.new-home-v3.nh3-vintage .nh3-hero h1 {\n  font-size: clamp(2rem, 4vw, 3.15rem) !important;\n  line-height: 1.15 !important;\n  max-width: 20ch !important;\n  margin: 0 auto;\n}\n\n.new-home-v3.nh3-vintage .nh3-hero p,\n.new-home-v3.nh3-vintage .nh3-section p {\n  font-size: 17px !important;\n  line-height: 1.5 !important;\n  max-width: 68ch;\n  margin-left: auto;\n  margin-right: auto;\n}\n\n.new-home-v3.nh3-vintage .nh3-cards-3,\n.new-home-v3.nh3-vintage .nh3-cards-2,\n.new-home-v3.nh3-vintage .nh3-authority,\n.new-home-v3.nh3-vintage .nh3-split,\n.new-home-v3.nh3-vintage .nh3-split.reverse {\n  grid-template-columns: 1fr !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-image-wrap {\n  border: 1px solid rgba(106, 85, 51, 0.35) !important;\n  margin: 8px auto 0;\n  max-width: 780px;\n  min-height: 220px !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-contact-row {\n  justify-content: center;\n}\n\n@media (prefers-reduced-motion: no-preference) {\n  .new-home-v3.nh3-vintage {\n    animation: vintage-flicker 2.6s steps(1, end) infinite;\n  }\n}\n\n.new-home-v3.nh3-vintage .nh3-header-wrap {\n  background: #e8ee93 !important;\n  border-bottom: 1px solid rgba(106, 85, 51, 0.35) !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-topbar {\n  background: transparent !important;\n  border-bottom: 1px solid rgba(106, 85, 51, 0.35);\n  color: #4b0018 !important;\n  font-size: 20px;\n  font-weight: 700;\n  letter-spacing: 0;\n  text-transform: none !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-header {\n  justify-content: center;\n  padding: 12px 16px;\n}\n\n.new-home-v3.nh3-vintage .nh3-logo {\n  flex-direction: column;\n  gap: 8px;\n}\n\n.new-home-v3.nh3-vintage .nh3-logo img {\n  border: 1px solid rgba(106, 85, 51, 0.35);\n  border-radius: 999px !important;\n  height: 84px;\n  width: 84px;\n}\n.new-home-v3.nh3-vintage .nh3-vintage-logo {\n  height: 132px;\n  width: 132px;\n  border: 1px solid rgba(106, 85, 51, 0.35);\n  box-shadow: 0 8px 20px rgba(74, 0, 24, 0.26);\n}\n\n.new-home-v3.nh3-vintage .nh3-logo span {\n  color: #4b0018 !important;\n  font-size: 42px;\n  font-weight: 700;\n  letter-spacing: 0;\n}\n\n.new-home-v3.nh3-vintage .nh3-nav.desktop {\n  justify-content: center;\n  margin-top: 4px;\n  width: 100%;\n}\n\n.new-home-v3.nh3-vintage .nh3-nav button,\n.new-home-v3.nh3-vintage .nh3-dd > button {\n  color: #0000ee !important;\n  font-size: 16px;\n}\n\n.new-home-v3.nh3-vintage .nh3-mobile-toggle,\n.new-home-v3.nh3-vintage .nh3-nav-mobile {\n  display: none !important;\n}\n\n.new-home-v3.nh3-vintage .desktop {\n  display: inline-flex !important;\n}\n\n.new-home-v3.nh3-vintage .nh3-hero,\n.new-home-v3.nh3-vintage .nh3-section {\n  border-top: 1px solid rgba(106, 85, 51, 0.35);\n}\n\n.new-home-v3.nh3-vintage .nh3-section h2 {\n  font-size: clamp(2rem, 3.2vw, 3rem) !important;\n  margin-left: auto;\n  margin-right: auto;\n}\n\n.new-home-v3.nh3-vintage .nh3-cards-3 article,\n.new-home-v3.nh3-vintage .nh3-cards-2 article,\n.new-home-v3.nh3-vintage .nh3-metrics > div {\n  border-top: 1px solid rgba(106, 85, 51, 0.35) !important;\n  padding: 22px 8px 14px;\n}\n\n.new-home-v3.nh3-vintage footer {\n  background: #e8ee93 !important;\n  border-top: 1px solid rgba(106, 85, 51, 0.35) !important;\n  margin-bottom: 68px;\n}\n\n.new-home-v3.nh3-vintage .nh3-vintage-dock {\n  align-items: center;\n  background: #e8de87;\n  border-top: 2px solid rgba(106, 85, 51, 0.4);\n  bottom: 0;\n  display: flex;\n  gap: 8px;\n  justify-content: center;\n  left: 0;\n  padding: 9px 10px;\n  position: fixed;\n  right: 0;\n  z-index: 60;\n}\n\n.new-home-v3.nh3-vintage .nh3-vintage-dock button {\n  background: #d23f2f !important;\n  border: 2px outset #f3a153 !important;\n  color: #ffe8b5 !important;\n  font-size: 12px;\n  letter-spacing: 0;\n  padding: 6px 10px;\n}\n\n@keyframes vintage-flicker {\n  0%, 100% { filter: none; }\n  50% { filter: contrast(1.02); }\n}\n\n@keyframes nh3-pan {\n  from { background-position: 0 0; }\n  to { background-position: 80px 0; }\n}\n\n@media (min-width: 1100px) {\n  .nh3-nav.desktop, .nh3-cta.desktop { display: inline-flex; }\n  .nh3-mobile-toggle { display: none; }\n}\n\n@media (max-width: 1080px) {\n  .nh3-cards-3 { grid-template-columns: 1fr; }\n  .nh3-cards-2 { grid-template-columns: 1fr; }\n  .nh3-authority, .nh3-split, .nh3-split.reverse { grid-template-columns: 1fr; }\n  .nh3-section,\n  .nh3-hero { padding: 72px 20px; }\n  .nh3-hero { padding-top: 78px; }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .new-home-v3 *,\n  .new-home-v3 *::before,\n  .new-home-v3 *::after {\n    animation: none !important;\n    transition: none !important;\n  }\n}\n"},{"path":"src/styles/new-home-v4.css","content":".new-home-v4 {\n  --v4-bg: #f6fbfa;\n  --v4-surface: #ffffff;\n  --v4-surface-2: #eefaf8;\n  --v4-text: #18333a;\n  --v4-muted: #52717a;\n  --v4-line: rgba(38, 125, 133, 0.18);\n  --v4-accent: #9b3139;\n  --v4-accent-strong: #7a2730;\n  --v4-accent-soft: #f4d9dc;\n  --v4-accent-2: #18b7b0;\n  --v4-accent-2-soft: #e3fbf8;\n}\n\n.new-home-v4 > div {\n  background:\n    radial-gradient(1100px 640px at 92% -16%, rgba(24, 183, 176, 0.18), transparent 62%),\n    radial-gradient(900px 520px at -8% 10%, rgba(155, 49, 57, 0.16), transparent 60%),\n    linear-gradient(180deg, #f9fffe 0%, #f6fbfa 44%, #eef8f6 100%) !important;\n}\n\n.new-home-v4 > div > div {\n  background: color-mix(in srgb, var(--v4-surface) 92%, #f7fffd) !important;\n  border-color: var(--v4-line) !important;\n  box-shadow:\n    0 1px 0 rgba(255, 255, 255, 0.95) inset,\n    0 20px 34px rgba(27, 72, 80, 0.08),\n    0 50px 100px rgba(21, 58, 63, 0.1) !important;\n}\n\n.new-home-v4 [data-name=\"Section Hero\"] {\n  isolation: isolate;\n  overflow: hidden;\n  padding-top: 90px !important;\n  position: relative;\n}\n\n.new-home-v4 [data-name=\"Section Hero\"]::before {\n  background:\n    linear-gradient(90deg, rgba(249, 255, 254, 0.82) 0%, rgba(249, 255, 254, 0.56) 34%, rgba(249, 255, 254, 0.38) 62%, rgba(249, 255, 254, 0.74) 100%),\n    linear-gradient(180deg, rgba(24, 183, 176, 0.1), rgba(155, 49, 57, 0.1));\n  background-position: center, center;\n  background-repeat: no-repeat;\n  background-size: 100% 100%, 100% 100%;\n  content: \"\";\n  inset: 0;\n  mask-image: none;\n  pointer-events: none;\n  position: absolute;\n  z-index: -2;\n}\n\n.new-home-v4 [data-name=\"Section Hero\"]::after {\n  animation: new-home-v4-orb 10s ease-in-out infinite;\n  background: radial-gradient(circle at center, rgba(155, 49, 57, 0.18) 0%, rgba(155, 49, 57, 0) 70%);\n  border-radius: 999px;\n  content: \"\";\n  filter: blur(28px);\n  height: 360px;\n  opacity: 1;\n  pointer-events: none;\n  position: absolute;\n  right: -90px;\n  top: -120px;\n  width: 360px;\n  z-index: -1;\n}\n\n.new-home-v4 .nh4-hero-rotator {\n  inset: 0;\n  pointer-events: none;\n  position: absolute;\n  z-index: -3;\n}\n\n.new-home-v4 .nh4-hero-image,\n.new-home-v4 .nh4-hero-overlay {\n  inset: 0;\n  position: absolute;\n}\n\n.new-home-v4 .nh4-hero-image {\n  background-position: center;\n  background-repeat: no-repeat;\n  background-size: cover;\n  opacity: 0;\n  transition: opacity 900ms ease;\n}\n\n.new-home-v4 .nh4-hero-image.is-active {\n  opacity: 1;\n}\n\n.new-home-v4 .nh4-hero-overlay {\n  background:\n    linear-gradient(90deg, rgba(249, 255, 254, 0.9) 0%, rgba(249, 255, 254, 0.64) 34%, rgba(249, 255, 254, 0.42) 62%, rgba(249, 255, 254, 0.78) 100%),\n    linear-gradient(180deg, rgba(24, 183, 176, 0.08), rgba(155, 49, 57, 0.08));\n}\n\n.new-home-v4 #hero h1 {\n  color: var(--v4-text) !important;\n}\n\n.new-home-v4 #hero p,\n.new-home-v4 #services p,\n.new-home-v4 #authority p,\n.new-home-v4 #local p,\n.new-home-v4 #case-studies p,\n.new-home-v4 #solutions p,\n.new-home-v4 #ai-aeo p,\n.new-home-v4 #contact p,\n.new-home-v4 footer p,\n.new-home-v4 footer a {\n  color: var(--v4-muted) !important;\n}\n\n.new-home-v4 #services,\n.new-home-v4 #case-studies,\n.new-home-v4 #contact {\n  background: linear-gradient(180deg, rgba(227, 251, 248, 0.55) 0%, rgba(255, 255, 255, 0.5) 100%) !important;\n}\n\n.new-home-v4 #local,\n.new-home-v4 #ai-aeo {\n  background: linear-gradient(180deg, rgba(155, 49, 57, 0.05) 0%, transparent 74%) !important;\n}\n\n.new-home-v4 #services h2,\n.new-home-v4 #authority h2,\n.new-home-v4 #local h2,\n.new-home-v4 #case-studies h2,\n.new-home-v4 #solutions h2,\n.new-home-v4 #ai-aeo h2,\n.new-home-v4 #contact h2,\n.new-home-v4 #services h3,\n.new-home-v4 #case-studies h3,\n.new-home-v4 #solutions h3 {\n  color: var(--v4-text) !important;\n}\n\n.new-home-v4 #authority .bg-\\[\\#f9f9f9\\],\n.new-home-v4 #services .bg-white,\n.new-home-v4 #case-studies .bg-white,\n.new-home-v4 #solutions .bg-\\[\\#f9f9f9\\],\n.new-home-v4 #local .bg-\\[\\#f9f9f9\\],\n.new-home-v4 #ai-aeo .bg-\\[\\#f9f9f9\\],\n.new-home-v4 #contact .bg-\\[\\#fafafa\\] {\n  background: linear-gradient(160deg, var(--v4-surface), var(--v4-surface-2)) !important;\n  border: 1px solid var(--v4-line) !important;\n  box-shadow: 0 16px 30px rgba(30, 87, 94, 0.08);\n}\n\n.new-home-v4 #services .group,\n.new-home-v4 #case-studies .group,\n.new-home-v4 #solutions .group {\n  transition: transform 280ms ease, box-shadow 280ms ease, border-color 280ms ease !important;\n}\n\n.new-home-v4 #services .group:hover,\n.new-home-v4 #case-studies .group:hover,\n.new-home-v4 #solutions .group:hover {\n  border-color: rgba(24, 183, 176, 0.36) !important;\n  box-shadow: 0 22px 34px rgba(24, 91, 96, 0.12) !important;\n  transform: translateY(-6px) !important;\n}\n\n.new-home-v4 #hero button:first-of-type,\n.new-home-v4 #contact button,\n.new-home-v4 .w-full.bg-\\[\\#9B3139\\],\n.new-home-v4 .bg-\\[\\#9B3139\\].content-stretch {\n  background: linear-gradient(92deg, var(--v4-accent), #c55a63) !important;\n  box-shadow: 0 14px 28px rgba(155, 49, 57, 0.2);\n}\n\n.new-home-v4 #hero button:first-of-type p,\n.new-home-v4 #contact button p,\n.new-home-v4 .w-full.bg-\\[\\#9B3139\\] > p,\n.new-home-v4 .bg-\\[\\#9B3139\\].content-stretch p {\n  color: #ffffff !important;\n  text-shadow: none !important;\n}\n\n.new-home-v4 #hero button:last-of-type {\n  background: color-mix(in srgb, #ffffff 80%, var(--v4-accent-2-soft)) !important;\n}\n\n.new-home-v4 #hero button:last-of-type div {\n  border-color: rgba(24, 183, 176, 0.38) !important;\n}\n\n.new-home-v4 #hero button:last-of-type p {\n  color: var(--v4-text) !important;\n}\n\n.new-home-v4 #case-studies .bg-\\[\\#FFAA1D\\]\\/10 {\n  background: rgba(155, 49, 57, 0.1) !important;\n}\n\n.new-home-v4 #case-studies .bg-\\[\\#FFAA1D\\]\\/10 p,\n.new-home-v4 #authority .text-\\[\\#9B3139\\],\n.new-home-v4 #ai-aeo .text-\\[\\#9B3139\\] {\n  color: var(--v4-accent) !important;\n}\n\n.new-home-v4 #ai-aeo .text-\\[\\#4FA5AE\\],\n.new-home-v4 footer .text-\\[\\#9B3139\\] {\n  color: var(--v4-accent-2) !important;\n}\n\n.new-home-v4 header > div:first-child {\n  background: linear-gradient(90deg, #0ea9a4, #2dc9c1) !important;\n}\n\n.new-home-v4 header p {\n  color: #efffff !important;\n}\n\n.new-home-v4 nav p,\n.new-home-v4 nav svg {\n  color: var(--v4-text) !important;\n}\n\n.new-home-v4 nav button:hover p {\n  color: var(--v4-accent-strong) !important;\n}\n\n.new-home-v4 .absolute.bg-\\[\\#9B3139\\],\n.new-home-v4 .h-\\[2px\\].bg-\\[\\#9B3139\\],\n.new-home-v4 .h-\\[6px\\].w-\\[6px\\].shrink-0.rounded-full.bg-\\[\\#9B3139\\] {\n  background: var(--v4-accent) !important;\n}\n\n.new-home-v4 [style*=\"#9B3139 1px\"] {\n  background-image:\n    linear-gradient(rgba(155, 49, 57, 0.32) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(24, 183, 176, 0.34) 1px, transparent 1px) !important;\n}\n\n.new-home-v4 footer {\n  background: #f2fbf9 !important;\n  border-top-color: var(--v4-line) !important;\n}\n\n.new-home-v4 footer h3 {\n  color: var(--v4-text) !important;\n}\n\n@keyframes new-home-v4-orb {\n  0%,\n  100% {\n    transform: translate3d(0, 0, 0) scale(1);\n  }\n  50% {\n    transform: translate3d(-24px, 20px, 0) scale(1.08);\n  }\n}\n\n@media (max-width: 920px) {\n  .new-home-v4 #hero h1 {\n    max-width: 18ch !important;\n  }\n\n  .new-home-v4 [data-name=\"Section Hero\"]::after {\n    height: 280px;\n    right: -80px;\n    top: -80px;\n    width: 280px;\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .new-home-v4 *,\n  .new-home-v4 *::before,\n  .new-home-v4 *::after {\n    animation: none !important;\n    transition: none !important;\n  }\n}\n"},{"path":"src/styles/new-home.css","content":".new-home-redesign {\n  --nh-bg: #07172c;\n  --nh-surface: #0f2946;\n  --nh-surface-2: #123255;\n  --nh-text: #f5f8ff;\n  --nh-muted: #afc3da;\n  --nh-line: rgba(180, 209, 240, 0.24);\n  --nh-accent: #ff9f43;\n  --nh-accent-2: #53d2c6;\n}\n\n.new-home-redesign > div {\n  background:\n    radial-gradient(1200px 760px at 86% -16%, rgba(83, 210, 198, 0.2), transparent 64%),\n    radial-gradient(1100px 720px at -8% 14%, rgba(255, 159, 67, 0.2), transparent 60%),\n    linear-gradient(155deg, #071426 7%, #07172c 42%, #102441 100%) !important;\n}\n\n.new-home-redesign > div > div {\n  background: color-mix(in srgb, #0b1d34 82%, #0e2139) !important;\n  border-color: rgba(160, 193, 226, 0.2) !important;\n  box-shadow:\n    0 1px 0 rgba(255, 255, 255, 0.14) inset,\n    0 24px 44px rgba(0, 0, 0, 0.45),\n    0 80px 140px rgba(3, 7, 16, 0.62) !important;\n}\n\n.new-home-redesign [data-name=\"Section Hero\"] {\n  isolation: isolate;\n  padding-top: 90px !important;\n  position: relative;\n}\n\n.new-home-redesign [data-name=\"Section Hero\"]::before {\n  animation: new-home-grid-pan 28s linear infinite;\n  background-image:\n    linear-gradient(var(--nh-line) 1px, transparent 1px),\n    linear-gradient(90deg, var(--nh-line) 1px, transparent 1px);\n  background-size: 44px 44px;\n  content: \"\";\n  inset: 0;\n  mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.7) 0%, transparent 100%);\n  pointer-events: none;\n  position: absolute;\n  z-index: -2;\n}\n\n.new-home-redesign [data-name=\"Section Hero\"]::after {\n  animation: new-home-orb 9s ease-in-out infinite;\n  background: radial-gradient(circle at center, rgba(255, 159, 67, 0.65) 0%, rgba(255, 159, 67, 0) 68%);\n  content: \"\";\n  filter: blur(24px);\n  height: 420px;\n  pointer-events: none;\n  position: absolute;\n  right: -110px;\n  top: -170px;\n  width: 420px;\n  z-index: -1;\n}\n\n.new-home-redesign #hero h1 {\n  color: var(--nh-text) !important;\n  font-family: var(--font-family-sans) !important;\n  font-size: clamp(2.3rem, 6vw, 5.2rem) !important;\n  letter-spacing: -0.03em;\n  max-width: 15ch !important;\n  text-wrap: balance;\n}\n\n.new-home-redesign #hero p {\n  color: var(--nh-muted) !important;\n}\n\n.new-home-redesign #hero button {\n  border: 1px solid transparent;\n  will-change: transform;\n}\n\n.new-home-redesign #hero button:first-of-type {\n  background: linear-gradient(92deg, var(--nh-accent), #ffbc7b) !important;\n  box-shadow: 0 16px 32px rgba(255, 159, 67, 0.26);\n}\n\n.new-home-redesign #hero button:first-of-type p {\n  color: #1f1911 !important;\n}\n\n.new-home-redesign #hero button:last-of-type {\n  background: color-mix(in srgb, #0f2946 66%, transparent) !important;\n  border-color: rgba(202, 223, 245, 0.5);\n}\n\n.new-home-redesign #hero button:last-of-type p {\n  color: var(--nh-text) !important;\n}\n\n.new-home-redesign section[id]:not(#hero) {\n  background: transparent !important;\n}\n\n.new-home-redesign #services,\n.new-home-redesign #case-studies,\n.new-home-redesign #contact {\n  background: color-mix(in srgb, #0f2946 36%, transparent) !important;\n}\n\n.new-home-redesign #local,\n.new-home-redesign #ai-aeo {\n  background:\n    linear-gradient(180deg, color-mix(in srgb, #53d2c6 12%, transparent), transparent 70%) !important;\n}\n\n.new-home-redesign #services h2,\n.new-home-redesign #authority h2,\n.new-home-redesign #local h2,\n.new-home-redesign #case-studies h2,\n.new-home-redesign #solutions h2,\n.new-home-redesign #ai-aeo h2,\n.new-home-redesign #contact h2,\n.new-home-redesign #services h3,\n.new-home-redesign #case-studies h3,\n.new-home-redesign #solutions h3 {\n  color: var(--nh-text) !important;\n}\n\n.new-home-redesign #services p,\n.new-home-redesign #authority p,\n.new-home-redesign #local p,\n.new-home-redesign #case-studies p,\n.new-home-redesign #solutions p,\n.new-home-redesign #ai-aeo p,\n.new-home-redesign #contact p,\n.new-home-redesign footer p,\n.new-home-redesign footer a {\n  color: var(--nh-muted) !important;\n}\n\n.new-home-redesign #authority .bg-\\[\\#f9f9f9\\],\n.new-home-redesign #services .bg-white,\n.new-home-redesign #case-studies .bg-white,\n.new-home-redesign #solutions .bg-\\[\\#f9f9f9\\],\n.new-home-redesign #local .bg-\\[\\#f9f9f9\\],\n.new-home-redesign #ai-aeo .bg-\\[\\#f9f9f9\\],\n.new-home-redesign #contact .bg-\\[\\#fafafa\\] {\n  background: linear-gradient(165deg, var(--nh-surface), var(--nh-surface-2)) !important;\n  border: 1px solid var(--nh-line) !important;\n  box-shadow: 0 20px 38px rgba(0, 0, 0, 0.16);\n}\n\n.new-home-redesign #case-studies .bg-\\[\\#FFAA1D\\]\\/10 {\n  background: rgba(255, 159, 67, 0.14) !important;\n}\n\n.new-home-redesign #case-studies .bg-\\[\\#FFAA1D\\]\\/10 p,\n.new-home-redesign #authority .text-\\[\\#9B3139\\],\n.new-home-redesign #ai-aeo .text-\\[\\#4FA5AE\\],\n.new-home-redesign #ai-aeo .text-\\[\\#9B3139\\] {\n  color: var(--nh-accent) !important;\n}\n\n.new-home-redesign #services .group:hover,\n.new-home-redesign #case-studies .group:hover,\n.new-home-redesign #solutions .group:hover {\n  transform: translateY(-6px) !important;\n}\n\n.new-home-redesign header > div:first-child {\n  background: linear-gradient(90deg, #0b3454, #16456e) !important;\n}\n\n.new-home-redesign header p {\n  color: #cfe4ff !important;\n}\n\n.new-home-redesign nav p,\n.new-home-redesign nav svg {\n  color: #d7e8fb !important;\n}\n\n.new-home-redesign nav button:hover p {\n  color: #ffffff !important;\n}\n\n.new-home-redesign footer {\n  background: color-mix(in srgb, #081a2e 92%, transparent) !important;\n  border-top-color: var(--nh-line) !important;\n}\n\n.new-home-redesign footer h3 {\n  color: #f1f6ff !important;\n}\n\n.new-home-redesign footer .text-\\[\\#9B3139\\] {\n  color: var(--nh-accent-2) !important;\n}\n\n@keyframes new-home-grid-pan {\n  from {\n    transform: translate3d(0, 0, 0);\n  }\n  to {\n    transform: translate3d(44px, 44px, 0);\n  }\n}\n\n@keyframes new-home-orb {\n  0%,\n  100% {\n    transform: translate3d(0, 0, 0) scale(1);\n  }\n  50% {\n    transform: translate3d(-26px, 24px, 0) scale(1.08);\n  }\n}\n\n@media (max-width: 900px) {\n  .new-home-redesign #hero h1 {\n    max-width: 20ch !important;\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .new-home-redesign *,\n  .new-home-redesign *::before,\n  .new-home-redesign *::after {\n    animation: none !important;\n    transition: none !important;\n  }\n}\n"},{"path":"src/styles/our-approach-section.css","content":".oas-section {\n  padding: 88px 20px;\n}\n\n.oas-shell {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.oas-header,\n.oas-editorial-feature,\n.oas-ladder-card {\n  display: grid;\n  gap: 16px;\n}\n\n.oas-eyebrow,\n.oas-mini-label {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.oas-header {\n  margin-bottom: 36px;\n  max-width: 780px;\n}\n\n.oas-header h2,\n.oas-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.oas-header h2 {\n  font-size: clamp(2.2rem, 4vw, 4rem);\n  line-height: 0.98;\n}\n\n.oas-header p,\n.oas-editorial-feature > p,\n.oas-ladder-card p,\n.oas-feature-metrics p {\n  color: var(--mis-muted);\n  line-height: 1.7;\n  margin: 0;\n}\n\n.oas-editorial-shell {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: minmax(0, 0.98fr) minmax(0, 1.02fr);\n}\n\n.oas-editorial-feature {\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.74), rgba(255, 250, 243, 0.96)),\n    radial-gradient(circle at top left, rgba(166, 32, 37, 0.08), transparent 28%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 36px;\n  box-shadow: 0 22px 52px rgba(107, 74, 30, 0.09);\n  padding: 34px;\n}\n\n.oas-editorial-feature h3 {\n  font-size: clamp(2.2rem, 3.8vw, 3.8rem);\n  line-height: 0.96;\n}\n\n.oas-feature-metrics {\n  display: grid;\n  gap: 12px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.oas-feature-metrics div {\n  background: rgba(255, 255, 255, 0.62);\n  border: 1px solid rgba(166, 32, 37, 0.1);\n  border-radius: 22px;\n  padding: 18px;\n}\n\n.oas-feature-metrics span {\n  color: var(--mis-text);\n  display: block;\n  font-family: \"Manrope\", sans-serif;\n  font-size: 2.4rem;\n  font-weight: 300;\n  line-height: 1;\n  margin-bottom: 8px;\n}\n\n.oas-editorial-ladder {\n  display: grid;\n  gap: 18px;\n}\n\n.oas-ladder-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 28px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  padding: 24px;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease;\n}\n\n.oas-ladder-card:hover {\n  box-shadow: 0 24px 56px rgba(107, 74, 30, 0.16);\n  transform: translateY(-8px);\n}\n\n.oas-ladder-card--2 {\n  margin-left: 36px;\n}\n\n.oas-ladder-card--3 {\n  margin-left: 72px;\n}\n\n.oas-ladder-card--4 {\n  margin-left: 108px;\n}\n\n.oas-ladder-card__title {\n  align-items: center;\n  color: var(--accent);\n  display: flex;\n  gap: 12px;\n}\n\n.oas-ladder-card__title svg {\n  flex-shrink: 0;\n  height: 20px;\n  width: 20px;\n}\n\n.oas-ladder-card h3 {\n  font-size: clamp(1.45rem, 1.8vw, 2rem);\n  line-height: 1.08;\n}\n\n.oas-ladder-card__rail {\n  background: linear-gradient(90deg, color-mix(in srgb, var(--accent) 36%, white), transparent);\n  border-radius: 999px;\n  height: 2px;\n  margin-top: 8px;\n  width: 100%;\n}\n\n@media (max-width: 1100px) {\n  .oas-editorial-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .oas-ladder-card--2,\n  .oas-ladder-card--3,\n  .oas-ladder-card--4 {\n    margin-left: 0;\n  }\n}\n\n@media (max-width: 760px) {\n  .oas-section {\n    padding: 72px 16px;\n  }\n\n  .oas-editorial-feature,\n  .oas-ladder-card {\n    border-radius: 24px;\n    padding: 22px;\n  }\n\n  .oas-editorial-feature h3 {\n    font-size: 2rem;\n  }\n\n  .oas-feature-metrics {\n    grid-template-columns: 1fr;\n  }\n}\n"},{"path":"src/styles/resources-faq-variants.css","content":".resources-faq-lab {\n  background:\n    radial-gradient(circle at top center, rgba(255, 187, 84, 0.16), transparent 22%),\n    linear-gradient(180deg, #f7f1e7 0%, #eee0cd 100%);\n  color: #2c231d;\n}\n\n.rfv-hero {\n  padding: 5.5rem 1.5rem 3rem;\n}\n\n.rfv-hero-inner,\n.rfv-section {\n  width: min(1200px, 100%);\n  margin: 0 auto;\n}\n\n.rfv-hero-inner {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.rfv-back-link,\n.rfv-link {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.5rem;\n  font-weight: 600;\n  letter-spacing: 0.02em;\n  transition: opacity 180ms ease, transform 180ms ease;\n}\n\n.rfv-back-link {\n  color: #7a4f1d;\n}\n\n.rfv-back-link:hover,\n.rfv-link:hover {\n  opacity: 0.84;\n  transform: translateX(2px);\n}\n\n.rfv-hero h1 {\n  margin: 0;\n  max-width: 12ch;\n  font-size: clamp(2.6rem, 5vw, 4.8rem);\n  line-height: 0.98;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4c261f;\n}\n\n.rfv-hero p:not(.rfv-eyebrow) {\n  margin: 0;\n  max-width: 56rem;\n  font-size: 1.08rem;\n  line-height: 1.7;\n  color: #6e5849;\n}\n\n.rfv-section {\n  padding: 2rem 1.5rem 4.5rem;\n}\n\n.rfv-header {\n  display: flex;\n  flex-direction: column;\n  gap: 0.85rem;\n  max-width: 50rem;\n  margin-bottom: 2.25rem;\n}\n\n.rfv-eyebrow {\n  margin: 0;\n  font-size: 0.78rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.22em;\n  color: #9b3139;\n}\n\n.rfv-header h2 {\n  margin: 0;\n  font-size: clamp(2rem, 3vw, 3.2rem);\n  line-height: 1.05;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  color: #4b2d22;\n}\n\n.rfv-header p {\n  margin: 0;\n  font-size: 1rem;\n  line-height: 1.75;\n  color: #735d4d;\n}\n\n.rfv-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 1.5rem;\n}\n\n.rfv-card,\n.rfv-shelf,\n.rfv-atlas-card,\n.rfv-midnight-card {\n  border-radius: 1.8rem;\n  border: 1px solid rgba(94, 60, 45, 0.12);\n  background: rgba(255, 252, 247, 0.92);\n  box-shadow: 0 20px 40px rgba(90, 55, 33, 0.06);\n}\n\n.rfv-card--editorial,\n.rfv-shelf,\n.rfv-atlas-card,\n.rfv-midnight-card {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.4rem 1.5rem 1.5rem;\n}\n\n.rfv-card--editorial,\n.rfv-shelf,\n.rfv-atlas-card,\n.rfv-midnight-card {\n  transition:\n    transform 220ms ease,\n    box-shadow 220ms ease,\n    border-color 220ms ease;\n}\n\n.rfv-card--editorial:hover,\n.rfv-shelf:hover,\n.rfv-atlas-card:hover,\n.rfv-midnight-card:hover {\n  transform: translateY(-8px);\n  border-color: rgba(255, 153, 2, 0.24);\n  box-shadow: 0 28px 52px rgba(90, 55, 33, 0.12);\n}\n\n.rfv-chip {\n  display: inline-flex;\n  align-items: center;\n  width: fit-content;\n  border-radius: 999px;\n  background: rgba(255, 170, 29, 0.12);\n  padding: 0.38rem 0.7rem;\n  font-size: 0.78rem;\n  font-weight: 700;\n  letter-spacing: 0.06em;\n  text-transform: uppercase;\n  color: #8b541f;\n}\n\n.rfv-chip--light {\n  background: rgba(255, 255, 255, 0.08);\n  color: #f7ecdf;\n}\n\n.rfv-card h3,\n.rfv-shelf h3,\n.rfv-atlas-card h3,\n.rfv-midnight-card h3,\n.rfv-story h3,\n.rfv-atlas-core h3,\n.rfv-midnight-aside h3 {\n  margin: 0;\n  font-size: clamp(1.55rem, 2vw, 2.1rem);\n  line-height: 1.08;\n  font-weight: 500;\n  letter-spacing: -0.03em;\n  color: #6a4d2b;\n}\n\n.rfv-card ul,\n.rfv-shelf ul,\n.rfv-atlas-card ul,\n.rfv-midnight-card ul {\n  margin: 0;\n  padding: 0;\n  list-style: none;\n  display: grid;\n  gap: 0.85rem;\n}\n\n.rfv-card li,\n.rfv-shelf li,\n.rfv-atlas-card li,\n.rfv-midnight-card li,\n.rfv-story p,\n.rfv-atlas-core p,\n.rfv-midnight-aside p {\n  color: #8d714d;\n  font-size: 1rem;\n  line-height: 1.75;\n}\n\n.rfv-card li::before,\n.rfv-shelf li::before,\n.rfv-atlas-card li::before,\n.rfv-midnight-card li::before {\n  content: \"•\";\n  color: #ff9902;\n  margin-right: 0.55rem;\n}\n\n.rfv-link {\n  margin-top: auto;\n  color: #ff9902;\n}\n\n.rfv-flag,\n.rfv-flag--light {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.55rem;\n  width: fit-content;\n  font-size: 0.82rem;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.rfv-flag {\n  color: #9b3139;\n}\n\n.rfv-flag--light {\n  color: #ffcb86;\n}\n\n.rfv-flag svg,\n.rfv-back-link svg,\n.rfv-link svg,\n.rfv-midnight-top svg {\n  width: 1rem;\n  height: 1rem;\n  flex: 0 0 auto;\n}\n\n.rfv-split-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 0.92fr) minmax(0, 1.38fr);\n  gap: 1.5rem;\n}\n\n.rfv-story {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 2rem;\n  border-radius: 2rem;\n  background: linear-gradient(180deg, #6a2f24 0%, #3d231f 100%);\n  box-shadow: 0 24px 52px rgba(58, 29, 23, 0.22);\n}\n\n.rfv-story h3,\n.rfv-story p {\n  color: #f7ecdf;\n}\n\n.rfv-split-list {\n  display: grid;\n  gap: 1rem;\n}\n\n.rfv-card--row {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  gap: 1rem;\n  align-items: start;\n  padding: 1.25rem 1.4rem;\n}\n\n.rfv-shelves {\n  display: grid;\n  gap: 1rem;\n}\n\n.rfv-shelf {\n  display: grid;\n  grid-template-columns: 0.5rem minmax(0, 1fr) auto;\n  gap: 1rem;\n  align-items: start;\n}\n\n.rfv-shelf-spine {\n  align-self: stretch;\n  border-radius: 999px;\n}\n\n.rfv-shelf-body {\n  display: flex;\n  flex-direction: column;\n  gap: 0.9rem;\n}\n\n.rfv-atlas {\n  position: relative;\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 1rem;\n  min-height: 34rem;\n}\n\n.rfv-atlas-core {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  justify-content: center;\n  padding: 1.8rem;\n  border-radius: 2rem;\n  background:\n    radial-gradient(circle at top left, rgba(255, 187, 84, 0.18), transparent 30%),\n    rgba(255, 252, 247, 0.92);\n  border: 1px solid rgba(94, 60, 45, 0.12);\n}\n\n.rfv-atlas-card {\n  position: relative;\n  background:\n    radial-gradient(circle at top right, color-mix(in srgb, var(--accent) 14%, transparent), transparent 32%),\n    rgba(255, 252, 247, 0.94);\n}\n\n.rfv-atlas-card--1 {\n  transform: translateY(1.2rem);\n}\n\n.rfv-atlas-card--2 {\n  transform: translateX(-1.2rem);\n}\n\n.rfv-atlas-card--3 {\n  transform: translate(5rem, -1rem);\n}\n\n.rfv-midnight-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 0.82fr) minmax(0, 1.38fr);\n  gap: 1.5rem;\n  padding: 1.6rem;\n  border-radius: 2.25rem;\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.16), transparent 18%),\n    linear-gradient(180deg, #52261f 0%, #261614 100%);\n  box-shadow: 0 34px 78px rgba(40, 19, 16, 0.26);\n}\n\n.rfv-midnight-aside {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.2rem;\n}\n\n.rfv-midnight-aside h3 {\n  color: #fff2e6;\n}\n\n.rfv-midnight-aside p {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.rfv-midnight-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 1rem;\n}\n\n.rfv-midnight-card {\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.09);\n  box-shadow: none;\n}\n\n.rfv-midnight-card h3,\n.rfv-midnight-card li {\n  color: #fff2e6;\n}\n\n.rfv-midnight-card li {\n  color: rgba(243, 232, 218, 0.72);\n}\n\n.rfv-midnight-top {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 0.8rem;\n}\n\n.rfv-midnight-card .rfv-link {\n  color: #ffb24a;\n}\n\n@media (max-width: 960px) {\n  .rfv-grid,\n  .rfv-midnight-grid,\n  .rfv-split-shell,\n  .rfv-atlas,\n  .rfv-midnight-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .rfv-shelf,\n  .rfv-card--row {\n    grid-template-columns: 1fr;\n  }\n\n  .rfv-atlas-card--1,\n  .rfv-atlas-card--2,\n  .rfv-atlas-card--3 {\n    transform: none;\n  }\n}\n\n@media (max-width: 640px) {\n  .rfv-hero {\n    padding-top: 4.5rem;\n  }\n\n  .rfv-section {\n    padding-bottom: 3.5rem;\n  }\n\n  .rfv-grid {\n    grid-template-columns: 1fr;\n  }\n}\n"},{"path":"src/styles/services-outcomes-variants.css","content":".services-outcomes-lab {\n  background:\n    radial-gradient(circle at top right, rgba(255, 170, 29, 0.14), transparent 28%),\n    linear-gradient(180deg, #fffdf9 0%, #fff7ea 100%);\n  color: var(--mis-text);\n}\n\n.services-outcomes-lab *,\n.services-outcomes-lab *::before,\n.services-outcomes-lab *::after {\n  box-sizing: border-box;\n}\n\n.sov-hero,\n.sov-section {\n  padding: clamp(3.5rem, 6vw, 5.5rem) clamp(1.25rem, 4vw, 3rem);\n}\n\n.sov-hero-inner,\n.sov-header,\n.sov-editorial-grid,\n.sov-split-shell,\n.sov-mosaic-grid,\n.sov-rail-shell,\n.sov-midnight-shell {\n  margin: 0 auto;\n  max-width: 1180px;\n}\n\n.sov-hero-inner,\n.sov-header {\n  display: grid;\n  gap: 1rem;\n}\n\n.sov-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 0.5rem;\n  text-decoration: none;\n}\n\n.sov-back-link:hover {\n  opacity: 0.72;\n}\n\n.sov-eyebrow,\n.sov-mini-label {\n  font-size: 0.82rem;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n}\n\n.sov-eyebrow {\n  color: #9b3139;\n}\n\n.sov-mini-label {\n  color: #8d6a2a;\n}\n\n.sov-hero h1,\n.sov-header h2,\n.sov-story h3,\n.sov-midnight-aside h3 {\n  color: #6b4a1e;\n  font-size: clamp(2.2rem, 5vw, 4rem);\n  letter-spacing: -0.04em;\n  line-height: 0.98;\n  margin: 0;\n}\n\n.sov-header h2 {\n  font-size: clamp(1.8rem, 3vw, 2.9rem);\n  line-height: 1.02;\n}\n\n.sov-hero p:last-child,\n.sov-header > p:last-child,\n.sov-story p,\n.sov-midnight-aside p {\n  color: rgba(107, 74, 30, 0.8);\n  font-size: 1.08rem;\n  line-height: 1.7;\n  margin: 0;\n  max-width: 56rem;\n}\n\n.sov-section {\n  border-top: 1px solid rgba(201, 146, 61, 0.12);\n}\n\n.sov-editorial-grid {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: repeat(12, minmax(0, 1fr));\n}\n\n.sov-editorial-card,\n.sov-split-card,\n.sov-mosaic-hero,\n.sov-mosaic-card,\n.sov-rail-card,\n.sov-midnight-card,\n.sov-story,\n.sov-midnight-aside {\n  border-radius: 2rem;\n  position: relative;\n}\n\n.sov-editorial-card {\n  background: rgba(255, 253, 249, 0.94);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  box-shadow: 0 30px 60px rgba(107, 74, 30, 0.08);\n  display: grid;\n  gap: 1.1rem;\n  min-height: 18rem;\n  overflow: hidden;\n  padding: 1.5rem;\n  grid-column: span 4;\n}\n\n.sov-editorial-card::before {\n  background: linear-gradient(90deg, var(--accent), transparent 78%);\n  content: \"\";\n  height: 4px;\n  left: 0;\n  position: absolute;\n  right: 0;\n  top: 0;\n}\n\n.sov-editorial-card--1 {\n  grid-column: span 7;\n  min-height: 22rem;\n}\n\n.sov-editorial-card--2 {\n  grid-column: span 5;\n}\n\n.sov-editorial-card--3,\n.sov-editorial-card--4,\n.sov-editorial-card--5 {\n  min-height: 16rem;\n}\n\n.sov-editorial-top,\n.sov-split-card__top,\n.sov-mosaic-card__top,\n.sov-mosaic-hero__top,\n.sov-rail-card__top,\n.sov-midnight-card__top {\n  align-items: center;\n  display: flex;\n  gap: 0.8rem;\n  justify-content: space-between;\n}\n\n.sov-card-index,\n.sov-card-chip,\n.sov-chip {\n  border-radius: 999px;\n  display: inline-flex;\n  font-size: 0.78rem;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n}\n\n.sov-card-index {\n  color: var(--accent);\n}\n\n.sov-card-chip,\n.sov-chip {\n  border: 1px solid color-mix(in srgb, var(--accent) 24%, white);\n  color: var(--accent);\n  padding: 0.38rem 0.72rem;\n}\n\n.sov-editorial-card h3,\n.sov-split-card h3,\n.sov-mosaic-hero h3,\n.sov-mosaic-card h3,\n.sov-rail-card h3,\n.sov-midnight-card h3 {\n  color: #6b4a1e;\n  font-size: clamp(1.45rem, 2.2vw, 2.2rem);\n  line-height: 1.06;\n  margin: 0;\n}\n\n.sov-editorial-card p,\n.sov-split-card p,\n.sov-mosaic-hero p,\n.sov-mosaic-card p,\n.sov-rail-card p,\n.sov-midnight-card p {\n  color: rgba(107, 74, 30, 0.82);\n  font-size: 1.02rem;\n  line-height: 1.7;\n  margin: 0;\n}\n\n.sov-pill-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.5rem 0.6rem;\n}\n\n.sov-pill-item {\n  align-items: center;\n  display: inline-flex;\n  gap: 0.6rem;\n}\n\n.sov-pill {\n  color: #8d6a2a;\n  font-size: 0.98rem;\n  font-weight: 500;\n  text-decoration: none;\n  transition: opacity 180ms ease;\n}\n\n.sov-pill:hover {\n  opacity: 0.65;\n}\n\n.sov-pill-separator {\n  color: rgba(141, 106, 42, 0.36);\n}\n\n.sov-section--split {\n  background: linear-gradient(180deg, rgba(255, 249, 239, 0.72), rgba(255, 244, 226, 0.88));\n}\n\n.sov-split-shell {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: 0.92fr 1.4fr;\n}\n\n.sov-story {\n  background: linear-gradient(155deg, #fff4df 0%, #ffe7c1 100%);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  display: grid;\n  gap: 1rem;\n  padding: 2rem;\n}\n\n.sov-story h3,\n.sov-midnight-aside h3 {\n  font-size: clamp(1.8rem, 3vw, 3rem);\n}\n\n.sov-story-note {\n  align-items: center;\n  color: #8d6a2a;\n  display: inline-flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.sov-split-list {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: 1fr;\n}\n\n.sov-split-card {\n  background: rgba(255, 253, 249, 0.92);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  display: grid;\n  gap: 1rem;\n  padding: 1.4rem;\n  grid-template-columns: minmax(10rem, 12rem) minmax(0, 1fr);\n  align-items: start;\n}\n\n.sov-split-card__lead {\n  align-content: start;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n  align-content: start;\n}\n\n.sov-split-card__body {\n  display: grid;\n  gap: 0.9rem;\n}\n\n.sov-section--mosaic {\n  background: linear-gradient(180deg, rgba(255, 253, 249, 0.56), rgba(255, 247, 234, 0.94));\n}\n\n.sov-mosaic-grid {\n  display: grid;\n  gap: 1.25rem;\n  grid-template-columns: repeat(12, minmax(0, 1fr));\n}\n\n.sov-mosaic-hero {\n  background:\n    radial-gradient(circle at top right, color-mix(in srgb, var(--accent) 18%, transparent), transparent 34%),\n    rgba(255, 253, 249, 0.96);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  box-shadow: 0 30px 55px rgba(107, 74, 30, 0.09);\n  display: grid;\n  gap: 1.1rem;\n  grid-column: span 7;\n  min-height: 22rem;\n  padding: 2rem;\n}\n\n.sov-mosaic-card {\n  background: rgba(255, 251, 244, 0.94);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  display: grid;\n  gap: 0.9rem;\n  min-height: 16rem;\n  padding: 1.4rem;\n  grid-column: span 5;\n}\n\n.sov-mosaic-card:nth-child(3) {\n  grid-column: span 5;\n}\n\n.sov-mosaic-card:nth-child(4),\n.sov-mosaic-card:nth-child(5) {\n  grid-column: span 6;\n}\n\n.sov-section--rail {\n  background: linear-gradient(180deg, rgba(255, 244, 226, 0.46), rgba(255, 253, 249, 0.92));\n}\n\n.sov-rail-shell {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: 0.85fr 1.35fr;\n}\n\n.sov-rail-intro {\n  background: linear-gradient(155deg, #fff4df 0%, #ffe7c1 100%);\n  border: 1px solid rgba(201, 146, 61, 0.18);\n  border-radius: 2rem;\n  display: grid;\n  gap: 1rem;\n  padding: 2rem;\n}\n\n.sov-rail-intro h3 {\n  color: #6b4a1e;\n  font-size: clamp(1.9rem, 2.6vw, 2.8rem);\n  line-height: 1.02;\n  margin: 0;\n}\n\n.sov-rail-intro p:last-child {\n  color: rgba(107, 74, 30, 0.8);\n  font-size: 1.04rem;\n  line-height: 1.72;\n  margin: 0;\n}\n\n.sov-rail-track {\n  display: grid;\n  gap: 1rem;\n  position: relative;\n  padding-left: 2.6rem;\n}\n\n.sov-rail-line {\n  background: linear-gradient(180deg, rgba(201, 146, 61, 0.38), rgba(166, 32, 37, 0.18));\n  bottom: 0;\n  left: 1.45rem;\n  position: absolute;\n  top: 0;\n  width: 1px;\n}\n\n.sov-rail-card {\n  background: rgba(255, 253, 249, 0.94);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  display: grid;\n  gap: 0.85rem;\n  min-height: 14rem;\n  padding: 1.3rem 1.3rem 1.3rem 1.4rem;\n  z-index: 1;\n  position: relative;\n}\n\n.sov-rail-card::before {\n  background: var(--accent);\n  border: 5px solid #fff7ea;\n  border-radius: 999px;\n  content: \"\";\n  height: 1.15rem;\n  left: -1.85rem;\n  position: absolute;\n  top: 1.6rem;\n  width: 1.15rem;\n}\n\n.sov-rail-card--2,\n.sov-rail-card--4 {\n  margin-left: 2rem;\n}\n\n.sov-rail-card--3,\n.sov-rail-card--5 {\n  margin-left: 4rem;\n}\n\n.sov-section--midnight {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.12), transparent 28%),\n    linear-gradient(180deg, #2b1b10 0%, #120c08 100%);\n}\n\n.sov-section--midnight .sov-header h2,\n.sov-section--midnight .sov-header > p:last-child,\n.sov-section--midnight .sov-eyebrow {\n  color: #fff7ea;\n}\n\n.sov-midnight-shell {\n  display: grid;\n  gap: 1.5rem;\n  grid-template-columns: 0.9fr 1.5fr;\n}\n\n.sov-midnight-aside {\n  background: rgba(255, 255, 255, 0.04);\n  border: 1px solid rgba(255, 231, 193, 0.1);\n  display: grid;\n  gap: 1rem;\n  padding: 2rem;\n}\n\n.sov-chip--light {\n  background: rgba(255, 255, 255, 0.06);\n  border-color: rgba(255, 231, 193, 0.18);\n  color: #ffe7c1;\n}\n\n.sov-midnight-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.sov-midnight-card {\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 231, 193, 0.1);\n  display: grid;\n  gap: 1rem;\n  padding: 1.4rem;\n  align-content: start;\n}\n\n.sov-midnight-card h3,\n.sov-midnight-card p,\n.sov-midnight-aside h3,\n.sov-midnight-aside p {\n  color: #fff7ea;\n}\n\n.sov-pill-row.is-light .sov-pill {\n  color: #ffe7c1;\n}\n\n.sov-pill-row.is-light .sov-pill:hover {\n  opacity: 0.68;\n}\n\n.sov-pill-row.is-light .sov-pill-separator {\n  color: rgba(255, 231, 193, 0.34);\n}\n\n@media (max-width: 1100px) {\n  .sov-split-list,\n  .sov-midnight-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .sov-split-shell,\n  .sov-midnight-shell,\n  .sov-mosaic-grid,\n  .sov-rail-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .sov-editorial-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .sov-editorial-card,\n  .sov-editorial-card--1,\n  .sov-editorial-card--2 {\n    grid-column: span 1;\n    min-height: 17rem;\n  }\n\n  .sov-mosaic-card,\n  .sov-mosaic-hero {\n    grid-column: auto;\n  }\n\n  .sov-split-card {\n    grid-template-columns: 1fr;\n  }\n\n  .sov-rail-card--2,\n  .sov-rail-card--3,\n  .sov-rail-card--4,\n  .sov-rail-card--5 {\n    margin-left: 0;\n  }\n}\n\n@media (max-width: 720px) {\n  .sov-hero,\n  .sov-section {\n    padding-inline: 1rem;\n  }\n\n  .sov-rail-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .sov-editorial-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .sov-editorial-card,\n  .sov-editorial-card--1,\n  .sov-editorial-card--2 {\n    grid-column: auto;\n  }\n\n  .sov-rail-track {\n    padding-left: 1.5rem;\n  }\n\n  .sov-rail-line {\n    left: 0.78rem;\n  }\n\n  .sov-rail-card::before {\n    left: -1.2rem;\n  }\n\n  .sov-pill-row {\n    gap: 0.6rem;\n  }\n\n  .sov-pill {\n    font-size: 0.92rem;\n  }\n}\n"},{"path":"src/styles/services-page.css","content":".services-page-hero {\n  background:\n    linear-gradient(180deg, rgba(255, 255, 255, 0.48), rgba(255, 248, 237, 0.82)),\n    radial-gradient(circle at 82% 16%, rgba(79, 165, 174, 0.16), transparent 32%),\n    radial-gradient(circle at 12% 24%, rgba(255, 170, 29, 0.12), transparent 28%);\n}\n\n.services-page-hero .hero-video-layer {\n  opacity: 1;\n}\n\n.services-page-hero .hero-video-layer video {\n  filter: saturate(0.82) brightness(0.68) contrast(1.02);\n}\n\n.services-page-hero .hero-video-scrim {\n  opacity: 1;\n  background:\n    linear-gradient(90deg, rgba(255, 253, 249, 0.94) 0%, rgba(255, 248, 237, 0.76) 32%, rgba(255, 244, 231, 0.48) 62%, rgba(250, 239, 225, 0.84) 100%),\n    linear-gradient(180deg, rgba(255, 255, 255, 0.2) 0%, rgba(255, 248, 237, 0.36) 100%);\n}\n\n.services-page-hero .services-hero-trust {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem 1.25rem;\n  align-items: center;\n  margin: 0;\n  padding: 0;\n  list-style: none;\n}\n\n.services-page-hero .services-hero-trust li {\n  align-items: center;\n  color: #5d5047;\n  display: inline-flex;\n  font-size: 0.875rem;\n  gap: 0.625rem;\n  letter-spacing: 0.01em;\n}\n\n.services-page-hero .services-hero-trust-dot {\n  background: #9b3139;\n  border-radius: 999px;\n  display: inline-block;\n  flex: 0 0 auto;\n  height: 0.375rem;\n  width: 0.375rem;\n}\n\n.services-page-faq-shell {\n  background: rgba(255, 253, 249, 0.92);\n  border: 1px solid rgba(201, 146, 61, 0.16);\n  border-radius: 2rem;\n  box-shadow: 0 24px 50px rgba(107, 74, 30, 0.07);\n  padding: 1.5rem 2rem;\n}\n\n.services-page-faq-trigger {\n  color: #6b4a1e;\n  font-size: 1.25rem;\n  font-weight: 600;\n  line-height: 1.45;\n  text-decoration: none;\n}\n\n.services-page-faq-trigger:hover {\n  text-decoration: none;\n}\n\n.services-page-faq-content {\n  color: rgba(107, 74, 30, 0.82);\n  font-size: 1rem;\n  line-height: 1.8;\n}\n\n@media (max-width: 640px) {\n  .services-page-hero .services-hero-trust {\n    gap: 0.625rem;\n  }\n\n  .services-page-hero .services-hero-trust li {\n    font-size: 0.8125rem;\n  }\n\n  .services-page-faq-shell {\n    padding: 1rem 1.25rem;\n  }\n\n  .services-page-faq-trigger {\n    font-size: 1.08rem;\n  }\n}\n"},{"path":"src/styles/services-section-variants.css","content":".services-section-lab {\n  background:\n    radial-gradient(circle at top, rgba(255, 153, 2, 0.12), transparent 30%),\n    linear-gradient(180deg, var(--mis-panel) 0%, #fff9ef 100%);\n}\n\n.ssv-hero,\n.ssv-section {\n  padding: 88px 20px;\n}\n\n.ssv-hero-inner,\n.ssv-section > * {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.ssv-hero-inner {\n  display: grid;\n  gap: 18px;\n}\n\n.ssv-back-link,\n.ssv-inline-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 10px;\n  text-decoration: none;\n  transition: opacity 160ms ease;\n}\n\n.ssv-back-link:hover,\n.ssv-inline-link:hover {\n  opacity: 0.72;\n}\n\n.ssv-hero h1,\n.ssv-header h2,\n.ssv-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.03em;\n}\n\n.ssv-hero h1 {\n  font-size: clamp(2.9rem, 6vw, 5.5rem);\n  line-height: 0.98;\n  max-width: 12ch;\n}\n\n.ssv-hero p:last-child,\n.ssv-header p:last-child,\n.ssv-section p {\n  color: var(--mis-muted);\n  line-height: 1.65;\n}\n\n.ssv-eyebrow,\n.ssv-card-eyebrow {\n  color: var(--mis-brand-red);\n  font-size: 0.78rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  text-transform: uppercase;\n}\n\n.ssv-header {\n  display: grid;\n  gap: 16px;\n  margin-bottom: 36px;\n  max-width: 760px;\n}\n\n.ssv-header h2 {\n  font-size: clamp(2.2rem, 4vw, 3.8rem);\n  line-height: 1.02;\n}\n\n.ssv-editorial-grid {\n  display: grid;\n  gap: 22px;\n  grid-template-columns: 1.05fr 0.95fr;\n}\n\n.ssv-editorial-card {\n  background: linear-gradient(160deg, rgba(255, 255, 255, 0.96), rgba(255, 247, 234, 0.92));\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  box-shadow: 0 22px 45px rgba(107, 74, 30, 0.09);\n  overflow: hidden;\n  padding: 28px 28px 32px;\n  position: relative;\n}\n\n.ssv-editorial-card--1 {\n  min-height: 340px;\n}\n\n.ssv-editorial-card--2,\n.ssv-editorial-card--3 {\n  min-height: 260px;\n}\n\n.ssv-editorial-card--1,\n.ssv-editorial-card--3 {\n  transform: translateY(20px);\n}\n\n.ssv-editorial-bar {\n  height: 6px;\n  left: 0;\n  position: absolute;\n  right: 0;\n  top: 0;\n}\n\n.ssv-editorial-index {\n  color: rgba(107, 74, 30, 0.12);\n  font-size: clamp(4.5rem, 9vw, 7rem);\n  font-weight: 700;\n  line-height: 0.9;\n  position: absolute;\n  right: 18px;\n  top: 18px;\n}\n\n.ssv-icon-wrap {\n  align-items: center;\n  background: rgba(255, 255, 255, 0.88);\n  border: 1px solid currentColor;\n  border-radius: 999px;\n  display: inline-flex;\n  height: 54px;\n  justify-content: center;\n  margin-bottom: 24px;\n  width: 54px;\n}\n\n.ssv-icon-wrap svg {\n  height: 22px;\n  width: 22px;\n}\n\n.ssv-editorial-card h3,\n.ssv-spotlight-card h3,\n.ssv-rail-card h3,\n.ssv-mosaic-hero h3,\n.ssv-mosaic-card h3,\n.ssv-stacked-aside h3,\n.ssv-stacked-card h3 {\n  font-size: clamp(1.5rem, 2vw, 2.1rem);\n  line-height: 1.08;\n  margin: 0 0 12px;\n}\n\n.ssv-editorial-card p:last-child,\n.ssv-spotlight-card p,\n.ssv-rail-card p,\n.ssv-mosaic-hero p:last-of-type,\n.ssv-mosaic-card p:last-child,\n.ssv-stacked-aside p:last-of-type,\n.ssv-stacked-card p:last-child {\n  font-size: 1rem;\n}\n\n.ssv-section--spotlight {\n  background:\n    radial-gradient(circle at 16% 10%, rgba(255, 153, 2, 0.14), transparent 18%),\n    linear-gradient(180deg, #6f211e 0%, #a62025 52%, #7b261b 100%);\n}\n\n.ssv-section--spotlight .ssv-header .ssv-eyebrow,\n.ssv-section--spotlight .ssv-header h2,\n.ssv-section--spotlight .ssv-header p,\n.ssv-section--spotlight .ssv-spotlight-copy h3,\n.ssv-section--spotlight .ssv-spotlight-copy p,\n.ssv-section--spotlight .ssv-spotlight-copy .ssv-card-eyebrow {\n  color: #fff7ea;\n}\n\n.ssv-spotlight-shell {\n  align-items: start;\n  display: grid;\n  gap: 26px;\n  grid-template-columns: 0.9fr 1.1fr;\n}\n\n.ssv-spotlight-copy {\n  display: grid;\n  gap: 16px;\n  padding-top: 12px;\n}\n\n.ssv-spotlight-copy h3 {\n  font-size: clamp(2rem, 3vw, 3.2rem);\n  line-height: 1.02;\n}\n\n.ssv-spotlight-grid {\n  display: grid;\n  gap: 18px;\n}\n\n.ssv-spotlight-card {\n  backdrop-filter: blur(8px);\n  background: linear-gradient(180deg, rgba(255, 247, 234, 0.15), rgba(255, 247, 234, 0.08));\n  border: 1px solid rgba(255, 247, 234, 0.2);\n  border-radius: 24px;\n  color: #fff7ea;\n  display: grid;\n  gap: 14px;\n  padding: 26px;\n}\n\n.ssv-pill {\n  border: 1px solid;\n  border-radius: 999px;\n  display: inline-flex;\n  font-size: 0.78rem;\n  font-weight: 600;\n  justify-self: start;\n  letter-spacing: 0.08em;\n  padding: 7px 12px;\n  text-transform: uppercase;\n}\n\n.ssv-rail-grid {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.ssv-rail-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 28px;\n  box-shadow: 0 16px 34px rgba(107, 74, 30, 0.08);\n  display: grid;\n  gap: 16px;\n  min-height: 320px;\n  padding: 24px;\n}\n\n.ssv-rail-card.is-featured {\n  background: linear-gradient(180deg, #fff7ea 0%, #ffefcf 100%);\n  transform: translateY(-14px);\n}\n\n.ssv-rail-top {\n  align-items: center;\n  display: flex;\n  justify-content: space-between;\n}\n\n.ssv-rail-line {\n  border-radius: 999px;\n  height: 6px;\n  margin-top: auto;\n  width: 84px;\n}\n\n.ssv-mosaic-grid {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: 1.2fr 0.8fr;\n  grid-template-rows: repeat(2, minmax(220px, auto));\n}\n\n.ssv-mosaic-hero,\n.ssv-mosaic-card {\n  border-radius: 28px;\n  overflow: hidden;\n  padding: 30px;\n  position: relative;\n}\n\n.ssv-mosaic-hero {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.2), transparent 26%),\n    linear-gradient(155deg, #fff8ef 0%, #ffefcf 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  box-shadow: 0 20px 40px rgba(107, 74, 30, 0.08);\n  grid-row: 1 / span 2;\n}\n\n.ssv-signal-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 22px;\n}\n\n.ssv-signal {\n  align-items: center;\n  background: rgba(255, 255, 255, 0.7);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 999px;\n  color: var(--mis-text);\n  display: inline-flex;\n  gap: 8px;\n  padding: 10px 14px;\n}\n\n.ssv-signal svg {\n  height: 16px;\n  width: 16px;\n}\n\n.ssv-mosaic-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  box-shadow: 0 16px 34px rgba(107, 74, 30, 0.08);\n}\n\n.ssv-mosaic-card--accent {\n  background: linear-gradient(160deg, #f8eaea 0%, #fff6f0 100%);\n}\n\n.ssv-stacked-shell {\n  align-items: start;\n  display: grid;\n  gap: 24px;\n  grid-template-columns: 0.8fr 1.2fr;\n}\n\n.ssv-stacked-aside {\n  display: grid;\n  gap: 16px;\n  padding-right: 18px;\n  position: sticky;\n  top: 108px;\n}\n\n.ssv-stacked-aside h3 {\n  font-size: clamp(2rem, 3vw, 3rem);\n  line-height: 1.02;\n}\n\n.ssv-stacked-list {\n  display: grid;\n  gap: 18px;\n}\n\n.ssv-stacked-card {\n  align-items: start;\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-left: 8px solid var(--mis-primary);\n  border-radius: 24px;\n  box-shadow: 0 14px 28px rgba(107, 74, 30, 0.07);\n  display: grid;\n  gap: 18px;\n  grid-template-columns: auto 1fr;\n  padding: 24px;\n}\n\n.home-services-section {\n  padding: 96px 20px;\n  position: relative;\n}\n\n.home-services-header {\n  margin-bottom: 18px;\n}\n\n.home-services-shell {\n  gap: 42px;\n  min-height: 1320px;\n}\n\n.home-services-aside {\n  gap: 18px;\n  max-width: 34rem;\n}\n\n.home-services-aside h2 {\n  font-family: var(--font-family-sans);\n  font-weight: 300;\n  font-size: clamp(2.4rem, 4vw, 4.4rem);\n  line-height: 0.98;\n  max-width: 11ch;\n}\n\n.home-services-link {\n  align-items: center;\n  align-self: start;\n  background: linear-gradient(135deg, var(--mis-primary) 0%, #ffb638 100%);\n  border: 0;\n  border-radius: 999px;\n  box-shadow: 0 20px 40px rgba(255, 153, 2, 0.22);\n  color: #ffffff;\n  cursor: pointer;\n  display: inline-flex;\n  font-family: \"Manrope\", sans-serif;\n  font-size: 0.95rem;\n  font-weight: 700;\n  gap: 10px;\n  letter-spacing: 0.03em;\n  margin-top: 8px;\n  padding: 15px 24px;\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease,\n    opacity 180ms ease;\n}\n\n.home-services-link:hover {\n  box-shadow: 0 24px 46px rgba(255, 153, 2, 0.28);\n  transform: translateY(-2px);\n}\n\n.home-services-list {\n  display: block;\n  height: 700px;\n  position: sticky;\n  top: 132px;\n}\n\n.home-services-card {\n  backdrop-filter: blur(10px);\n  background:\n    linear-gradient(180deg, rgba(255, 253, 250, 0.97) 0%, rgba(255, 247, 234, 0.96) 100%);\n  border-left: 8px solid var(--mis-primary);\n  grid-template-columns: auto 1fr;\n  min-height: 0;\n  position: absolute;\n  left: 0;\n  padding: 24px 24px 26px;\n  right: 0;\n  top: 0;\n}\n\n.home-services-card .ssv-icon-wrap {\n  background: rgba(255, 255, 255, 0.82);\n}\n\n.home-services-card h3 {\n  font-size: clamp(1.8rem, 2.3vw, 2.5rem);\n}\n\n.home-services-card p:last-child {\n  max-width: 42ch;\n}\n\n.home-services-card--1 {\n  top: 0;\n  z-index: 1;\n}\n\n.home-services-card--2 {\n  border-left: 8px solid var(--mis-brand-red);\n  top: 214px;\n  z-index: 2;\n}\n\n.home-services-card--3 {\n  border-left: 8px solid #c9923d;\n  top: 438px;\n  z-index: 3;\n}\n\n@media (max-width: 980px) {\n  .ssv-editorial-grid,\n  .ssv-spotlight-shell,\n  .ssv-mosaic-grid,\n  .ssv-stacked-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .ssv-rail-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .ssv-editorial-card--1,\n  .ssv-editorial-card--3,\n  .ssv-rail-card.is-featured {\n    transform: none;\n  }\n\n  .ssv-mosaic-hero {\n    grid-row: auto;\n  }\n\n  .ssv-stacked-aside {\n    position: static;\n    top: auto;\n  }\n\n  .home-services-section {\n    padding: 80px 20px;\n  }\n\n  .home-services-shell {\n    gap: 28px;\n    min-height: 0;\n  }\n\n  .home-services-card,\n  .home-services-card--1,\n  .home-services-card--2,\n  .home-services-card--3 {\n    left: auto;\n    position: relative;\n    right: auto;\n    top: auto;\n    transform: none;\n  }\n\n  .home-services-list {\n    display: grid;\n    gap: 18px;\n    height: auto;\n  }\n}\n\n@media (max-width: 640px) {\n  .ssv-hero,\n  .ssv-section {\n    padding: 64px 16px;\n  }\n\n  .ssv-editorial-card,\n  .ssv-spotlight-card,\n  .ssv-rail-card,\n  .ssv-mosaic-hero,\n  .ssv-mosaic-card,\n  .ssv-stacked-card {\n    padding: 22px;\n  }\n\n  .ssv-editorial-index {\n    font-size: 4rem;\n  }\n\n  .home-services-section {\n    padding: 72px 16px;\n  }\n\n  .home-services-link {\n    width: 100%;\n    justify-content: center;\n  }\n}\n"},{"path":"src/styles/solutions-section-variants.css","content":".solutions-section-lab {\n  background:\n    radial-gradient(circle at top, rgba(255, 153, 2, 0.12), transparent 28%),\n    linear-gradient(180deg, var(--mis-panel) 0%, #fff8ed 100%);\n}\n\n.solv-hero,\n.solv-section {\n  padding: 88px 20px;\n}\n\n.solv-hero-inner,\n.solv-section > * {\n  margin: 0 auto;\n  max-width: 1200px;\n}\n\n.solv-hero-inner,\n.solv-header,\n.solv-card,\n.solv-mosaic-lead,\n.solv-radial-core,\n.solv-midnight-aside,\n.solv-midnight-card,\n.solv-rail-card {\n  display: grid;\n  gap: 16px;\n}\n\n.solv-back-link {\n  align-items: center;\n  color: var(--mis-brand-red);\n  display: inline-flex;\n  gap: 10px;\n  text-decoration: none;\n  transition: opacity 160ms ease;\n}\n\n.solv-back-link:hover {\n  opacity: 0.72;\n}\n\n.solv-eyebrow,\n.solv-chip {\n  color: var(--mis-brand-red);\n  font-size: 0.76rem;\n  font-weight: 700;\n  letter-spacing: 0.16em;\n  margin: 0;\n  text-transform: uppercase;\n}\n\n.solv-hero h1,\n.solv-header h2,\n.solv-section h3 {\n  color: var(--mis-text);\n  font-family: \"Manrope\", sans-serif;\n  font-weight: 300;\n  letter-spacing: -0.04em;\n  margin: 0;\n}\n\n.solv-hero h1 {\n  font-size: clamp(3rem, 6vw, 5.4rem);\n  line-height: 0.96;\n  max-width: 11ch;\n}\n\n.solv-hero p:last-child,\n.solv-header p:last-child,\n.solv-section p {\n  color: var(--mis-muted);\n  line-height: 1.7;\n  margin: 0;\n}\n\n.solv-header {\n  margin-bottom: 36px;\n  max-width: 760px;\n}\n\n.solv-header h2 {\n  font-size: clamp(2.2rem, 4vw, 4rem);\n  line-height: 0.98;\n}\n\n.solv-card,\n.solv-column-card,\n.solv-radial-card,\n.solv-midnight-card,\n.solv-rail-card {\n  --accent: var(--mis-primary);\n  transition:\n    transform 180ms ease,\n    box-shadow 180ms ease,\n    border-color 180ms ease;\n}\n\n.solv-card:hover,\n.solv-column-card:hover,\n.solv-radial-card:hover,\n.solv-midnight-card:hover,\n.solv-rail-card:hover {\n  box-shadow: 0 24px 56px rgba(107, 74, 30, 0.16);\n  transform: translateY(-8px);\n}\n\n.solv-card-top {\n  align-items: center;\n  display: flex;\n  justify-content: space-between;\n}\n\n.solv-card-top svg,\n.solv-mini-pill svg,\n.solv-radial-core svg {\n  color: var(--accent);\n  flex-shrink: 0;\n  height: 20px;\n  width: 20px;\n}\n\n.solv-chip {\n  align-items: center;\n  align-self: start;\n  border: 1px solid color-mix(in srgb, var(--accent, var(--mis-brand-red)) 24%, white);\n  border-radius: 999px;\n  color: var(--accent, var(--mis-brand-red));\n  display: inline-flex;\n  justify-self: start;\n  padding: 7px 12px;\n}\n\n.solv-chip--light {\n  border-color: rgba(255, 244, 227, 0.18);\n  color: #fff4e3;\n}\n\n.solv-section h3 {\n  font-size: clamp(1.55rem, 2vw, 2.2rem);\n  line-height: 1.06;\n}\n\n.solv-mosaic-grid {\n  align-items: stretch;\n  display: grid;\n  gap: 20px;\n  grid-template-columns: 1.02fr 1.38fr;\n}\n\n.solv-mosaic-lead,\n.solv-mosaic-card {\n  border-radius: 30px;\n  overflow: hidden;\n  position: relative;\n}\n\n.solv-mosaic-lead {\n  background:\n    radial-gradient(circle at top right, rgba(255, 153, 2, 0.2), transparent 28%),\n    linear-gradient(160deg, #fff8ef 0%, #ffefcf 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  box-shadow: 0 22px 46px rgba(107, 74, 30, 0.09);\n  grid-template-rows: auto auto 1fr auto;\n  height: 100%;\n  padding: 34px;\n}\n\n.solv-mosaic-lead h3 {\n  font-size: clamp(2.2rem, 3.4vw, 3.8rem);\n  line-height: 0.96;\n}\n\n.solv-mosaic-lead > p {\n  align-self: end;\n  margin-top: 14px;\n  max-width: 28ch;\n}\n\n.solv-mini-stack {\n  align-items: flex-start;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  justify-self: start;\n  margin-top: 18px;\n  max-width: 360px;\n}\n\n.solv-mini-pill {\n  align-self: flex-start;\n  align-items: center;\n  background: rgba(255, 255, 255, 0.7);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 999px;\n  color: var(--mis-text);\n  display: inline-flex;\n  flex: 0 0 auto;\n  font-size: 0.96rem;\n  gap: 8px;\n  height: auto;\n  padding: 9px 13px;\n}\n\n.solv-mosaic-cards {\n  display: grid;\n  gap: 20px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  grid-template-rows: repeat(3, minmax(0, 1fr));\n}\n\n.solv-mosaic-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  box-shadow: 0 16px 36px rgba(107, 74, 30, 0.07);\n  min-height: 205px;\n  padding: 22px;\n}\n\n.solv-mosaic-card__title {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n}\n\n.solv-mosaic-card__title svg {\n  color: var(--accent);\n  flex-shrink: 0;\n  height: 20px;\n  width: 20px;\n}\n\n.solv-mosaic-card__title h3 {\n  font-size: clamp(1.45rem, 1.8vw, 2rem);\n  line-height: 1.08;\n}\n\n.solv-mosaic-card p {\n  max-width: 31ch;\n}\n\n.solv-columns-grid {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n}\n\n.solv-column {\n  display: grid;\n  gap: 18px;\n}\n\n.solv-column-marker {\n  color: rgba(107, 74, 30, 0.12);\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(3rem, 5vw, 4.6rem);\n  font-weight: 700;\n  line-height: 0.9;\n}\n\n.solv-column-card {\n  background: linear-gradient(180deg, #fffdfa 0%, #fff6e6 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-top: 6px solid var(--accent);\n  border-radius: 28px;\n  box-shadow: 0 18px 36px rgba(107, 74, 30, 0.08);\n  min-height: 270px;\n  padding: 24px;\n}\n\n.solv-radial-grid {\n  align-items: center;\n  display: grid;\n  gap: 20px;\n  grid-template-areas:\n    \"a core b\"\n    \"c core d\"\n    \"e core f\";\n  grid-template-columns: 1fr 1.08fr 1fr;\n}\n\n.solv-radial-core {\n  align-items: center;\n  grid-area: core;\n  justify-items: center;\n  padding: 24px;\n  position: relative;\n}\n\n.solv-radial-core::before {\n  background:\n    radial-gradient(circle, rgba(255, 170, 29, 0.14), transparent 58%),\n    radial-gradient(circle, rgba(255, 255, 255, 0.04), transparent 66%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 999px;\n  content: \"\";\n  inset: 0;\n  position: absolute;\n}\n\n.solv-radial-core__inner {\n  align-items: center;\n  aspect-ratio: 1;\n  background: rgba(255, 253, 250, 0.75);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 999px;\n  box-shadow: 0 18px 40px rgba(107, 74, 30, 0.08);\n  display: grid;\n  gap: 10px;\n  justify-items: center;\n  max-width: 320px;\n  padding: 40px;\n  position: relative;\n  text-align: center;\n  z-index: 1;\n}\n\n.solv-radial-card {\n  background: #fffdfa;\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-radius: 26px;\n  box-shadow: 0 16px 34px rgba(107, 74, 30, 0.08);\n  min-height: 210px;\n  padding: 22px;\n}\n\n.solv-radial-card svg {\n  color: var(--accent);\n  height: 20px;\n  width: 20px;\n}\n\n.solv-radial-card--1 { grid-area: a; }\n.solv-radial-card--2 { grid-area: b; }\n.solv-radial-card--3 { grid-area: c; }\n.solv-radial-card--4 { grid-area: d; }\n.solv-radial-card--5 { grid-area: e; }\n.solv-radial-card--6 { grid-area: f; }\n\n.solv-section--midnight {\n  background:\n    radial-gradient(circle at top left, rgba(255, 153, 2, 0.14), transparent 18%),\n    linear-gradient(180deg, #451b17 0%, #261614 100%);\n}\n\n.solv-section--midnight .solv-eyebrow,\n.solv-section--midnight .solv-header h2,\n.solv-section--midnight .solv-header p,\n.solv-section--midnight .solv-midnight-aside h3,\n.solv-section--midnight .solv-midnight-aside p,\n.solv-section--midnight .solv-midnight-card h3,\n.solv-section--midnight .solv-midnight-card p,\n.solv-section--midnight .solv-chip--light {\n  color: #fff4e3;\n}\n\n.solv-midnight-shell {\n  align-items: start;\n  display: grid;\n  gap: 24px;\n  grid-template-columns: 0.9fr 1.1fr;\n}\n\n.solv-midnight-aside {\n  backdrop-filter: blur(8px);\n  background: linear-gradient(180deg, rgba(255, 248, 237, 0.11), rgba(255, 248, 237, 0.06));\n  border: 1px solid rgba(255, 244, 227, 0.14);\n  border-radius: 30px;\n  padding: 32px;\n}\n\n.solv-midnight-aside h3 {\n  font-size: clamp(2rem, 3vw, 3.2rem);\n}\n\n.solv-midnight-grid {\n  display: grid;\n  gap: 18px;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.solv-midnight-card {\n  backdrop-filter: blur(10px);\n  background: linear-gradient(180deg, rgba(255, 248, 237, 0.1), rgba(255, 248, 237, 0.05));\n  border: 1px solid rgba(255, 244, 227, 0.14);\n  border-radius: 28px;\n  box-shadow: 0 22px 44px rgba(0, 0, 0, 0.2);\n  min-height: 240px;\n  padding: 24px;\n}\n\n.solv-midnight-card .solv-card-top svg {\n  color: var(--accent);\n}\n\n.solv-rail-list {\n  display: grid;\n  gap: 18px;\n}\n\n.solv-rail-card {\n  align-items: stretch;\n  background: linear-gradient(145deg, #fffdfa 0%, #fff4e1 100%);\n  border: 1px solid rgba(166, 32, 37, 0.12);\n  border-left: 8px solid var(--accent);\n  border-radius: 28px;\n  box-shadow: 0 18px 38px rgba(107, 74, 30, 0.08);\n  grid-template-columns: 120px 1fr;\n  overflow: hidden;\n  padding: 22px;\n}\n\n.solv-rail-index {\n  color: color-mix(in srgb, var(--accent) 28%, white);\n  font-family: \"Manrope\", sans-serif;\n  font-size: clamp(2.8rem, 4vw, 4.6rem);\n  font-weight: 700;\n  letter-spacing: -0.04em;\n  line-height: 0.9;\n}\n\n.solv-rail-main {\n  display: grid;\n  gap: 14px;\n}\n\n@media (max-width: 1100px) {\n  .solv-mosaic-grid,\n  .solv-columns-grid,\n  .solv-midnight-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .solv-mosaic-cards {\n    grid-template-columns: 1fr;\n    grid-template-rows: none;\n  }\n\n  .solv-radial-grid {\n    grid-template-areas:\n      \"core\"\n      \"a\"\n      \"b\"\n      \"c\"\n      \"d\"\n      \"e\"\n      \"f\";\n    grid-template-columns: 1fr;\n  }\