n intent; final implementation may need button behavior instead if smooth scrolling is required in Webflow."},{"code":"provider-warning-4","level":"warning","message":"The decorative video, scrim, and grid are structural placeholders only. No styling, z-index, opacity, or color decisions are encoded in this skeleton step."}],"elementTree":{"id":"b3fa47680ccb0bcb-root","tag":"section","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"video","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"source","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"p","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"h1","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"p","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"button","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"a","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]},"reusableClasses":["hero_background-scrim","text-style-tagline","hero_heading","text-size-medium","button-group","hero_actions","button","is-primary"],"sectionMetadata":{"pageId":"59873aeb46eecbd7","re