provider-warning-4","level":"warning","message":"The decorative grid overlay in source is represented as hero_background-grid without styling details to avoid hardcoded colors and non-structural implementation in this stage."}],"elementTree":{"id":"b3fa47680ccb0bcb-root","tag":"section","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"video","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"source","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"p","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"h1","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"p","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root","tag":"button","type":"box","children":[],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"button","type":"box","children":[],"classNames":[]}],"classNames":[]},{"id":"b3fa47680ccb0bcb-root","tag":"div","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]},"reusableClasses":["hero_background-scrim","text-style-tagline","hero_heading","text-size-medium","button-group","button","is-primary"],"sectionMetadata":{"pageId":"59873aeb46eecbd7","repoId":"78a43a7ac135d5d7","pageName":"CaseStudiesPage","sectionId":"b3fa47680ccb0bcb","sourceFile":"src/app/components/sections/HeroSection.tsx","sectionName":"Hero"},"suggestedNewClasses":["section_hero","hero_background-media","hero_background-video","hero_background-grid","hero_component","hero_content","hero_actions","hero_supplemental"]}', NULL, '2026-05-24T20:09:45.097Z', NULL);
INSERT OR REPLACE INTO section_runs (id, user_id, repo_id, webflow_site_id, webflow_page_id, repo_page_id, repo_section_id, run_type, payload_json, approval_outcome, created_at, approved_at) VALUES ('3cc2b068ae487577', 'misinc', '78a43a7ac135d5d7', '6a0fb2ee3fd646cd2a754be0', '6a0fb2f03fd646cd2a754c25', '6ec34f64d8ae235b', '730d24f9268f2be7', 'analysis', '{"goals":["Preserve the section hierarchy from the repo source before styling.","Use the current Webflow structure as the styling target to move faster.","Reuse shared typography, spacing, and utility classes where possible.","Keep new classes Client-First-compatible and section-functional."],"content":[],"summary":"Solutions section with custom section structure.","warnings":[],"sourceCode":"import { motion } from \"motion/react\";\nimport { Link } from \"react-router\";\nimport type { ReactNode } from \"react\";\nimport { defaultSolutionIndustries, type SolutionIndustryItem } from \"@/app/data/solutionIndustries\";\nimport \"@/styles/solutions-section-variants.css\";\nexport type { SolutionIndustryItem } from \"@/app/data/solutionIndustries\";\n\nexport type SolutionsSectionProps = {\n  sectionId?: string;\n  title?: ReactNode;\n  leadTitle?: ReactNode;\n  leadDescription?: ReactNode;\n  industries?: SolutionIndustryItem[];\n  backgroundColor?: string;\n};\n\nexport function SolutionsSection({\n  sectionId = \"solutions\",\n  title = \"Solutions Tailored to Your Industry\",\n  leadTitle = \"Solutions designed around how each industry actually operates.\",\n  leadDescription = \"Instead of presenting every audience at the same weight, this version creates a stronger entry point and a more editorial scan path.\",\n  industries = defaultSolutionIndustries,\n  backgroundColor,\n}: SolutionsSectionProps) {\n  return (\n    <section\n      id={sectionId}\n      className=\"solv-section content-stretch flex flex-col items-center relative shrink-0 w-full\"\n      style={backgroundColor ? { backgroundColor } : undefined}\n    >\n      <div className=\"content-stretch flex flex-col gap-[48px] md:gap-[64px] items-start relative shrink-0 w-full max-w-[1200px]\">\n        <motion.div\n          className=\"content-stretch flex flex-col gap-[16px] items-start relative shrink-0 w-full\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <h2 className=\"font-[''Manrope:Light'',sans-serif] font-light leading-[1.2] text-[#151515] text-[32px] md:text-[40px] lg:text-[48px] w-full\">\n            {title}\n          </h2>\n        </motion.div>\n\n        <div className=\"solv-mosaic-grid w-full\">\n          <motion.article\n            className=\"solv-mosaic-lead\"\n            initial={{ opacity: 0, y: 36 }}\n            whileInView={{ opacity: 1, y: 0 }}\n            viewport={{ once: true, margin: \"-100px\" }}\n            transition={{ duration: 0.6 }}\n          >\n            <h3>{leadTitle}</h3>\n            <p>{leadDescription}</p>\n            <div className=\"solv-mini-stack\">\n              {industries.map((industry) => {\n                const Icon = industry.icon;\n\n                return (\n                  <Link key={`solutions-pill-${industry.title}`} to={industry.to ?? \"#\"} className=\"solv-mini-pill\">\n                    <Icon />\n                    <span>{industry.title}</span>\n                  </Link>\n                );\n              })}\n            </div>\n          </motion.article>\n\n          <div className=\"solv-mosaic-cards\">\n            {industries.map((industry, index) => {\n              const Icon = industry.icon;\n\n              return (\n                <motion.div\n                  key={industry.title}\n                  initial={{ opacity: 0, y: 40 }}\n                  whileInView={{ opacity: 1, y: 0 }}\n                  viewport={{ once: true, margin: \"-100px\" }}\n                  transition={{ duration: 0.5, delay: index * 0.08 }}\n                >\n                  <Link\n                    to={industry.to ?? \"#\"}\n                    className={`solv-card solv-mosaic-card solv-mosaic-card--${index + 1}`}\n                    style={{ [\"--accent\" as string]: industry.accent }}\n                  >\n                    <div className=\"solv-mosaic-card__title\">\n                      <Icon />\n                      <h3>{industry.title}</h3>\n                    </div>\n                    <p>{industry.description}</p>\n                  </Link>\n                </motion.div>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","navbar7_item-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","navbar7_icon-wrapper","margin-tiny","padding-xxsmall"],"sectionMetadata":{"pageId":"6ec34f64d8ae235b","repoId":"78a43a7ac135d5d7","pageName":"HomePage","sectionId":"730d24f9268f2be7","sourceFile":"src/app/components/sections/SolutionsSection.tsx","sectionName":"Solutions"},"suggestedNewClasses":["section_solutions","solutions_layout","solutions_content"]}', NULL, '2026-05-24T22:49:45.188Z', NULL);
