","message":"Source references icon components, but no concrete asset or icon element structure is provided; icon placeholders use existing shared icon wrapper classes only."}],"elementTree":{"id":"730d24f9268f2be7-root","tag":"section","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"h2","type":"box","children":[],"classNames":[]}],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"article","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"h3","type":"box","children":[],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"p","type":"box","children":[],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"a","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"span","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"a","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[{"id":"730d24f9268f2be7-root","tag":"div","type":"box","children":[],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"h3","type":"box","children":[],"classNames":[]}],"classNames":[]},{"id":"730d24f9268f2be7-root","tag":"p","type":"box","children":[],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"classNames":[]}],"cla