n    >\n      <div className=\"content-stretch flex flex-col gap-[48px] md:gap-[64px] items-start relative shrink-0 w-full max-w-[1200px]\">\n        <motion.div\n          className=\"content-stretch flex flex-col gap-[16px] items-start relative shrink-0 w-full\"\n          initial={{ opacity: 0, y: 30 }}\n          whileInView={{ opacity: 1, y: 0 }}\n          viewport={{ once: true, margin: \"-100px\" }}\n          transition={{ duration: 0.6 }}\n        >\n          <h2 className=\"font-[''Manrope:Light'',sans-serif] font-light leading-[1.2] text-[#151515] text-[32px] md:text-[40px] lg:text-[48px] w-full\">\n            {title}\n          </h2>\n        </motion.div>\n\n        <div className=\"solv-mosaic-grid w-full\">\n          <motion.article\n            className=\"solv-mosaic-lead\"\n            initial={{ opacity: 0, y: 36 }}\n            whileInView={{ opacity: 1, y: 0 }}\n            viewport={{ once: true, margin: \"-100px\" }}\n            transition={{ duration: 0.6 }}\n          >\n            <h3>{leadTitle}</h3>\n            <p>{leadDescription}</p>\n            <div className=\"solv-mini-stack\">\n              {industries.map((industry) => {\n                const Icon = industry.icon;\n\n                return (\n                  <Link key={`solutions-pill-${industry.title}`} to={industry.to ?? \"#\"} className=\"solv-mini-pill\">\n                    <Icon />\n                    <span>{industry.title}</span>\n                  </Link>\n                );\n              })}\n            </div>\n          </motion.article>\n\n          <div className=\"solv-mosaic-cards\">\n            {industries.map((industry, index) => {\n              const Icon = industry.icon;\n\n              return (\n                <motion.div\n                  key={industry.title}\n                  initial={{ opacity: 0, y: 40 }}\n                  whileInView={{ opacity: 1, y: 0 }}\n                  viewport={{ once: true, margin: \"-100px\" }}\n                  transition={{ duration: 0.5, delay: index * 0.08 }}\n                >\n                  <Link\n                    to={industry.to ?? \"#\"}\n                    className={`solv-card solv-mosaic-card solv-mosaic-card--${index + 1}`}\n                    style={{ [\"--accent\" as string]: industry.accent }}\n                  >\n                    <div className=\"solv-mosaic-card__title\">\n                      <Icon />\n                      <h3>{industry.title}</h3>\n                    </div>\n                    <p>{industry.description}</p>\n                  </Link>\n                </motion.div>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","navbar7_item-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","navbar7_icon-wrapper","margin-tiny","padding-xxsmall"],"sectionMetadata":{"pageId":"6ec34f64d8ae235b","repoId":"78a43a7ac135d5d7","pageName":"HomePage","sectionId":"730d24f9268f2be7","sourceFile":"src/app/components/sections/SolutionsSection.tsx","sectionName":"Solutions"},"suggestedNewClasses":["section_solutions","solutions_layout","solutions_content"]}', NULL, '2026-05-24T22:56:26.268Z', NULL);
