    transition={{ duration: 0.5, delay: index * 0.08 }}\n                >\n                  <Link\n                    to={industry.to ?? \"#\"}\n                    className={`solv-card solv-mosaic-card solv-mosaic-card--${index + 1}`}\n                    style={{ [\"--accent\" as string]: industry.accent }}\n                  >\n                    <div className=\"solv-mosaic-card__title\">\n                      <Icon />\n                      <h3>{industry.title}</h3>\n                    </div>\n                    <p>{industry.description}</p>\n                  </Link>\n                </motion.div>\n              );\n            })}\n          </div>\n        </div>\n      </div>\n    </section>\n  );\n}\n","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","navbar7_item-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","navbar7_icon-wrapper","margin-tiny","padding-xxsmall"],"sectionMetadata":{"pageId":"6ec34f64d8ae235b","repoId":"78a43a7ac135d5d7","pageName":"HomePage","sectionId":"730d24f9268f2be7","sourceFile":"src/app/components/sections/SolutionsSection.tsx","sectionName":"Solutions"},"suggestedNewClasses":["section_solutions","solutions_layout","solutions_content"]}', NULL, '2026-05-24T23:17:46.964Z', NULL);
INSERT OR REPLACE INTO section_runs (id, user_id, repo_id, webflow_site_id, webflow_page_id, repo_page_id, repo_section_id, run_type, payload_json, approval_outcome, created_at, approved_at) VALUES ('3dd69f2fa9dfcab4', 'misinc', '78a43a7ac135d5d7', '6a0fb2ee3fd646cd2a754be0', '6a132d9a9e8bf0a84975c7d5', '59873aeb46eecbd7', 'b3fa47680ccb0bcb', 'analysis', '{"goals":["Preserve the section hierarchy from the repo source before styling.","Generate a lightweight skeleton only where structure is still missing.","Reuse shared typography, spacing, and utility classes where possible.","Keep new classes Client-First-compatible and section-functional."],"content":[],"summary":"Hero section with custom section structure.","warnings":[],"sourceCode":"import { motion } from \"motion/react\";\nimport type { ReactNode } from \"react\";\nimport { Link } from \"react-router\";\nimport heroBackgroundVideo from \"@/assets/MIS 30th anniversary Video April 09, 2026 - 12_17PM.mp4\";\nimport { cn } from \"@/app/components/ui/utils\";\n\nconst fadeInUp = {\n  hidden: { opacity: 0, y: 60 },\n  visible: {\n    opacity: 1,\n    y: 0,\n    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },\n  },\n};\n\nconst staggerContainer = {\n  hidden: { opacity: 0 },\n  visible: {\n    opacity: 1,\n    transition: {\n      staggerChildren: 0.12,\n      delayChildren: 0.1,\n    },\n  },\n};\n\nexport type HeroSectionAction = {\n  label: string;\n  to?: string;\n  scrollToId?: string;\n  variant?: \"primary\" | \"secondary\";\n};\n\nexport type HeroSectionProps = {\n  sectionId?: string;\n  eyebrow?: ReactNode;\n  title?: ReactNode;\n  description?: ReactNode;\n  backgroundVideoSrc?: string;\n  primaryAction?: HeroSectionAction;\n  secondaryAction?: HeroSectionAction;\n  supplemental?: ReactNode;\n  className?: string;\n};\n\nconst defaultPrimaryAction: HeroSectionAction = {\n  label: \"Book a Free Strategy Call\",\n  scrollToId: \"contact\",\n  variant: \"primary\",\n};\n\nconst defaultSecondaryAction: HeroSectionAction = {\n  label: \"View Case Studies\",\n  scrollToId: \"case-studies\",\n  variant: \"secondary\",\n};\n\nfunction HeroAction({\n  action,\n  onScroll,\n}: {\n  action: HeroSectionAction;\n  onScroll: (id: string) => void;\n}) {\n  const variant = action.variant ?? \"primary\";\n  const className =\n    variant === \"primary\"\n      ? \"bg-[#9B3139] content-stretch flex items-center justify-center px-[28px] py-[16px] relative rounded-[500px] shrink-0 z-[1]\"\n      : \"content-stretch flex items-center justify-center px-[28px] py-[16px] relative rounded-[500px] shrink-0 transition-all hover:bg-black/5\";\n  const textClassName =\n    variant === \"primary\"\n      ? \"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-[15px] text-white tracking-[1px]\"\n      : \"font-[''Manrope:Medium'',sans-serif] font-medium leading-[1.4] relative shrink-0 text-[#151515] text-[15px] tracking-[1px]\";\n  const content = (\n    <>\n      {variant === \"secondary\" ? (\n        <div\n          aria-hidden=\"true\"\n          className=\"absolute border border-[rgba(21,21,21,0.6)] border-solid inset-0 pointer-events-none rounded-[500px]\"\n        />\n      ) : null}\n      <span className={textClassName}>{action.label}</span>\n    </>\n  );\n\n  if (action.to) {\n    return (\n      <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>\n        <Link to={action.to} className={className}>\n          {content}\n        </Link>\n      </motion.div>\n    );\n  }\n\n  return (\n    <motion.button\n      type=\"button\"\n      onClick={() => {\n        if (action.scrollToId) {\n          onScroll(action.scrollToId);\n        }\n      }}\n      className={className}\n      whileHover={variant === \"primary\" ? { scale: 1.05, backgroundColor: \"#7A2730\" } : { scale: 1.05 }}\n      whileTap={{ scale: 0.95 }}\n    >\n      {content}\n    </motion.button>\n  );\n}\n\nexport function HeroSection({\n  sectionId = \"hero\",\n  eyebrow,\n  title = (\n    <>\n      Strategic Web Design & <br />\n      AI Solutions That Drive Business Growth\n    </>\n  ),\n  description = \"We design websites, build custom tools, and use AI to help you attract more customers and grow your business.\",\n  backgroundVideoSrc = heroBackgroundVideo,\n  primaryAction = defaultPrimaryAction,\n  secondaryAction = defaultSecondaryAction,\n  supplemental,\n  className,\n}: HeroSectionProps) {\n  const scrollToSection = (id: string) => {\n    const element = document.getElementById(id);\n    if (element) {\n      element.scrollIntoView({ behavior: \"smooth\" });\n    }\n  };\n\n  return (\n    <section\n      id={sectionId}\n      className={cn(\n        \"content-stretch flex flex-col items-center pb-[80px] md:pb-[120px] pt-[64px] md:pt-[100px] relative shrink-0 w-full overflow-hidden\",\n        className,\n      )}\n      data-name=\"Section Hero\"\n    >\n      <div className=\"hero-video-layer\" aria-hidden=\"true\">\n        <video autoPlay muted loop playsInline preload=\"metadata\">\n          <source src={backgroundVideoSrc} type=\"video/mp4\" />\n        </video>\n      </div>\n      <div className=\"hero-video-scrim\" aria-hidden=\"true\" />\n\n      <div\n        className=\"absolute inset-0 opacity-[0.03] pointer-events-none z-[2]\"\n        style={{\n          backgroundImage:\n            \"linear-gradient(#9B3139 1px, transparent 1px), linear-gradient(90deg, #9B3139 1px, transparent 1px)\",\n          backgroundSize: \"60px 60px\",\n        }}\n      />\n\n      <div className=\"content-stretch flex items-start relative shrink-0 w-full max-w-[1200px] px-5 md:px-8 lg:px-12 z-10\" data-name=\"Container\">\n        <motion.div\n          className=\"content-stretch flex flex-[1_0_0] flex-col gap-[32px] md:gap-[40px] isolate items-start min-h-px min-w-0 relative w-full\"\n          initial=\"hidden\"\n          animate=\"visible\"\n          variants={staggerContainer}\n        >\n          <motion.div\n            className=\"content-stretch flex flex-col font-[''Manrope:Light'',sans-serif] font-light gap-[20px] items-start relative shrink-0 text-[#2A2420] w-full z-[2]\"\n            variants={fadeInUp}\n          >\n            {eyebrow ? (\n              <motion.p\n                className=\"text-[12px] font-normal uppercase tracking-[1px] text-[#9B3139]\"\n                initial={{ opacity: 0, y: 24 }}\n                animate={{ opacity: 1, y: 0 }}\n                transition={{ duration: 0.6, delay: 0.12, ease: [0.22, 1, 0.36, 1] }}\n              >\n                {eyebrow}\n              </motion.p>\n            ) : null}\n            <motion.h1\n              className=\"leading-[1.1] relative shrink-0 text-[32px] sm:text-[48px] md:text-[56px] lg:text-[72px] w-full max-w-[900px]\"\n              initial={{ opacity: 0, y: 40 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.8, delay: 0.2, ease: [0.22, 1, 0.36, 1] }}\n            >\n              {title}\n            </motion.h1>\n            <motion.p\n              className=\"leading-[1.6] relative shrink-0 text-[16px] sm:text-[18px] md:text-[20px] max-w-[700px] text-[#4A3F37]\"\n              initial={{ opacity: 0, y: 30 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.8, delay: 0.4, ease: [0.22, 1, 0.36, 1] }}\n            >\n              {description}\n            </motion.p>\n          </motion.div>\n          <motion.div\n            className=\"flex flex-col sm:flex-row gap-[16px] items-start\"\n            initial={{ opacity: 0, y: 20 }}\n            animate={{ opacity: 1, y: 0 }}\n            transition={{ duration: 0.6, delay: 0.6 }}\n          >\n            <HeroAction action={primaryAction} onScroll={scrollToSection} />\n            <HeroAction action={secondaryAction} onScroll={scrollToSection} />\n          </motion.div>\n          {supplemental ? (\n            <motion.div\n              className=\"w-full\"\n              initial={{ opacity: 0, y: 20 }}\n              animate={{ opacity: 1, y: 0 }}\n              transition={{ duration: 0.6, delay: 0.72 }}\n            >\n              {supplemental}\n            </motion.div>\n          ) : null}\n        </motion.div>\n      </div>\n    </section>\n  );\n}\n","recommendedMode":"fullAssist","reusableClasses":["rl-styleguide_form-wrapper","navbar7_item-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","navbar7_icon-wrapper","margin-tiny","padding-xxsmall"],"sectionMetadata":{"pageId":"59873aeb46eecbd7","repoId":"78a43a7ac135d5d7","pageName":"CaseStudiesPage","sectionId":"b3fa47680ccb0bcb","sourceFile":"src/app/components/sections/HeroSection.tsx","sectionName":"Hero"},"suggestedNewClasses":["section_hero","hero_layout","hero_content"]}', NULL, '2026-05-24T23:18:47.863Z', NULL);
