be handled in a later step."},{"code":"provider-warning-4","level":"warning","message":"The source supports a supplemental content slot, but no concrete supplemental content was provided. An empty hero_supplemental wrapper is included for review and can be removed if unused."}],"elementTree":{"id":"b3fa47680ccb0bcb-root-parsed-0","tag":"section","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-1","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-2","tag":"video","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-3","tag":"source","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-4","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-5","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-6","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-7","tag":"div","type":"box","children":[{"id":"b3fa47680ccb0bcb-root-parsed-8","tag":"p","type":"text","children":[{"id":"b3fa47680ccb0bcb-root-parsed-9","tag":"button","type":"button","children":[],"classNames":["button","is-primary","button.button","div.hero_supplemental"]}],"classNames":["text-style-tagline","h1.hero_heading","p.text-size-medium","div.button-group.hero_actions"]}],"classNames":["hero_content"]}],"classNames":["hero_component"]}],"classNames":["padding-section-medium"]}],"classNames":["container-large"]}],"classNames":["div.hero_background-scrim","div.hero_background-grid","div.padding-global"]}],"classNames":["hero_background-video"]}],"classNames":["hero_background-media"]}],"classNames":["section_hero"]},"reusableClasses":["hero_background-scrim","padding-global","container-large","padding-section-medium","hero_heading","text-style-tagline","text-size-medium","button-group","button","is-primary"],"sectionMetadata":{"pageId":"59873aeb46eecbd7","repoId":"78a43a7ac135d5d7","pageName":"CaseStudiesPage","sectionId":"b3fa47680ccb0bcb","sourceFile":"src/app/components/sections/HeroSection.tsx","sectionName":"Hero"},"suggestedNewClasses":["section_hero","hero_background-media","hero_background-video","hero_background-grid","hero_component","hero_content","hero_actions","hero_supplemental"]}', NULL, '2026-05-25T02:19:28.648Z', NULL);
INSERT OR REPLACE INTO section_runs (id, user_id, repo_id, webflow_site_id, webflow_page_id, repo_page_id, repo_section_id, run_type, payload_json, approval_outcome, created_at, approved_at) VALUES ('5c2652201ed0237d', 'misinc', '6214c13d4994a673', '6a04ecde3b7207f4f9c49507', '6a051ee35138ec2c44533b60', '928cbe9e54d8c24f', '0a9f7c5f8595ea33', 'analysis', '{"goals":["Preserve the section hierarchy from the repo source before styling.","Use the current Webflow structure as the styling target to move faster.","Reuse shared typography, spacing, and utility classes where possible.","Keep new classes Client-First-compatible and section-functional."],"content":[],"summary":"Attorney Profiles section with custom section structure.","warnings":[{"code":"deterministic-analysis-0","level":"warning","message":"Source uses page- or section-scoped class patterns. Rename them to Client-First-compatible functional classes in Webflow."}],"sourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-12 text-foreground text-center\">\n            Our Attorneys\n          </h2>\n          \n          {/* Rebecca Windsor */}\n          <div className=\"mb-20\">\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={markPhoto}\n                    alt=\"Portrait of Mark Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Mark Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  mark@windsorlaw.us<br />\n                  (626) 792-6700\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had &quot;fought like tigers&quot; for his client in an alien smuggling trial.\n                  </p>\n                  <p>\n                    Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\n                  </p>\n                  <p>\n                    Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\n                  </p>\n                  <p>\n                    Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\n                  </p>\n                  \n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Bar Admissions</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>State Bar of California</li>\n                      <li>California State Courts</li>\n                      <li>U.S. District Court, Northern District of California</li>\n                      <li>U.S. District Court, Central District of California</li>\n                      <li>U.S. District Court, Southern District of California</li>\n                      <li>U.S. Court of Appeals, Ninth Circuit</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A. in History, Brown University</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Michael Kimball */}\n          <div>\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={katyPhoto}\n                    alt=\"Portrait of Katy Kimball Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Katy Kimball Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  katy@windsorlaw.us<br />\n                  (213) 663-9219\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\n                  </p>\n                  <p>\n                    She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\n                  </p>\n                  <p>\n                    Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\n                  </p>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A., Vassar College</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Experience</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)</li>\n                      <li>Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)</li>\n                      <li>Private practice focused on federal criminal defense and appeals</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","home-hero_badge-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","margin-tiny","padding-xxsmall","margin-huge"],"sectionMetadata":{"pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","pageName":"About","sectionId":"0a9f7c5f8595ea33","sourceFile":"src/app/pages/about.tsx","sectionName":"Attorney Profiles"},"suggestedNewClasses":["section_attorney-profiles","attorney-profiles_layout","attorney-profiles_content"]}', NULL, '2026-05-31T02:31:46.467Z', NULL);
