"heading-style-h1"],"textContent":"About Windsor Kimball APC"},{"id":"eb95636db4ddc198-root-parsed-7","tag":"p","type":"text","children":[],"classNames":["text-size-medium"],"textContent":"We are a boutique criminal defense firm serving clients in federal district court, California state court, and throughout the Ninth Circuit. Our practice is built on individualized attention, disciplined preparation, creative strategy, and direct client access at every stage of the case."}],"classNames":["header_content"]}],"classNames":["header_component"]}],"classNames":["padding-section-medium"]}],"classNames":["container-large"]}],"classNames":["padding-global"]}],"classNames":["section_header"]},"assetBindings":[],"reusableClasses":["heading-style-h1","text-size-medium"],"sectionMetadata":{"pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","pageName":"About","sectionId":"eb95636db4ddc198","sourceFile":"src/app/pages/about.tsx","sectionName":"Header"},"suggestedNewClasses":["section_header","header_component","header_content"]}', NULL, '2026-05-31T03:34:35.803Z', NULL);
INSERT OR REPLACE INTO section_runs (id, user_id, repo_id, webflow_site_id, webflow_page_id, repo_page_id, repo_section_id, run_type, payload_json, approval_outcome, created_at, approved_at) VALUES ('034fbfcc1589613e', 'misinc', '6214c13d4994a673', '6a04ecde3b7207f4f9c49507', '6a051ee35138ec2c44533b60', '928cbe9e54d8c24f', '0a9f7c5f8595ea33', 'analysis', '{"goals":["Preserve the section hierarchy from the repo source before styling.","Use the current Webflow structure as the styling target to move faster.","Reuse shared typography, spacing, and utility classes where possible.","Keep new classes Client-First-compatible and section-functional."],"content":[],"summary":"Attorney Profiles section with custom section structure.","warnings":[{"code":"deterministic-analysis-0","level":"warning","message":"Source uses page- or section-scoped class patterns. Rename them to Client-First-compatible functional classes in Webflow."}],"sourceCode":"<section className=\"bg-white py-20\">\n        <div className=\"max-w-7xl mx-auto px-6 lg:px-8\">\n          <h2 className=\"text-3xl mb-12 text-foreground text-center\">\n            Our Attorneys\n          </h2>\n          \n          {/* Rebecca Windsor */}\n          <div className=\"mb-20\">\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={markPhoto}\n                    alt=\"Portrait of Mark Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Mark Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  mark@windsorlaw.us<br />\n                  (626) 792-6700\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had &quot;fought like tigers&quot; for his client in an alien smuggling trial.\n                  </p>\n                  <p>\n                    Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\n                  </p>\n                  <p>\n                    Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\n                  </p>\n                  <p>\n                    Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\n                  </p>\n                  \n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Bar Admissions</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>State Bar of California</li>\n                      <li>California State Courts</li>\n                      <li>U.S. District Court, Northern District of California</li>\n                      <li>U.S. District Court, Central District of California</li>\n                      <li>U.S. District Court, Southern District of California</li>\n                      <li>U.S. Court of Appeals, Ninth Circuit</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A. in History, Brown University</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Michael Kimball */}\n          <div>\n            <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n              <div className=\"lg:col-span-1\">\n                <div className=\"relative aspect-[3/4] mb-6 overflow-hidden rounded\">\n                  <ImageWithFallback\n                    src={katyPhoto}\n                    alt=\"Portrait of Katy Kimball Windsor\"\n                    className=\"w-full h-full object-cover\"\n                  />\n                </div>\n                <h3 className=\"text-2xl mb-2\">\n                  Katy Kimball Windsor\n                </h3>\n                <p className=\"text-sm text-muted-foreground mb-4\">Partner</p>\n                <p className=\"text-sm text-muted-foreground\">\n                  katy@windsorlaw.us<br />\n                  (213) 663-9219\n                </p>\n              </div>\n              <div className=\"lg:col-span-2\">\n                <div className=\"space-y-6 text-muted-foreground leading-relaxed\">\n                  <p>\n                    For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\n                  </p>\n                  <p>\n                    She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\n                  </p>\n                  <p>\n                    Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\n                  </p>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Education</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>J.D., University of California, Davis (Martin Luther King, Jr. School of Law)</li>\n                      <li>B.A., Vassar College</li>\n                    </ul>\n                  </div>\n\n                  <div className=\"pt-4\">\n                    <h4 className=\"mb-3\">Experience</h4>\n                    <ul className=\"list-disc list-inside space-y-1 text-sm\">\n                      <li>Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)</li>\n                      <li>Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)</li>\n                      <li>Private practice focused on federal criminal defense and appeals</li>\n                    </ul>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","home-hero_badge-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","margin-tiny","padding-xxsmall","margin-huge"],"sectionMetadata":{"pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","pageName":"About","sectionId":"0a9f7c5f8595ea33","sourceFile":"src/app/pages/about.tsx","sectionName":"Attorney Profiles"},"suggestedNewClasses":["section_attorney-profiles","attorney-profiles_layout","attorney-profiles_content"]}', NULL, '2026-05-31T03:35:19.821Z', NULL);
INSERT OR REPLACE INTO section_runs (id, user_id, repo_id, webflow_site_id, webflow_page_id, repo_page_id, repo_section_id, run_type, payload_json, approval_outcome, created_at, approved_at) VALUES ('c6cd61b15c4849d4', 'misinc', '6214c13d4994a673', '6a04ecde3b7207f4f9c49507', '6a051ee35138ec2c44533b60', '928cbe9e54d8c24f', '0a9f7c5f8595ea33', 'skeleton', '{"treeText":"section.section_attorney-profiles\n  div.padding-global\n    div.container-large\n      div.padding-section-medium\n        div.attorney-profiles_component\n          h2.heading-style-h2 \"Our Attorneys\"\n          div.attorney-profiles_list\n            div.attorney-profiles_item\n              div.attorney-profiles_content\n                div.attorney-profiles_card\n                  div.attorney-profiles_media\n                    img.attorney-profiles_image\n                  h3.heading-style-h3 \"Mark Windsor\"\n                  p.text-size-small \"Partner\"\n                  p.text-size-small \"mark@windsorlaw.us (626) 792-6700\"\n                div.attorney-profiles_content\n                  div.attorney-profiles_content\n                    p.text-size-medium \"Mr. Windsor is a veteran criminal defense lawyer, widely regarded in the legal community as a fierce, creative, and relentless advocate for his clients. He began his career in 1997 as a trial lawyer at the renowned Federal Defenders of San Diego, Inc. There he quickly distinguished himself with victories at both the trial and appellate levels. In one notable case, the former Chief Justice for the Ninth Circuit Court of Appeals declared in his written opinion that Mr. Windsor and co-counsel had \\\"fought like tigers\\\" for his client in an alien smuggling trial.\"\n                    p.text-size-medium \"Since 2000, Mr. Windsor has been in private practice representing the accused in federal district court in the Northern, Southern, and Central Districts of California, as well as in the Ninth Circuit Court of Appeals and in California State Courts. He has broad experience in all areas of criminal defense, including complex litigation in RICO conspiracy, narcotics offenses, international wire and bank fraud, tax evasion, VICAR murder, and Fourth and Fifth amendment challenges to government overreach. In recent years, Mr. Windsor has continued his tradition of success at the trial and appellate levels, having been named California Super Lawyer for the years 2018 to 2021, and one of Pasadena Magazine''s Top Lawyers for 2020 and 2021.\"\n                    p.text-size-medium \"Mr. Windsor currently shares his experience and expertise as an Adjunct Assistant Professor of Constitutional Law at a local law school in Los Angeles.\"\n                    p.text-size-medium \"Mr. Windsor spent his childhood on Martha''s Vineyard, an island off the coast of Cape Cod, Massachusetts. He graduated from Brown University with a B.A. in history, and then spent several years working abroad and traveling extensively. Mr. Windsor finally settled in California, where he attended law school at the University of California, Davis (Martin Luther King, Jr. School of Law). He now lives and works in Pasadena, California. His law office is located at 65 North Raymond Avenue, Suite 320, Pasadena, California 91103.\"\n                    div.attorney-profiles_list\n                      div.attorney-profiles_item\n                        h4.heading-style-h4 \"Bar Admissions\"\n                        ul.attorney-profiles_list\n                          li.attorney-profiles_item \"State Bar of California\"\n                          li.attorney-profiles_item \"California State Courts\"\n                          li.attorney-profiles_item \"U.S. District Court, Northern District of California\"\n                          li.attorney-profiles_item \"U.S. District Court, Central District of California\"\n                          li.attorney-profiles_item \"U.S. District Court, Southern District of California\"\n                          li.attorney-profiles_item \"U.S. Court of Appeals, Ninth Circuit\"\n                      div.attorney-profiles_item\n                        h4.heading-style-h4 \"Education\"\n                        ul.attorney-profiles_list\n                          li.attorney-profiles_item \"J.D., University of California, Davis (Martin Luther King, Jr. School of Law)\"\n                          li.attorney-profiles_item \"B.A. in History, Brown University\"\n            div.attorney-profiles_item\n              div.attorney-profiles_content\n                div.attorney-profiles_card\n                  div.attorney-profiles_media\n                    img.attorney-profiles_image\n                  h3.heading-style-h3 \"Katy Kimball Windsor\"\n                  p.text-size-small \"Partner\"\n                  p.text-size-small \"katy@windsorlaw.us (213) 663-9219\"\n                div.attorney-profiles_content\n                  div.attorney-profiles_content\n                    p.text-size-medium \"For nearly thirty years, Ms. Kimball Windsor has represented clients fighting criminal charges in federal court. Focused primarily on appellate practice, she has handled a wide variety of cases from white collar fraud to RICO, drug trafficking, and immigration crimes.\"\n                    p.text-size-medium \"She has represented numerous clients in the Ninth Circuit Court of Appeals, and is also an experienced trial lawyer who has litigated in the Central and Southern Districts of California. Before entering private practice, she served as a trial attorney at Federal Defenders of San Diego, Inc. from 1996 to 2002, and as a Supervising Attorney at the same office from 2002 to 2003.\"\n                    p.text-size-medium \"Ms. Kimball Windsor received her B.A. from Vassar College, and her J.D. from University of California, Davis, Martin Luther King, Jr. School of Law.\"\n                    div.attorney-profiles_list\n                      div.attorney-profiles_item\n                        h4.heading-style-h4 \"Education\"\n                        ul.attorney-profiles_list\n                          li.attorney-profiles_item \"J.D., University of California, Davis (Martin Luther King, Jr. School of Law)\"\n                          li.attorney-profiles_item \"B.A., Vassar College\"\n                      div.attorney-profiles_item\n                        h4.heading-style-h4 \"Experience\"\n                        ul.attorney-profiles_list\n                          li.attorney-profiles_item \"Federal Defenders of San Diego, Inc., Trial Attorney (1996-2002)\"\n                          li.attorney-profiles_item \"Federal Defenders of San Diego, Inc., Supervising Attorney (2002-2003)\"\n                          li.attorney-profiles_item \"Private practice focused on federal criminal defense and appeals\"","warnings":[{"code":"skeleton-html-fallback","level":"warning","message":"OpenAI skeleton generation was unavailable, so a deterministic HTML-derived fallback skeleton was used."},{"code":"skeleton-error","level":"warning","message":"OpenAI skeleton_plan timed out after 25 seconds."}],"elementTree":{"id":"0a9f7c5f8595ea33-root","tag":"section","type":"box","children":[{"id":"0a9f7c5f8595ea33-padding","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-container","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-section-padding","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-component","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-component-0","tag":"h2","type":"heading","children":[],"classNames":["heading-style-h2"],"textContent":"Our Attorneys"},{"id":"0a9f7c5f8595ea33-component-list-1","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-component-item-1","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-component-item-1-0","tag":"div","type":"box","children":[{"id":"0a9f7c5f8595ea33-component-item-1-0-0","tag":"div","type":"box","children":[{"id":"0a9