div>\n              <div className=\"bg-white p-6 rounded\">\n                <h3 className=\"mb-4\">Appellate Courts</h3>\n                <ul className=\"space-y-2 text-sm text-muted-foreground\">\n                  <li>• U.S. Court of Appeals, Ninth Circuit</li>\n                </ul>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>","recommendedMode":"styleExisting","reusableClasses":["rl-styleguide_form-wrapper","home-hero_badge-text","stylesystem_margin-right","margin-custom1","padding-large","margin-small","padding-medium","margin-medium","padding-xsmall","padding-custom2","text-weight-normal","stylesystem_margin-vertical","padding-0","margin-tiny","padding-xxsmall","margin-huge"],"sectionMetadata":{"pageId":"928cbe9e54d8c24f","repoId":"6214c13d4994a673","pageName":"About","sectionId":"5c0f83636ab8632f","sourceFile":"src/app/pages/about.tsx","sectionName":"Jurisdictions"},"suggestedNewClasses":["section_jurisdictions","jurisdictions_layout","jurisdictions_content"]}', NULL, '2026-05-31T14:15:57.603Z', NULL);
